INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Crossover', '', '"With a bolt of lightning on my kicks . . .The court is SIZZLING. My sweat is DRIZZLING. Stop all that quivering. Cuz tonight I''m delivering," announces dread-locked, 12-year old Josh Bell. He and his twin brother Jordan are awesome on the court. But Josh has more than basketball in his blood, he''s got mad beats, too, that tell his family''s story in verse, in this fast and furious middle grade novel of family and brotherhood.
Josh and Jordan must come to grips with growing up on and off the court to realize breaking the rules comes at a terrible price, as their story''s heart-stopping climax proves a game-changer for the entire family.', 'https://images.gr-assets.com/books/1390427593m/18263725.jpg', '18263725', '4.22', '23725', '3990', 'https://www.goodreads.com/book/show/18263725-the-crossover');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'Opening with Professor Tomlinson''s superbly clear and helpful introduction this selection reflects the most up-to-date Williams scholarship. In addition to including many more pieces, Tomlinson has organized the whole in chronological order.
It isn''t what he [the poet] says that counts as a work of art," Williams maintained, "it''s what he makes, with such intensity of purpose that it lives with an intrinsic movement of its own to verify its authenticity.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '65336', '4.15', '11922', '116', 'https://www.goodreads.com/book/show/65336.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Portable Dorothy Parker', '', 'This collection ranges over the verse, stories, essays, and journalism of one of the twentieth century''s most quotable authors.', 'https://images.gr-assets.com/books/1386926061m/46231.jpg', '46231', '4.34', '8776', '304', 'https://www.goodreads.com/book/show/46231.The_Portable_Dorothy_Parker');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Collected Poems of Emily Dickinson', '', '&&LDIV&&R&&LDIV&&R&&LI&&RThe Collected Poems of Emily Dickinson&&L/I&&R, by &&LB&&REmily Dickinson&&L/B&&R, is part of the &&LI&&R&&LI&&RBarnes & Noble Classics&&L/I&&R &&L/I&&Rseries, which offers quality editions at affordable prices to the student and the general reader, including new scholarship, thoughtful design, and pages of carefully crafted extras. Here are some of the remarkable features of &&LI&&RBarnes & Noble Classics&&L/I&&R: &&LDIV&&R
New introductions commissioned from today''s top writers and scholars
Biographies of the authors
Chronologies of contemporary historical, biographical, and cultural events
Footnotes and endnotes
Selective discussions of imitations, parodies, poems, books, plays, paintings, operas, statuary, and films inspired by the work
Comments by other famous authors
Study questions to challenge the reader''s viewpoints and expectations
Bibliographies for further reading
Indices & Glossaries, when appropriate
All editions are beautifully designed and are printed to superior specifications; some include illustrations of historical interest. &&LI&&RBarnes & Noble Classics &&L/I&&Rpulls together a constellation of influences--biographical, historical, and literary--to enrich each reader''s understanding of these enduring works.&&L/DIV&&R&&L/DIV&&R&&L/DIV&&R&&LDIV&&R &&L/DIV&&R&&LDIV&&RBorn in Amherst, Massachusetts in 1830, &&LB&&RDickinson&&L/B&&R began life as an energetic, outgoing young woman who excelled as a student. However, in her mid-twenties she began to grow reclusive, and eventually she rarely descended from her room in her father''s house. She spent most of her time working on her poetry, largely without encouragement or real interest from her family and peers, and died at age fifty-five. Only a handful of her 1,775 poems had been published during her lifetime. When her poems finally appeared after her death, readers immediately recognized an artist whose immense depth and stylistic complexities would one day make her the most w', 'https://images.gr-assets.com/books/1411632009m/67522.jpg', '67522', '4.21', '8458', '145', 'https://www.goodreads.com/book/show/67522.The_Collected_Poems_of_Emily_Dickinson');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Complete English Poems', '', 'Yet it is only this century that Donne has been indisputably established as a great poet--and even, many feel, the greatest love poet of them all. Jonson went on to remark that ''That Donne, for not keeping of an accent, deserved hanging'', yet Donne''s rhythms, once thought ''unmusical'' are now recognized as the natural rhythms of the speaking voice; his ''eccentricity'' as a complex self-doubt; his ''obscurity'' the reflection of a brilliantly learned and allusive mind. Poets such as Eliot and Empson have found Donne''s poetry profoundly attuned to our modern age, while Yeats'' glowing comment will always be true: ''the intricacy and subtlety of his imagination are the length and depth of the furrow made by his passion.''
This volume, superbly edited by Professor Smith, is the first complete edition to make a serious attempt to guide the reader closely through the complexities of Donne''s poetry. Considerable attention has been paid to the text, and a selection of the important manuscript variants are included. This edition is also the first to make use of the newly discovered manuscript of the verse letter to Lady Carey and Mistress Essex Rich.', 'https://images.gr-assets.com/books/1373042930m/134025.jpg', '134025', '4.14', '8309', '59', 'https://www.goodreads.com/book/show/134025.The_Complete_English_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Teaching My Mother How to Give Birth', '', 'What elevates ''teaching my mother how to give birth'', what gives the poems their disturbing brilliance, is Warsan Shire''s ability to give simple, beautiful eloquence to the veiled world where sensuality lives in the dominant narrative of Islam; reclaiming the more nuanced truths of earlier times - as in Tayeb Salih''s work - and translating to the realm of lyric the work of the likes of Nawal El Saadawi. As Rumi said, "Love will find its way through all languages on its own"; in ''teaching my mother how to give birth'', Warsan''s debut pamphlet, we witness the unearthing of a poet who finds her way through all preconceptions to strike the heart directly. Warsan Shire is a Kenyan-born Somali poet and writer who is based in London. Born in 1988, she is an artist and activist who uses her work to document narratives of journey and trauma. Warsan has read her work internationally, including recent readings in South Africa, Italy and Germany, and her poetry has been translated into Italian, Spanish and Portuguese.', 'https://images.gr-assets.com/books/1456003618m/13376363.jpg', '13376363', '4.38', '7830', '745', 'https://www.goodreads.com/book/show/13376363-teaching-my-mother-how-to-give-birth');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Kaddish and Other Poems', '', 'Great strange visionary poems by the author of Howl, "in the midst of the broken consciousness of mid-twentieth century . . ."
In the midst of the broken consciousness of mid-twentieth century suffering anguish of separation from my own body and its natural infinity of feeling its own self one with all self, I instinctively seeking to reconstitute that blissful union which I experience so rarely. I took it to be supernatural an gave it holy Name thus made hymn laments of longing and litanies of triumphancy of Self over mind-illusion mechano-universe of un-feeling Time in which I saw my self my own mother and my very nation trapped desolate our worlds of consciousness homeless and at war except for the original trembling of bliss in breast and belly of every body that nakedness rejected in suits of fear that familiar defenseless living hurt self which is myself same as all others abandoned scared to own unchanging desire for each other. These poems almost unconscious to confess the beatific human fact, the language intuitively chosen as in trance & dream, the rhythms rising on breath from belly thru breast, the hymn completed in tears, the movement of the physical poetry demanding and receiving decades of life while chanting Kaddish the names of Death in many worlds the self seeking the Key to life found at last in our self.', 'https://images.gr-assets.com/books/1327958040m/47180.jpg', '47180', '4.19', '7760', '91', 'https://www.goodreads.com/book/show/47180.Kaddish_and_Other_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Egghead: Or, You Can''t Survive on Ideas Alone', '', 'A strange and charming collection of hilariously absurd poetry, writing, and illustration from one of today''s most popular young comedians...
Bo Burnham was a precocious teenager living in his parents'' attic when he started posting material on YouTube. 100 million people viewed those videos, turning Bo into an online sensation with a huge and dedicated following. Bo taped his first of two Comedy Central specials four days after his 18th birthday, making him the youngest to do so in the channel''s history. Now Bo is a rising star in the comedy world, revered for his utterly original and intelligent voice. And, he can SIIIIIIIIING!
In EGGHEAD, Bo brings his brand of brainy, emotional comedy to the page in the form of off-kilter poems, thoughts, and more. Teaming up with his longtime friend, artist, and illustrator Chance Bone, Bo takes on everything from death to farts in this weird book that will make you think, laugh and think, "why did I just laugh?"', 'https://images.gr-assets.com/books/1400879372m/17333426.jpg', '17333426', '4.12', '6461', '553', 'https://www.goodreads.com/book/show/17333426-egghead');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Annabel Lee', '', 'The poem by Edgar Allan Poe set, by the artist, Gilles Tibo, in the 1930s on the Gaspe Peninsula, Quebec.', 'https://images.gr-assets.com/books/1172464693m/178911.jpg', '178911', '4.35', '6049', '238', 'https://www.goodreads.com/book/show/178911.Annabel_Lee');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poetry and Prose', '', 'This Library of America edition is the most comprehensive volume of the work of Walt Whitman (1819-1892) ever published. It includes all of his poetry and what he considered his complete prose. It is also the only collection that includes, in exactly the form in which it appeared in 1855, the first edition of Leaves of Grass. This was the book, a commercial failure, which prompted Emerson''s famous message to Whitman: "I greet you at the beginning of a great career." These twelve poems, including what were later to be entitles "Song of Myself" and "I Sing the Body Electric," and a preface announcing the author''s poetic theories, were the first stage of a massive, lifelong work. Six editions and some thirty-seven years later, Leaves of Grass had become one of the central volumes in the history of world poetry.
Each edition involved revisions of earlier poems and the incorporation of new ones. In 1856, for example, he added such poems as "Crossing Brooklyn Ferry" and "Spontaneous Me;" in the third edition (1860), "Out of the Cradle Endlessly Rocking" and two new sections, "Calamus" and "Children of Adam." In the fourth (1867), he incorporated the Civil War poems published a few years earlier as Drum-Taps and Sequel to Drum-Taps, including the poems on the death of Lincoln, notably "When Lilacs Last in the Door Yard Bloom''d." As it progressed, it was hailed by Emerson, Thoreau, Rosetti and others, but was also, as with the sixth edition in 1881-82, beset by charges of obscenity for such poems as "A Woman Waits for Me." Printed here is the final, great culminating edition of 1891-92, the last supervised by Whitman himself just before his death.
Whitman''s prose is no lessextraordinary. Specimen Days and Collect (1882) includes reminiscences of nineteenth-century New York City that will fascinate readers in the twenty-first, notes on the Civil War, especially his service in Washington hospitals, and trenchant comments on books and authors. Democratic Vistas (1871), in its ', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '45287', '4.29', '5859', '48', 'https://www.goodreads.com/book/show/45287.Poetry_and_Prose');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'With the publication of his first book of poems, The Weary Blues, in 1926, Langston Hughes electrified readers and launched a renaissance in black writing in America. The poems Hughes wrote celebrated the experience of invisible men and women: of slaves who "rushed the boots of Washington"; of musicians on Lenox Avenue; of the poor and the lovesick; of losers in "the raffle of night." They conveyed that experience in a voice that blended the spoken with the sung, that turned poetic lines into the phrases of jazz and blues, and that ripped through the curtain separating high from popular culture. They spanned the range from the lyric to the polemic, ringing out "wonder and pain and terror-- and the marrow of the bone of life."
The poems in this collection were chosen by Hughes himself shortly before his death in 1967 and represent work from his entire career, including "The Negro Speaks of Rivers," "The Weary Blues," "Still Here," "Song for a Dark Girl," "Montage of a Dream Deferred," and "Refugee in America." It gives us a poet of extraordinary range, directness, and stylistic virtuosity.', 'https://images.gr-assets.com/books/1327930875m/65335.jpg', '65335', '4.29', '5468', '158', 'https://www.goodreads.com/book/show/65335.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Pan Tadeusz', '', 'An epic tale of country life among the Polish and Lithuanian gentry in 1811-1812, PAN TADEUSZ by Adam Mickiewicz is perhaps Poland''s best-known literary work and has been translated into almost every European language. This bilingual edition, with side by side Polish and English, features Kenneth R. Mackenzie''s celebrated English translation.
The plot has the typical elements of a romantic, historical novel: a feud between two ancient families, a love story crossed by the feud, a mysterious figure who dominates the action, and a number of eccentric subordinate characters humorously depicted.
To Poles of all generations, the life, the scenes, and the characters embody the ideals, sentiments and way of life of the whole nation.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '881508', '3.33', '4819', '30', 'https://www.goodreads.com/book/show/881508.Pan_Tadeusz');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Jabberwocky and Other Poems', '', 'Carefully chosen collection contains 34 of Carroll''s most appealing verses -- nonsense verse, parodies, burlesques, more -- including such unforgettable pieces as "The Walrus and the Carpenter," "The Mock Turtle''s Song," and "Father William," as well as such lesser-known gems as "My Fancy," "A Sea Dirge," "Brother and Sister," "Hiawatha''s Photographing," "The Mad Gardener''s Song," "What Tottles Meant," "Poeta Fit, non Nascitur," "The Little Man That Had a Little Gun," and many others.', 'https://images.gr-assets.com/books/1328866147m/143466.jpg', '143466', '4.18', '4661', '57', 'https://www.goodreads.com/book/show/143466.Jabberwocky_and_Other_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Stop Pretending: What Happened When My Big Sister Went Crazy', '', 'Continuously in print for nearly two decades, this groundbreaking and profoundly moving story told in verse, from award-winning author Sonya Sones, has been repackaged with a striking new cover and bonus content.
When her beloved older sister is hospitalized after a sudden mental breakdown, Cookie is left behind to cope with a family torn apart by grief, friends who shun her, and her fear that she, too, might one day lose her mind.
Based on award-winning author Sonya Sones''s own true story, this novel explores the chilling landscape of mental illness, revealing glimmers of beauty and of hope along the way. Told in a succession of short and powerful poems, it takes us deep into the cyclone of the narrator''s emotions: despair, anger, guilt, resentment, and ultimately, acceptance.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '111044', '3.89', '3956', '453', 'https://www.goodreads.com/book/show/111044.Stop_Pretending');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Nibelungenlied', '', 'Written by an unknown author in the twelfth century, this powerful tale of murder and revenge reaches back to the earliest epochs of German antiquity, transforming centuries-old legend into a masterpiece of chivalric drama. Siegfried, a great prince of the Netherlands, wins the hand of the beautiful princess Kriemhild of Burgundy, by aiding her brother Gunther in his struggle to seduce a powerful Icelandic Queen. But the two women quarrel, and Siegfried is ultimately destroyed by those he trusts the most. Comparable in scope to the Iliad, this skilfully crafted work combines the fragments of half-forgotten myths to create one of the greatest epic poems - the principal version of the heroic legends used by Richard Wagner, in The Ring.', 'https://images.gr-assets.com/books/1377408982m/18261.jpg', '18261', '3.87', '3536', '139', 'https://www.goodreads.com/book/show/18261.The_Nibelungenlied');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('في عقيدة الحب كلنا يهود', '', '', 'https://images.gr-assets.com/books/1363451490m/17619475.jpg', '17619475', '3.62', '3386', '297', 'https://www.goodreads.com/book/show/17619475');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Pleasures of the Damned', '', 'To his legions of fans, Charles Bukowski was--and remains--the quintessential counterculture icon. A hard-drinking wild man of literature and a stubborn outsider to the poetry world, he wrote unflinchingly about booze, work, and women, in raw, street-tough poems whose truth has struck a chord with generations of readers.
Edited by John Martin, the legendary publisher of Black Sparrow Press and a close friend of Bukowski''s, The Pleasures of the Damnedis a selection of the best works from Bukowski''s long poetic career, including the last of his never-before-collected poems. Celebrating the full range of the poet''s extraordinary and surprising sensibility, and his uncompromising linguistic brilliance, these poems cover a rich lifetime of experiences and speak to Bukowski''s "immense intelligence, the caring heart that saw through the sham of our pretenses and had pity on our human condition" (New York Quarterly). The Pleasures of the Damnedis an astonishing poetic treasure trove, essential reading for both longtime fans and those just discovering this unique and legendary American voice.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '220682', '4.43', '3335', '142', 'https://www.goodreads.com/book/show/220682.The_Pleasures_of_the_Damned');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('رباعيات خيام', '', 'The rubaiyat are a series of poems or ''stanzas'' by the famous 12th century Persian atronomer and philosopher
The Rubaiyat of Omar Khayyam (Persian: rb`yt `mr khym) is the title that Edward FitzGerald gave to his translation of a selection of poems, originally written in Persian and numbering about a thousand, attributed to Omar Khayyam (1048-1131), a Persian poet, mathematician and astronomer. A ruba''i is a two-line stanza with two parts (or hemistichs) per line, hence the word rubaiyat (derived from the Arabic language root for "four"), meaning "quatrains". (Courtesy: Wikipedia)(less)', 'https://images.gr-assets.com/books/1441007730m/716696.jpg', '716696', '4.18', '3251', '161', 'https://www.goodreads.com/book/show/716696._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Plumb', '', 'Bacovia cel adevarat e in poemele in care spiritul "decadent" al simbolistilor francezi e absorbit de atmosfera apasatoare si sumbra a tristelor locuri unde nu s-a intamplat nimic. El e intaiul mare poet al "deznadejdii provinciale", fara el n-ar fi de inteles o intreaga literatura de dupa primul razboi. Bacovia reprezinta punctul cel mai inalt al simbolismului romanesc, situandu-se totodata, prin valoare, mai presus de simbolism si de orice curent literar, in universalitate. Influenta lui asupra poeziei secolului XX ramane o pagina nescrisa a istoriei noastre literare. Ea e extraordinara, dar implica un paradox: poetul cu cel mai adanc ecou asupra poeziei romane moderne este, izolat in strania lui frumusete, inimitabil.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6061538', '4.1', '2911', '19', 'https://www.goodreads.com/book/show/6061538-plumb');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Epic of Gilgamesh', '', 'Andrew George''s "masterly new translation" (The Times) of the world''s first truly great work of literature
Miraculously preserved on clay tablets dating back as much as four thousand years, the poem of Gilgamesh, king of Uruk, is the world''s oldest epic, predating Homer by many centuries. The story tells of Gilgamesh''s adventures with the wild man Enkidu, and of his arduous journey to the ends of the earth in quest of the Babylonian Noah and the secret of immortality. Alongside its themes of family, friendship and the duties of kings, the Epic of Gilgameshis, above all, about mankind''s eternal struggle with the fear of death.
The Babylonian version has been known for over a century, but linguists are still deciphering new fragments in Akkadian and Sumerian. Andrew George''s gripping translation brilliantly combines these into a fluent narrative and will long rank as the definitive English Gilgamesh.
For more than seventy years, Penguin has been the leading publisher of classic literature in the English-speaking world. With more than 1,700 titles, Penguin Classics represents a global bookshelf of the best works throughout history and across genres and disciplines. Readers trust the series to provide authoritative texts enhanced by introductions and notes by distinguished scholars and contemporary authors, as well as up-to-date translations by award-winning translators.', 'https://images.gr-assets.com/books/1327978290m/617495.jpg', '617495', '3.63', '2848', '200', 'https://www.goodreads.com/book/show/617495.The_Epic_of_Gilgamesh');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('شعرها ١٣٢٣ - ١٣٧٨ : دفتر یکم', '', 'Ahmad Shamlu (1925-2000) is considered to be one of Iran''s greatest poets and one of the most influential literary figures of the 20th century. A native of Tehran, Shamlu has been publishing poetry and other writings since the mid-1940s. His poetry, like much great literature, appears simple on the surface but actually have many layers of meaning to appreciate. Shamlu has also written many plays.
In addition to acclaim from critics and readers alike, Shamlu has also received honors from organizations such as Human Rights Watch for his emphasis on freedom of expression and social justice.
This book is a collection of Shamlu''s works, covering Persian years 1323-1378 (1944-1999 Common Era). Originally published as a two-volume set, this edition combines the two volumes into one.
The text is written entirely in Persian (Farsi). It makes an excellent introduction to Shamlu''s works as well as a comprehensive reference for scholars and fans.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '433478', '4.43', '2647', '71', 'https://www.goodreads.com/book/show/433478._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Complete Poems', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '75494', '4.14', '2436', '53', 'https://www.goodreads.com/book/show/75494.The_Complete_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Piers Plowman', '', 'Astonishing in its cultural and theological scope, William Langland''s iconoclastic masterpiece is at once a historical relic and a deeply spiritual vision, probing not only the social and religious aristocracy but also the day-to-day realities of a largely voiceless proletariat class. E. Talbot Donaldson''s translation of the text has been selected for this Norton Critical Edition because of its skillful emulation of the original poem''s distinct alliterative verse. Selections of the authoritative Middle English text are also included for comparative analysis. "Sources and Backgrounds" includes a large collection of contemporary religious and historical documents pertaining to the poem, including selections from the Douai Bible, accounts of the plague, and legal statutes. "Criticism" includes twenty interpretive essays by leading medievalists, among them E. Talbot Donaldson, George Kane, Jill Mann, Derek Pearsall, C. David Benson, and Elizabeth D. Kirk. A Glossary and Selected Bibliography are also included.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '429679', '3.4', '2044', '48', 'https://www.goodreads.com/book/show/429679.Piers_Plowman');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Book of Nightmares', '', 'Galway Kinnell''s poetry has always been marked by richness of language, devotion to the things and creatures of the world, and an effort to transform every understanding into the universality of art.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '18901', '4.24', '1978', '98', 'https://www.goodreads.com/book/show/18901.The_Book_of_Nightmares');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Medea', '', 'Ahl''s translations of three Senecan tragedies will gratify and challenge readers and performers. With stage performance specifically in mind, Ahl renders Seneca''s dramatic force in a modern idiom and style that move easily between formality and colloquialism as the text demands, and he strives to reproduce the richness of the original Latin, to retain the poetic form, images, wordplays, enigmas, paradoxes, and dark humor of Seneca''s tragedies.
In this powerful and imaginative translation of Medea, Frederick Ahl retains the compelling effects of the monologues, as well as the special feeling and pacing of Seneca''s choruses.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '381209', '4.06', '1970', '29', 'https://www.goodreads.com/book/show/381209.Medea');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Conference of the Birds', '', 'Composed in the twelfth century in north-eastern Iran, Attar''s great mystical poem is among the most significant of all works of Persian literature. A marvellous, allegorical rendering of the Islamic doctrine of Sufism - an esoteric system concerned with the search for truth through God - it describes the consequences of the conference of the birds of the world when they meet to begin the search for their ideal king, the Simorgh bird. On hearing that to find him they must undertake an arduous journey, the birds soon express their reservations to their leader, the hoopoe. With eloquence and insight, however, the hoopoe calms their fears, using a series of riddling parables to provide guidance in the search for spiritual truth. By turns witty and profound, The Conference of the Birdstransforms deep belief into magnificent poetry.', 'https://images.gr-assets.com/books/1332633919m/144870.jpg', '144870', '4.2', '1861', '110', 'https://www.goodreads.com/book/show/144870.The_Conference_of_the_Birds');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Scattered Poems', '', 'Spontaneous poetry by the author of On the Road, gathered from underground and ephemeral publications; including "San Francisco Blues," the variant texts of "Pull My Daisy," and American haiku.
HERE DOWN ON DARK EARTH
before we all go to Heaven
VISIONS OF AMERICA
All that hitchhikin
All that railroadin
All that comin back
to America --Jack Kerouac', 'https://images.gr-assets.com/books/1428902356m/260683.jpg', '260683', '3.75', '1809', '55', 'https://www.goodreads.com/book/show/260683.Scattered_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('رسائل الأحزان', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '4096668', '4.09', '1731', '323', 'https://www.goodreads.com/book/show/4096668');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'In his unconventional verse, Walt Whitman spoke in a powerful, sensual, oratorical, and inspiring voice. His most famous work, Leaves of Grass,was a long-term project that the poet compared to the building of a cathedral or the slow growth of a tree. During his lifetime, from 1819 to 1892, it went through nine editions. Today it is regarded as a landmark of American literature.
This volume contains 24 poems from Leaves of Grass,offering a generous sampling of Whitman''s best and most representative verses. Featured works include "I Hear America Singing," "I Sing the Body Electric," "Song of the Open Road," "Out of Cradle Endlessly Rocking," "When Lilacs Last in the Dooryard Bloom''d," and "O Captain! My Captain!" -- all reprinted from an authoritative text.', 'https://images.gr-assets.com/books/1328868118m/752886.jpg', '752886', '4.1', '1668', '22', 'https://www.goodreads.com/book/show/752886.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Persians', '', 'Essa peca e considerada unica entre as tragedias remanescentes do periodo por retratar um evento historico - a guerra entre os gregos e os persas - em vez de dramatizar uma epoca distante, de herois miticos. A peca gira em torno do desastre em que os invasores da Grecia viram suas forcas navais aniquiladas pelos gregos na Batalha de Salamina.
A acao se passa na capital persa onde um mensageiro leva a rainha a noticia do desastre. Depois de atribuir a derrota da Persia a independencia e bravura gregas assim como ao castigo dos deuses aos persas por terem ido alem dos limites da Asia, a peca termina com o retorno do rei Xerxes, falido e humilhado, confirmando a extincao do poderio persa.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '237794', '3.62', '1592', '68', 'https://www.goodreads.com/book/show/237794.The_Persians');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('All the Words Are Yours: Haiku on Love', '', '', 'https://images.gr-assets.com/books/1443657057m/24611612.jpg', '24611612', '4.16', '1530', '185', 'https://www.goodreads.com/book/show/24611612-all-the-words-are-yours');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Some Ether', '', 'Winner of a "Discovery"/The NationAward
Winner of the 1999 PEN/Joyce Osterweil Award for Poetry
Some Etheris one of the more remarkable debut collections of poetry to appear in America in recent memory. As Mark Doty has noted, "these poems are more than testimony; in lyrics of ringing clarity and strange precision, Flynn conjures a will to survive, the buoyant motion toward love which is sometimes all that saves us. Some Etherresonates in the imagination long after the final poem; this is a startling, moving debut."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '20657', '4.16', '1480', '75', 'https://www.goodreads.com/book/show/20657.Some_Ether');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Season in Hell & Illuminations', '', '"The definitive translation for our time."
-Edward Hirsch
From Dante''s Inferno to Sartre''s No Exit, writers have been fascinated by visions of damnation. Within that rich literature of suffering, Arthur Rimbaud''s A Season in Hell-written when the poet was nineteen-provides an astonishing example of the grapple with self.
As a companion to Rimbaud''s journey, readers could have no better guide than Wyatt Mason. One of our most talented young translators and critics, Mason''s new version of A Season in Hell renders the music and mystery of Rimbaud''s tale of Hell on Earth with exceptional finesse and power.
This bilingual edition includes maps, a helpful chronology of Rimbaud''s life, and the unfinished suite of prose poems, Illuminations. With A Season in Hell, they cement Rimbaud''s reputation as one of the foremost, and most influential, writers in French literature.', 'https://images.gr-assets.com/books/1320480037m/168496.jpg', '168496', '4.33', '1443', '32', 'https://www.goodreads.com/book/show/168496.A_Season_in_Hell_Illuminations');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Shropshire Lad', '', 'Few volumes of poetry in the English language have enjoyed as much success with both literary connoisseurs and the general reader as A. E. Housman''s A Shropshire Lad, first published in 1896. Scholars and critics have seen in these timeless poems an elegance of taste and perfection of form and feeling comparable to the greatest of the classic. Yet their simple language, strong musical cadences and direct emotional appeal have won these works a wide audience among general readers as well.
This finely produced volume, reprinted from an authoritative edition of A Shropshire Lad, contains all 63 original poems along with a new Index of First Lines and a brief new section of Notes to the Text. Here are poems that deal poignantly with the changing climate of friendship, the fading of youth, the vanity of dreams -- poems that are among the most read, shared, and quoted in our language.', 'https://images.gr-assets.com/books/1414599637m/752936.jpg', '752936', '4.04', '1438', '86', 'https://www.goodreads.com/book/show/752936.A_Shropshire_Lad');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Crossing the Water', '', 'The Poetry of Sylvia Plath.', 'https://images.gr-assets.com/books/1410139871m/295148.jpg', '295148', '4.14', '1405', '48', 'https://www.goodreads.com/book/show/295148.Crossing_the_Water');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Dogs I Have Kissed', '', 'Known for her eponymous blog and her confessional style of writing, this is Trista Mateer''s second collection of poetry.', 'https://images.gr-assets.com/books/1435125785m/25784766.jpg', '25784766', '3.63', '1395', '192', 'https://www.goodreads.com/book/show/25784766-the-dogs-i-have-kissed');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('I Could Chew on This: And Other Poems by Dogs', '', 'A New York Timesbestseller? Oh, you know the dogs weren''t going to let the cats get away with that! This canine companion to I Could Pee on This, the beloved volume of poems by cats, I Could Chew on Thiswill have dog lovers laughing out loud. Doggie laureates not only chew on quite a lot of things, they also reveal their creativity, their hidden motives, and their eternal (and sometimes misguided) effervescence through such musings as "I Dropped a Ball," "I Lose My Mind When You Leave the House," and "Can You Smell That?" Accompanied throughout by portraits of the canine poets in all their magnificence, I Could Chew on Thisis a work of unbridled enthusiasm, insatiable appetite, and, yes, creative genius.', 'https://images.gr-assets.com/books/1365994584m/17324134.jpg', '17324134', '3.88', '1279', '210', 'https://www.goodreads.com/book/show/17324134-i-could-chew-on-this');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Grapefruit: A Book of Instructions and Drawings', '', 'Back in print for the first time in nearly thirty years, here is Yoko Ono''s whimsical, delightful, subversive, startling book of instructions for art and for life.
"Burn this book after you''ve read it." -- Yoko
"A dream you dream alone may be a dream, but a dream two people dream together is a reality."
"This is the greatest book I''ve ever burned." -- John', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '120726', '4.24', '1275', '103', 'https://www.goodreads.com/book/show/120726.Grapefruit');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Season in Hell', '', 'Written by Rimbaud at age 18 in the wake of a tempestuous affair with fellow poet, Paul Verlaine, A Season in Hell has been a touchstone for anguished poets, artists and lovers for over a century. This volume presents the text in French and English with photographs by Robert Mapplethorpe.', 'https://images.gr-assets.com/books/1343552153m/168499.jpg', '168499', '4.13', '1208', '43', 'https://www.goodreads.com/book/show/168499.A_Season_in_Hell');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Layla and Majnun', '', 'The text is a prose rendition of Nizami''s 12th-century poetic masterpiece, in which he reshapes the legends of Majnun, the quintessential romantic fool, into a tale of the ideal lover. For the Sufis, Majnun represents the perfect devotee of the "religion of the heart," and the story is an allegory of the soul''s longing for God. This is a beautiful production, and it includes a final chapter newly translated from the Persian by Omid Safi and Zia Inayat Khan.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '67397', '3.94', '1205', '91', 'https://www.goodreads.com/book/show/67397.Layla_and_Majnun');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Pictures of the Gone World', '', 'Published to celebrate forty years of City Lights publishing, which began with the letterpress printing of this book in 1955.
It was Lawrence Ferlinghetti''s first book, and it has been reprinted twenty-one times, having never been out of print. The original edition contained the first twenty-seven poems to which the author has now added eighteen new verses.
Lawrence Ferlinghetti, poet and founder of City Lights Books, author of A Coney Island of the Mindand Pictures of the Gone World, among numerous other books, has been drawing from life since his student days in Paris where he frequented the Academie Julienand where he did his first oil painting.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '63477', '4.09', '1115', '36', 'https://www.goodreads.com/book/show/63477.Pictures_of_the_Gone_World');
