INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Flash of Lightning Behind the Mountain: New Poems', '', 'The second of five new books of unpublished poems from the late, great Charles Bukowski, America''s most imitated and influential poet -- 143 never-before-seen works of gritty, amusing, and inspiring verse.', 'https://images.gr-assets.com/books/1407707997m/50472.jpg', '50472', '4.09', '963', '39', 'https://www.goodreads.com/book/show/50472.The_Flash_of_Lightning_Behind_the_Mountain');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Mahabharata: The Greatest Spiritual Epic of All Time', '', 'A powerful and moving tale, the Mahabharata recounts the history of the five heroic Pandava brothers. Cheated of their kingdom and sent into exile they set off on a fascinating journey.Profound spiritual themes underlie the thrilling narrative, making it one of the world''ss most revered texts. Culminating in an apocalyptic war, Mahabharata is a masterpiece of suspense, intrigue, and illuminating wisdom.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '118251', '4.29', '957', '24', 'https://www.goodreads.com/book/show/118251.Mahabharata');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'Sylvia Plath is one of the defining voices in twentieth-century poetry. This classic selection of her work, made by her former husband Ted Hughes, provides the perfect introduction to this most influential of poets. The poems are taken from Sylvia Plath''s four collections Ariel, The Colossus, Crossing the Water and Winter Trees, and include many of her most celebrated works, such as ''Daddy'', ''Lady Lazarus'' and ''Wuthering Heights''.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '295149', '4.13', '953', '33', 'https://www.goodreads.com/book/show/295149.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poems Of Wilfred Owen', '', 'This is the definitive single-volume edition of the work of the greatest poet of the First World War, whose death in battle a few days before Armistice was the most disastrous loss to English letters since Keats. Containing the texts of all the finished poems of Owen''s maturity and twelve important fragments, with extensive notes, it derives from Jon Stallworthy''s monumental edition of the Complete Poems and Fragments(1983) and is aimed at the student and general reader alike.', 'https://images.gr-assets.com/books/1374603366m/820474.jpg', '820474', '4.34', '919', '27', 'https://www.goodreads.com/book/show/820474.The_Poems_Of_Wilfred_Owen');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('يوميات الحزن العادي', '', 'ywmyt ktbt `n ftr@ `ysh drwysh l''wl~ fy flsTyn qbl thjyrh, ttsm blHzn wlthwry@
fy hdh lktb ywSWf mHmwd drwysh nthran m alt lyh Hl@ lsh`b lflsTyny wm y`nyh mn l`dw lsry''yly lshrs fy lwTn lmHtl wfy lmnfy Ht~ btt ''ymh ywman Twylan mn lqhr wlHzn. SHyH `ndm bd'' yktb mHmwd drwysh ktb `n nfsh wm`nth lshkhSy@. lkn m y`nyh lsh`r y`nyh lmlyyn mn sh`bh', 'https://images.gr-assets.com/books/1267909730m/5269911.jpg', '5269911', '4.28', '905', '108', 'https://www.goodreads.com/book/show/5269911');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Lyrics: 1962-2001', '', 'This collection contains Bob Dylan''s lyrics, from his first album, Bob Dylan,to 2001''s "Love and Theft."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '761271', '4.6', '887', '28', 'https://www.goodreads.com/book/show/761271.Lyrics');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Child''s Calendar', '', 'Twelve poems follow a family and their friends through the seasons. A Caldecott Honor Book.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '235846', '4.03', '859', '134', 'https://www.goodreads.com/book/show/235846.A_Child_s_Calendar');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Blood Dazzler', '', 'In minute-by-minute detail, Patricia Smith tracks Hurricane Katrina as it transforms into a full-blown mistress of destruction. From August 23, 2005, the day Tropical Depression Twelve developed, through August 28 when it became a Category Five storm with its "scarlet glare fixed on the trembling crescent," to the heartbreaking aftermath, these poems evoke the horror that unfolded in New Orleans as America watched it on television.
Assuming the voices of flailing politicians, the dying, their survivors, and the voice of the hurricane itself, Smith follows the woefully inadequate relief effort and stands witness to families held captive on rooftops and in the Superdome. She gives voice to the thirty-four nursing home residents who drowned in St. Bernard Parish and recalls the day after their deaths when George W. Bush accompanied country singer Mark Willis on guitar:
The cowboy grins through the terrible din,
***
And in the Ninth, a choking woman wails
Look like this country done left us for dead.
An unforgettable reminder that poetry can still be "news that stays news," Blood Dazzler is a necessary step toward national healing.
Patricia Smith is the author of four previous collections of poetry, including Teahouse of the Almighty, winner of the Hurston/Wright Legacy Award and the Paterson Poetry Prize. A record-setting, national poetry slam champion, she was featured in the film Slamnation, on the HBO series Def Poetry Jam, and is a frequent contributor to Harriet, the Poetry Foundation''s blog. Visit her website at www.wordwoman.ws.', 'https://images.gr-assets.com/books/1354209745m/3348584.jpg', '3348584', '4.37', '849', '71', 'https://www.goodreads.com/book/show/3348584-blood-dazzler');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Ballad of the White Horse', '', 'The Ballad of the White Horseis one of the last great epic poems in the English language. On the one hand it describes King Alfred''s battle against the Danes in 878. On the other hand it is a timeless allegory about the ongoing battle between Christianity and the forces of nihilistic heathenism. Filled with colorful characters, thrilling battles and mystical visions, it is as lively as it is profound. Chesterton incorporates brilliant imagination, atmosphere, moral concern, chronological continuity, wisdom and fancy. He makes his stanzas reverberate with sound, and hurries his readers into the heart of the battle. This deluxe volume is the definitive edition of the poem. It exactly reproduces the 1928 edition with Robert Austin''s beautiful woodcuts, and includes a thorough introduction and wonderful endnotes by Sister Bernadette Sheridan, from her 60 years researching the poem.
"When Chesterton writes poetry, he excels like no other modern writer. The rhyme, rhythm, alliteration and imagery are a complete joy to the ear. But The Ballad of the White Horseis not just a poem. It is a prophecy." --Dale Ahlquist, President, The American Chesterton Society
"Not only a charming poem and a great tale, this is a keystone work of Christian literature that will be read long after most of the books of our era are forgotten." --Michael O''Brien, Author, Father Elijah', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1160501', '4.24', '846', '59', 'https://www.goodreads.com/book/show/1160501.The_Ballad_of_the_White_Horse');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Man Suit', '', 'Poetry. THE MAN SUIT, a darkly comic debut from poet Zachary Schomburg, assembles a macabre cast of doppelgangers, talking animals and dead presidents in poems that explore concepts of identity, truth and fate. The resulting body of work walks a dynamic line often reading like anecdotal fables or cautionary tales in the form of prose poems. Through it all, Schomburg balances irony with sincerity; wit with candor; and a playful tone with the knowledge of inevitable sorrow.
"The often funny yet haunting prose and verse poems of this eagerly anticipated debut deal with the subtle and unexpected ways things can transform, usually just beneath an observer''s awareness.... Schomburg may be one of the sincerest surrealists around." Publishers Weekly
"Zachary Schomburg is a wildly imaginative poet who will take you many places you''ve never been or even dreamed of, always with grace and quirky humor. Whether you are caught in Abraham Lincoln''s Death Scene or the Sea of Japan, you are certain to enjoy the original vision of this highly entertaining poet. It''s a book like no other." James Tate
"Zachary Schomburg''s THE MAN SUIT comes to us from the past but it is a thoroughly new book. It comes to us out of the familiar and it strikes us in the face with its novelty. You will recognize your own history, the history of our nation, the influence of Mad Magazineand Benjamin Peret. And underneath it all, and what holds it all together, however unlikely, is the deep and abiding love of the little things that make up our days." Matthew Rohrer
"It is a rare and fine thing when a poet momentarily affiliates his words and his cadences with the entirety of a world, thus freeing his poem from all burden of mediation, all transgression. In our own era, Rene Char and Pablo Neruda come most vividly to mind in this regard. With THE MAN SUIT, Zachary Schomburg, quietly but with deep conviction, begins to join their company. His book is a blessing." Donald Revell"', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '659775', '4.24', '841', '69', 'https://www.goodreads.com/book/show/659775.The_Man_Suit');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Door', '', 'The Door, Margaret Atwood''s first book of poetry since her award-winning Morning in the Burned House, is a magnificent achievement. These fifty lucid, urgent poems range in tone from lyric to ironic to meditative to prophetic, and in subject from the personal to the political, viewed in its broadest sense. They investigate the mysterious writing of poetry itself, as well as the passage of time and our shared sense of mortality.
Brave and compassionate, The Door interrogates the certainties that we build our lives on, and reminds us once again of Margaret Atwood''s unique accomplishments as one of the finest and most celebrated writers of our time.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1233859', '3.81', '814', '80', 'https://www.goodreads.com/book/show/1233859.The_Door');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('هملت', '', 'One of the greatest plays of all time, the compelling tragedy of the tormented young prince of Denmark continues to capture the imaginations of modern audiences worldwide. Confronted with evidence that his uncle murdered his father, and with his mother''s infidelity, Hamlet must find a means of reconciling his longing for oblivion with his duty as avenger. The ghost, Hamlet''s feigned madness, Ophelia''s death and burial, the play within a play, the "closet scene" in which Hamlet accuses his mother of complicity in murder, and breathtaking swordplay are just some of the elements that make Hamlet an enduring masterpiece of the theater.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1499941', '4.01', '807', '48', 'https://www.goodreads.com/book/show/1499941._');
