INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems of Christina Rossetti', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '338809', '4.03', '792', '17', 'https://www.goodreads.com/book/show/338809.Poems_of_Christina_Rossetti');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Canterbury Tales (Barnes & Noble Classics Series)', '', 'The Canterbury Tales, by Geoffrey Chaucer, is part of the Barnes & Noble Classicsseries, which offers quality editions at affordable prices to the student and the general reader, including new scholarship, thoughtful design, and pages of carefully crafted extras. Here are some of the remarkable features of Barnes & Noble ClassicsNew introductions commissioned from today''s top writers and scholars Biographies of the authors Chronologies of contemporary historical, biographical, and cultural events Footnotes and endnotes Selective discussions of imitations, parodies, poems, books, plays, paintings, operas, statuary, and films inspired by the work Comments by other famous authors Study questions to challenge the reader''s viewpoints and expectations Bibliographies for further reading Indices & Glossaries, when appropriate. All editions are beautifully designed and are printed to superior specifications; some include illustrations of historical interest. Barnes & Noble Classicspulls together a constellation of influences - biographical, historical, and literary - to enrich each reader''s understanding of these enduring works.
Pilgrims on their way to worship at the shrine of Saint Thomas a Becket in Canterbury stop at the Tabard Inn. Representing a cross-section of medieval English society, the group includes a knight and his squire, a prioress, a friar, a miller, and a wife. To amuse themselves on their journey, they agree that each will tell a tale. These stories - by turns bawdy, hilarious, scurrilous, romantic, heroic, and moving - reveal a great deal about the tellers and the world they live in, which, despite the distance of six hundred years, seems remarkably like our own. Indeed, the structure of The Canterbury Talesand the sophisticated, intricate interplay between the stories, their narrators, and the general narrator (himself a complex comic character) give the book its strikingly modern flavor. Often called the first book of poetry written in English, Chaucer''', 'https://images.gr-assets.com/books/1356176140m/7083492.jpg', '7083492', '3.48', '789', '10', 'https://www.goodreads.com/book/show/7083492-the-canterbury-tales');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('El caballero de Olmedo', '', 'Sobre un cantar de gran difusion e intrigante origen que sirve de lugar de encuentro del autor y su publico, amor, muerte y destino son los pilares de la ironia tragica en El caballero de Olmedo. Pocas tramas de Lope son mas limpidas y sencillas y, sin embargo, mas ricas. En la presente edicion el profesor Francisco Rico hace un estudio muy documentado del nucleo literario de la comedia y aporta conclusiones nuevas sobre la genesis e historia de la leyenda del Caballero, situando en esas coordenadas la que muchos consideran la obra maestra del teatro de Lope.', 'https://images.gr-assets.com/books/1328630011m/65210.jpg', '65210', '3.52', '780', '31', 'https://www.goodreads.com/book/show/65210.El_caballero_de_Olmedo');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Leaves of Grass and Other Writings', '', 'This revised Norton Critical Edition contains the most complete and authoritative collection of Whitman''s work available in a paperback student edition. The text of Leaves of Grassis again that of the indispensable "Reader''s Comprehensive Edition," edited by Sculley Bradley and Harold W. Blodgett, which is accompanied by revised and expanded explanatory annotations. New to this edition is the full text of the celebrated 1855 first edition of Leaves of Grass, as well as generous excerpts from Whitman''s two prose masterpieces, Democratic Vistasand Specimen Days.
Following the texts is an album of portraits of Whitman, as well as "Whitman on His Art," a collection of Whitman''s statements about his role as a poet taken from his notebooks, letters, conversations, and newspaper articles.
While continuing to provide leading commentary on Whitman by major twentieth-century poets and critics, among them D. H. Lawrence, William Carlos Williams, and Randall Jarrell, this revised edition adds important commentary by Whitman contemporaries Henry David Thoreau, Fanny Fern, Henry James, and Oscar Wilde, among others. An entirely new section of recent criticism includes six essays--by David S. Reynolds, Karen Sanchez-Eppler, John Irwin, Allen Grossman, Betsy Erkkila, and Michael Moon--that reflect both the continuing historicist mainstream of Whitman literary interpretation and influential recent work in gender and sexuality studies.
The volume also includes a Chronology, a Selected Bibligraphy, and an Index of Titles.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '609155', '4.28', '762', '21', 'https://www.goodreads.com/book/show/609155.Leaves_of_Grass_and_Other_Writings');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Personæ: The Shorter Poems', '', 'If the invention of literary modernism is usually attributed to James Joyce, T. S. Eliot and Ezra Pound, it was Pound alone who provided (in Hugh Kenner''s words) "the synergetic presence" to convert individual experiment into an international movement. In 1926 Pound carefully sculpted his body of shorter poems into a definitive collection which would best show the concentration of force, the economy of means, and the habit of analysis that were, to him, the hallmarks of the new style.This collection, where Pound presented himself in a variety of characters or "masks," was called Personae. In 1926, Personae''s publication gave solidity to a movement today the work stands as one of the classic texts of the twentieth century. Pound scholars Lea Baechler (of Columbia) and A. Walton Litz (Holmes Professor of English Literature at Princeton) have prepared a corrected text and supplied an informative "Note on the Text" explaining both Pound''s original criteria for his selection and the volume''s subsequent history.', 'https://images.gr-assets.com/books/1390232802m/998064.jpg', '998064', '4.09', '743', '29', 'https://www.goodreads.com/book/show/998064.Person_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ozymandias', '', 'A picture book edition of the poem. The poem, Ozymandias, was composed in 1817. It is one of the most famous poems of P.B. Shelley. It was composed in competition with Shelley''s friend, Horace Smith who wrote another sonnet on the same topic named Ozymandias. The theme of this sonnet is the decline of all leaders of all the empires they built. However mighty they have been in their time, history has destroyed them. Ozymandias was another name for Ramesses, a great Pharaoh king of ancient Egypt.', 'https://images.gr-assets.com/books/1356208377m/2355014.jpg', '2355014', '4.31', '740', '36', 'https://www.goodreads.com/book/show/2355014.Ozymandias');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Canterbury Tales', '', 'On a spring day in April--sometime in the waning years of the 14th century--29 travelers set out for Canterbury on a pilgrimage to the shrine of Saint Thomas Beckett. Among them is a knight, a monk, a prioress, a plowman, a miller, a merchant, a clerk, and an oft-widowed wife from Bath. Travel is arduous and wearing; to maintain their spirits, this band of pilgrims entertains each other with a series of tall tales that span the spectrum of literary genres. Five hundred years later, people are still reading Geoffrey Chaucer''s Canterbury Tales. If you haven''t yet made the acquaintance of the Franklin, the Pardoner, or the Squire because you never learned Middle English, take heart: this edition of the Taleshas been translated into modern idiom. From the heroic romance of "The Knight''s Tale" to the low farce embodied in the stories of the Miller, the Reeve, and the Merchant, Chaucer treated such universal subjects as love, sex, and death in poetry that is simultaneously witty, insightful, and poignant. The Canterbury Talesis a grand tour of 14th-century English mores and morals--one that modern-day readers will enjoy.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2701', '3.48', '719', '56', 'https://www.goodreads.com/book/show/2701.The_Canterbury_Tales');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Bridge', '', 'Begun in 1923 and published 1930, The Bridgeis Crane''s major work. "Very roughly," he wrote a friend, "it concerns a mystical synthesis of ''America'' . . . The initial impulses of ''our people'' will have to be gathered up toward the climax of the bridge, symbol of our constructive future, our unique identity."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '75495', '4.15', '693', '33', 'https://www.goodreads.com/book/show/75495.The_Bridge');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('اطاق آبی', '', 'yddsht hy pyrwz syr wyrstr mtn, Tq aby, m`lm nqshy m, gft gw b std', 'https://images.gr-assets.com/books/1292004001m/552186.jpg', '552186', '3.77', '681', '34', 'https://www.goodreads.com/book/show/552186._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Inferno', '', 'Belonging in the company of the works of Homer and Virgil, The Infernois a moving human drama, a journey through the torment of Hell, an expression of the Middle Ages, and a protest against the ways in which men have thwarted the divine plan.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6553280', '3.99', '674', '69', 'https://www.goodreads.com/book/show/6553280-the-inferno');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Behind My Eyes [With CD]', '', 'Combining sensitivity and eloquence with a broad appeal, Li-Young Lee walks in the footsteps of Stanley Kunitz and Billy Collins as one of the United States s most beloved poets. Playful, erotic, at times mysterious, his work describes the immanent value of everyday experience. Straightforward language and simple narratives become gateways to the most powerful formulations of beauty, wisdom, and divine love.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '906943', '4.07', '673', '71', 'https://www.goodreads.com/book/show/906943.Behind_My_Eyes_With_CD_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Songs of Innocence', '', 'William Blake''s innovations in engraving techniques brought about his brilliant synthesis of visual and poetic art and signaled the beginning of his famous "Illuminated Books," of which the Songs of Innocencewas the first and most popular. Unfortunately, Blake''s vision is generally known to the world in amputated form: because of the difficulty and expense of reproducing his original conception, most editions of Blake''s work offer only the printed text, with no trace of the visual counterpart so essential to his "System."
This new, facsimile edition of the Songs of Innocencereproduces Blake''s color plates in a fashion which the artist himself would have approved. The 31 plates -- printed on facing pages which are the same size of Blake''s own first edition -- offer one of the more brightly colored versions of this significant volume, no two copies of which are the same. As a special aid to readers, a typographical reprint of the text of poems follows the plates. Such classic "songs" as "The Lamb" and "The Chimney Sweeper" are now accessible to all in the symbiotic union of poem and picture that is crucial to a total understating of Blake''s mind and art.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '272102', '4.11', '673', '33', 'https://www.goodreads.com/book/show/272102.Songs_of_Innocence');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Facts About the Moon', '', 'In her powerful fourth collection, Dorianne Laux once again strikes fire from neighborhood moments: a quiet street at dusk, a pool hall, a bare tree. Focusing on the grace of working people, she captures the pain and beauty of women in all their variety, caught in the "lunar pull" of our time.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '515188', '4.32', '673', '71', 'https://www.goodreads.com/book/show/515188.Facts_About_the_Moon');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Kick in the Head: An Everyday Guide to Poetic Forms', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '222383', '4.07', '664', '107', 'https://www.goodreads.com/book/show/222383.A_Kick_in_the_Head');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Canzoniere', '', 'In concomitanza con il settimo centenario della nascita del poeta, la curatrice, tra i massimi specialisti del Petrarca volgare, conclude un lavoro durato quasi vent''anni. Commentando minuziosamente ogni verso e ogni espressione petrarchesca, il fittissimo richiamo dei testi classici e della poesia volgare precedente e coeva diventa un caleidoscopio culturale e letterario che rifrange, con varieta, ma con rigorosa precisione, il senso di ogni singola poesia e del "Canzoniere" nel suo insieme.', 'https://images.gr-assets.com/books/1360880779m/14623094.jpg', '14623094', '3.92', '648', '11', 'https://www.goodreads.com/book/show/14623094-canzoniere');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('West Wind', '', 'The New York Times has called Mary Oliver''s poems "thoroughly convincing - as genuine, moving, and implausible as the first caressing breeze of spring." In this stunning collection of forty poems - nineteen previously unpublished - she writes of nature and love, of the way they transform over time. And the way they remain constant. And what did you think love would be like? A summer day? The brambles in their places, and the long stretches of mud? Flowers in every field, in every garden, with their soft beaks and their pastel shoulders? On one street after another, the litter ticks in the gutter. In one room after another, the lovers meet, quarrel, sicken, break apart, cry out. One or two leap from windows. Most simply lean, exhausted, their thin arms on the sill. They have done all they could. The golden eagle, that lives not far from here, has perhaps a thousand tiny feathers flowing from the back of its head, each one shaped like an infinitely small but perfect spear.', 'https://images.gr-assets.com/books/1382938461m/499918.jpg', '499918', '4.22', '637', '51', 'https://www.goodreads.com/book/show/499918.West_Wind');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Cremation of Sam McGee', '', 'In 1986 Kids Can Press published an edition of Robert Service''s "The Cremation of Sam McGee" illustrated by painter Ted Harrison, who used his signature broad brushstrokes and unconventional choice of color to bring this gritty narrative poem to life. Evoking both the spare beauty and the mournful solitude of the Yukon landscape, Harrison''s paintings proved the perfect match for Service''s masterpiece about a doomed prospector adrift in a harsh land. Harrison''s Illustrator''s Notes on each page enhanced both poem and illustrations by adding valuable historical background. Upon its original publication, many recognized the book as an innovative approach to illustrating poetry for children. For years The Cremation of Sam McGee has stood out as a publishing landmark, losing none of its appeal both as a read-aloud and as a work of art. Kids Can Press proudly publishes this deluxe hardcover twentieth anniversary edition -- complete with a spot-varnished cover, new cover art and heavy coated stock -- of a book that remains as entrancing as a night sky alive with the vibrant glow of the Northern Lights.', 'https://images.gr-assets.com/books/1396842645m/267764.jpg', '267764', '4.36', '625', '53', 'https://www.goodreads.com/book/show/267764.The_Cremation_of_Sam_McGee');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('First Indian on the Moon', '', 'Poetry. Native American Studies. FIRST INDIAN ON THE MOON opens with the section "Influences": "where I have been/ most of my lives/ is where I''m going/--Lucille Clifton." The stories and poems of Sherman Alexie, an enrolled Spokane/Coeur d''Alene Indian from Wellpint, Washington, have appeared widely, in such publications as Caliban, Esquire, The World, Beloit Poetry Journal, Red Dirt, Zyzzyva and Story. Alexie has won a National Endowment for the Arts Writing Fellowship, and lives in Spokane. "These elegiac poems and stories will break your heart. Watch this guy. He''s making myth"--Joy Harjo.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '159087', '4.13', '619', '34', 'https://www.goodreads.com/book/show/159087.First_Indian_on_the_Moon');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Pillow Thoughts', '', 'Pillow Thoughts is a collection of poetry and prose about heartbreak, love and raw emotions.
It is divided into sections to read when you feel you need them most.
Make a cup of tea and let yourself feel.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '32468495', '3.9', '614', '105', 'https://www.goodreads.com/book/show/32468495-pillow-thoughts');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('All the Things I Never Said', '', 'All The Things I Never Said is a collection of poetry and journal-like entries. Throughout the pages you will experience heartbreak, happiness, sadness, and be reminded of what it was like to be a teenager.', 'https://images.gr-assets.com/books/1387175097m/19134941.jpg', '19134941', '3.48', '612', '73', 'https://www.goodreads.com/book/show/19134941-all-the-things-i-never-said');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Coleridge''s Poetry and Prose', '', '"Criticism" includes twenty assessments of Coleridge''s poetry and prose by British and American authors A Chronology and Selected Bibliography are also included.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '350097', '4.1', '579', '3', 'https://www.goodreads.com/book/show/350097.Coleridge_s_Poetry_and_Prose');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Human Landscapes from My Country: An Epic Novel in Verse', '', 'When, on the eve of the Second World War, Nazim Hikmet (1902-1963) -- Turkey''s most acclaimed and popular poet -- was sentenced to twenty-eight years in prison for his Communist beliefs, he embarked on the writing of his epic, Human Landscapes from My Country. This 17,000-line verse-novel is made up of a traveler''s vivid encounters with Turkish men and women from all walks of life. In colloquial language, Hikmet stages their private hopes and griefs, and through these many human dramas, he documents Turkey''s historic transformation into a secular republic. Human Landscapes from My Countryis "lively . . . cinematographic . . . [able] to capture the least scholarly reader" (Denise Levertov).
Human Landscapes from My Countrywas published in a abridged English-language version by Persea Books twenty years ago. This new edition marks a major event in contemporary world literature.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '206644', '4.59', '574', '10', 'https://www.goodreads.com/book/show/206644.Human_Landscapes_from_My_Country');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Walking the Black Cat', '', 'Hamlet''s ghost wandering the halls of a Vegas motel, a street corner ventriloquist using passersby as dummies, and Jesus panhandling in a weed-infested Eden are just a few of the startling conceits Simic unleashes in this collection. "Few contemporary poets have been as influential-or inimitable-as Charles Simic" (New York Times Book Review).', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '175033', '4.02', '567', '38', 'https://www.goodreads.com/book/show/175033.Walking_the_Black_Cat');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('هكذا أكتب تاريخ النساء', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '7920056', '3.35', '554', '75', 'https://www.goodreads.com/book/show/7920056');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('مجموعه کامل اشعار', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '693275', '3.93', '544', '22', 'https://www.goodreads.com/book/show/693275._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Field Work', '', '"Field Work," which first appeared in 1979, is a superb collection of lyrics and narrative poems from one of the literary masters of our time. As the critic Dennis Donoghue wrote in "The New York Times Book Review": "In 1938, not a moment too soon, W. B. Yeats admonished his colleagues: ''Irish poets, learn your trade.'' Seamus Heaney, born the following year, has learned his trade so well that it is now a second nature wonderfully responsive to his first. And the proof is in "Field Work," a superb book . . . [This is] a perennial poetry offered at a time when many of us have despaired of seeing such a thing."
Seamus Heaney received the Nobel Prize in Literature in 1995. His recent translations include "Beowulf" and "Diary of One Who Vanished"; his recent poetry collections include "Opened Ground" and "Electric Light."
"Field Work," which first appeared in 1979, is a superb collection of lyrics and narrative poems from one of the literary masters of our time. As the critic Dennis Donoghue wrote in "The New York Times Book Review": "In 1938, not a moment too soon, W. B. Yeats admonished his colleagues: ''Irish poets, learn your trade.'' Seamus Heaney, born the following year, has learned his trade so well that it is now a second nature wonderfully responsive to his first. And the proof is in "Field Work," a superb book . . . [This is] a perennial poetry offered at a time when many of us have despaired of seeing such a thing."
"Heaney is keyed and pitched unlike any significant poet now at work in the language, anywhere."--Harold Bloom, "The Times Literary Supplement"
"For all the qualities I list, the most important is song [and] the tune Heaney sings [is] poetry''s tune, resolutions of cherished language."--Donald Hall, "The Nation"', 'https://images.gr-assets.com/books/1311997762m/784084.jpg', '784084', '4.29', '511', '26', 'https://www.goodreads.com/book/show/784084.Field_Work');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Iliad', '', 'The Iliadis one of the two great epics of Homer, and is typically described as one of the greatest war stories of all time, but to say the Iliad is a war story does not begin to describe the emotional sweep of its action and characters: Achilles, Helen, Hector, and other heroes of Greek myth and history in the tenth and final year of the Greek siege of Troy.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '18744759', '3.83', '507', '9', 'https://www.goodreads.com/book/show/18744759-the-iliad');
