INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Casi sin querer', '', 'El amor algunas veces es tan complicado como impredecible. Pero al final lo que mas valoramos son los detalles mas simples, los mas bonitos, los que llegan sin avisar. Y a la hora de escribir sobre sentimientos, no hay nada mas limpio que hacerlo desde el corazon. Y eso hace @Defreds en este libro.', 'https://images.gr-assets.com/books/1444577982m/25527249.jpg', '25527249', '3.71', '493', '62', 'https://www.goodreads.com/book/show/25527249-casi-sin-querer');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Happy Birthday of Death', '', 'It is true that he has been one of the inner circle of the ''Beats'' from the first, but many admirers of his poetry feel that it belongs quite as much to other and older traditions in world literature. One of these is the revival of pure poetry whenever an "original"--be it Rimbaud or Whitman--has broken with current verse conventions to give free rein to the magic of language. Another is that ancient pre-occupation of poets--the sense of the immediacy of death. Like Villon or Dylan Thomas, Corso lives close to the mystery of death. It is, perhaps, his central theme, on which variations ranging from the terrible to the comic are sounded. But Corso is seldom macabre. A bursting vitality always carries him back to the sensations of the living, though always it is the reality behind the obvious which has caught his eye. "How I love to probe life," Corso has written, "That''s what poetry is to me, a wondrous prober... It''s not the metre or measure of a line, a breath; not ''law'' music; but the assembly of great eye sounds placed into an inspired measured idea."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '439008', '4.15', '488', '23', 'https://www.goodreads.com/book/show/439008.The_Happy_Birthday_of_Death');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('ديوان محمد الثبيتي الأعمال الكاملة', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '7852603', '4.26', '483', '101', 'https://www.goodreads.com/book/show/7852603');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Odyssey', '', 'Robert Fagles'' translation is a jaw-droppingly beautiful rendering of Homer''s Odyssey, the most accessible and enthralling epic of classical Greece. Fagles captures the rapid and direct language of the original Greek, while telling the story of Odysseus in lyrics that ring with a clear, energetic voice. The story itself has never seemed more dynamic, the action more compelling, nor the descriptions so brilliant in detail. It is often said that every age demands its own translation of the classics. Fagles''s work is a triumph because he has not merely provided a contemporary version of Homer''s classic poem, but has located the right language for the timeless character of this great tale. Fagles brings the Odyssey so near, one wonders if the Hollywood adaption can be far behind. This is a terrific book.
If The Iliadis the world''s greatest war epic, then The Odysseyis literature''s grandest evocation of everyman''s journey though life. Odysseus''s reliance on his wit and wiliness for survival in his encounters with divine and natural forces during his ten-year voyage home to Ithaca after the Trojan War is at once a timeless human story and an individual test of moral endurance.
Robert Fagles, winner of the PEN/Ralph Manheim Medal for Translation and a 1996 Academy Award in Literature from the American Academy of Arts and Letters presents us with Homer''s best-loved and most accessible poem in a stunning new modern-verse translation.
"Sing to me of the man, Muse, the man of twists and turns driven time and again off course, once he had plundered the hallowed heights of Troy."
So begins Robert Fagles'' magnificent translation of the Odyssey, which Jasper Griffin in The New York Times Review of Books hails as "a distinguished achievement."
If the Iliad is the world''s greatest war epic, the Odyssey is literature''s grandest evocation of everyman''s journey through life. Odysseus'' reliance on his wit and wiliness for survival in his encounters with divine and natural forces, during', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '77201', '3.73', '480', '54', 'https://www.goodreads.com/book/show/77201.The_Odyssey');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Art of Recklessness: Poetry as Assertive Force and Contradiction', '', 'In The Art of Recklessness, Dean Young''s sprawling and subversive first book of prose on poetry, imagination swerves into primitivism and surrealism and finally toward empathy. How can recklessness guide the poet, the artist, and the reader into art, and how can it excite in us a sort of wild receptivity, beyond craft? "Poetry is not a discipline," Young writes. "It is a hunger, a revolt, a drive, a mash note, a fright, a tantrum, a grief, a hoax, a debacle, an application, an affect . . ."', 'https://images.gr-assets.com/books/1316637843m/7517330.jpg', '7517330', '4.15', '468', '56', 'https://www.goodreads.com/book/show/7517330-the-art-of-recklessness');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Erec and Enide', '', 'Erec and Enidemarks the birth of the Arthurian romance as a literary genre. Written circa 1170, this version of the Griselda legend tells the story of the marriage of Erec, a handsome and courageous Welsh prince and knight of the Round Table, and Enide, an impoverished noblewoman. When the lovers become estranged because Erec neglects his knightly obligations, they subsequently ride off together on a series of adventures that culminate in their reconciliation and the liberation of a captive knight in an enchanted orchard.An innovative poet working during a time of great literary creativity, Chretien de Troyes wrote poems that had a lively pace, skillful structure, and vivid descriptive detail. Ruth Harwood Cline re-creates for modern audiences his irony, humor, and charm, while retaining the style and substance of the original octosyllabic couplets. Her thorough introduction includes discussions of courtly love and the Arthurian legend in history and literature, as well as a new and provocative theory about the identity of Chretien de Troyes. This clearly presented translation, faithful in preserving the subtle expressive qualities of the original work, is accessible reading for any Arthurian legend aficionado and an ideal text for students of medieval literature.', 'https://images.gr-assets.com/books/1328809137m/544867.jpg', '544867', '3.72', '458', '20', 'https://www.goodreads.com/book/show/544867.Erec_and_Enide');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('More Notes of a Dirty Old Man: The Uncollected Columns', '', '"He loads his head full of coal and diamonds shoot out of his finger tips. What a trick. The mole genius has left us with another digest. It''s a full houseread ''em and weep."--Tom Waits
After toiling in obscurity for years, Charles Bukowski suddenly found fame in 1967 with his autobiographical newspaper column, "Notes of a Dirty Old Man," and a book of that name in 1969. He continued writing this column, in one form or another, through the mid-1980s. More Notes of a Dirty Old Mangathers many uncollected gems from the column''s twenty-year run. Drawn from ephemeral underground publications, these stories and essays haven''t been seen in decades, making Morea valuable addition to Bukowski''s oeuvre. Filled with his usual obsessionssex, booze, gamblingMorefeatures Bukowski''s offbeat insights into politics and literature, his tortured, violent relationships with women, and his lurid escapades on the poetry reading circuit. Highlighting his versatility, the book ranges from thinly veiled autobiography to purely fictional tales of dysfunctional suburbanites, disgraced politicians, and down-and-out sports promoters, climaxing with a long, hilarious adventure among French filmmakers, "My Friend the Gambler," based on his experiences making the movie Barfly. From his lowly days at the post office through his later literary fame, Morefollows the entire arc of Bukowski''s colorful career.
Edited by Bukowski scholar David Stephen Calonne, More Notes of a Dirty Old Manfeatures an afterword outlining the history of the column and its effect on the author''s creative development.
Born in Andernach, Germany in 1920, Charles Bukowskicame to California at age three and spent most of his life in Los Angeles. He died in San Pedro, California, on March 9, 1994.', 'https://images.gr-assets.com/books/1328774974m/10984643.jpg', '10984643', '4.07', '452', '35', 'https://www.goodreads.com/book/show/10984643-more-notes-of-a-dirty-old-man');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Blind Huber', '', 'Award-winning poet Nick Flynn takes readers into the dangerous and irresistible center of the hive
I sit in a body & think of a body, I picture
Burnens'' hands, my words
make them move. I say, plunge them into the hive,
& his hands go in.
--from "Blind Huber"
Blindness does not deter Francois Huber--the eighteenth-century beekeeper--in his quest to learn about bees through their behavior. Through an odd, but productive arrangement, Huber''s assistant Burnens becomes his eyes, his narrator as he goes about his work. In Nick Flynn''s extraordinary new collection, Huber and Burnens speak and so do the bees. The strongest virgin waits silently to kill the other virgins; drones are "made of waiting"; the swarm attempts to protect the queen. It is a cruel existence. Everyone sacrifices for the sweet honey, except the human hand that harvests it all in a single afternoon.
Blind Huberis about the body, love, and devotion and also about the limits of what can be known and what will forever be unknown. Nick Flynn''s bees and keepers--sometimes in a state of magnificent pollen-drunk dizziness--view the world from a striking and daring perspective.', 'https://images.gr-assets.com/books/1312039741m/20658.jpg', '20658', '3.97', '448', '40', 'https://www.goodreads.com/book/show/20658.Blind_Huber');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Three Poems: Host and Guest / Aluda Ketelauri / The Snake-Eater', '', 'Vazha Pshavela (1861-1915) is considered one of the great poets in the fifteen-centuried Georgian literature. The three poems represented in the book are the most distinguished works of the poet.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '13423864', '4.7', '448', '4', 'https://www.goodreads.com/book/show/13423864-three-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Mayakovsky''s Revolver', '', 'From a dazzling, award-winning young poet, a collection that paints life as a celebration in the dark.
At the center of Mayakovsky''s Revolveris the suicide of Matthew Dickman''s older brother. "Known for poems of universality of feeling, expressive lyricism of reflection, and heartrending allure" (Major Jackson), Dickman is a powerful poet whose new collection explores how to persevere in the wake of grief.', 'https://images.gr-assets.com/books/1347033936m/13707574.jpg', '13707574', '4.3', '440', '46', 'https://www.goodreads.com/book/show/13707574-mayakovsky-s-revolver');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Wild Book', '', 'Fefa struggles with words. She has word blindness, or dyslexia, and the doctor says she will never read or write. Every time she tries, the letters jumble and spill off the page, leaping and hopping away like bullfrogs. How will she ever understand them?But her mother has an idea. She gives Fefa a blank book filled with clean white pages. "Think of it as a garden," she says. Soon Fefa starts to sprinkle words across the pages of her wild book. She lets her words sprout like seedlings, shaky at first, then growing stronger and surer with each new day. And when her family is threatened, it is what Fefa has learned from her wild book that saves them.', 'https://images.gr-assets.com/books/1313006735m/12352685.jpg', '12352685', '3.72', '437', '103', 'https://www.goodreads.com/book/show/12352685-the-wild-book');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('One Hundred Poems from the Chinese', '', 'The lyric poetry of Tu Fu ranks with the greatest in all world literature. Across the centuries--Tu Fu lived in the T''ang Dynasty (731-770)--his poems come through to us with an immediacy that is breathtaking in Kenneth Rexroth''s English versions. They are as simple as they are profound, as delicate as they are beautiful.
Thirty-five poems by Tu Fu make up the first part of this volume. The translator then moves on to the Sung Dynasty (10th-12th centuries) to give us a number of poets of that period, much of whose work was not previously available in English. Mei Yao Ch''en, Su Tung P''o, Lu Yu, Chu Hsi, Hsu Chao, and the poetesses Li Ch''iang Chao and Chu Shu Chen. There is a general introduction, biographical and explanatory notes on the poets and poems, and a bibliography of other translations of Chinese poetry.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '236188', '4.32', '437', '38', 'https://www.goodreads.com/book/show/236188.One_Hundred_Poems_from_the_Chinese');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Desiderata: A Poem for a Way of Life', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '653047', '4.5', '435', '33', 'https://www.goodreads.com/book/show/653047.Desiderata');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Inherit the Wind', '', 'A meaningful play based on the Scopes Monkey Trial of 1925, in which a Tennessee teacher was tried for teaching evolution. The accused was a slight, frightened man who''d deliberately broken the law. His trial was a Roman circus, the chief gladiators being the two great legal giants of the century. Locked in mortal combat, they bellowed & roared imprecations & abuse. The spectators sat uneasily in the sweltering heat with murder in their hearts, barely restraining themselves. America''s freedom was at stake.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '250810', '3.96', '434', '38', 'https://www.goodreads.com/book/show/250810.Inherit_the_Wind');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Writings', '', '"This collection, a retrospective exhibit of the work of a woman who created a unique place for herself in the world of letters, contains a sample of practically every period and every manner in Gertrude Stein''s career. It includes The Autobiography of Alice B. Toklas in its entirety; selected passages from The Making of Americans; "Melanctha"from Three Lives; portraits of the painters Cezanne, Matisse, and Picasso; Tender Buttons; the opera Four Saints in Three Acts; and poem, plays, lectures, articles, sketches, and a generous portion of her famous book on the Occupation of France, Wars I Have Seen.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '250048', '3.88', '431', '26', 'https://www.goodreads.com/book/show/250048.Selected_Writings');
