INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Charge of the Light Brigade', '', 'A narrative poem about the Charge of the Light Brigade at the Battle of Balaclava during the Crimean War.
Excerpt:
"[...] Yet know you, as your England knows
That you and all your men
Were soldiers to her heart''s desire,
When, in the vanish''d year,
You saw the league-long rampart-fire
Flare from Tel-el-Kebir
Thro'' darkness, and the foe was driven,
And Wolseley overthrew
Arabi, and the stars in heaven
Paled, and the glory grew.
THE CHARGE OF THE HEAVY BRIGADE AT BALACLAVA
October 25, 1854
[...]".', 'https://images.gr-assets.com/books/1474167350m/1121132.jpg', '1121132', '4.25', '425', '25', 'https://www.goodreads.com/book/show/1121132.The_Charge_of_the_Light_Brigade');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Auden: Poems', '', 'The Everyman''s Library Pocket Poets hardcover series is popular for its compact size and reasonable price which does not compromise content. Poems: Audenis just another reminder of his exhilarating lyric power and his understanding of love and longing in all their sacred and profane guises. One of English poetry''s great 20th century masters, Poems: Audenis the short collection of an exemplary champion of human wisdom in its encounter with the mysteries of experience.', 'https://images.gr-assets.com/books/1320400081m/152532.jpg', '152532', '4.25', '423', '30', 'https://www.goodreads.com/book/show/152532.Auden');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Twenty Prose Poems', '', 'From the introduction by Michael Hamburger:
"Baudelaire''s prose poems were written at long intervals during the last twelve or thirteen years of his life. The prose poem was a medium much suited to his habits and character. Being pre-eminently a moralist, he needed a medium that enabled him to illustrate a moral insight as briefly and vividly as possible. Being an artist and sensualist, he needed a medium that was epigrammatic or aphoristic, but allowed him scope for fantasy and for that element of suggestiveness which he considered essential to beauty. His thinking about society and politics, as about everything else, was experimental; like the thinking of most poets it drew on experience and imagination, rather than on facts and general arguments. That is another reason why the prose poem proved a medium so congenial to Baudelaire."
Translation of selections from: Le spleen de Paris.
Original French text accompanied by English translation on opposite pages.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '50479', '4.35', '422', '22', 'https://www.goodreads.com/book/show/50479.Twenty_Prose_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Song of the Simple Truth: The Complete Poems of Julia de Burgos', '', 'Song of the Simple Truth(Cancion de la verdad sencilla) is the first bilingual edition of Julia de Burgos'' complete poems. Numbering more than 200, these poems form a literary landmark--the first time her poems have appeared in a complete edition in either English or Spanish. Many of the verses presented here had been lost and are presented here for the first time in print. De Burgos broke new ground in her poetry by fusing a romantic temperament with keen political insights. This book will be essential reading for lovers of poetry and for feminists.', 'https://images.gr-assets.com/books/1418364160m/165251.jpg', '165251', '3.89', '418', '16', 'https://www.goodreads.com/book/show/165251.Song_of_the_Simple_Truth');
