INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('El estudiante de Salamanca', '', 'Es el texto mas celebre de Espronceda. El personaje de Felix de Montemar, de personalidad faustica, se inspira en la leyenda de don Juan Tenorio. Terrorifico relato en el que se percibe la influencia de Lord Byron y de la novela gotica inglesa. El heroe desafia a los poderes divinos.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1639333', '3.62', '410', '15', 'https://www.goodreads.com/book/show/1639333.El_estudiante_de_Salamanca');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('دریا پری، کاکل زری', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '346381', '3.47', '405', '16', 'https://www.goodreads.com/book/show/346381._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Circles of Hell', '', '''I truly thought I''d never make it back.''
Ten of the most memorable and most terrifying cantos from Dante''s Inferno.
Introducing Little Black Classics: 80 books for Penguin''s 80th birthday. Little Black Classics celebrate the huge range and diversity of Penguin Classics, with books from around the world and across many centuries. They take us from a balloon ride over Victorian London to a garden of blossom in Japan, from Tierra del Fuego to 16th-century California and the Russian steppe. Here are stories lyrical and savage; poems epic and intimate; essays satirical and inspirational; and ideas that have shaped the lives of millions.
Dante Alighieri (1265-1321).
Dante''s works available in Penguin Classics are Inferno, Purgatorio, Paradiso, The Divine Comedy and Vita Nuova.', 'https://images.gr-assets.com/books/1423751924m/24874449.jpg', '24874449', '3.29', '399', '51', 'https://www.goodreads.com/book/show/24874449-circles-of-hell');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'This new collection of Sandburg''s finest and most representative poetry draws on all of his previous volumes and includes four unpublished poems about Lincoln. The Hendricks'' comprehensive introduction discusses how Sandburg''s life and beliefs colored his work and why it continues to resonate so deeply with Americans today. Edited and with an Introduction by George and Willene Hendrick.', 'https://images.gr-assets.com/books/1286419737m/120724.jpg', '120724', '4.04', '396', '21', 'https://www.goodreads.com/book/show/120724.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Water Sings Blue: Ocean Poems', '', 'Come down to the shore with this rich and vivid celebration of the ocean! With watercolors gorgeous enough to wade in by award-winning artist Meilo So and playful, moving poems by Kate Coombs, Water Sings Blue evokes the beauty and power, the depth and mystery, and the endless resonance of the sea.', 'https://images.gr-assets.com/books/1356139644m/12429335.jpg', '12429335', '3.97', '392', '125', 'https://www.goodreads.com/book/show/12429335-water-sings-blue');
