INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('World War One British Poets: Brooke, Owen, Sassoon, Rosenberg and Others', '', 'Ironically, the horrors of World War One produced a splendid flowering of British verse as young poets, many of them combatants, confronted their own morality, the death of dear friends, the loss of innocence, the failure of civilization, and the madness of war itself.
This volume contains a rich selection of poems from that time by Rupert Brooke, Wilfred Owen, Siegfried Sassoon, Isaac Rosenberg, and others known especially for their war poetry -- as well as poems by such major poets as Robert Graves, Thomas Hardy, A. E. Housman, Robert Bridges, and Rudyard Kipling.
Included among a wealth of memorable verses are Rupert Brooke''s "The Soldier," Wilfred Owen''s "Anthem for Doomed Youth," "In the Pink" by Siegfried Sassoon, "In Flanders Fields" by Lieut. Col. McCrae, Robert Bridges'' "To the United States of America," Thomas Hardy''s "In Time of ''The Breaking of Nations,''" as well as works by Walter de la Mare, May Wedderburn Cannan, Ivor Gurney, Alice Meynell, and Edward Thomas.
Moving and powerful, this carefully chosen collection offers today''s readers an excellent overview of the brutal range of verse produced as poets responded to the carnage on the fields of Belgium and France.', 'https://images.gr-assets.com/books/1416873208m/33538.jpg', '33538', '4.0', '390', '30', 'https://www.goodreads.com/book/show/33538.World_War_One_British_Poets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('گزینه اشعار مهدی اخوان ثالث', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '657504', '4.17', '384', '17', 'https://www.goodreads.com/book/show/657504._');
