INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Üvercinka', '', 'Cemal Sureya, ilk kitabi Uvercinka 1958''de ciktiginda, 27 yasinda, ilk siiri ("Sarkisi Beyaz") daha bes yil once yayimlanmis genc bir sairdi. Bu kitapla cagcil Turk siirinin en cok konusulan, en cok tartisilan akimlarindan Ikinci Yeni''nin onculerinden biri olacagini ne kendisi ne de bir baskasi bilebilirdi.
Lirik, erotik, ideolojik... Sicak, tilsimli ve olumsuz.
Turk siirinin kavsak noktasinda, tek basina ayakta duran bir kitap.', 'https://images.gr-assets.com/books/1348921272m/16052994.jpg', '16052994', '4.15', '368', '14', 'https://www.goodreads.com/book/show/16052994-vercinka');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Thoughts and Meditations', '', 'This collection of thoughts by Kahlil Gibran, author of "The Prophet," "The Broken Wings," "The Voice of the Master," and other twentieth-century classics, demonstrates three major aspects of his genius. Here is the fiery prophet, assailing the corruptions of Syrian governmental and upper social circles with the wrath and scorn of Biblical seers.
Here, too, is the poet of love, apostrophizing beauty, youth and nature, particularly the wonderful vistas of Lebanon, with its cedar groves and mountains, in poetry of passionate tenderness.
And above all, here is the author of the remarkable poetic narratives in which Gibran''s mystical, spiritual vision of the transmigration of souls is embodied in tales of lovers tragically parted in one existence and rapturously reunited, after centuries of separation, in a later incarnation.
The spiritual message of the great Lebanese prophet and poet is conveyed with exceptional beauty and power in these sensitive writings.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '842814', '4.2', '367', '14', 'https://www.goodreads.com/book/show/842814.Thoughts_and_Meditations');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Smoke', '', 'Dorianne Laux''s long-awaited third book of poetry follows her collection, What We Carry, a finalist for the 1994 National Book Critics Circle Award for Poetry. In Smoke, Laux revisits familiar themes of family, working class lives and the pleasures of the body in poetry that is vital and artfully crafted--poetry that "gets hard in the face of aloofness," in the words of one reviewer. In Smoke, as in her previous work, Laux weaves the warp and woof of ordinary lives into extraordinary and complex tapestries. In "The Shipfitter''s Wife," a woman recalls her husband''s homecoming at the end of his work day:
Then I''d open his clothes and take
the whole day inside me--the ship''s
gray sides, the miles of copper pipe,
the voice of the foreman clanging
off the hull''s silver ribs. Spark of lead
kissing metal. The clamp, the winch,
the white fire of the torch, the whistle,
and the long drive home.
And in the title poem, Laux muses on her own guilty pleasures:
Who would want to give it up, the coal
a cat''s eye in the dark room, no one there
but you and your smoke, the window
cracked to street sounds, the distant cries
of living things. Alone, you are almost
safe . . .
With her keen ear and attentive eye, Dorianne Laux offers us a universe with which we are familiar, but gives it to us fresh.
Dorianne Lauxis the author of two previous collections of poetry from BOA Editions, Ltd., and is co-author, with Kim Addonizio, of The Poet''s Companion: A Guide to the Joys of Writing Poetry(W.W. Norton, 1997), chosen as an alternate selection by several bookclubs. Laux was the judge for the 2012 A. Poulin, Jr. Poetry Contest, and is a tenured professor in the creative writing program at the University of Oregon. Laux lives in Eugene, Oregon.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '515187', '4.43', '366', '27', 'https://www.goodreads.com/book/show/515187.Smoke');
