INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Grief is the Thing with Feathers', '', 'In a London flat, two young boys face the unbearable sadness of their mother''s sudden death. Their father, a Ted Hughes scholar and scruffy romantic, imagines a future of well-meaning visitors and emptiness.
In this moment of despair they are visited by Crow - antagonist, trickster, healer, babysitter. This self-described sentimental bird is attracted to the grieving family and threatens to stay until they no longer need him. As weeks turn to months and physical pain of loss gives way to memories, this little unit of three begin to heal.
In this extraordinary debut - part novella, part polyphonic fable, part essay on grief, Max Porter''s compassion and bravura style combine to dazzling effect. Full of unexpected humour and profound emotional truth, Grief is the Thing with Feathersmarks the arrival of a thrilling new talent.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '26530848', '3.9', '358', '17', 'https://www.goodreads.com/book/show/26530848-grief-is-the-thing-with-feathers');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Serious Concerns', '', 'Wendy Cope''s first book of poems and parodies, Making Cocoa for Kingsley Amis, went straight into the bestseller lists. Its successor, Serious Concernshas proved even more popular, addressing such topics as ''Bloody Men'', ''Men and Their Boring Arguments'', ''Two Cures for Love'', ''Kindness to Animals'' and ''Tumps'' (Typically Useless Male Poets).', 'https://images.gr-assets.com/books/1468542903m/936208.jpg', '936208', '4.18', '349', '34', 'https://www.goodreads.com/book/show/936208.Serious_Concerns');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('سکوت سرشار از ناگفته‌هاست', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '3396801', '4.38', '347', '18', 'https://www.goodreads.com/book/show/3396801');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Vampire Haiku', '', 'You hold in your hands a recently discovered poetry journal--the poetry journal of a vampire. William Butten was en route to a new land on the Mayflower when he was turned into a vampire by a fellow passenger, a beautiful woman named Katherine. These pages contain his heartbreaking story--the story of a vampire who has lived through (and perhaps caused) some of America''s defining events. As he travels the country and as centuries pass, he searches for his lost love and records his adventures and misadventures using the form of poetry known as haiku.As Butten documents bloody wars, a certain tea party in Boston, living the high life during the Great Depression, two Woodstock festivals, the corruption of Emily Dickinson, and hanging out with Davy Crockett, he keeps to the classic 5-7-5 syllable structure of haiku. The resulting poems are hilarious, repulsive, oddly romantic, and bizarre.
Read along, and you just may find a new appreciation for--and insight into--various events in American history. And blood.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6254746', '3.82', '347', '69', 'https://www.goodreads.com/book/show/6254746-vampire-haiku');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Digger, Dozer, Dumper', '', 'Each truck and big machine in these enticing rhyming poems is different -- and little readers are invited to find a vehicle that''s like them.
Sixteen boisterous, rhyming poems -- each one highlighting the job and personality of a different vehicle, from a backhoe to an ambulance to a snowplow -- invite young children to meet their favorite trucks face-to-face. Cheerful illustrations show each one in action, digging (or dozing, or dumping) away. Engaging visual details like an anxious turtle crossing the street just ahead of a steamroller are sure to keep preschoolers poring over the pages as they consider the question, "Trucks as far as eyes can see. . . . Which truck would you like to be?"', 'https://images.gr-assets.com/books/1367256732m/17262248.jpg', '17262248', '3.95', '346', '80', 'https://www.goodreads.com/book/show/17262248-digger-dozer-dumper');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Unfortunately, It Was Paradise: Selected Poems', '', 'Mahmoud Darwish is a literary rarity: at once critically acclaimed as one of the most important poets in the Arabic language, and beloved as the voice of his people. He is a living legend whose lyrics are sung by fieldworkers and schoolchildren. He has assimilated some of the world''s oldest literary traditions at the same time that he has struggled to open new possibilities for poetry. This collection spans Darwish''s entire career, nearly four decades, revealing an impressive range of expression and form. A splendid team of translators has collaborated with the poet on these new translations, which capture Darwish''s distinctive voice and spirit.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '130546', '4.39', '345', '30', 'https://www.goodreads.com/book/show/130546.Unfortunately_It_Was_Paradise');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Seam', '', 'The poems in this captivating collection weave beauty with violence, the personal with the historic as they recount the harrowing experiences of the two hundred thousand female victims of rape and torture at the hands of the Pakistani army during the 1971 Liberation War. As the child of Bangladeshi immigrants, the poet in turn explores her own losses, as well as the complexities of bearing witness to the atrocities these war heroines endured.
Throughout the volume, the narrator endeavors to bridge generational and cultural gaps even as the victims recount the horror of grief and personal loss. As we read, we discover the profound yet fragile seam that unites the fields, rivers, and prisons of the 1971 war with the poet''s modern-day hotel, or the tragic death of a loved one with the holocaust of a nation.
Moving from West Texas to Dubai, from Virginia to remote villages in Bangladesh and back again, the narrator calls on the legacies of Willa Cather, Cesar Vallejo, Tomas Transtromer, and Paul Celan to give voice to the voiceless. Fierce yet loving, devastating and magical at once, Seamis a testament to the lingering potency of memory and the bravery of a nation''s victims.
Winner, Great Lakes Colleges Association New Writers Award, 2014
Winner, Binghamton University Milt Kessler Poetry Book Award, 2015', 'https://images.gr-assets.com/books/1387569330m/17937655.jpg', '17937655', '4.51', '341', '32', 'https://www.goodreads.com/book/show/17937655-seam');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Mahabharata', '', 'A bitter, generation-spanning conflict between two great ruling families for India''s most precious lands forms the enthralling central thread of "Mahabharata." It is this sweeping, shifting struggle - with its magnificent cast of characters and its deep moral ramifications - that William Buck brings to us in this beautiful retelling of the ancient Sanskrit epic. The men and women, gods, demons, and animals are once again restored to life as they take part in this drama of savage battle and tender love, sensuous celebration and profound meditation.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1785216', '4.29', '338', '10', 'https://www.goodreads.com/book/show/1785216.Mahabharata');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Iliad', '', 'Rage--Goddess, sing the rage of
Peleus'' son Achilles,
murderous, doomed, that cost the
Achaeans countless losses,
hurling down to the House of Death
so many sturdy souls ...
Thus begins the stirring story of the Trojan War and the rage of Achilles that has gripped listeners and readers for 2,700 years. This timeless poem still vividly conveys the horror and heroism of men and gods wrestling with towering emotions and battling amidst devastation and destruction, as it moves inexorably to its wrenching, tragic conclusion. Renowned classicist Bernard Knox observes in his superb Introduction that although the violence of the Iliadis grim and relentless, it coexists with both images of civilized life and a poignant yearning for peace.
Combining the skills of a poet and scholar, Robert Fagles brings the energy of contemporary language to this enduring heroic epic. He maintains the drive and metric music of Homer''s poetry, and evokes the impact and nuance of the Iliad''s mesmerizing repeated phrases in what Peter Levi calls "an astonishing performance."', 'https://images.gr-assets.com/books/1309284044m/516650.jpg', '516650', '3.83', '337', '40', 'https://www.goodreads.com/book/show/516650.The_Iliad');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Earth Prayers: From Around the World: 365 Prayers, Poems, and Invocations for Honoring the Earth', '', 'In forest clearings, beneath star-filled skies, in cathedrals, and before the hearth... women and men have always given voice to the impulse to celebrate the world that surrounds and sustains them. Now, as we face a diminished present and an uncertain future, the need to honor the interconnection between people and the planet is heightened. From Walt Whitman, Thich Nhat Hanh, and Black Elk, to Margaret Atwood, the Rig Veda, and the chant of a Samar fisherman, the varied voices linked here offer songs and prayers for land, sea, and air; graces for food; and invocations, poems, and passages that reveal in the common spiritual heritage of all who cherish creation.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '949011', '4.28', '330', '29', 'https://www.goodreads.com/book/show/949011.Earth_Prayers');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Beautiful And Damned', '', 'With the same heartwarming composition and genius Robert M. Drake brought to his international bestselling books Beautiful Chaos, Black Butterfly and A Brilliant Madness, Robert M. Drake now takes his readers to a deeper level of his consciousness with this collection of stories. A man encounters God in a bar; a family is saved by a time traveler in the middle of the night; a journey into the mind of a severely autistic man; a woman finds herself one night out in the city and more.
Beautiful and Damned is as haunting and as captivating as the stories it tells, it is proof that Robert M. Drake is one of the most visionary writers working today.', 'https://images.gr-assets.com/books/1458962139m/29621148.jpg', '29621148', '3.82', '327', '39', 'https://www.goodreads.com/book/show/29621148-beautiful-and-damned');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Who Can Be Happy And Free In Russia', '', '', 'https://images.gr-assets.com/books/1334357333m/1473236.jpg', '1473236', '3.35', '323', '3', 'https://www.goodreads.com/book/show/1473236.Who_Can_Be_Happy_And_Free_In_Russia');
