INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('42 Miles', '', 'JoEllen''s parents divorced when she was very young, so she was used to splitting her time between them, shuttling four blocks from one Cincinnati apartment to another. But when her dad moved to the old family farm last year, her life was suddenly divided. Now on weekdays she''s a city girl, called Ellen, who hangs out with her friends, plays the sax, and loves old movies. And on weekends she''s a country girl, nicknamed Joey, who rides horseback with her cousin, Hayden, goes fishing, and listens to bluegrass. So where do her loyalties lie? Who is the real JoEllen? Linked free-verse poems, illustrated with a quirky array of found objects and mementos, create the vivid, realistic portrait of a young girl at a defining moment in her life.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2149610', '3.77', '320', '87', 'https://www.goodreads.com/book/show/2149610.42_Miles');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Eclogues. Georgics. Aeneid: Books 1-6', '', 'Virgil (Publius Vergilius Maro) was born in 70 BCE near Mantua and was educated at Cremona, Milan and Rome. Slow in speech, shy in manner, thoughtful in mind, weak in health, he went back north for a quiet life. Influenced by the group of poets there, he may have written some of the doubtful poems included in our Virgilian manuscripts. All his undoubted extant work is written in his perfect hexameters. Earliest comes the collection of ten pleasingly artificial bucolic poems, the "Eclogues," which imitated freely Theocritus''s idylls. They deal with pastoral life and love. Before 29 BCE came one of the best of all didactic works, the four hooks of Georgics on tillage, trees, cattle, and bees. Virgil''s remaining years were spent in composing his great, not wholly finished, epic the "Aeneid," on the traditional theme of Rome''s origins through Aeneas of Troy. Inspired by the Emperor Augustus''s rule, the poem is Homeric in metre and method but influenced also by later Greek and Roman literature, philosophy, and learning, and deeply Roman in spirit. Virgil died in 19 BCE at Brundisium on his way home from Greece, where he had intended to round off the "Aeneid." He had left in Rome a request that all its twelve books should be destroyed if he were to die then, but they were published by the executors of his will.
The Loeb Classical Library edition of Virgil is in two volumes.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1402', '4.28', '316', '10', 'https://www.goodreads.com/book/show/1402.Eclogues_Georgics_Aeneid');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems in the Attic', '', 'During a visit to her grandma s house, a young girl discovers a box of poems in the attic, poems written by her mother when she was growing up. Her mother s family often moved around the United States and the world because her father was in the Air Force. Over the years, her mother used poetry to record her experiences in the many places the family lived. Reading the poems and sharing those experiences through her mother s eyes, the young girl feels closer to her mother than ever before. To let her mother know this, she creates a gift: a book with her own poems and copies of her mother s. And when she returns her mother s poems to the box in the attic, she leaves her own poems too, for someone else to find, someday. Using free verse for the young girl s poems and tanka for her mother s, master poet Nikki Grimes creates a tender intergenerational story that speaks to every child s need to hold onto special memories of home, no matter where that place might be."', 'https://images.gr-assets.com/books/1433992572m/22162514.jpg', '22162514', '3.85', '310', '82', 'https://www.goodreads.com/book/show/22162514-poems-in-the-attic');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Divine Comedy', '', 'This single volume, blank verse translation of The Divine Comedy includes an introduction, maps of Dante''s Italy, Hell, Purgatory, Geocentric Universe, and political panorama of the thirteenth and early fourteenth century, diagrams and notes providing the reader with invaluable guidance. Described as the "fifth gospel" because of its evangelical purpose, this spiritual autobiography creates a world in which reason and faith have transformed moral and social chaos into order. It is one of the most important works in the literature of Western Europe and is considered the greatest poem of the European Middle Ages.
About the Series: For over 100 yearsOxford World''s Classicshas made available the broadest spectrum of literature from around the globe. Each affordable volume reflects Oxford''s commitment to scholarship, providing the most accurate text plus a wealth of other valuable features, including expert introductions by leading authorities, voluminous notes to clarify the text, up-to-date bibliographies for further study, and much more.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2764176', '4.06', '310', '29', 'https://www.goodreads.com/book/show/2764176-the-divine-comedy');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Solo', '', 'When the heart gets lost, let the music find you.
Blade never asked for a life of the rich and famous. In fact, he''d give anything not to be the son of Rutherford Morrison, a washed-up rock star and drug addict with delusions of a comeback. Or to no longer be part of a family known most for lost potential, failure, and tragedy. The one true light is his girlfriend, Chapel, but her parents have forbidden their relationship, assuming--like many--that Blade will become just like his father.
In reality, the only thing Blade has in common with Rutherford is the music that lives inside them. But not even the songs that flow through Blade''s soul are enough when he''s faced with two unimaginable realities: the threat of losing Chapel forever, and the revelation of a long-held family secret, one that leaves him questioning everything he thought was true. All that remains is a letter and a ticket to Ghana--both of which could bring Blade the freedom and love he''s been searching for, or leave him feeling even more adrift.', 'https://images.gr-assets.com/books/1479444434m/33004293.jpg', '33004293', '4.03', '305', '67', 'https://www.goodreads.com/book/show/33004293-solo');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poe: Poems', '', 'Poe''s poems have been memorized and recited by millions. Among his best-loved works are "The Raven" with its hypnotic chant of "nevermore, " and the sensuous and lyrical "Annabel Lee." This collection includes all of Poe''s most popular rhymes.', 'https://images.gr-assets.com/books/1320400091m/403506.jpg', '403506', '4.28', '304', '7', 'https://www.goodreads.com/book/show/403506.Poe');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Prophet', '', 'Kahlil Gibran''s masterpiece, The Prophet, is one of the most beloved classics of our time. Published in 1923, it has been translated into more than twenty languages, and the American editions alone have sold more than nine million copies.
The Prophet is a collection of poetic essays that are philosophical, spiritual, and, above all, inspirational. Gibran''s musings are divided into twenty-eight chapters covering such sprawling topics as love, marriage, children, giving, eating and drinking, work, joy and sorrow, housing, clothes, buying and selling, crime and punishment, laws, freedom, reason and passion, pain, self-knowledge, teaching, friendship, talking, time, good and evil, prayer, pleasure, beauty, religion, and death.', 'https://images.gr-assets.com/books/1414348163m/846490.jpg', '846490', '4.23', '304', '25', 'https://www.goodreads.com/book/show/846490.The_Prophet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Fragment of the Head of a Queen: Poems', '', 'Cate Marvin''s new poems, their wrought music, unblinking focus, and hard-edged sensuality, are wreathed with an entirely different silence than her first collection. The brokenness and loss of the fragmented queen--seeming to rise up through centuries--is their tutelary spirit.', 'https://images.gr-assets.com/books/1354903036m/868591.jpg', '868591', '4.07', '297', '28', 'https://www.goodreads.com/book/show/868591.Fragment_of_the_Head_of_a_Queen');
