INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Месопотамія', '', '"Istoriyi Vavilona, perekazani dlia tikh, khto tsikavit''sia pitanniami liubovi i smerti. Zhittia mista, shcho lezhit'' pomizh rik, biografiyi personazhiv, iaki b''iut''sia za svoie pravo buti pochutimi, zronika vulichnikh sutichok i shchodennikh pristrastei. Osvichennia i zradi, vtechi i povernennia, nizhnist'' i zhorstokist''. Nailirichnisha kniga avtora.
Shcho take Mesopotamiia - tse kozhen rozumiie po-svoiemu. Napriklad, vona mozhe buti osilim mizh dvoma zamulenimi richkami pagorbom Kharkova. Abo bud''-iakim inshim mezhirichchiam. Iz pritamannim iomu mezhimov''iam, mezhikul''utr''ias, mezhiderzhav''iam ta reshtoiu tragikomichnikh viprobuvan'', shcho pidsterigaiut'' nas mezhi narodzhenniam i smertiu. Odne slovo, ne skhozhe, shchob za ostanni 5-6 tisiach rokiv shchos'' na ts''omu sviti suttievo zminilosia. Nam zalishaiet''sia povtoriuvati vse ti zh mesopotams''ki podvigi i grikhi. Zhadanu lishaiet''sia skladati pro nikh virshi i prozu. Bo khto shche mizh Donom i Sianom umiie tak shchemko pisati pro te, shcho staiet''sia z usima skriz'' i zavzhdi?"
Oleksandr Boichenko, literaturnii kritik, publitsist, perekladach', 'https://images.gr-assets.com/books/1390663374m/20631997.jpg', '20631997', '4.0', '291', '22', 'https://www.goodreads.com/book/show/20631997');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Now We Are Sick: An Anthology of Nasty Verse', '', 'A collection of funny, frivolous and frightening poems by thirty of the world''s best known science fiction, fantasy and horror authors. It includes poems by: Brian Aldiss, Sharon Baker, Robert Bloch, Ramsey Campbell, Simon Ian Childer, Storm Constantine, Galad Elflandsson, Jo Fletcher, John M Ford, Stephen Gallagher, David Garnett and John Grant.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '47721', '3.76', '289', '13', 'https://www.goodreads.com/book/show/47721.Now_We_Are_Sick');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Crow With No Mouth: Ikkyu, Fifteenth Century Zen Master', '', 'When Zen master Ikkyu Sojun (1394-1481) was appointed headmaster of the great temple at Kyoto, he lasted nine days before denouncing the rampant hypocrisy he saw among the monks there. He in turn invited them to look for him in the sake parlors of the Pleasure Quarters. A Zen monk-poet-calligrapher-musician, he dared to write about the joys of erotic love, along with more traditional Zen themes. He was an eccentric and genius who dared to defy authority and despised corruption. Although he lived during times plagued by war, famine, rioting, and religious upheaval, his writing and music prevailed, influencing Japanese culture to this day.
Stephen Bergis the Editor and founder of American Poetry Review.
Also available by Stephen Berg
Steel Cricket
PB $16.00, 1-55659-075-X * CUSA
New & Selected Poems
PB $12.00, 1-55659-043-1 * CUSA', 'https://images.gr-assets.com/books/1328757977m/97528.jpg', '97528', '4.48', '286', '38', 'https://www.goodreads.com/book/show/97528.Crow_With_No_Mouth');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('El hacedor', '', 'Caracterizan las paginas de "El hacedor" el cruce de generos (relatos, ensayos u poemas) u la diversidad tematica. Homero u Dante alternan con Rosas u Facundo; la fantasia que inventa laberintos ineditos, con la cronica de sucesos aparentemente triviales pero cargados de insospechadas significaciones; el particularismo criollo, con la universalidad historica que abarca tanto la simbologia oriental como la cultura europea. "De cuantos libros he entregado a la imprenta - escribio el propio Jorge Luis Borges - ninguno, creo, es tan personal como esta colectiva u desordenada "silva de varia leccion".', 'https://images.gr-assets.com/books/1450012008m/929582.jpg', '929582', '4.21', '285', '16', 'https://www.goodreads.com/book/show/929582.El_hacedor');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hamlet', '', 'One of the greatest plays of all time, the compelling tragedy of the tormented young prince of Denmark continues to capture the imaginations of modern audiences worldwide. Confronted with evidence that his uncle murdered his father, and with his mother''s infidelity, Hamlet must find a means of reconciling his longing for oblivion with his duty as avenger. The ghost, Hamlet''s feigned madness, Ophelia''s death and burial, the play within a play, the "closet scene" in which Hamlet accuses his mother of complicity in murder, and breathtaking swordplay are just some of the elements that make Hamlet an enduring masterpiece of the theater.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '65214', '4.01', '285', '19', 'https://www.goodreads.com/book/show/65214.Hamlet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Preobraženja', '', 'Antun Branko Simic zbirku pjesama Preobrazenja izdao je 1920. sa svoje 22. godine. Ona se smatra kamenom temeljcem modernog hrvatskog pjesnistva. Stihovi u pjesmama iz zbirke su posve svjezi, jednostavno originalni. Puni su boje, ritma i zvuka. U zbirci se po prvi put javlja nevezani (slobodni) stih u kojem se izostavlja interpunkcija, sto daje vizualnu snagu lirskim motivima.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '8340952', '4.2', '283', '4', 'https://www.goodreads.com/book/show/8340952-preobra-enja');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Things Left Unsaid: A Novel in Poems', '', 'Sarah used to be the good girl. The one who always had her hand raised in class, always obeyed her parents.
Until she met Robin. Once Robin comes into the picture, Sarah''s life changes. Her closet begins to fill with black clothes. Good grades become something to be studiously avoided. And maintaining her other friendships doesn''t seem so important anymore. Sarah thought she knew Robin. But Robin eats danger for breakfast, pushes the limits way too far, and forces Sarah to question everything in her life - everything Sarah thought she had wanted.
In stunning verse, this novel slowly reveals the complexities of friendship - the power it has to define, destroy, and eventually heal again.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '836062', '3.59', '279', '39', 'https://www.goodreads.com/book/show/836062.Things_Left_Unsaid');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('სტუმარ მასპინძელი', '', 'Vazha-Pshavela was born in a small village Chargali (Pshavi mountainous province in Eastern Georgia) in a family of clergyman. He graduated from the Pedagogical Seminary in Gori 1882, where he became close to Georgian populists (narodniki). Then 1883 entered Law Department of St. Petersburg University (Russia) as a non-credit student, but returned to Georgia in 1884 due to financial restraints. Worked as a teacher of Georgian language. He was also a famous representative of a National-Liberation movement of Georgia.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '15796357', '4.58', '278', '4', 'https://www.goodreads.com/book/show/15796357');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Haiku Anthology:  Haiku And Senryu In English', '', 'Originally a Japanese form that flourished in the seventeenth and eighteenth centuries, haiku has recently experienced tremendous growth in popularity in the English language. The Haiku Anthology, first published in 1974, is a landmark work in modern haiku, honoring a genre of poetry that celebrates simplicity, emotion, and imagery--in which only a few words convey worlds of mystery and meaning. This third edition, now completely revised and updated, comprises 850 haiku and senryu (a related genre, usually humorous and concerned with human nature) written in English by 89 poets, including the top haiku writers of the American past and present. A new foreword details developments since the publication of the last edition. "Each of these perfect little poems will come as a revelation to the uninitiated reader and will bring joy to the haiku enthusiast. . . . This is an exceptional selection of English-language haiku at its finest."--Library Booknotes', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '211530', '4.2', '277', '33', 'https://www.goodreads.com/book/show/211530.The_Haiku_Anthology');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Seventh Octave: The Early Writings of Saul Williams', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '95894', '4.23', '276', '7', 'https://www.goodreads.com/book/show/95894.The_Seventh_Octave');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Beauty: Poems', '', 'The Beauty,an incandescent new collection from one of American poetry''s most distinctive and essential voices, opens with a series of dappled, ranging "My" poems--"My Skeleton," "My Corkboard," "My Species," "My Weather"--using materials sometimes familiar, sometimes unexpected, to explore the magnitude, singularity, and permeability of our shared existence. With a pen faithful to the actual yet dipped at times in the ink of the surreal, Hirshfield considers the inner and outer worlds we live in yet are not confined by; reflecting on advice given her long ago--to avoid the word "or"--she concludes, "Now I too am sixty. / There was no other life." Hirshfield''s lines cut, as always, directly to the heart of human experience. Her robust affirmation of choice even amid inevitability, her tender consciousness of the unjudging beauty of what exists, her abiding contemplation of our moral, societal, and biological intertwinings, sustain poems that tune and retune the keys of a life. For this poet, "Zero Plus Anything Is a World." Hirshfield''s riddling recipes for that world ("add salt to hunger"; "add time to trees") offer a profoundly altered understanding of our lives'' losses and additions, and of the small and larger beauties we so often miss.', 'https://images.gr-assets.com/books/1411922492m/22543937.jpg', '22543937', '3.82', '274', '49', 'https://www.goodreads.com/book/show/22543937-the-beauty');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Il libro dell''inquietudine di Bernardo Soares', '', 'En 2014 se cumple el treinta aniversario de la publicacion en Espana (en Seix Barral --dirigida en aquel entonces por Mario Lacruz--, con organizacion y traduccion de Angel Crespo) de la primera edicion en castellano, que fue la primera traduccion a cualquier lengua, del Libro del desasosiego. A partir de esa edicion, el exito de la obra fue mundial en innumerables lenguas.
Editorial Funambulista, que cumple en este mismo 2014 diez anos de andadura, homenajea la efemeride con esta antologia personal y traduccion de Luis Morales, destinada al lector no iniciado o con prisa, y configurada en un orden original y audaz, casi transgresor, que prescinde de la numeracion y disposicion habituales para darle la consistencia del diario de una jornada cualquiera en la (no) vida de Bernardo Soares, alter ego de Fernando Pessoa.', 'https://images.gr-assets.com/books/1332746268m/2092897.jpg', '2092897', '4.5', '274', '31', 'https://www.goodreads.com/book/show/2092897.Il_libro_dell_inquietudine_di_Bernardo_Soares');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Howl', '', 'Now a Major Motion Picture! 
First published in 1956, Allen Ginsberg''s Howlis a prophetic masterpiecean epic raging against dehumanizing society that overcame censorship trials and obscenity charges to become one of the most widely read poems of the century.', 'https://images.gr-assets.com/books/1331512209m/1026806.jpg', '1026806', '4.21', '271', '8', 'https://www.goodreads.com/book/show/1026806.Howl');
