INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('My Noiseless Entourage', '', '', 'https://images.gr-assets.com/books/1328876788m/175035.jpg', '175035', '3.96', '264', '34', 'https://www.goodreads.com/book/show/175035.My_Noiseless_Entourage');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Baghavad Gita', '', 'The most important, the most influential, and the most luminous of all the Hindu scriptures." --R.C. ZAEHNER Vivid literature, lofty philosophy -- the Bhagavad Gita distills the finest in India''s vast and varied culture. * On the morning of battle, facing Armageddon, prince Arjuna loses his nerve and refuses to fight. Krishna knows better: "Your very nature will drive you to fight. Your only choice is what to fight against." His advice gives an inspiring model of the man or woman of action -- the person who aims at goodness in a world of conflict and change. * In this translation, the Gita stands out as a book of choices--direct, practical, universal. The introduction sketches the background of the poem and gives clear, contemporary explanations of the basic ideas of Indian philosophy, karma, reincarnation, yoga, freedom. Separate chapter introductions outline the drama as it unfolds. "The translation . . . is smooth, eloquent, and reliable . . . (1)would unhesitatingly recommend Easwaran to someone searching for the spirituality of the Gita." --CHOICE * Eknath Easwaran, writer, Fulbright scholar, and former professor of English literature, is at home in both English and Sanskrit. He brings to this translation 25 years'' experience of teaching the Gita to an American audience.
Excerpt:
The "Bhagavad Gita" sometimes called "The Lord''s Lay," or the "Message of the Master," is an episode of the great Hindu epic, the Mahabharata, in the Sixth (or "Bhishma") Parva. It enjoys the highest esteem among the Hindu people, and is constantly quoted there as a great authority regarding doctrine. Its philosophy embodies the prevailing Hindu beliefs, as expounded by the Brahmans, and in its teachings it subtly blends into a harmonious whole the varying points of doctrine of Patanjali, Kapila and of the Vedas. It is supposed to have been written by Vyasa whose personality is veiled in doubt for of the time of his existence in the world no record seems to have been kept.
To the reade', 'https://images.gr-assets.com/books/1415764190m/3479389.jpg', '3479389', '4.1', '263', '14', 'https://www.goodreads.com/book/show/3479389-baghavad-gita');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'As a poet, editor and essayist, T. S. Eliot was one of the defining figures of twentieth century poetry. This selection, which was made by Eliot himself, includes many of his most celebrated works, including The Love Song of J. Alfred Prufrockand The Waste Land.
Other volumes in this series: Auden, Betjemen, Plath, Hughes and Yeats.', 'https://images.gr-assets.com/books/1429593992m/6639509.jpg', '6639509', '4.24', '263', '17', 'https://www.goodreads.com/book/show/6639509-selected-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems for the Millennium, Vol. 1: Modern and Postmodern Poetry from Fin-de-Siècle to Negritude', '', 'As we come to the end of the century, the entire vista of modern poetry has dramatically changed. Poems for the Millenniumcaptures the essence of that change, and unlike any anthology available today, it reveals the revolutionary concepts at the very heart of twentieth-century poetry.
International in its coverage, these volumes depart from the established poetic modes that grew out of the nineteenth century and instead bring together the movements that radically altered the ways that art and language express the human condition.
The first volume offers three "galleries" of individual poetsfigures such as Mallarme, Stein, Rilke, Tzara, Mayakovsky, Pound, H.D., Vallejo, Artaud, Cesaire, and Tsvetayeva.
Included, too, are sections dedicated to some of the most significant pre-World War II movements in poetry and the other arts: Futurism, Expressionism, Dada, Surrealism, Objectivism, and Negritude. The second volume will extend the gathering to the present, forming a synthesizing, global anthology that surpasses other collections in its international scope and experimental range.
Poet-editors Jerome Rothenberg and Pierre Joris provide informative and irreverent commentaries throughout. They challenge old truths and propose alternative directions, in the tradition of the revolutionary manifestos that have marked the art and poetry of the twentieth century. The result is both an essential source book for experiencing the full range of this century''s poetic possibilities and a powerful statement on the future of poetry in the millennium ahead.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1337117', '4.47', '262', '11', 'https://www.goodreads.com/book/show/1337117.Poems_for_the_Millennium_Vol_1');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Loop of Jade', '', '*SHORTLISTED FOR THE FORWARD PRIZE FOR BEST FIRST COLLECTION 2015*
There is a Chinese proverb that says: ''It is more profitable to raise geese than daughters.'' But geese, like daughters, know the obligation to return home. In her exquisite first collection, Sarah Howe explores a dual heritage, journeying back to Hong Kong in search of her roots.
With extraordinary range and power, the poems build into a meditation on hybridity, intermarriage and love - what meaning we find in the world, in art, and in each other. Crossing the bounds of time, race and language, this is an enthralling exploration of self and place, of migration and inheritance, and introduces an unmistakable new voice in British poetry.', 'https://images.gr-assets.com/books/1443609471m/23346611.jpg', '23346611', '3.93', '262', '38', 'https://www.goodreads.com/book/show/23346611-loop-of-jade');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('أول الجسد آخر البحر', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6150334', '3.56', '262', '33', 'https://www.goodreads.com/book/show/6150334');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poesías completas', '', 'La Coleccion AUSTRAL se honra al ofrecer esta edicion que, por primera vez en todo el ambito editorial hispano, merece con justicia el titulo de POESIAS COMPLETAS de Antonio Machado. Porque no solo incorporan los poemas escritos durante la guerra civil largamente llamados a la lectura de los espanoles, sino que anade una veintena de textos hasta ahora dispersos y practicamente desconocidos. A pesar de su excepcional categoria literaria no ha tenido don Antonio Machado demasiada suerte en la transmision de sus textos y con razon podia decir: <>. Espana le debia, ante todo, una edicion completa y limpia. Se la ofrecemos hoy gracias al profesor Manuel Alvar, catedratico de la Universidad Complutense y miembro de la Real Academia, que ha voleado aqui su saber filologico y su amor a las Letras de Espana. COLECCION AUSTRAL. ESPASA CALPE SOLEDADES (1899-1907) - DEL CAMINO - CANCIONES - HUMORISMOS, FANTASIAS, APUNTES. Los grandes inventos - GALERIAS VARIA - CAMPOS DE CASTILLA (1907-1917) - ELOGIOS - NUEVAS CANCIONES (1917-1930) - DE UN CANCIONERO APOCRIFO - CANCIONERO APOCRIFO - POESIAS DE "SOLEDADES" (1898-1907) - NUEVAS CANCIONES (1917-1930) - LOS COMPLEMENTARIOS - POESIAS SIN AGRUPAR - CANCIONERO APOCRIFO DE "JUAN DE MAIRENA" (1936) - DE "MAIRENA POSTUMO" (1936-1939) - POESIAS DE GUERRA.', 'https://images.gr-assets.com/books/1335698708m/1254774.jpg', '1254774', '4.26', '261', '7', 'https://www.goodreads.com/book/show/1254774.Poes_as_completas');
