INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Rock Can Be . . .', '', 'Rocks may seem like boring, static objects--until you discover that a rock can spark a fire, glow in the dark, and provide shelters of all shapes and sizes. Laura Purdie Salas''s lyrical rhyming text and Violeta Dabija''s glowing illustrations show how rocks decorate and strengthen the world around them.', 'https://images.gr-assets.com/books/1416182337m/23080135.jpg', '23080135', '4.24', '257', '63', 'https://www.goodreads.com/book/show/23080135-a-rock-can-be');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Dyer''s Hand', '', 'In this volume, W. H. Auden assembled, edited, and arranged the best of his prose writing, including the famous lectures he delivered as Oxford Professor of Poetry. The result is less a formal collection of essays than an extended and linked series of observations--on poetry, art, and the observation of life in general.
The Dyer''s Handis a surprisingly personal, intimate view of the author''s mind, whose central focus is poetry--Shakespearean poetry in particular--but whose province is the author''s whole experience of the twentieth century.', 'https://images.gr-assets.com/books/1320461998m/152535.jpg', '152535', '4.28', '254', '11', 'https://www.goodreads.com/book/show/152535.The_Dyer_s_Hand');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Pet Project: Cute and Cuddly Vicious Verses', '', 'Embark on a methodical, meticulous, and hilarious quest for the perfect pet in this wickedly witty cautionary collection of pet poems.
If you''re the type that oohs and aahs 
at furry faces, precious paws, 
the words ahead may be alarming: 
Animals aren''t always charming.
If you think you''d like a cute and cuddly pet, you may need to do some research. Formulate a query. Devise a scientific plan. And be sure to write down every observation of the animals you encounter. Join one budding young scientist as she catalogs the pros and pitfalls of potential pet ownership in this assortment of zany and relatable poems that will change the way you look at cuddly animals--and give you the giggles.', 'https://images.gr-assets.com/books/1376784393m/13260516.jpg', '13260516', '4.05', '253', '74', 'https://www.goodreads.com/book/show/13260516-the-pet-project');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Sir Gawain and the Green Knight', '', 'Composed during the fourteenth century in the English Midlands, Sir Gawain and the Green Knight describes the events that follow when a mysterious green-coloured knight rides into King Arthur''s Camelot in deep mid-winter. The mighty knight presents a challenge to the court: he will allow himself to be struck by one blow, on the condition that he will be allowed to return the strike on the following New Year''s Eve. Sir Gawain takes up the challenge, decapitating the stranger - only to see the Green Knight seize up his own severed head and ride away, leaving Gawain to seek him out and honour their pact. Blending Celtic myth and Christian faith, Gawain is among the greatest Middle English poems: a tale of magic, chivalry and seduction.', 'https://images.gr-assets.com/books/1311643645m/380544.jpg', '380544', '3.68', '251', '21', 'https://www.goodreads.com/book/show/380544.Sir_Gawain_and_the_Green_Knight');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hamlet', '', 'This Norton Critical Edition of Hamletfeatures a newly edited text based on the Second Quarto (1604-05). It is accompanied by detailed explanatory annotations and appendices providing important passages from both the First Quarto Hamlet(1603) and the Folio Hamlet(1623). Robert S. Miola''s thought-provoking introduction, "Imagining Hamlet," considers this tragedy as it has taken shape in the theater, in criticism, and in various cultures.
"The Actors'' Gallery" presents famous actors and actresses--among them Sarah Bernhardt, Ellen Terry, John Gielgud, Laurence Olivier, Richard Burton, Kenneth Branagh, and Jude Law--reflecting on their roles in major productions of Hamletfor stage and screen. "Contexts" includes generous selections from the Bible, Greek (Aeschylus, Sophocles, and Euripides) and Roman (Seneca) tragedies, Saxo Grammaticus, Dante, Thomas More, and Thomas Kyd.
"Criticism" reprints a wide range of historical and scholarly commentary including English critics (John Dryden, Samuel Taylor Coleridge, Samuel Johnson), European and Russian writers (Voltaire, Johann Wolfgang von Goethe, Leo Tolstoy), and Americans (John Quincy Adams, Edgar Allan Poe, Abraham Lincoln). Recent scholarly writing takes various approaches to Hamlet--mythic (Gilbert Murray), psychoanalytic (Ernest Jones), comparativist (Harry Levin), feminist (Elaine Showalter), and New Historicist (Stephen Greenblatt), among others.
An engaging selection of Hamlet''s "Afterlives" includes the seventeenth-century Der Bestrafte Brudermord; David Garrick''s altered stage version; comic reflections by Charles Dickens, Mark Twain, and Tom Stoppard; and selections from Heinrich Muller''s postmodern nightmare (Hamletmachine), Jawad al Assadi''s cynical Arab adaptation (Forget Hamlet), and John Updike''s haunting novel (Gertrude and Claudius).
A Selected Bibliography is also included.', 'https://images.gr-assets.com/books/1403199778m/8411147.jpg', '8411147', '4.01', '250', '18', 'https://www.goodreads.com/book/show/8411147-hamlet');
