INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Huzursuzluğun Kitabı', '', '20. yuzyil Portekiz edebiyatinin buyuk ismi Fernando Pessoa, sagliginda yayinlanan yapitlari olduysa da, esas olarak olumunden sonra, yazilarini topladigi sandigin bulunmasiyla un kazandi. Yaklasik 27 bin sayfaya yayilan, farkli turlerde eserler veren yazar, bunlarin buyuk bir kismini kendi adiyla degil, birer yasamoykusuyle, kisilikle, hatta edebi durus ve tarzla donattigi 70 ayri kurmaca yazarin, diskimligin adiyla imzalamisti; kotu bir Portekizce''yle ilkel doga siirleri yazan Alberto Caeiro, pagan dinlere inanan hekim Ricardo Reis, "icinde bir Yunan sairi barindiran Whitman" diye tarif edilen Alvaro de Campos gibi... Bu kurmaca yazarlardan biri olan Bernardo Soares, Pessoa''nin "yari-diskimlik" olarak niteledigi, ona cok yakin bir karakterdi ve Huzursuzlugun Kitabi''nin yazari olarak yaratilmisti. Soares, gunduzleri bir kumas magazasinda calisan, geceleri yagmurun sesinde, ayak seslerinde yalnizligini duyumsayan bir Lizbonluydu.
Huzursuzlugun Kitabi, kurmaca bir karakterin kendi hayatini anlattigi bir roman olarak gorulebilir; ancak yazarla kahramani sik sik birbirinin yerine gectiginden, Pessoa''nin hayatla ilgili kendine ait olan ve olmayan dusunceleri doktugu, evirip cevirdigi bir denemeler, anlatilar toplami olarak da kabul edilebilir. Pessoa bu kitap uzerinde 1913''ten itibaren calismaya baslamis, olumune dek parca parca yazmaya da devam etmisti. Sandik acildiktan sonra, daginik metinler bir araya getirilmeye baslandi ve 1982''de Portekiz''de yapit ilk kez olarak basildi; daha sonra, yeni bulunan parcalarin eklenmesi ve elyazmalarinda yanlis okunmus yerlerin duzeltilmesiyle yeni basimlar yapildi.
Dunyayi seyretmekle yetinmek isteyen, eylemsizligi en yuce erdem ve gercek yasam olarak goren Soares, Pessoa icin belki de dunyanin ve yasamanin ne oldugunu gosteren bir perdedir. Huzursuzlugun Kitabi ayni zamanda, bir edebiyatcinin ulasmak istedigi yapitla kagida dokebildiklerinin arasindaki mesafedir de; hayal edilenin soluk, titrek bir sureti, golgesi olarak kalmaya, k', 'https://images.gr-assets.com/books/1442738765m/11390422.jpg', '11390422', '4.5', '249', '32', 'https://www.goodreads.com/book/show/11390422-huzursuzlu-un-kitab');
