INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Insectlopedia', '', 'The windows are open and bugs are everywhere! Children will delight in this collection of twenty-one buggy poems - just don''t forget the calamine lotion.', 'https://images.gr-assets.com/books/1328876143m/1329652.jpg', '1329652', '4.08', '248', '41', 'https://www.goodreads.com/book/show/1329652.Insectlopedia');
