INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Balloon Pop Outlaw Black', '', 'Poetry. Even all by themselves, the titles of Patricia Lockwood''s poems reveal the sort of surreal, enigmatic, rhetorically-elongated world her sensibility inhabits effortlessly: "When We Move Away From Here, You''ll See A Clean Square of Paper Where His Picture Hung," "The Cartoon''s Mother Builds a House in Hammerspace," "The Front Half and the Back Half of a Horse in Conversation," "Children With Lamps Pouring Out of Their Foreheads," and the inimitable "Killed With an Apple Corer, She Asks What Does That Make Me."', 'https://images.gr-assets.com/books/1351826681m/12675105.jpg', '12675105', '3.97', '245', '38', 'https://www.goodreads.com/book/show/12675105-balloon-pop-outlaw-black');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('In Praise of Darkness', '', '', 'https://images.gr-assets.com/books/1320798367m/17720.jpg', '17720', '3.6', '243', '25', 'https://www.goodreads.com/book/show/17720.In_Praise_of_Darkness');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Edgar Allan Poe''s Pie: Math Puzzlers in Classic Poems', '', 'Is this poetry? Math? A brainteaser? Yes! It''s all that and more. The poet J. Patrick Lewis
has reimagined classic poems--such as Edgar Allan Poe''s "The Raven" and Langston
Hughes''s "April Rain Song"--and added a dash of math. Between the silly parodies
and the wonderfully wacky art, kids will have so much fun figuring out the puzzles,
they won''t guess they''re learning! Answers appear unobtrusively on each page, and
engaging information about the original poets is included. Math games and concepts,
poetry and poet biographies--it''s all so cleverly put together. This funny book is a
treat for fans of words and numbers alike.', 'https://images.gr-assets.com/books/1328836791m/12823369.jpg', '12823369', '3.99', '243', '74', 'https://www.goodreads.com/book/show/12823369-edgar-allan-poe-s-pie');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Gilgamesh', '', 'A new verse rendering of the great epic of ancient Mesopotamia, one of the oldest works in Western Literature. Ferry makes Gilgameshavailable in the kind of energetic and readable translation that Robert Fitzgerald and Richard Lattimore have provided for readers in their translations of Homer and Virgil.', 'https://images.gr-assets.com/books/1403169286m/32531.jpg', '32531', '3.63', '240', '29', 'https://www.goodreads.com/book/show/32531.Gilgamesh');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poesia de Fernando Pessoa', '', 'A presente edicao reproduz integralmente a obra Poesia de Fernando Pessoa Introducao e Seleccao de Adolfo Casais Monteiro, 2a edicao, 1945, Editorial Confluencia, Lisboa. Trata-se de uma compilacao abrangente e criteriosamente seleccionada, que compreende todas as facetas da obra de Fernando Pessoa. Nela se encontram reunidos os momentos mais significativos da sua poesia ortonima bem como da dos seus principais heteronimos Alberto Caeiro, Ricardo Reis e Alvaro de Campos. De extremo interesse e ainda a inclusao nesta obra da carta sobre a origem dos heteronimos que o poeta escreveu a Casais Monteiro. Dirigida por um profundo conhecedor do universo pessoano, esta antologia oferece-nos ainda uma introducao que constitui, a todos os titulos, uma perspectiva enriquecedora da obra daquele que e um dos poetas maiores da literatura portuguesa.', 'https://images.gr-assets.com/books/1499611194m/118457.jpg', '118457', '4.53', '238', '4', 'https://www.goodreads.com/book/show/118457.Poesia_de_Fernando_Pessoa');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Prophet', '', 'A hugely influential philosophical work of prose poetry, Kahlil Gibran''s The Prophet is an inspirational, allegorical guide to living, and this Penguin Modern Classics edition includes an introduction by Robin Waterfield.
First published in the 1920''s, The Prophetis perhaps the most famous work of religious fiction of the twentieth century, and has sold millions of copies in more than twenty languages. Gibran''s Prophet speaks of many things central to daily life: love, marriage, death, beauty, passion, eating, work and play. The spiritual message he imparts, of finding divinity through love, blends eastern mysticism, religious faith and philosophy with simple advice.The Prophet became the bible of 1960s culture and was credited with founding the New Age movement, yet it still continues to inspire people around the world today. This edition is illustrated with Gibran''s famous visionary paintings.
Kahlil Gibran (1883-1931) was a poet, philosopher and artist, who stands among the most important Arabic language authors of the early twentieth century. Born in Lebanon, he spent the last twenty years of his life in the United States, where for many years he was the leader of a Lebansese writing circle in New York. He is the author of numerous volumes, including The Garden of the Prophet, The Storm,The Beloved: Reflections on the Path of the Heart, The Vision, Reflections on the Way of the Soul, and Spirit Brides.
If you enjoyed The Prophet, you might like Herman Hesse''s Siddhartha, also available in Penguin Modern Classics.
''His work goes on from generation to generation''
Daily Mail
''To read it was to transcend ordinary levels of perception, to become aware ... of a more intense level of being''
Independent', 'https://images.gr-assets.com/books/1327963838m/846491.jpg', '846491', '4.23', '237', '34', 'https://www.goodreads.com/book/show/846491.The_Prophet');
