INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Good Poems: American Places', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '9028798', '4.14', '235', '42', 'https://www.goodreads.com/book/show/9028798-good-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poems of Doctor Zhivago', '', 'The 25 poems from Pasternak''s masterpiece Doctor Zhivago are followed by a masterful critique of their function in the novel and their value as poetry.', 'https://images.gr-assets.com/books/1336164038m/15635.jpg', '15635', '4.04', '235', '16', 'https://www.goodreads.com/book/show/15635.The_Poems_of_Doctor_Zhivago');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Courtship of Miles Standish', '', 'This is a poem about the courtship of Miles Standish and Priscilla Mullins and then the Marriage of Priscilla Mullins to John Alden', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1575203', '3.52', '233', '20', 'https://www.goodreads.com/book/show/1575203.The_Courtship_of_Miles_Standish');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Jacklight', '', 'Intimate, honest and generous meditations on the delicate balance of mothering a baby and maintaining an artistic life, from the celebrated novelist and poet."Observant, tender and honest." "--New York Times Book Review"', 'https://images.gr-assets.com/books/1312031036m/879302.jpg', '879302', '3.83', '233', '13', 'https://www.goodreads.com/book/show/879302.Jacklight');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Journals: Early Fifties, Early Sixties', '', 'In the 1950s and early 1960s, Allen Ginsberg and his fellow Beats led an insurrection that profoundly altered the American literary and cultural landscapes. Collected here are journal entries culed from eighteen notebooks that Ginsberg kept during this extraordinary period -- thoughts, poems, dreams, reflections, and diary notes that intimately illuminate Ginsberg''s actual travels and his mental journeys. They reveal a remarkable and fascinating life: conversations with William Carlos Williams; drug experiences; a chance meeting with Dylan Thomas; stays in Mexico, San Francisco, and New York; first impressions of "Naked Lunch"; bits and peices of "America, Kaddish" and other poems; political "ravings"; and, of course, times with William S. Burroughs, Jack Kerouac, Gergory Corso, Herbert Huncke, Peter Orlovsky, and many, many others. What emerges is a truly unique personal account that will touch the mind and the soul.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '226946', '3.86', '232', '11', 'https://www.goodreads.com/book/show/226946.Journals');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Reach for the Sun: Selected Letters 1978-1994, Volume 3', '', 'Literary Criticism. Reach for the Sunis the third volume of Bukowski''s letters from Black Sparrow Press, selected by Seamus Cooney.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '220686', '4.12', '230', '9', 'https://www.goodreads.com/book/show/220686.Reach_for_the_Sun');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Awakening the Heart: Exploring Poetry in Elementary and Middle School', '', 'Fans of the best-selling For the Good of the Earth and Sunwill applaud this sequel by beloved author Georgia Heard - an inspiring and practical handbook that celebrates the natural power of poetry to teach the essential tools of all writing.
Awakening the Heartexplores how to cultivate the poet in every elementary and middle school student - through well-drawn examples, detailed exercises, creative projects, and down-to-earth classroom teachings. Along the way, we learn how to: create environments that encourage children to express their innate sense of wonder; introduce poetry that will engage them; and help children make the transition from reading and talking to writing.
Best of all, Awakening the Heartis filled with luminous poems - by children, famous poets, and Heard herself.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '27041', '4.44', '230', '26', 'https://www.goodreads.com/book/show/27041.Awakening_the_Heart');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Vintage Book of Contemporary World Poetry', '', 'This groundbreaking volume may well be the poetry anthology for the global village. As selected by J.D. McClatchy, this collection includes masterpieces from four continents and more than two dozen languages in translations by such distinguished poets as Elizabeth Bishop, W.S. Merwin, Ted Hughes, and Seamus Heaney. Among the countries and writers represented are:
Bangladesh--Taslima Nasrin
Chile--Pablo Neruda
China--Bei Dao, Shu Ting
El Salvador--Claribel Alegria
France--Yves Bonnefoy
Greece--Odysseus Elytis, Yannis Ritsos
India--A.K. Ramanujan
Israel--Yehuda Amichai
Japan--Shuntaro Tanikawa
Mexico--Octavio Paz
Nicaragua--Ernesto Cardenal
Nigeria--Wole Soyinka
Norway--Tomas Transtromer
Palestine--Mahmoud Darwish
Poland--Zbigniew Herbert, Czeslaw Milosz
Russia--Joseph Brodsky, Yevgeny Yevtushenko
Senegal--Leopold Sedar Senghor
South Africa--Breyten Breytenbach
St. Lucia, West Indies--Derek Walcott', 'https://images.gr-assets.com/books/1403173063m/584302.jpg', '584302', '4.23', '229', '25', 'https://www.goodreads.com/book/show/584302.The_Vintage_Book_of_Contemporary_World_Poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Collected Poems of Oscar Wilde', '', 'Wilde, glamorous and notorious, more famous as a playwright or prisoner than as a poet, invites readers of his verse to meet an unknown and intimate figure. The poetry of his formative years includes the haunting elegy to his young sister and the grieving lyric at the death of his father. The religious drama of his romance with Rome is captured here, as well as its resolution in his renewed love of ancient Greece. He explores forbidden sexual desires, pays homage to the great theatre stars and poets of his day, observes cityscapes with impressionist intensity. His final masterpiece, The Ballad of Reading Gaol, tells the painful story of his own prison experience and calls for universal compassion. This edition of Wilde''s verse presents the full range of his achievement as a poet.', 'https://images.gr-assets.com/books/1414351792m/157608.jpg', '157608', '3.85', '228', '20', 'https://www.goodreads.com/book/show/157608.The_Collected_Poems_of_Oscar_Wilde');
