INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Polkabats and Octopus Slacks: 14 Stories', '', 'Georgie Spider catches flies but never eats the little guys. Instead he cooks them up in pies. He doesn''t use the legs or eyes or any artificial dyes . . . Not far from a greenish town, the Bathtub Driver is selling cut-rate imported shampoo. Georgie Spider serves up award-winning pies, while overhead on Highwire 66 there''s a small problem causing an acrobat traffic jam. Ed''s funny smell, Eliza''s special jacket - they''re all part of the picture in Polkabats and Octopus Slacks, fourteen stories about pesky snails, sleeping fruit, and one funky snowman. In the tradition of Edward Lear, Calef Brown has fashioned fourteen nonsense poems so zany that both young and old will be unable to suppress their laughter. Brown''s invented words and sounds and their visual counterparts create both an audible and a visual feast. This is the kind of silliness children relish.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '341717', '4.56', '226', '49', 'https://www.goodreads.com/book/show/341717.Polkabats_and_Octopus_Slacks');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Divine Comedy [Illustrated]', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6223326', '4.06', '226', '4', 'https://www.goodreads.com/book/show/6223326-the-divine-comedy-illustrated');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Yellow Heart', '', 'In the introduction to this bilingual volume, the translator reminds us: "Neruda spent the last forty years of his life making himself dangerous with his poetry... He came to see poetry as a moral act, with personal and communal responsibilities." But here, Neruda is at his playful and irreverent best. Whether writing a celebration, allegory, lament or self-parody, the poet declares the strong sense of an improvisational spirit. Highlighted as "Essential" by Library Journal.', 'https://images.gr-assets.com/books/1328757994m/99403.jpg', '99403', '4.06', '225', '17', 'https://www.goodreads.com/book/show/99403.The_Yellow_Heart');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Porphyria''s Lover', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '21219304', '3.96', '223', '17', 'https://www.goodreads.com/book/show/21219304-porphyria-s-lover');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Transbluesency: Selected Poems, 1961-1995', '', 'Finally in print in a single volume, a selection from Baraka''s mostly out-of-print collections of poetry, from 1961 to the present. Starting with Preface to a Twenty Volume Suicide Noteand concluding with recent limited-edition chapbooks and broadsides, this selection traces the more than thirty year career of a major writer who - along with Ezra Pound - may be one of the most significant, and least understood, American poets of our century.
Edited by noted poet and translator Paul Vengelisti, Transbluesencyoffers an ample selection of works from every period of Baraka''s extraordinarily innovative, often controversial struggle as a serious and ideologically committed American artist - from Beat to Black Nationist to Maxist-Leninist. This volume reveals a writer shaping a body of poetry that is well a body of knowledge; a passionate reflection upon the cultural, political, and aesthetic questions of his time.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '79521', '4.18', '222', '9', 'https://www.goodreads.com/book/show/79521.Transbluesency');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Waste Land and Other Poems', '', 'This volume includes the title poem as well as "The Love Song of J. Alfred Prufrock," "Gerontion," "Ash Wednesday," "Sweeney Among the Nightingales," and other poems from Eliot''s early and middle work. "Eliot has left upon English poetry a mark more unmistakable than that of any other poet writing in English" (Edmund Wilson).', 'https://images.gr-assets.com/books/1286742260m/7328221.jpg', '7328221', '4.23', '222', '7', 'https://www.goodreads.com/book/show/7328221-the-waste-land-and-other-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Rincón de haikus', '', '', 'https://images.gr-assets.com/books/1328885940m/4525853.jpg', '4525853', '3.68', '220', '23', 'https://www.goodreads.com/book/show/4525853-rinc-n-de-haikus');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('الأجنحة المتكسرة', '', '''wl qS@ Hb ljbrn khlyl jbrn', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6673292', '3.93', '220', '23', 'https://www.goodreads.com/book/show/6673292');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Doré''s Illustrations for "Paradise Lost"', '', 'Gustave Dore''s Romantic style of illustration, supremely imaginative and richly detailed, was ideally suited to literary subjects. His wood-engraved illustrations for John Milton''s monumental epic poem Paradise Lost,recounting mankind''s fall from the grace of God through the work of Satan, were among his finest and most dramatic works. This volume presents superb reproductions of all 50 plates drawn by Dore and engraved in his studios for the original edition of Paradise Lost.
Artists and art lovers will find in these pages supreme examples of the illustrator''s art. Among the events depicted: the expulsion of Satan from heaven, Adam and Eve in Paradise, the nine-day fall of Lucifer''s legions to Hell, the Creation, the temptation of Eve, the Flood, Moses holding up the Ten Commandments, and the fearsome creatures Milton referred to as "Gorgons, and Hydras, and Chimeras dire."
The dreamlike, otherworldly quality Dore often brought to his work seems especially appropriate for Paradise Lostwith its lofty spirit and epic events. Indeed, Dore''s grand conception seems to realize perfectly Milton''s own poetic version. Appropriate quotes from the text of Paradise Lostare printed alongside each illustration. A plot summary of the entire poem is also included.', 'https://images.gr-assets.com/books/1380034332m/141600.jpg', '141600', '4.58', '220', '10', 'https://www.goodreads.com/book/show/141600.Dor_s_Illustrations_for_Paradise_Lost_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Blues', '', 'Nove vydani vsech basni legendarniho ceskeho beatnika Vaclava Hrabete (1940-1965). Vychazi v nove graficke uprave s fotografiemi Pavla Banky, ktery v roce 1964 spolecne s V. Hrabetem, I. Zemankovou a V. Cerepkovou vystupoval v text-apellove skupine v prazske Viole.', 'https://images.gr-assets.com/books/1482870412m/4261458.jpg', '4261458', '4.7', '220', '13', 'https://www.goodreads.com/book/show/4261458-blues');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('this emotion was a little e-book', '', 'A chapbook of poetry.
friday night alone in the library reading nietzsche / i''m going to touch you very hard / i''m tired / i have high self-esteem and it''s making me stare / i''ll write another poem instead of looking for a job / terrible asshole / i am fucked if i really think all human beings are terrible assholes / a young hamster / a poem written by a bear', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '9670742', '3.76', '219', '23', 'https://www.goodreads.com/book/show/9670742-this-emotion-was-a-little-e-book');
