INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Remember, Body...', '', '''All those excessive, useless regrets...''
A collection of nostalgic, erotic poetry from one of the greatest Greek poets to have ever lived.
Introducing Little Black Classics: 80 books for Penguin''s 80th birthday. Little Black Classics celebrate the huge range and diversity of Penguin Classics, with books from around the world and across many centuries. They take us from a balloon ride over Victorian London to a garden of blossom in Japan, from Tierra del Fuego to 16th-century California and the Russian steppe. Here are stories lyrical and savage; poems epic and intimate; essays satirical and inspirational; and ideas that have shaped the lives of millions.
C.P. Cavafy (1863-1933).
The Selected Poems of Cavafy is available in Penguin Classics.', 'https://images.gr-assets.com/books/1423750304m/24874309.jpg', '24874309', '3.6', '219', '34', 'https://www.goodreads.com/book/show/24874309-remember-body');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Best of Robert Service', '', 'This new and revised edition of poems about the men and women of the North features the most loved ballads by Robert Service, and is illustrated with lively art by Marilen Van Nimwegen. While living in Whitehorse, Robert Service wrote The Cremation of Sam McGee, and other well-known poems. He wrote and published into his mid-eighties. He was quoted as saying, I just go for a walk and come back with a poem in my pocket.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '113209', '4.29', '218', '22', 'https://www.goodreads.com/book/show/113209.The_Best_of_Robert_Service');
