INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poems of Marianne Moore', '', 'More than thirty years after her death, Marianne Moore continues to be one of America''s most beloved poets. However, her Collected Poems(1951) omits twenty years of later beauties. And her inaccurately titled Complete Poems(1967) is likewise incomplete, leaving out nearly half of her body of verse and giving readers only a partial view of her work.
This complete collection of Moore''s poetry, lovingly edited by the prizewinning poet Grace Schulman, for the first time contains allof Moore''s poems, including 120 previously uncollected and unpublished ones. Organized chronologically to allow readers to follow Moore''s development as a poet, the volume includes an introduction, all of Moore''s original notes to the poems, along with Schulman''s notes, attributions, and some variants. This long-needed volume will reveal to Moore''s admirers the scope of her poetic voice and will introduce new generations of readers to her great achievement. The Poems of Marianne Mooreis a must have both for Moore devotees and any reader seeking an introduction to the work of one of America''s greatest poets.', 'https://images.gr-assets.com/books/1309202222m/1063434.jpg', '1063434', '4.06', '209', '16', 'https://www.goodreads.com/book/show/1063434.The_Poems_of_Marianne_Moore');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Gulf Music: Poems', '', 'Dollars, dolors. Callings and contrivances. King Zulu. Comus.
Sephardic ju-ju and verses. Voodoo mojo, Special Forces.
Henry formed a group named Professor Longhair and his
Shuffling Hungarians. After so much renunciation
And invention, is this the image of the promised end?
All music haunted by all the music of the dead forever.
Becky haunted forever by Pearl the daughter she abandoned
For love, O try my tra-la-la, ma la belle, mah walla-woe.
--from "Gulf Music"
An improvised, even desperate music, yearning toward knowledge across a gulf, informs Robert Pinsky''s first book of poetry since Jersey Rain (2000).
On the large scale of war or the personal scale of family history, in the movements of people and cultures across oceans or between eras, these poems discover connections between things seemingly disparate.
Gulf Music is perhaps the most ambitious, politically impassioned, and inventive book by this major American poet.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '897487', '3.69', '209', '34', 'https://www.goodreads.com/book/show/897487.Gulf_Music');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Isla Negra: A Notebook', '', 'In the over one hundred poems contained in Isla Negra, Pablo Neruda fashioned a kind of poetic autobiography in which he set out to explore and gather the various "lives" or "selves" he had left behind him in the huge span of his writing existence. Written in his "autumnal" period, from the vantage point of Isla Negra, the small village on the Pacific coast of Chile which he came to regard as the center of his world, the book reads like a series of notes in which present and past interact, and is perhaps the most self-confronting of all his collections.', 'https://images.gr-assets.com/books/1311976838m/538121.jpg', '538121', '4.19', '209', '10', 'https://www.goodreads.com/book/show/538121.Isla_Negra');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('My Private Property', '', 'Author of Madness, Rack, and Honey("One of the wisest books I''ve read in years," according to the New York Times) and Trances of the Blast, Mary Ruefle continues to be one of the most dazzling poets in America. My Private Property, comprised of short prose pieces, is a brilliant and charming display of her humor, deep imagination, mindfulness, and play in a finely crafted edition.
Personalia
When I was young, a fortune-teller told me that an old woman who wanted to die had accidentally become lodged in my body. Slowly, over time, and taking great care in following esoteric instructions, including lavender baths and the ritual burial of keys in the backyard, I rid myself of her presence. Now I am an old woman who wants to die and lodged inside me is a young woman dying to live; I work on her.
Mary Ruefleis the author of Trances of the Blast; Madness, Rack, and Honey: Collected Lectures, a finalist for the 2013 National Book Critics Circle Award in criticism; and Selected Poems, winner of the William Carlos Williams Award. She has published ten other books of poetry, a book of prose (The Most of It), and a comic book, Go Home and Go to Bed!; she is also an erasure artist whose treatments of nineteenth-century texts have been exhibited in museums and galleries as well as published in the book A Little White Shadow. Ruefle is the recipient of numerous honors, including an Award in Literature from the American Academy of Arts and Letters, a Guggenheim fellowship, a National Endowment for the Arts fellowship, and a Whiting Award. She lives in Bennington, Vermont and teaches in the MFA program at Vermont College.', 'https://images.gr-assets.com/books/1461817827m/29363291.jpg', '29363291', '4.43', '208', '38', 'https://www.goodreads.com/book/show/29363291-my-private-property');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Cat Talk', '', 'From cuddler to troublemaker, kitten to tom, cats have a lot to say. Authors Patricia MacLachlan and Emily MacLachlan Charest and illustrator Barry Moser give voice to and celebrate our most opinionated furry friends in this spirited collection of poems filled with rich language, perfect for reading aloud. Cat Talkis sure to make readers wonder what their own four-legged friends have to say.
Supports the Common Core State Standards', 'https://images.gr-assets.com/books/1355928340m/15818015.jpg', '15818015', '4.01', '206', '66', 'https://www.goodreads.com/book/show/15818015-cat-talk');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poem-Mobiles: Crazy Car Poems', '', 'The U.S. Children''s Poet Laureate and an award-winning children''s poet join their prolific forces in this picture book of poems about cars. But they''re not just anycars: there''s the "Sloppy-Floppy-Nonstop-Jalopy" ("So unique there is no copy"); the Bathtub Limosine ("With hot water heating / And porcelain seating"); and the "High Heel Car." Each of the thirteen quirky, inventive poems will speak directly to the imaginations of children, as will Holmes''s high-concept, detail-filled illustrations.', 'https://images.gr-assets.com/books/1372682441m/14823534.jpg', '14823534', '3.95', '206', '70', 'https://www.goodreads.com/book/show/14823534-poem-mobiles');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Bill Martin Jr Big Book of Poetry', '', 'The definitive anthology of children''s poetry, collected by a beloved authorYears in the making, this full-color treasury contains nearly two hundred poems, all of them handpicked by Bill Martin Jr. Traditional children''s poems are presented alongside contemporary pieces, and the collection is capped off with tributes by Eric Carle and Steven Kellogg, two of Bill Martin Jr''s best-known collaborators. This essential compilation also features original illustrations by award-winning artists, including Ashley Bryan, Lois Ehlert, Steven Kellogg, Chris Raschka, Dan Yaccarino, Nancy Tafuri, and Derek Anderson. This beautiful anthology is sure to become a classic.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '3128710', '4.24', '204', '62', 'https://www.goodreads.com/book/show/3128710-the-bill-martin-jr-big-book-of-poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('World''s Tallest Disaster: Poems', '', 'Cate Marvin uses language the way a gymnast uses her body; she is a formalist who has thoroughly learned the pleasures and gains of abandon. But it is her excursions into wild image and passionate song that win the reader''s heart. The heart is central in World''s Tallest Disaster, which is essentially a book of love poems--love lost and found, love requited, love abandoned and betrayed. What Cate Marvin has done in her remarkably assured and powerful first collection is to remind us in fresh terms of the news that stays news: that our desire is "Not a sea of longing,// but the brack of wanting what''s physical/ to help us forget we are physical."
"Violently passionate and firmly symmetrical, like tango or the blues, these poems-at first-are about sexual passion. . . . But in the great tradition of love poetry, these poems don''t stop with love. They move from eros to imagination. Or they thrash between the two. . . . This is an encouraging book in the context of American poetry''s fashions or factions, because it evades categories. [Marvin''s] is an urgent as well as an artful voice."--from the Foreword by Robert Pinsky
Marketing Planso Author tour in Ohio, Kentucky, and NYC
o Brochure and postcard mailings
o Advertisements in key literary and trade magazines
Book tour dates including:
o Cincinnati
o Louisville
o New York City
Cate Marvinwas born in Washington, D.C. She received her B.A. from Marlboro College in Vermont, and holds two M.F.A.s: one from the University of Houston in poetry, the other from the Iowa Writers'' Workshop in fiction. She has been awarded scholarships to attend both Bread Loaf and Sewanee Writers'' Conferences. Her poems have appeared in such magazines as New England Review, The Antioch Review, The Paris Review, The Georgia Review,and Ploughshares,among others. She is lives in Cincinnati, Ohio, and is currently a Ph.D. candidate in English at the university there.', 'https://images.gr-assets.com/books/1354902670m/868590.jpg', '868590', '3.99', '200', '16', 'https://www.goodreads.com/book/show/868590.World_s_Tallest_Disaster');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ivy in Bloom: The Poetry of Spring from Great Poets and Writers from the Past', '', 'Ivy in Bloomcaptures the weariness of a young girl tired of a long winter. "I stare out the window," she says on the first spread of brown and gray, "looking for birds or flowers / or even warm showers / but I don''t see any such thing." But then Spring comes when "March is out of breath snow melting to flowery waters and watery flowers spring rose from its wintry rest." And Ivy''s "heart dances with daffodils." As these words also dance across each spread, Ivy''s world erupts into a riot of color.
Ivy in Bloomintroduces the poetry of Dickinson, Longfellow, Browning, Wordsworth, Frost and others. Excerpts from their writings, as seen through Ivy''s eyes, will open up poetry as a way for children to express their own feelings about the changing of seasons. This book includes longer excerpts and brief bios of each author.', 'https://images.gr-assets.com/books/1341202405m/6270527.jpg', '6270527', '3.72', '199', '151', 'https://www.goodreads.com/book/show/6270527-ivy-in-bloom');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Spring Essence: The Poetry of Hô Xuân Huong', '', 'Ho Xuan Huong -- whose name translates as "Spring Essence" -- is one of the most important and popular poets in Vietnam. A concubine, she became renowned for her poetic skills, writing subtly risque poems which used double entendre and sexual innuendo as a vehicle for social, religious, and political commentary.
"The Unwed Mother"
Because I was too easy, this happened.
Can you guess the hollow in my heart?
Fate did not push out a bud
even though the willow grew.
He will carry this a hundred years
but I must bear the burden now.
Never mind the gossip of the world.
Don''t have it, yet have it! So simple.
The publication of Spring Essenceis a major historical and cultural event. It features a "tri-graphic" presentation of English translations alongside both the modern Vietnamese alphabet and the nearly extinct calligraphic Nomwriting system, the hand-drawn calligraphy in which Ho Xuan Huong originally wrote her poems. It represents the first time that this calligraphy--the carrier of Vietnamese culture for over a thousand years--will be printed using moveable type. From the technology demonstrated in this book scholars worldwide can begin to recover an important part of Vietnam''s literary history. Meanwhile, readers of all interests will be fascinated by the poetry of Ho Xuan Huong, and the scholarship of John Balaban.
The translator, John Balaban, was twice a National Book Award finalist for his own poetry and is one of the preeminent American authorities on Vietnamese literature. During the war Balaban served as a conscientious objector, working to bring war-injured children better medical care. He later returned to Vietnam to record folk poetry. Like Alan Lomax''s pioneering work in American music, Balaban was to first to record Vietnam''s oral tradition. This important work led him to the poetry of Ho Xuan Huong.
Ngo Than Nhan, a computational linguist from NYU''s Courant Institute of Mathematics, has digitized the ancient Nomcalligraphy.', 'https://images.gr-assets.com/books/1328757973m/807765.jpg', '807765', '4.15', '199', '29', 'https://www.goodreads.com/book/show/807765.Spring_Essence');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Year of No Mistakes: A Collection of Poetry', '', 'Intimate, observant, and unflinchingly honest, The Year of No Mistakes is Cristin O''Keefe Aptowicz''s tribute to the broken heart. Aptowicz''s sixth poetry collection chronicles the author''s story as she leaves New York City, her home of fourteen years, and bears witness to the unravelling of Aptowicz''s decade-long relationship. Along the way, Aptowicz explores love, nostalgia, grief, desire, envy and hope in poems that showcase her emblematic funny and heartbreaking style. Stripped down, open, and intimate, this collection continues Aptowicz''s tradition of engaging and auto-biographical work with new favorites like "Op-Ed for the Sad Sack Review," "Not Doing Something Wrong isn''t the Same as Doing Something Right," and "December." For a poet already known for her honesty, The Year of No Mistakes shines with brave vulnerability. It is a triumph that will push even the most stubbornly busted heart back into the light.', 'https://images.gr-assets.com/books/1377635903m/17660097.jpg', '17660097', '4.32', '197', '37', 'https://www.goodreads.com/book/show/17660097-the-year-of-no-mistakes');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('It Is Daylight', '', 'Arda Collins is the 2008 winner of the annual Yale Series of Younger Poets competition. Mesmerizing and electric, her poems seem to be articulated in the privacy of an enclosed space. The poems are concrete and yet metaphysically challenging, both witty and despairing. Collins'' emotional complexity and uncommon range make this debut both thrillingly imaginative and ethical in its uncompromising attention to detail. In her Foreword, contest judge Louise Gluck observes, "I know no poet whose sense of fraud, the inflated emptiness that substitutes for feeling, is more acute." Gluck calls Collins'' volume "savage, desolate, brutally ironic . . . a book of astonishing originality and intensity, unprecedented, unrepeatable."', 'https://images.gr-assets.com/books/1328826809m/5294568.jpg', '5294568', '4.04', '195', '24', 'https://www.goodreads.com/book/show/5294568-it-is-daylight');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Tent', '', 'One of the world''s most celebrated authors, Margaret Atwood has penned a collection of smart and entertaining fictional essays, in the genre of her popular books Good Bonesand Murder in the Dark, punctuated with wonderful illustrations by the author. Chilling and witty, prescient and personal, delectable and tart, these highly imaginative, vintage Atwoodian mini-fictions speak on a broad range of subjects, reflecting the times we live in with deadly accuracy and knife-edge precision.
In pieces ranging in length from a mere paragraph to several pages, Atwood gives a sly pep talk to the ambitious young; writes about the disconcerting experience of looking at old photos of ourselves; gives us Horatio''s real views on Hamlet; and examines the boons and banes of orphanhood. Bring Back Mom: An Invocation; explores what life was really like for the "perfect" homemakers of days gone by, and in The Animals Reject Their Namesshe runs history backward, with surprising results.
Chilling and witty, prescient and personal, delectable and tart, The Tentis vintage Atwood, enhanced by the author''s delightful drawings.', 'https://images.gr-assets.com/books/1320433006m/175869.jpg', '175869', '3.7', '195', '22', 'https://www.goodreads.com/book/show/175869.The_Tent');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Chorus', '', 'An anthology of poetry by young people, edited by superstar poet and author of The Dead Emcee Scrolls and ,said the shotgun to the head, Saul Williams. 
CHORUS is the anthem of a new generation of poets unified by the desire to transcend the identity politics of the day and begin to be seen as one. One hundred voices woven through testimony and new testament. It is the cry of the unheard. The occupation of the page itself. It embodies the "speak-up" spirit of the moment, the confidence propagated through hip-hop, and the defiant "WTF?" of the now. It is the voice that comes after the rebellious voice that once cried, "I want my MTV!" branded back to where punk was, slammed up and beyond it. A combination of trash, heart, and craft. An anthology in rant.
CHORUS is what all modern-day losers chant.', 'https://images.gr-assets.com/books/1344664857m/13259644.jpg', '13259644', '4.08', '195', '22', 'https://www.goodreads.com/book/show/13259644-chorus');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Otto the Owl Who Loved Poetry', '', 'An owl with an unusual passion learns to shine in this fresh, funny debut picture book introducing a poetry-loving owl whom kids will cheer for.
Otto loves poetry--Keats, Rossetti, Dickinson, even T. S. Eliot. He prefers reading to roosting and reciting to hunting. Ordinarily, this wouldn''t be a problem. But, you see, Otto is an owl. When the other owls begin to make fun of Otto, he embarks on a difficult journey, finding along the way both his inner poet and a community that accepts him for who he is. Celebrating courage and the importance of sticking with your passion, and incorporating an engaging mix of original and famous poems, Vern Kousky has created an enchanting and inviting world--a forest filled with the sounds of poetry.', 'https://images.gr-assets.com/books/1403179978m/22521931.jpg', '22521931', '3.67', '191', '46', 'https://www.goodreads.com/book/show/22521931-otto-the-owl-who-loved-poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Teeth', '', 'Stunning, highly original poems that celebrate the richness of the author''s multicultural tradition, Teethexplores loves, wars, wild hope, defiance, and the spirit of creativity in a daring use of language and syntax. Behind this language one senses a powerful, inventive woman who is not afraid to tackle any subject, including rape, genocide, and love, always sustained by an optimistic voice, assuring us that in the end justice will triumph and love will persevere.
LOVE,
you be the reason why
we swagger & jive,
lift the guitar, & pick up the axe.
when it is i tilt my hat to the side,
wearing colors & perfumes, it''s cause, love,
you did it to me. oh,
you do sure turn my tongue to fiddle,
& make the salt taste sweet. man,
i don''t need a rooster, or peacock even,
to help me spend my time, nope,
just you, love, right & solid as
a line.', 'https://images.gr-assets.com/books/1418364008m/508702.jpg', '508702', '4.27', '189', '23', 'https://www.goodreads.com/book/show/508702.Teeth');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Poems', '', 'Taut, densely lyrical, and everywhere informed by a powerful and subtle music, this collection begins with the compact fragments of Spokes and Unearth (both written when Auster was in his early twenties), continues on through the more ample meditations of "Wall Writing," "Disappearances," "Effigies," "Fragments From the Cold," "Facing the Music" and "White Spaces," then moves further back in time to include Auster''s revealing translations of many of the French poets who influenced his own writing--including Paul Eluard, Andre Breton, Tristan Tzara, Philippe Soupault, Robert Desnos, and Rene Char--as well as the provocative and previously unpublished "Notes From a Composition Book" (1967). An introduction by Normal Finkelstein connects the biographical elements to a consideration of the work and takes in Auster''s early literary and philosophical influences. Penetrating, lyric, and tempered with the same brooding intelligence that informs The New York Trilogy, these poems offer a unique window into postmodern consciousness.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '382075', '3.58', '187', '12', 'https://www.goodreads.com/book/show/382075.Collected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('We Slept Here', '', 'We Slept Here is a case study in vulnerability and honesty. In this sequence of memoir-esque poems, Sierra DeMulder pulls at the threads of a past abusive relationship and the long road to forgiveness. The poems themselves become an act of recovery and reclamation, wherein the poet finds again the voice which was taken from her. These are hard poems, made up of clarity and healing, which attempt to share some of their peace with the world.', 'https://images.gr-assets.com/books/1436460340m/25864029.jpg', '25864029', '4.57', '187', '18', 'https://www.goodreads.com/book/show/25864029-we-slept-here');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('What Is Amazing', '', 'Inspired by a voracious curiosity about humans and other subjects, the poems in Heather Christle''s What Is Amazing describe and invent worlds in an attempt to understand through participation. The book draws upon the wisdom of foolishness and the logic of glee, while simultaneously exploring the suffering inherent to embodied consciousness. Speakers play out moments of bravado and fear, love and mortality, disappointment and desire. They socialize incorrigibly with lakes, lovers, fire, and readers, reasoning their way to unreasonable conclusions. These poems try to understand how it is that we come to recognize and differentiate objects and beings, how wholly each is attached to its name, and which space reveals them. What Is Amazing delights in fully inhabiting its varied forms and voices, singing worlds that often coincide with our own.', 'https://images.gr-assets.com/books/1326594062m/13413481.jpg', '13413481', '4.25', '186', '21', 'https://www.goodreads.com/book/show/13413481-what-is-amazing');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poetry for Cats: The Definitive Anthology of Distinguished Feline Verse', '', 'In the vein of his bestselling French for Cats, Henry Beard has assembled a brilliant anthology of treasured works by feline poets. Includes " Do Not Go Gentle to That Damned Vet" by Dylan Thomas''s cat, " The Human" by Edgar Allan Poe''s cat and other works. Poetry for Cats will prove as thrilling as a stiff shot of catnip. Color illustrations.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '884306', '4.16', '184', '38', 'https://www.goodreads.com/book/show/884306.Poetry_for_Cats');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('مقام عراق', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6413056', '4.17', '183', '27', 'https://www.goodreads.com/book/show/6413056');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Árbol de Diana', '', 'Prologado por Octavio Paz, esta obra supuso el reconocimiento definitivo de la autora por parte de la critica. Los poemas son mayoritariamente cortos, todos en verso libre, plagados de contradicciones y sugerencias a veces increibles por su lucidez. La soledad de la conciencia, del ser humano, se afronta sin contemplaciones y sin renuncias. La gente habla para no verse, evita cuestionarse a si misma para no caer en la desolacion. El lenguaje puede ser una trampa, hay que conocerlo bien para lograr intuir una via de comunicacion entre nosotros. Y a eso se dedica Alejandra, a desenmascarar las palabras y darles un sentido verdadero para ella, una traduccion exacta de lo que piensa y de lo que siente.', 'https://images.gr-assets.com/books/1343735887m/15779049.jpg', '15779049', '4.35', '183', '14', 'https://www.goodreads.com/book/show/15779049-rbol-de-diana');
