INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Honey Month', '', 'A fascinating experiment in literary synesthesia in which the scents, tastes and textures of assorted honeys are transmuted into a wordsmith''s cycle of fey mischief. These bewitching poems and stories unwind a fevered world of magic and longing and young women who chance the uncanny and gain wisdom beyond their years.', 'https://images.gr-assets.com/books/1288188978m/8789052.jpg', '8789052', '4.12', '182', '34', 'https://www.goodreads.com/book/show/8789052-the-honey-month');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ciento volando de catorce', '', '"El mundo de Joaquin es real y matizado porque surge de la melancolia para desembocar en los impulsos ironicos. El vitalismo de sus consignas procura darle la vuelta a los relojes y a las palabras. Cuando camina, lo mismo que cuando baila, no hace otra cosa que sonar con los pies, perseguir en los horizontes de la lentitud un argumento seductor para la defender la prisa. Y Joaquin resulta convincente porque su mundo personal es fruto de una experiencia colectiva, recuerdo de unos anos en los que habia que correr para escapar de la mediocridad, la sopa triste, la moral de las mesas de camilla y los argumentos asumidos a golpe secreto de renuncias personales." LUIS GARCIA MONTERO', 'https://images.gr-assets.com/books/1291651554m/63251.jpg', '63251', '3.46', '182', '15', 'https://www.goodreads.com/book/show/63251.Ciento_volando_de_catorce');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('XAIPE', '', 'Among many poems can be found "dying is fine)but Death," "so many selves(so many friends and gods," "when serpents bargain for the right to squirm," "no time ago," "I thank You God for most this amazing," and "now all the fingers of this tree(darling)have."', 'https://images.gr-assets.com/books/1372038222m/626676.jpg', '626676', '4.17', '178', '15', 'https://www.goodreads.com/book/show/626676.XAIPE');
