INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Евгений Онегин. Драмы', '', 'V knigu voshli roman v stikhakh `Evgenii Onegin`, dramy `Boris Godunov`, `Skupoi rytsar''`, `Motsart i Sal''eri` i dr.', 'https://images.gr-assets.com/books/1329914926m/2928309.jpg', '2928309', '4.09', '176', '4', 'https://www.goodreads.com/book/show/2928309');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Bhagavad Gita', '', 'The Bhagavad Gita, OC The Song of the Lord, OCO is probably the best known of all the Indian scriptures, and EaswaranOCOs clear, accessible translation is the best-selling edition. The Gita opens dramatically, with prince Arjuna collapsing in anguish on the brink of a war that he doesnOCOt want to fight. Arjuna has lost his way on the battlefield of life, and turns to his spiritual guide, Sri Krishna, the Lord himself. Krishna replies in 700 verses of sublime instruction on living and dying, loving and working, and the nature of the soul.
This book includes an extensive and very readable introduction, which places the Gita in its historical setting, explains the key concepts, and brings out the universality of its teachings. Individual chapter introductions prepare the reader for the main themes, and notes, a Sanskrit glossary, and an index are included.
Although the battlefield is a perfect backdrop, for Easwaran the GitaOCOs subject is the war within, the struggle for self-mastery that every human being must wage. ArjunaOCOs dilemma is acutely modern, and the GitaOCOs message remains as relevant for us now as it was for ancient India.
"', 'https://images.gr-assets.com/books/1328759098m/8805803.jpg', '8805803', '4.1', '176', '19', 'https://www.goodreads.com/book/show/8805803-bhagavad-gita');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('حسنی ما یه بره داشت', '', '', 'https://images.gr-assets.com/books/1375095633m/16705267.jpg', '16705267', '4.35', '176', '11', 'https://www.goodreads.com/book/show/16705267');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Dear Boy', '', 'Dear Boyis the dramatic and inventive debut by Emily Berry. These characterful, intelligent and darkly witty poems explore lives lived strangely in unusual worlds, through a series of deft and seductive soliloquies.
In a collection with a taste for ventriloquy and wickedness, and a flair for vocal cross-dressing, the balance of power is always shifting in an unexpected direction - an ingenue masquerades as a femme fatale, a doctor appears more disturbed than his patient, and parents seem more unruly than their children. Eccentric, intimate, arch, anxious, decadent and sometimes mournful, the book''s confiding, conversational voices tell stories recognisable and refracted, carried along by the undercurrent on which the collection ebbs and rides: the anguish and energy brought about by a long-distance love affair, which propels and terrorises and ultimately unites the work.
Dear Boyis an irresistible and enlivening collection by a new poet of startling and various gifts.', 'https://images.gr-assets.com/books/1357755748m/17229678.jpg', '17229678', '3.85', '174', '23', 'https://www.goodreads.com/book/show/17229678-dear-boy');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Penguin''s Poems for Life', '', 'Taking its inspiration from Shakespeare''s idea of the seven ages of a human life, this new anthology brings together the best-loved poems in English to inspire, comfort and delight readers for a lifetime. Beginning with babies, the book is divided into sections on childhood, growing up, making a living and making love, family life, getting older, and approaching death, ending with poems of mourning and commemoration.
Ranging from Chaucer to Carol Ann Duffy, via Shakespeare, Keats, and Lemn Sissay, this book offers something for each of those moments in life, whether falling in love, finding your first grey hair or saying your final goodbyes, when only a poem will do.', 'https://images.gr-assets.com/books/1503395230m/2442582.jpg', '2442582', '4.03', '174', '12', 'https://www.goodreads.com/book/show/2442582.Penguin_s_Poems_for_Life');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Norton Anthology of English Literature Vol. 2', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '310884', '4.22', '174', '9', 'https://www.goodreads.com/book/show/310884.The_Norton_Anthology_of_English_Literature_Vol_2');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Complete Poems and Selected Letters', '', 'No American poet has so swiftly and decisively transformed the course of poetry as Hart Crane. In his haunted, brief life, Crane fashioned a distinctively modern idiom that fused the ornate rhetoric of the Elizabethans, the ecstatic enigmas of Rimbaud, and the prophetic utterances and cosmic sympathy of Whitman, in a quest for wholeness and healing in what he called "the broken world." White Buildings, perhaps the greatest debut volume in American poetry since Leaves of Grass, is but an exquisite prelude to Crane''s masterpiece The Bridge, his magnificent evocation of America from Columbus to the Jazz Age that countered the pessimism of Eliot''s The Waste Landand became a crucial influence on poets whose impact continues to this day. This edition is the largest collection of Crane''s writings ever published. Gathered here are the complete poems and published prose, along with a generous selection of Crane''s letters, several of which have never before been published. In his letters Crane elucidates his aims as an artist and provides fascinating glosses on his poetry. His voluminous correspondence also offers an intriguing glimpse into his complicated personality, as well as his tempestuous relationships with family, lovers, and writers such as Allen Tate, Waldo Frank, Yvor Winters, Jean Toomer, Marianne Moore, E. E. Cummings, William Carlos Williams, and Katherine Anne Porter. Several letters included here are published for the first time. 
This landmark 850-page volume features a detailed and freshly-researched chronology of Crane''s life by editor Langdon Hammer, chair of the English Department at Yale University and a biographer of Crane, as well as extensive explanatory notes, and over fifty biographical sketches of Crane''s correspondents.', 'https://images.gr-assets.com/books/1309200646m/75493.jpg', '75493', '4.31', '173', '11', 'https://www.goodreads.com/book/show/75493.Complete_Poems_and_Selected_Letters');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Lay of the Love and Death of Cornet Christopher Rilke', '', 'A lyric story originally published in 1906.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '128076', '4.09', '173', '11', 'https://www.goodreads.com/book/show/128076.The_Lay_of_the_Love_and_Death_of_Cornet_Christopher_Rilke');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Siste Viator', '', '-This book is for those of us who want to read more poetry but are frequently stopped by its--what is it? Its chilly self-seriousness? Its unwillingness to hold our hand every so often, while cracking an easy joke? Either way, Sarah Manguso, like her spiritual siblings David Berman and Tony Hoagland, is a friendly kind of savior and guide. Her writing is gorgeous and cerebral (imagine Anne Carson) but she doesn''t skimp on the wit (imagine Anne Carson''s ne''er-do-well niece). Poetry-fearers, don''t back away from this beautiful book; these might be the pages that bring you back into the form.- --Dave Eggers', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '91010', '3.85', '173', '16', 'https://www.goodreads.com/book/show/91010.Siste_Viator');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('IRL', '', 'IRL is a sweaty, summertime poem composed like a long text message, rooted in the epic tradition of A.R. Ammons, ancient Kumeyaay Bird Songs, and Beyonce''s visual albums. It follows Teebs, a reservation-born, queer NDN weirdo, trying to figure out his impulses/desires/history in the midst of Brooklyn rooftops, privacy in the age of the Internet, street harassment, suicide, boys boys boys, literature, colonialism, religion, leaving one''s 20s, and a love/hate relationship with English. He''s plagued by an indecision, unsure of which obsessions, attractions, and impulses are essentially his, and which are the result of Christian conversion, hetero-patriarchal/colonialist white supremacy, homophobia, Bacardi, gummy candy, and not getting laid.
IRL asks, what happens to a modern, queer indigenous person a few generations after his ancestors were alienated from their language, their religion, and their history? Teebs feels compelled towards "boys, burgers,booze," though he begins to suspect there is perhaps a more ancient goddess calling to him behind art, behind music, behind poetry.', 'https://images.gr-assets.com/books/1467926979m/30968235.jpg', '30968235', '4.39', '172', '30', 'https://www.goodreads.com/book/show/30968235-irl');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Box of Rain: Lyrics, 1965-1993', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '7278', '4.52', '171', '11', 'https://www.goodreads.com/book/show/7278.A_Box_of_Rain');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Door Into the Dark: Poems', '', '"Door into the Dark," Heaney''s second collection of poems, first appeared in 1969. Already his widely celebrated gifts of precision, thoughtfulness, and musicality were everywhere apparent.', 'https://images.gr-assets.com/books/1311973119m/19236.jpg', '19236', '4.02', '170', '21', 'https://www.goodreads.com/book/show/19236.Door_Into_the_Dark');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Fortune''s Bones: The Manumission Requiem', '', 'There is a skeleton in the Mattatuck Museum in Connecticut. It has been in the town for over 200 years. In 1996, community members decided to find out what they could about it. Historians discovered that the bones were those of a slave name Fortune, who was owned by a local doctor. After Fortune''s death, the doctor rendered the bones. Further research revealed that Fortune had married, had fathered four children, and had been baptized later in life. His bones suggest that after a life of arduous labor, he died in 1798 at about the age of 60. Merilyn Nelson wrote The Manumission Requiemto commemorate Fortune''s life. Detailed notes and archival photographs enhance the reader''s appreciation of the poem.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '129813', '3.93', '169', '39', 'https://www.goodreads.com/book/show/129813.Fortune_s_Bones');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('O Anjo Mudo', '', '', 'https://images.gr-assets.com/books/1386632639m/7203615.jpg', '7203615', '4.25', '168', '8', 'https://www.goodreads.com/book/show/7203615-o-anjo-mudo');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('ورد أكثر', '', 'mkhtrt sh`ry@ wnthry@', 'https://images.gr-assets.com/books/1344136536m/15787122.jpg', '15787122', '3.73', '168', '20', 'https://www.goodreads.com/book/show/15787122');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Maine Coon''s Haiku: And Other Poems for Cat Lovers', '', 'In evocative haiku, Michael J. Rosen depicts twenty different breeds of cats--whether mischievous or mysterious, comical or commanding.
Some cats have names that suggest far-off lands, like the Turkish Angora and the Norwegian forest cat. Others allude to places closer to home, such as California''s ragdoll and the Maine coon. Set against Lee White''s graceful illustrations, with intriguing facts about each of twenty breeds at the end, this charming haiku collection for lovers of America''s most popular house pet provides the purr-fect book to curl up with.', 'https://images.gr-assets.com/books/1416247638m/22747805.jpg', '22747805', '3.63', '167', '42', 'https://www.goodreads.com/book/show/22747805-the-maine-coon-s-haiku');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Black Maria', '', 'Praise for Aracelis Girmay:
"[Girmay''s] every loss--she calls them estrangements--is a yearning for connection across time and place; her every fragment is a bulwark against ruin." --O, The Oprah Magazine
Taking its name from the moon''s dark plains, misidentified as seas by early astronomers, the black maria investigates African diasporic histories, the consequences of racism within American culture, and the question of human identity. Central to this project is a desire to recognize the lives of Eritrean refugees who have been made invisible by years of immigration crisis, refugee status, exile, and resulting statelessness. The recipient of a 2015 Whiting Award for Poetry, Girmay''s newest collection elegizes and celebrates life, while wrestling with the humanistic notion of seeing beyond: seeing violence, seeing grace, and seeing each other better.
"to the sea"
great storage house, history
on which we rode, we touched
the brief pulse of your fluttering
pages, spelled with salt & life,
your rage, your indifference
your gentleness washing our feet,
all of you going on
whether or not we live,
to you we bring our carnations
yellow & pink, how they float
like bright sentences atop
your memory''s dark hair
Aracelis Girmay is the author of three poetry collections, the black maria; Kingdom Animalia, which won the Isabella Gardner Award and was a finalist for the NBCC Award; and Teeth. The recipient of a 2015 Whiting Award, she has received grants and fellowships from the Jerome, Cave Canem, and Watson foundations, as well as Civitella Ranieri and the NEA. She currently teaches at Hampshire College''s School for Interdisciplinary Arts and in Drew University''s low residency MFA program. Originally from Santa Ana, California, she splits her time between New York and Amherst, Massachusetts.', 'https://images.gr-assets.com/books/1455172379m/26196220.jpg', '26196220', '4.28', '166', '25', 'https://www.goodreads.com/book/show/26196220-the-black-maria');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Book of Nonsense', '', 'This book was converted from its physical edition to the digital format by a community of volunteers. You may find it for free on the web. Purchase of the Kindle edition includes wireless delivery.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6320213', '3.65', '165', '8', 'https://www.goodreads.com/book/show/6320213-a-book-of-nonsense');
