INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Complete Poems', '', 'Blaise Cendrars was a pioneer of modernist literature. The full range of his poetry--from classical rhymed alexandrines to "cubist" modernism, and from feverish, even visionary, depression to airy good humor--offers a challenge no translator has accepted until now.
Here, for the first time in English translation, is the complete poetry of a legendary twentieth-century French writer. Cendrars, born Frederick Louis Sauser in 1887, invented his life as well as his art. His adventures took him to Russia during the revolution of 1905 (where he traveled on the Trans-Siberian Railway), to New York in 1911, to the trenches of World War I (where he lost his right arm), to Brazil in the 1920s, to Hollywood in the 1930s, and back and forth across Europe.
With Guillaume Apollinaire and Max Jacob he was a pioneer of modernist literature, working alongside artist friends such as Chagall, Delaunay, Modigliani, and Leger, composers Eric Satie and Darius Milhaud, and filmmaker Abel Gance. The range of Cendrars''s poetry--from classical rhymed alexandrines to "cubist" modernism, and from feverish, even visionary, depression to airy good humor--offers a challenge no translator has accepted until now.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '356062', '4.23', '163', '10', 'https://www.goodreads.com/book/show/356062.Complete_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Mar - Antologia', '', 'Sao cerca de meia centena de poemas numa antologia singular na obra de um autor, neste caso Sophia de Mello Breyner Andresen (n. 1919), organizada pela sua filha, Maria Andresen de Sousa Tavares, a volta de um tema, o mar, pelo qual a escritora sempre teve um grande fascinio ("De todos os cantos do mundo / Amo com um amor mais forte e mais profundo / Aquela praia extasiada e nua / Onde me uni ao mar, ao vento e a lua").
"Em resumo, estamos perante um livro sem duvida aconselhavel para ler este Verao, talvez numa esplanada sobre o mar - um livro que recupera serenamente um tema quase omnipresente em Sophia e que, para la do "brilho do visivel frente a frente", nos sabe mostrar o esplendor de uma verdade pressentida a superficie das ondas, celebrando o retorno a um tempo magico e primordial - "Onde sou a mim mesma devolvida / (...) / A praia inicial da minha vida" (pag. 47) - e simultaneamente a promessa de um futuro regresso, a cumprir na eternidade: "Quando eu morrer voltarei para buscar /Os instantes que nao vivi junto do mar" (pag. 40)."
Fernando Pinto do Amaral, Publico, suplemento "Mil Folhas"', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6383306', '4.4', '163', '3', 'https://www.goodreads.com/book/show/6383306-mar---antologia');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Physics of Imaginary Objects', '', 'Winner of the 2010 Drue Heinz Literature Prize
The Physics of Imaginary Objects, in fifteen stories and a novella, offers a very different kind of short fiction, blending story with verse to evoke fantasy, allegory, metaphor, love, body, mind, and nearly every sensory perception. Weaving in and out of the space that connects life and death in mysterious ways, these texts use carefully honed language that suggests a newfound spirituality.', 'https://images.gr-assets.com/books/1328807802m/8620591.jpg', '8620591', '4.14', '163', '28', 'https://www.goodreads.com/book/show/8620591-the-physics-of-imaginary-objects');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Singular Pleasures', '', 'The subject of this unique book of short fiction is masturbation, a practice both universal and virtually taboo. In sixty-one vignettes, Mathews records the imaginative varieties of this solitary activity in prose that is playful, intimate, urgent, quirky, and humane.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '560724', '3.81', '162', '17', 'https://www.goodreads.com/book/show/560724.Singular_Pleasures');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Dazzling Display of Dogs', '', 'From the award-winning team behindA Curious Collection of Catscomes a new collection of visual poems celebrating all things canine--from obedience school, to backyard break outs, to flatulent Fidos. Whether your best friend is a plucky Jack Russell, an indecisive basset hound, or a poodle with an indiscriminate appetite, you''re sure to find this dazzling display doggone delightful.', 'https://images.gr-assets.com/books/1373937489m/9796853.jpg', '9796853', '3.87', '162', '55', 'https://www.goodreads.com/book/show/9796853-a-dazzling-display-of-dogs');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('آیدا در آینه', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '193605', '4.18', '158', '4', 'https://www.goodreads.com/book/show/193605._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Farming, a Hand Book', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '227288', '4.27', '158', '14', 'https://www.goodreads.com/book/show/227288.Farming_a_Hand_Book');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Narrow Road to the Interior: Poems', '', 'Kimiko Hahn, "a welcome voice of experimentation and passion" (Bloomsbury Review), takes up the Japanese prose-poetry genre zuihitsuliterally "running brush," which utilizes tactics such as juxtaposition, contradiction, and broad topical variety in exploring her various identities as mother and lover, wife and poet, daughter of varied traditions.', 'https://images.gr-assets.com/books/1279071728m/387577.jpg', '387577', '4.05', '157', '13', 'https://www.goodreads.com/book/show/387577.The_Narrow_Road_to_the_Interior');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Under the Mambo Moon', '', 'On summer nights Marisol helps out in Papi''s music store. As customers come and go, they share memories of the Latin music and dance of their various homelands, expressed in a dazzling array of poetry. The diversity of Latin American music is brought to life in poems that swivel, sway, and sizzle with the rhythms of merengue, vallenatos, salsa, and samba.
Back matter includes a map, author''s note, and further information about the musical heritage of Latin America.', 'https://images.gr-assets.com/books/1389598867m/11085473.jpg', '11085473', '3.17', '157', '40', 'https://www.goodreads.com/book/show/11085473-under-the-mambo-moon');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Rattle Bag: An Anthology of Poetry', '', '"The Rattle Bag" is an anthology of poetry (mostly in English but occasionally in translation) for general readers and students of all ages and backgrounds. These poems have been selected by the simple yet telling criteria that they are the personal favorites of the editors, themselves two of contemporary literature''s leading poets.
Moreover, Heaney and Hughes have elected to list their favorites not by theme or by author but simply by title (or by first line, when no title is given). As they explain in their Introduction: "We hope that our decision to impose an arbitrary alphabetical order allows the contents [of this book] to discover themselves as we ourselves gradually discovered them--each poem full of its singular appeal, transmitting its own signals, taking its chances in a big, voluble world."
With undisputed masterpieces and rare discoveries, with both classics and surprises galore, "The Rattle Bag" includes the work of such key poets as William Shakespeare, Walt Whitman, Emily Dickinson, Lewis Carroll, Dylan Thomas, Wallace Stevens, Elizabeth Bishop, and Sylvia Plath among its hundreds of poems. A helpful Glossary as well as an Index of Poets and Works are offered at the conclusion of this hefty, unorthodox, diverse, inspired, and inspiring collection of poetry.', 'https://images.gr-assets.com/books/1316739259m/743715.jpg', '743715', '4.26', '157', '15', 'https://www.goodreads.com/book/show/743715.The_Rattle_Bag');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('If You''re Not Here, Please Raise Your Hand: Poems About School', '', 'For every student who''s ever worried about spending a lifetime in the third grade and for every teacher who''s faced a class where nobody remembered to bring milk money, these thirty-eight poems capture the excitement, challenge, heartbreak, and wonder of life in elementary school. Through her fresh, lively word pictures, Dakos manages to find surprises in every corner of the school.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '661715', '3.89', '156', '24', 'https://www.goodreads.com/book/show/661715.If_You_re_Not_Here_Please_Raise_Your_Hand');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Call Me Ishmael Tonight: A Book of Ghazals', '', 'The beloved Kashmiri-American poet Agha Shahid Ali presents his own American ghazals. Calling on a line or phrase from fellow poets, Ali salutes those known and loved--W. S. Merwin, Mark Strand, James Tate, and more--while in other searingly honest verse he courageously faces his own mortality.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '101994', '4.3', '155', '16', 'https://www.goodreads.com/book/show/101994.Call_Me_Ishmael_Tonight');
