INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Possibility of Being: A Selection of Poems', '', 'The eighty-four poems included in this small volume will serve as a sound and inviting introduction to Rilke''s strategies in the pursuit of "being." And just as the unicorn in "This Is the Creature" has an eternal "possibility of being" but only becomes visible in the mirror held by a virgin, so can our own possibilities become manifest in the mirror held by the sensitive artist. The poems are chosen from The Book of Hours(1899-1903), The Book of Images(1902 and 1906), New Poems(1907 and 1908), Requiem(1909), Duino Elegies(1923), Sonnets to Orpheus(1923), and the posthumous Poems 1906-26. This selection was made by Professor Theodore Ziolkowski of Princeton University, who drew from the various New Directions volumes of Rilke''s work translated by J. B. Leishman.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '945770', '4.09', '153', '9', 'https://www.goodreads.com/book/show/945770.Possibility_of_Being');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems of Jerusalem & Love Poems', '', 'Bilingual edition, with translations by Assia Gutmann, Harold Schimmel, Chana Bloch, Y.A. & Ted Hughes, David Rosenberg, et al. A new printing of this large collection by the poet commonly regarded as Israel''s most prominent and one of the major contemporary world poets. Born in Germany in 1924, Amichai left with his family for Israel in 1936.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '105224', '4.43', '152', '9', 'https://www.goodreads.com/book/show/105224.Poems_of_Jerusalem_Love_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ten Windows: How Great Poems Transform the World', '', 'A dazzling collection of essays on how the best poems work, from the master poet and popular essayist.
Jane Hirshfield offers ten lively and eminently readable explorations into how great poems transform our experience of the world. Touching on everything from the concept of "windows" in poems (the moments where a word, phrase, or shift in tone "opens" something for the reader) to the mechanisms of surprise and uncertainty, Jane uses particular poems (by Basho, Dickinson, Szymoborska, Gilbert, Cavafy and Creeley, to name a few) to show us how poetry works, word by charged word. Most of all, she captures the ways in which poems make something possible that is separate from and beyond our daily reality ("[Poetry''s] seeing is not our usual seeing, its hearing is not our usual hearing"). Locating the border realm between inner and outer, what is known and what can only be apprehended in the realm of verse, Hirshfield''s lucid understanding is gripping and transformative itself, showing us at every turn how poems restore us to and expand our sense of a broader humanity.', 'https://images.gr-assets.com/books/1411933661m/22543936.jpg', '22543936', '4.38', '151', '30', 'https://www.goodreads.com/book/show/22543936-ten-windows');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Odyssey', '', 'The Odyssey" is a classical epic poem about the events following the fall of Troy and the end of the Trojan War which is generally thought to have been written at the end of the 8th century BC. The story centers on Odysseus and his ten year journey to reach his home of Ithaca, following the Trojan War. Odysseus''s death is assumed during this long absence, and his wife Penelope and son Telemachus must deal with a group of suitors, the Proci, who compete for Penelope''s hand in marriage. Generally attributed to the ancient Greek poet Homer, "The Odyssey" is a sequel to "The Iliad" and is considered one of the most important works of classical antiquity. Presented here in this edition is the prose translation of Samuel Butler.
Robert Fitzgerald''s is the best and best-loved modern translation of The Odyssey, and the only one admired in its own right as a great poem in English. Fitzgerald''s supple verse is ideally suited to the story of Odysseus'' long journey back to his wife and home after the Trojan War. Homer''s tale of love, adventure, food and drink, sensual pleasure, and mortal danger reaches the English-language reader in all its glory.', 'https://images.gr-assets.com/books/1418113053m/12868912.jpg', '12868912', '3.73', '150', '18', 'https://www.goodreads.com/book/show/12868912-the-odyssey');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Lifting Belly', '', 'Classic lesbian erotic poem by the mistress herself -- Gertrude Stein.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '58359', '4.16', '150', '7', 'https://www.goodreads.com/book/show/58359.Lifting_Belly');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Paul Celan: Selections', '', 'The best introduction to the work of Paul Celan, this anthology offers a broad collection of his writing in unsurpassed English translations along with a wealth of commentaries by major writers and philosophers. The present selection is based on Celan''s own 1968 selected poems, though enlarged to include both earlier and later poems, as well as two prose works, The Meridian, Celan''s core statement on poetics, and the narrative Conversation in the Mountains. This volume also includes letters to Celan''s wife, the artist Gisele Celan-Lestrange; to his friend Erich Einhorn; and to Rene Char and Jean-Paul Sartre--all appearing here for the first time in English.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '150273', '4.46', '150', '13', 'https://www.goodreads.com/book/show/150273.Paul_Celan');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Stolen Air: Selected Poems of Osip Mandelstam', '', 'A new selection and translation of the work of Osip Mandelstam, perhaps the most important Russian poet of the twentieth century.
Political nonconformist Osip Mandelstam''s opposition to Stalin''s totalitarian government made him a target of the communist state. The public recitation of his 1933 poem known in English as "The Stalin Epigram" led to his arrest, exile, and eventual imprisonment in a Siberian transit camp, where he died, presumably in 1938. Mandelstam''s work, much of it written under extreme duress, is an extraordinary testament to the enduring power of art in the face of oppression and terror.
Stolen Airspans Mandelstam''s entire poetic career, from his early highly formal poems in which he reacted against Russian Symbolism to the poems of anguish and defiant abundance written in exile, when Mandelstam became a truly great poet. Aside from the famous early poems, which have a sharp new vitality in Wiman''s versions, Stolen Airincludes large selections from The Moscow Notebooks and The Voronezh Notebooks.
Going beyond previous translators who did not try to reproduce Mandelstam''s music, Christian Wiman has captured in English for the first time something of Mandelstam''s enticing, turbulent, and utterly heartbreaking sounds.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '12389347', '4.43', '148', '20', 'https://www.goodreads.com/book/show/12389347-stolen-air');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Works Of Edna St. Vincent Millay', '', '', 'https://images.gr-assets.com/books/1355662484m/3190024.jpg', '3190024', '4.61', '147', '12', 'https://www.goodreads.com/book/show/3190024-collected-works-of-edna-st-vincent-millay');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Yedi Güzel Adam', '', 'Cahit Zarifoglu''nun siiri bunca anlasilmaz, kapali ya da zor anlasilir bulunmasina ragmen, simdiye kadar hicbir akli basinda siir okuyucusu (elestirmen ya da okuyucu olarak) bu siirleri reddetmek, yok saymak cesaretini gosterememistir.
Rasim Ozdenoren
Cahit Zarifoglu''na ait hangi metin olursa olsun, O''nun dunyasina, bir iklime gecer gibi girerseniz. Yeni bir iklime girmenin ne gibi etkileri oluyorsa, nasil degistiriyorsa insani oylece degisirsiniz.
Alim Kahraman
Kendinden sonra yazmaya baslayan genc Musluman sairlere, hangi ozellikleriyle yol gostermis olursa olsun, O''ndan sonrakiler, O''nda ders alinacak bir taraf bulacaklardir. Hem siirin kendine mahsus kaliteleri bakimindan, hem Musluman bir sairin dunya hayatindaki temayulleri bakimindan.
Ismet Ozel
Cahit Zarifoglu o hale gelmisti ki, kendi dunyasi icinde bir siir dili kurmustu ve bunu cok iyi kullanirdi. Yani siire, o anlatilmaz olana ait bir durum ciktigi zaman, bir algilama oldugu zaman, onu hemen aninda siire dokuverirdi.
Erdem Bayazit
Kanaatimce Cahit''in siiri belli bir kalip icerisinde hemen formule edilebilecek, anlatilabilecek bir huviyet tasimiyor. Cahit, eski tabirle sair-i maderzat, anadan dogma sair idi.
Akif Inan
Turkce''de hem ahenge ulasmak hem de duygu iletisimini saglamanin belki de en cetin bir sairlik gorevi oldugu gunumuzde, bir de buna ''avucunda kor tutmayi'' eklemisti. ''Hal''ini iyiye dogru surekli yuceltirken, ''siir''ni de yeni ''hal''ine uydurma savasiminda idi.
Prof. Dr. Huseyin Hatemi
Ece Ayhan''a sordum, ona gore "Cahit Zarifoglu" siirde yapi sorunun en iyi kavramis bu konuda ornek gosterilebilecek sanatcilardan biri. Kolsuz Bir Hattat''ta da ayrica belirtmis bunu.
Cemal Sureya
Cahit Zarifoglu''nun siirini ve duzyazisini o uzaklik, ayrilik gayrilik icinde ancak kendi uzlet kosemden izleyebiliyordum. Kamplasma havasinda kendine yer bulamayacak bu ince siir, kapali ama mutlaka sanatkarca duzyazi, kendine ozgu degerleri daima korurdu.
Selim Ileri
Cahit Zarifoglu''nun siiri, butun diger yapip ettikle', 'https://images.gr-assets.com/books/1369583455m/17979018.jpg', '17979018', '3.97', '147', '15', 'https://www.goodreads.com/book/show/17979018-yedi-g-zel-adam');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('77 Love Sonnets', '', '''77 Love Sonnets'' is American literary celebrity Garrison Keillor''s first collection of his own poetry. Included are two CDs on which he reads all the poems in the book.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6478280', '3.81', '147', '22', 'https://www.goodreads.com/book/show/6478280-77-love-sonnets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Tres mujeres', '', 'Sylvia Plath siempre apunta al corazon. Tres mujeres es un emocionante poema a tres voces que tiene como tema central la maternidad. Cada voz representa una forma de vivirla: la mujer que centra su realizacion en ser madre, la que sufre por no poder serlo y la que lo es a su pesar.
Sylvia concibio este poema, feminista y antibelicista, para ser leido en voz alta, y en 1962, un ano antes de su muerte, lo leyo en la BBC. La experiencia supuso un cambio de direccion en su forma de afrontar la escritura. Desde entonces concebiria los poemas <>, cambiando de forma definitiva su tecnica poetica.', 'https://images.gr-assets.com/books/1381743314m/18668883.jpg', '18668883', '4.23', '146', '17', 'https://www.goodreads.com/book/show/18668883-tres-mujeres');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hymns and Fragments', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '919674', '4.63', '145', '3', 'https://www.goodreads.com/book/show/919674.Hymns_and_Fragments');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The October Palace', '', 'Grounded in a series of mediations upon the life of the feeling heart in the world, Jane Hirshfield''s long-awaited third collection of poetry explores the ways that radiance dwells most truly in the ordinary, the difficult, and the plain.', 'https://images.gr-assets.com/books/1327884209m/355148.jpg', '355148', '4.21', '144', '5', 'https://www.goodreads.com/book/show/355148.The_October_Palace');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('I Wrote This Crap for You', '', '"This is the essence of what it truly means to be human.
It''s all right here in these words.
Everything you ever need to know.
That''s because I use all twenty-six letters, and you can make anything out of those twenty-six letters. So, you see, this book encompasses everything."
-- PleaseHelpMe
Rumored to be penned by the brother of the best-selling author of "I Wrote This For You," this new tour de force in poetry is sure to stab at your heart, or, at least, make you want to.
If you loved the international best-selling collection of poetry, "I Wrote This For You," you''ll probably hate this. But even those admirers of the free-verse artistry of that work will get a laugh from this classic parody.
Author and screenwriter Edward Savio put together a spot-on send up of the poetry best-seller with "I Wrote This Crap For You."
It''s a quick, fun read that we hope you enjoy.
"It touched my heart and moved me to tears."
"It''s as if he knew my inner thoughts and fears, and--come to think of it my diary is missing."', 'https://images.gr-assets.com/books/1355002988m/16174875.jpg', '16174875', '3.33', '143', '15', 'https://www.goodreads.com/book/show/16174875-i-wrote-this-crap-for-you');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('If I Don''t Know', '', 'Wendy Cope''s most recent collection, her first since Serious Concernsin 1992, extends her concern with the comedy of the examined life (''the way we have been, the way we sometimes are''), and imagines those adjustments to the ordinary which would fulfil our futures, or allow us to realize the golden age of five minutes ago, or weigh the ''out there'' of the present moment, where what is in sight is also out of reach. These are poems of well-tempered yearning, conditional idylls which sing in praise of lying fallow, the creativity of daydream, the yeast of boredom, the truths of intermediacy. Wendy Cope''s formal tact is alertly present - in triolets, rondeaux, villanelles, squibs, epigrams - small forms whose power to disarm goes hand in hand with her characteristically tart ripostes to the way things (usually) are. This collection extends the variousness of her occasions.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '936207', '4.01', '143', '17', 'https://www.goodreads.com/book/show/936207.If_I_Don_t_Know');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Taliesin: The Last Celtic Shaman', '', 'A new translation of the poems of sixth-century Celtic bard and shaman Taliesin that reveals the mysteries of Druidic practices.- The first collection of Taliesin''s major poetry with commentary by John Matthews, author of more than 40 books on the Celts.
- Reveals Druidic prophecy, methods of divination, and the rites, rituals, and beliefs that were essential to Celtic spiritual practice.
- Features Taliesin''s works as keys to the Arthurian legends.
Taliesin, Chief Bard of Britain and Celtic shaman, was a historical figure who lived in Wales during the latter half of the sixth century. Encoded within his work are the ancestral beliefs of the Celtic and pre-Celtic peoples. In addition, his verse is established as a direct precursor to the Arthurian Legends--and Taliesin himself, shaman and shapeshifter, is said to be the direct forebear to Merlin. Though the bard''s work is steeped in the rich traditions of druidic practice, few have explored the revelations of his writings--the secret poetic language of the bards, revelatory information about divination, the ancient mysteries of the Druids, and the cosmological rites that were central to Celtic worship. 
John Matthews, one of today''s preeminent Celtic scholars, sheds new light on the poems of Taliesin and on the vast body of allusion, story, and myth that grew from his body of work and shamanic practice. With the help of fellow Celtic scholar Caitlin Matthews, the author presents completely new translations of Taliesin''s major poems in their entirety, uncovering the meanings behind these great works for the first time.', 'https://images.gr-assets.com/books/1331808382m/73905.jpg', '73905', '4.1', '142', '8', 'https://www.goodreads.com/book/show/73905.Taliesin');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Poems of Emily Dickinson', '', 'The Collected Poems of Emily Dickinson, by Emily Dickinson, is part of the Barnes & Noble Classicsseries, which offers quality editions at affordable prices to the student and the general reader, including new scholarship, thoughtful design, and pages of carefully crafted extras. Here are some of the remarkable features of Barnes & Noble Classics:
All editions are beautifully designed and are printed to superior specifications; some include illustrations of historical interest. Barnes & Noble Classics pulls together a constellation of influences--biographical, historical, and literary--to enrich each reader''s understanding of these enduring works.
Born in Amherst, Massachusetts in 1830, Dickinsonbegan life as an energetic, outgoing young woman who excelled as a student. However, in her mid-twenties she began to grow reclusive, and eventually she rarely descended from her room in her father''s house. She spent most of her time working on her poetry, largely without encouragement or real interest from her family and peers, and died at age fifty-five. Only a handful of her 1,775 poems had been published during her lifetime. When her poems finally appeared after her death, readers immediately recognized an artist whose immense depth and stylistic complexities would one day make her the most widely recognized female poet to write in the English language. Dickinson''s poetry is remarkable for its tightly controlled emotional and intellectual energy. The longest poem covers less than two pages. Yet in theme and tone her writing reaches for the sublime as it charts the landscape of the human soul. A true innovator, Dickinson experimented freely with conventional rhythm and meter, and often used dashes, off rhymes, and unusual metaphors--techniques that strongly influenced modern poetry. Dickinson''s idiosyncratic style, along with her deep resonance of thought and her observations about life and death, love and nature, and solitude and society, have firmly established her as o', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '588900', '4.21', '141', '9', 'https://www.goodreads.com/book/show/588900.Collected_Poems_of_Emily_Dickinson');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Wintering Out', '', '''Seamus Heaney has gone beyond the themes of his earlier poetry and has made the giant step towards the most ambitious, most intractable themes of maturity. The power of this book comes from a sense that he is reaching out towards a type of desolation and of isolation without which no imagination can be seen to have grown up.'' Eavan Boland, Irish Times''Keyed and pitched unlike any other significant poet at work in the language anywhere.'' Harold Bloom, Times Literary Supplement', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '19248', '4.08', '140', '10', 'https://www.goodreads.com/book/show/19248.Wintering_Out');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('ديوان سيد قطب', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '11197510', '4.09', '140', '16', 'https://www.goodreads.com/book/show/11197510');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Spirits Rebellious/The Madman/The Forerunner', '', 'The selection in this volume features an anthology of four short stories published originally in Arabic as "Spirits Rebellious" (1908) and two collections of parables... "The Forerunner" and "The Madman" (1932).', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1337053', '4.33', '140', '3', 'https://www.goodreads.com/book/show/1337053.Spirits_Rebellious_The_Madman_The_Forerunner');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Poems', '', 'To commemorate the centennial of W. H. Auden''s birth, the Modern Library offers this elegant edition of the collected poems of one of the greatest poets of the twentieth century.
This volume includes all the poems that Auden wished to preserve, in a text that includes his final revisions, with corrections based on the latest research. Auden divided his poems into sections that corresponded to what he referred to as chapters in his life, each one beginning with a change in his inner life or external circumstances: the moment in 1933 when he first knew "exactly what it means to love one''s neighbor as oneself"; his move from Britain to America in 1939; his first summer in Italy in 1948; his move to a summerhouse in Austria in 1958; and his return to England in 1972.
Auden''s work has perhaps the widest range and the greatest depth of any English poet of the past three centuries. From the anxious warnings of his early verse through the expansive historical perspectives of his middle years to the celebrations and thanksgiving in his later work, Auden wrote in a voice that addressed readers personally rather than as part of a collective audience. His styles and forms extend from ballads and songs to haiku and limericks to sonnets, sestinas, prose poems, and dozens of other constructions of his own invention. His tone ranges from spirited comedy to memorable profundity-often within the same work. His poems manage to be secular and sacred, philosophical and erotic, personal and universal.
"All the poems I have written were written for love," Auden once said. This book includes his famous early poems about transient love ("Lay your sleeping head, my love," "Stop all the clocks, cut off the telephone") and his later poems about enduring love ("In Sickness and in Health," "First Things First"). The book also includes Auden''s longer, more thematically varied poems, from the expressionist charade "Paid on Both Sides" to the formal couplets of "New Year Letter"; the darkly comic s', 'https://images.gr-assets.com/books/1320436296m/152530.jpg', '152530', '4.26', '139', '7', 'https://www.goodreads.com/book/show/152530.Collected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('ساعت ۱۰ صبح بود', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '3425495', '3.55', '139', '12', 'https://www.goodreads.com/book/show/3425495');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Early Poems of Alfred Lord Tennyson', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '11091103', '3.91', '138', '1', 'https://www.goodreads.com/book/show/11091103-the-early-poems-of-alfred-lord-tennyson');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Aşka Dair Nesirler', '', 'Gelme diyecektim, geldin. Iyi ettin geldigine. Nerdeyiz? Bir sehir yaniyor, dikkat et. Tutusabiliriz, iste ilk ates gozlerine dustu, sonra dudaklarina, saclarinin arasina kivilcimlar doldu isil isil. Yaniyorsun, yaniyorum, yaniyoruz.
Aramakla yetinsek bunlar gelmeyecekti basimiza. Yine de memnunum. Iyi ettin geldigine. Tas olup kalmaktansa, agac olup yanmak iyi. Ellerini ver, ellerini. Opusmeye susadim. Tirnak uclarindan opmeye baslayacagim seni. Titreme, yaniyorsun.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '12559320', '4.54', '138', '8', 'https://www.goodreads.com/book/show/12559320-a-ka-dair-nesirler');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Complete Poems', '', 'Milton devoted much of his adult life to defending the cause of Cromwell''s Commonwealth. His later poetry, produced after Charles II''s Restoration led to the defeat of his hopes, reflects his understanding of politics and power. In this edition of Milton''s poetry, John Leonard has modernized spelling, capitalization and any punctuation likely to cause confusion. He calls particular attention to words invented by Milton and provides full notes to elucidate biblical, classical and historical allusions, many of which complicate or even conflict with the plain sense or moral implications of the text.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '193603', '4.04', '137', '2', 'https://www.goodreads.com/book/show/193603.The_Complete_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Complete Poems', '', 'A master of song poems which celebrate--and incarnate--the music of nature and history, love and mythology, religion and language, Basil Bunting (1900-1985) was a major figure in Modernist poetry, recognized by Pound and Zukofsky as early as the 1930s, and crowned, with the 1966 publication of his masterpiece "Briggflatts," Britain''s greatest poet. The poet himself called his great epic poem "old wives'' chatter, cottage wisdom," but for many writers "Briggflatts" is one of the dozen great poems of the 20th century: as Cyril Connolly put it, "the finest long poem to have been published in England since T. S. Eliot''s Four Quartets."
As well as "Briggflatts" (long out of print in the US, and now only available in this edition), this new Complete Poemsincludes Bunting''s other great sonatas, most notably Villon(1925) and The Spoils(1951), along with his two books of Odes, his vividly realized "Overdrafts" (as he called his free translations of Horace, Rudaki, and others), and his brilliantly condensed Japanese adaptation, Chomei at Toyama(1932). It also includes his posthumous Uncollected Poems. This centenary edition has an introduction by Richard Caddel, Director of the Basil Bunting Poetry Center at Durham University.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '428527', '4.37', '137', '9', 'https://www.goodreads.com/book/show/428527.Complete_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Rilke''s Book of Hours: Love Poems to God', '', 'While visiting Russia in his twenties, Rainer Maria Rilke, one of the twentieth century''s greatest poets, was moved by a spirituality he encountered there. Inspired, Rilke returned to Germany and put down on paper what he felt were spontaneously received prayers. Rilke''s Book of Hours is the invigorating vision of spiritual practice for the secular world, and a work that seems remarkably prescient today, one hundred years after it was written.Rilke''s Book of Hours shares with the reader a new kind of intimacy with God, or the divine-a reciprocal relationship between the divine and the ordinary in which God needs us as much as we need God. Rilke influenced generations of writers with his Letters to a Young Poet, and now Rilke''s Book of Hours tells us that our role in the world is to love it and thereby love God into being. These fresh translations rendered by Joanna Macy, a mystic and spiritual teacher, and Anita Barrows, a skilled poet, capture Rilke''s spirit as no one has done before.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6563502', '4.45', '136', '14', 'https://www.goodreads.com/book/show/6563502-rilke-s-book-of-hours');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poverty Creek Journal', '', '"That rush in between when it all comes undone. Knowing its edge like your own pulse and breathing. As I knew them this morning, racing a 10K in late-spring heat, the taste of panic in the last two miles as everything slipped away, losing time and barely finishing. A tingling in my limbs as if I were driving on ice, the road beneath me suddenly gone, the feeling of that in my hands. Deeper than words, being lost for a moment and then being done. Left with a pounding, stiff-legged stagger."
Spiritual improvisations, radiant acts of attention: echoing Thoreau''s Walden, the meditations of Guy Davenport, and Kenny Moore''s groundbreaking articles for Sports Illustrated, Thomas Gardner strides through inner and outer landscapes. Freed by disciplined effort, the runner''s mind here roams and mourns and remembers.', 'https://images.gr-assets.com/books/1420215020m/24262961.jpg', '24262961', '4.23', '135', '35', 'https://www.goodreads.com/book/show/24262961-poverty-creek-journal');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('İlahi Komedya', '', 'Dunya siirinin basyapiti "Ilahi Komedya", Dante''nin Cehennem''e, Araf''a ve Cennet''e yaptigi dussel bir geziyi destanlastirir. "Ilahi Komedya", 14233''e ulasan toplam dize sayisi ile, siir tarihinin en uzun soluklu siiridir. Dante''nin 1300 yilinin 7 Nisan Persembe gecesi baslayan gezisi bir hafta surer, Dante''ye Cehennem ve Araf yolculugu boyunca Latin sair Vergilius rehberlik eder. Araf''in tepesinde Vergilius yerini, Cennet''te Dante''ye rehberlik edecek olan Beatrice''ye birakir. Dante, Beatrice''yi ilk kez gordugunde kendisi dokuz, Beatrice sekiz yasindadir. Dante, omru boyunca Beatrice''ye bagli kaldigi gibi, dusunce dunyasinin da esin kaynagi olur Beatrice.
Vergilius''un Aeneis destanini ornek alan ve siradisi bir aska mitoloji, tarih ve kutsal metinlerle de desteklenen gercekustucu bir ortamda yakilan bir agit olarak da degerlendirilebilecek olan "Ilahi Komedya"nin, tarih ve felsefeden dinbilime, gokbilimden geometriye uzanan bir ansiklopedi niteligi tasimasi da bir baska ozelligidir.
Oglak Yayinlari, eksiksiz ve ilk kez siir olarak Turkcelestirilen "Ilahi Komedya"yi gururla sunar.', 'https://images.gr-assets.com/books/1474828205m/17332882.jpg', '17332882', '4.06', '134', '9', 'https://www.goodreads.com/book/show/17332882-lahi-komedya');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Kolam: Buku Puisi', '', 'Kolam adalah buku sastra terbaik yang terbit sepanjang tahun 2009.
(Majalah Tempo)
"Di tangannya, kata seolah mendapatkan tuah. Ungkapan verbal lumrah dalah puisi Sapardi menjelmakan sebuah ''dunia di seberang bahasa'' yang enigmatik, tempat segalanya terlihat begitu bening tapi sekaligus tak tertembus, begitu akrab namun selalu tak tertangkap."
(Arif Bagus Prasetyo, Resensi di Tempo)', 'https://images.gr-assets.com/books/1317121962m/6435644.jpg', '6435644', '4.05', '134', '15', 'https://www.goodreads.com/book/show/6435644-kolam');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('When I Heard the Learn''d Astronomer', '', 'Leave time for wonder.
Walt Whitman''s "When I Heard the Learn''d Astronomer" is an enduring celebration of the imagination. Here, Whitman''s wise words are beautifully recast by New York Times#1 best-selling illustrator Loren Long to tell the story of a boy''s fascination with the heavens. Toy rocket in hand, the boy finds himself in a crowded, stuffy lecture hall. At first he is amazed by the charts and the figures. But when he finds himself overwhelmed by the pontifications of an academic, he retreats to the great outdoors and does something as universal as the stars themselves...
he dreams.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '630740', '4.14', '134', '26', 'https://www.goodreads.com/book/show/630740.When_I_Heard_the_Learn_d_Astronomer');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Letters: 1958-1965', '', 'The 1960''s saw Charles Bukowski struggle for recognition and slowly emerge as a unique, talented and prolific poet and writer, whilst holding down a day job at the Post Office. These letters to various friends, lovers and literary contacts provide an intimate and fascinating look at Bukowski''s mind, his emotions, his attitude towards his own creativity and the comings and goings of his daily life.', 'https://images.gr-assets.com/books/1408928891m/50519.jpg', '50519', '4.02', '134', '8', 'https://www.goodreads.com/book/show/50519.Selected_Letters');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Split', '', '"To be a daughter, a survivor, and a poet are all aligned in the need "to rewrite everything," a need that [Cathy Linh Che] navigates with brutality and tenderness, devastation and irrepressible endurance." --Publishers Weekly
"Splitcrosses borders, exposing truths and dreams, violations of body and mind, aligning them until the deep push-pull of silence and song become a bridge. And here we cross over into a landscape where beauty interrogates, and we encounter a voice that refuses to let us off the hook."--Yusef Komunyakaa
In this stunning debut, we follow one woman''s profoundly personal account of sexual violence against the backdrop of cultural conflict deftly illustrated through her parents'' experiences of the Vietnam War, immigration, and its aftermath. By looking closely at landscape and psyche, Splitexplores what happens when deep trauma occurs and seeks to understand what it means to finally become whole.
From "The German word for dream is traume.":
When my mother whispered,
Has anyone touched you there?
I had to pick.
Alan, I said.
I was seven.
The training wheels
were coming off.
Between the couch
and wall, the ceiling was white
with popcorn bits. The boys stood
and watched. I lay there,
my eyes open like a doll''s.
Someone said, Let me try.
He rode on top
then abruptly stopped.
The boys laughed,
and then, they stood me up.
Cathy Linh Cheis a Vietnamese American poet from Los Angeles, CA. She has received awards from The Asian American Literary Review, The Center for Book Arts, The Fine Arts Work Center at Provincetown, Hedgebrook, Kundiman, The Lower Manhattan Cultural Council''s WorkspaceResidency, and Poets & Writers. She is a founding editor of Paperbag.', 'https://images.gr-assets.com/books/1392232997m/18406193.jpg', '18406193', '4.45', '133', '16', 'https://www.goodreads.com/book/show/18406193-split');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Broken Wings', '', 'Broken Wings tells the tale of a love doomed by the restrictions of a cruel society. The narrative highlights many of Gibran''s concerns about the plight of Eastern women, wealth as an impediment to happiness, the greed and corruption of the clergy, and the overwhelming power of love.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1081692', '3.93', '133', '10', 'https://www.goodreads.com/book/show/1081692.Broken_Wings');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Sorrow Gondola', '', 'The Sorrow Gondolawas the great Swedish poet Tomas Transtromer''s first collection of poems after his stroke in 1990. Translated by Michael McGriff, Transtromer''s great work is available in its first single-volume English edition.
Tomas Transtromer was awarded the Nobel Prize for Literature in 2011.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6693530', '3.74', '132', '20', 'https://www.goodreads.com/book/show/6693530-the-sorrow-gondola');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('True Stories', '', '', 'https://images.gr-assets.com/books/1379432790m/1497744.jpg', '1497744', '4.07', '132', '18', 'https://www.goodreads.com/book/show/1497744.True_Stories');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Homecoming: New and Collected Poems', '', 'Long before her award winning novel, How the Garcia Girls Lost Their Accents, and In the Time of the Butterflies, Julia Alvarezwas writing poetry that gave a distinctive voice to the Latina woman-and helped give to American letters a vibrant new literary form. Homecoming,was Alvarez''s first published collection of poetry, a work of great subtlety and power in which the young poet returned to her old-world childhood in the Dominican Republic.Now this revised and expanded edition adds thirteen new poems. These more recent writings are still deeply autobiographical in nature, but written with the edgier, more knowing tone of a woman who has seen, and survived, more of life. Wonderfully lucid and engaging, toned with deep emotionality and a wry observation of life, the poems of Julia Alvarez stand next to her fiction to both delight us and give us lessons in living and loving.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '11212', '3.97', '132', '12', 'https://www.goodreads.com/book/show/11212.Homecoming');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Geografías', '', '', 'https://images.gr-assets.com/books/1280853155m/554372.jpg', '554372', '4.09', '131', '8', 'https://www.goodreads.com/book/show/554372.Geograf_as');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('This is a Poem that Heals Fish', '', '"Exuding magic and unbridled creativity on every page, this is a book with the potential to heal more than just fish."--Publishers Weekly
"An enchantingly abstract invitation to ponder poetry."--Kirkus Reviews
"A great book for any age! At this very moment, it feels like one of the best books I''ve ever bought!"--A Year of Reading blog', 'https://images.gr-assets.com/books/1185906340m/1614684.jpg', '1614684', '4.14', '131', '33', 'https://www.goodreads.com/book/show/1614684.This_is_a_Poem_that_Heals_Fish');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Boat of Quiet Hours: Poems', '', '', 'https://images.gr-assets.com/books/1312030855m/435063.jpg', '435063', '4.25', '131', '13', 'https://www.goodreads.com/book/show/435063.The_Boat_of_Quiet_Hours');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poems of Octavio Paz', '', 'In 1990, the Swedish Academy awarded Octavio Paz the Nobel Prize in Literature for impassioned writing with wide horizons, characterized by sensuous intelligence and humanistic integrity. Paz is a writer for the entire world to celebrate (Chicago Tribune), the poet-archer who goes straight to the heart and mind, where the center of being is one (Nadine Gordimer), the living conscience of his age (Mario Vargas Llosa), a poet-prophet, a genius (Harold Bloom). Here at last is the first retrospective collection of Paz s poetry to span his entire writing career, from the first published poem, at age seventeen, to his magnificent last poem; the whole is assiduously edited and translated by acclaimed essayist Eliot Weinberger who has been translating Paz for over forty years with additional translations by several poet-luminaries. This edition includes many poems that have never been translated into English before, new translations based on Paz s final revisions, and a brilliant capsule biography of Paz by Weinberger, as well as notes on the poems in Paz s own words, taken from various interviews he gave throughout his life.', 'https://images.gr-assets.com/books/1351339164m/13792332.jpg', '13792332', '4.43', '131', '8', 'https://www.goodreads.com/book/show/13792332-the-poems-of-octavio-paz');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Iliad', '', 'One of the oldest extant works of Western literature, the Iliadis a timeless epic poem of great warriors trapped between their own heroic pride and the arbitrary, often vicious decisions of fate and the gods. Renowned scholar and acclaimed translator Peter Green captures the Iliadin all its surging thunder for a new generation of readers.
Featuring an enticingly personal introduction, a detailed synopsis of each book, a wide-ranging glossary, and explanatory notes for the few puzzling in-text items, the book also includes a select bibliography for those who want to learn more about Homer and the Greek epic. This landmark translation--specifically designed, like the oral original, to be read aloud--will soon be required reading for every student of Greek antiquity, and the great traditions of history and literature to which it gave birth.', 'https://images.gr-assets.com/books/1414559982m/23453211.jpg', '23453211', '3.83', '130', '9', 'https://www.goodreads.com/book/show/23453211-the-iliad');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('North and South', '', '', 'https://images.gr-assets.com/books/1316590851m/2118849.jpg', '2118849', '4.28', '130', '14', 'https://www.goodreads.com/book/show/2118849.North_and_South');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Black Automaton', '', '"Douglas Kearney''s innovative new collection makes me tremble like a ''mouth and mind full of fish hooks.'' . . . These poems literally vibrate with Kearney''s precocious intellect and passion. They hum, they bang, they bite. What else can I say? I have never encountered poetry like this before."--Terrance Hayes', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6473543', '4.29', '127', '15', 'https://www.goodreads.com/book/show/6473543-the-black-automaton');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poems', '', '', 'https://images.gr-assets.com/books/1320403049m/1401379.jpg', '1401379', '4.23', '125', '5', 'https://www.goodreads.com/book/show/1401379.The_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Where the Sidewalk Ends: The poems & drawings of Shel Silverstein', '', 'Where the Sidewalk Ends turns forty! Celebrate with this anniversary edition that features an eye-catching commemorative red sticker. This classic poetry collection, which is both outrageously funny and profound, has been the most beloved of Shel Silverstein''s poetry books for generations.
Where the sidewalk ends, Shel Silverstein''s world begins. There you''ll meet a boy who turns into a TV set and a girl who eats a whale. The Unicorn and the Bloath live there, and so does Sarah Cynthia Sylvia Stout who will not take the garbage out. It is a place where you wash your shadow and plant diamond gardens, a place where shoes fly, sisters are auctioned off, and crocodiles go to the dentist.
Shel Silverstein''s masterful collection of poems and drawings is one of Parent & Child magazine''s 100 Greatest Books for Kids. School Library Journal said, "Silverstein has an excellent sense of rhythm and rhyme and a good ear for alliteration and assonance that make these poems a pleasure to read aloud."
Shel Silverstein''s incomparable career as a children''s book author and illustrator began with Lafcadio, the Lion Who Shot Back. In 1964, Shel''s creativity continued to flourish as four more books were published in the same year--Don''t Bump the Glump!, A Giraffe and a Half, Who Wants a Cheap Rhinoceros?, and the beloved classic The Giving Tree. Later he continued to build his remarkable body of work with Where the Sidewalk Ends, A Light in the Attic, Falling Up, Every Thing On It, The Missing Piece, The Missing Piece Meets the Big O, and Runny Babbit.', 'https://images.gr-assets.com/books/1383532057m/30135.jpg', '30135', '4.29', '124', '11', 'https://www.goodreads.com/book/show/30135.Where_the_Sidewalk_Ends');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Last Gold of Expired Stars: Complete Poems 1908 - 1914', '', 'An aura of mystery surrounds the life and poetry of the Austrian poet Georg Trakl. Although he was born over a century ago, his starkly original poems provide a window into the psyche of the early twentieth century with its anguish, melancholy, and occasional exaltation. From a life inflicted with drug addiction and mental torment, Trakl paints a vivid, musical portrait of his autumn soul. This bilingual edition includes all of Trakl''s mature published work, as well as his youthful poems and prose, drama fragments and selected letters, and is the most comprehensive collection of his work in English to date.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '11552905', '4.76', '124', '4', 'https://www.goodreads.com/book/show/11552905-the-last-gold-of-expired-stars');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('soft thorns', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '35288488', '4.02', '123', '24', 'https://www.goodreads.com/book/show/35288488-soft-thorns');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Why Did You Leave the Horse Alone?', '', 'At once an intimate autobiography and a collective memory of the Palestinian people, Darwish''s intertwined poems are collective cries, songs, and glimpses of the human condition. Why Did You Leave the Horse Alone? is a poetry of myth and history, of exile and suspended time, of an identity bound to his displaced people and to the rich Arabic language. Darwish''s poems - specific and symbolic, simple and profound - are historical glimpses, existential queries, chants of pain and injustice of a people separated from their land.', 'https://images.gr-assets.com/books/1354208736m/130548.jpg', '130548', '4.06', '122', '10', 'https://www.goodreads.com/book/show/130548.Why_Did_You_Leave_the_Horse_Alone_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Collected Works of William Butler Yeats', '', 'This Halcyon Classics collection contains dozens of works by William Butler Yeats, one of the foremost figures of 20th-Century English-language poetry, drama, and literature. Yeats (1865-1939) is best known for his poetry, for which he was awarded the Nobel Prize in Literature in 1923, the first Irish writer so honored.
Yeats was born and educated in Dublin, studying poetry in his youth. From an early age he was fascinated by both Irish legends and the occult. Those topics feature in the first phase of his work, which lasted roughly until the turn of the century. His earliest volume of poetry was published in 1889. Yeats was also an important figure in the Irish Literary Revival, and a fervent Irish nationalist as well.
Contents:
Poetry Collections
In the Seven Woods
Michael Robartes and the Dancer
The Celtic Twilight
The Green Helmet and Other Poems
The Wild Swans and Coole
Drama
The Countess Cathleen
The Hour-Glass
The Land of Heart''s Desire
The Unicorn from the Stars
Fiction
Irish Fairy Tales
Rosa Alchemica
Stories of Red Hanrahan
The Secret Rose
Biography
Four Years
Synge and the Ireland of His Time
This unexpurgated edition contains the complete text with errors and omissions corrected.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '8729193', '4.5', '122', '2', 'https://www.goodreads.com/book/show/8729193-the-collected-works-of-william-butler-yeats');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Rubaiyat of Omar Khayyam', '', 'In the eleventh century, in Persia, there lived a mathematician named Ghiyathuddin Abulfath Omar bin Ibrahim al-Khayyami--or, Omar, son of Abraham, the tent-maker. Omar wrote poetry, and while his rhymes received little attention in their day, they were rediscovered and translated into beautiful English--more than seven centuries later--by a gentleman and scholar named Edward FitzGerald. It was a meeting of minds, a great collaboration of the past and the present, and FitzGerald''s rendition of those passionate verses has become one of the best loved poem cycles in the English language.
With their concern for the here and now, as opposed to the hereafter, Omar Khayyam''s quatrains are as romantic today as they were hundreds of years ago; they are a tribute to the power of one moment''s pleasure over a lifetime of sorrow, of desire over the vicissitudes of time. Rubaiyat of Omar Khayyam, presented here with Edward FitzGerald''s original preface, is truly a classic, and it will stand forever as one of our finest monuments to love.', 'https://images.gr-assets.com/books/1316637804m/131421.jpg', '131421', '4.18', '121', '9', 'https://www.goodreads.com/book/show/131421.Rubaiyat_of_Omar_Khayyam');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Then Suddenly--', '', 'Finalist for ForeWord Magazine''s 1999 Poetry Book of the Year
A reader and a writer don their respective roles and embark on the journey of a book. This is their story--ultimately a love story--darkly funny, mournful, testy. It is about a reader who at times presides over the page like a god, and at others follows the leash of the author''s voice through the dark streets of the book like a dog, and it is about a writer of determined slipperiness. As we read, we think that each of us is The Reader, the one who knows the Real Story. But the more we think we understand, the more the story moves away from us--all is not what it seems.
This eagerly awaited third volume by the poet whose work The New York Timesdescribed as "at once charmed and frightening" is a book of high-spirited subversiveness, a work of argument, seduction, and a relentless devotion to language. Then, Suddenly--bristles with the sound of the author''s voice--insistent, vital, hilarious, and iconoclastic--tearing away at the confinement of the page and at the distance between the page and the reader. Emanuel''s images are dazzling. She creates a performance that is fearsome and funny in its portrayal of the argument between the work of the text and the world of the body. The Gettsyburg Review has called her a writer of "exquisite craftsmanship" who can "strike from language . . . images chiseled clean as bas-relief." Then, Suddenly--is a book of spectacle and verve, part elegy, part vaudeville.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '771393', '3.94', '120', '10', 'https://www.goodreads.com/book/show/771393.Then_Suddenly_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('This Present Moment: New Poems', '', '"This present moment
That lives on
To become
Long ago."
For his first collection of new poems since his celebrated Danger on Peaks, published in 2004, Gary Snyder finds himself ranging over the planet. Journeys to the Dolomites, to the north shore of Lake Tahoe, from Paris and Tuscany to the shrine at Delphi, from Santa Fe to Sella Pass, Snyder lays out these poems as a map of the last decade. Placed side-by-side, they become a path and a trail of complexity and lyrical regard, a sort of riprap of the poet''s eighth decade. And in the mix are some of the most beautiful domestic poems of his great career, poems about his work as a homesteader and householder, as a father and husband, as a friend and neighbor. A centerpiece in this collection is a long poem about the death of his beloved, Carole Koda, a rich poem of grief and sorrow, rare in its steady resolved focus on a dying wife, of a power unequaled in American poetry.
As a friend is quoted in one of these new poems:
"I met the other lately in the far back of a bar,
musicians playing near the window and he
sweetly told me "listen to that music.
The self we hold so dear will soon be gone.""
Gary Snyder is one of the greatest American poets of the last century, and This Present Momentshows his command, his broad range, and his remarkable courage.', 'https://images.gr-assets.com/books/1415678164m/23281518.jpg', '23281518', '4.14', '120', '30', 'https://www.goodreads.com/book/show/23281518-this-present-moment');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Eight American Poets: An Anthology', '', 'In this generous anthology, Joel Conarroe has assembled the work of eight poets who have shaped--and to some extent defined--American verse since 1940: Elizabeth Bishop, James Merrill, Sylvia Plath, Allen Ginsberg, Theodore Roethke, John Berryman, Anne Sexton, and Robert Lowell. The 164 selections in Eight American Poetsinclude widely anthologized works like Roethke''s "My Papa''s Waltz," several of Berryman''s "Dream Songs," and Anne Sexton''s "Ringing the Bells," as well as poems that are less familiar but just as haunting. Prefaced with a discerning introduction and individual biographical essays.', 'https://images.gr-assets.com/books/1320428171m/567011.jpg', '567011', '4.13', '120', '15', 'https://www.goodreads.com/book/show/567011.Eight_American_Poets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Bluets', '', 'Maggie Nelson is one of the most electrifying writers at work in America today, among the sharpest and most supple thinkers of her generation - Olivia Laing
Bluetswinds its way through depression, divinity, alcohol, and desire, visiting along the way with famous blue figures, including Joni Mitchell, Billie Holiday, Yves Klein, Leonard Cohen and Andy Warhol. While its narrator sets out to construct a sort of ''pillow book'' about her lifelong obsession with the colour blue, she ends up facing down both the painful end of an affair and the grievous injury of a dear friend. The combination produces a raw, cerebral work devoted to the inextricability of pleasure and pain, and to the question of what role, if any, aesthetic beauty can play in times of great heartache or grief.
Much like Roland Barthes''s A Lover''s Discourse, Bluetshas passed between lovers in the ecstasy of new love, and been pressed into the hands of the heartbroken. Visceral, learned, and acutely lucid, Bluetsis a slim feat of literary innovation and grace, never before published in the UK.', 'https://images.gr-assets.com/books/1497524150m/31817300.jpg', '31817300', '4.29', '119', '23', 'https://www.goodreads.com/book/show/31817300-bluets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ignatz', '', '', 'https://images.gr-assets.com/books/1327959481m/7624994.jpg', '7624994', '4.1', '118', '16', 'https://www.goodreads.com/book/show/7624994-ignatz');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Around the World on Eighty Legs: Animal Poems: Animal Poems', '', 'A fun, fresh animal journey!
Pack your bags and put on your travelin'' shoes! There''s an animal adventure waiting for you! Awake with the HOWLER MONKEYS, twist into a pretzel like a QUETZAL, hang with a SLOTH, be will-nilly like a CHINCHILLA. Squawk with an AUK, bump your rump like a CAMEL, be silly with a BILBY, and drift off to sleep in the deep of the OUTBACK. Fun-filled and fact-packed, AROUND THE WORLD ON EIGHTY LEGS is the ticket for an unforgettable adventure!
YAK
The yakkity yakkity yakkity yak-
Why is it the yak never answers you back?
To a yak, nothing''s worse
Than to have to converse-
The yakkity yakkity yak.', 'https://images.gr-assets.com/books/1328842551m/7257331.jpg', '7257331', '4.05', '118', '50', 'https://www.goodreads.com/book/show/7257331-around-the-world-on-eighty-legs');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Revolting Rhymes & Dirty Beasts', '', 'Revolting RhymesIf you thought you knew the stories of some of the most popular fairy tales, think again. Here are six of the best known tales retold with more than a twist or two, by that master of the comic and the bloodcurdling, Roald Dahl.
Dirty BeastsMeet Roald Dahl''s ghastly menagerie of wonderful comic animals. The collection includes the poor toad that jumps to France, the pig who ponders on the meaning of life, and the anteater who gets the wrong end of the stick.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '74534', '4.21', '118', '15', 'https://www.goodreads.com/book/show/74534.Revolting_Rhymes_Dirty_Beasts');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Madwomen: The "Locas mujeres" Poems of Gabriela Mistral, a Bilingual Edition', '', 'A schoolteacher whose poetry catapulted her to early fame in her native Chile and an international diplomat whose boundary-defying sexuality still challenges scholars, Gabriela Mistral (1889-1957) is one of the most important and enigmatic figures in Latin American literature of the last century. The Locas mujerespoems collected here are among Mistral''s most complex and compelling, exploring facets of the self in extremis--poems marked by the wound of blazing catastrophe and its aftermath of mourning.
From disquieting humor to balladlike lyricism to folkloric wisdom, these pieces enact a tragic sense of life, depicting "madwomen" who are anything but mad. Strong and intensely human, Mistral''s poetic women confront impossible situations to which no sane response exists. This groundbreaking collection presents poems from Mistral''s final published volume as well as new editions of posthumous work, featuring the first English-language appearance of many essential poems. Madwomenpromises to reveal a profound poet to a new generation of Anglophone readers while reacquainting Spanish readers with a stranger, more complicated "madwoman" than most have ever known.', 'https://images.gr-assets.com/books/1328831419m/2213236.jpg', '2213236', '3.98', '117', '21', 'https://www.goodreads.com/book/show/2213236.Madwomen');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('ديوان الإمام الشافعي', '', 'yqwl lfqyh ywns bn `bd l''`l~:" kn lshf`y dh ''khdh fy l`rby@ qlt: hw bhdh ''`lm, wdh tklm fy lsh`r wnshdh qlt: hw bhdh ''`lm, wdh tklm fy lfqh qlt: hw bhdh ''`lm"', 'https://images.gr-assets.com/books/1280443735m/8680420.jpg', '8680420', '4.48', '117', '34', 'https://www.goodreads.com/book/show/8680420');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Women Poets of China', '', 'This book (originally published in 1972 by The Seabury Press as The Orchid Boat) is the first representative collection of the poetry of Chinese women to appear in English. Unlike Japan with its long tradition of women writers, poetry by women did not become fashionable in China until the Ch''ing dynasty (1644-1911), although poems from earlier centuries that do in fact survive will quickly dispel any stereotyped views. Included here are samplings from the legendary earliest poetry of courtesans, palace women, and Tao priestesses to works by contemporary Chinese women living in both the East and West. Appendixes include notes on the poems, an introductory essay on Chinese women and literature, a table of historical periods, and a bibliography.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '304433', '4.28', '116', '13', 'https://www.goodreads.com/book/show/304433.Women_Poets_of_China');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('مصر المصرية بتغنى', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6004176', '3.69', '116', '17', 'https://www.goodreads.com/book/show/6004176');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Mother Goose''s Pajama Party', '', '"Star light, star bright, come to story time tonight." You''re invited to a magical pajama party with all your nursery rhyme friends! Join Little Bo-Peep, Georgie Porgie, Miss Muffet, the cow that jumped over the moon, and all their pals as they march merrily toward Mother Goose''s house for a cozy slumber party full of stories. And after they are all tucked in, continue to the back of the book and find a special section with your favorite nursery rhymes.', 'https://images.gr-assets.com/books/1423890587m/24178192.jpg', '24178192', '3.87', '116', '41', 'https://www.goodreads.com/book/show/24178192-mother-goose-s-pajama-party');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Jelly Belly', '', 'A collection of humorous poems about all sorts of unusual people and situations.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '233636', '4.31', '116', '8', 'https://www.goodreads.com/book/show/233636.Jelly_Belly');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('El Dorado', '', 'There is a serial child killer stalking the streets of Melbourne. He kills his victims gently and places a gold mark on their head. The mark of El Dorado.
He doesn''t kill because he hates children, but because he loves them. He believes in Childhood Innocence, and he will kill to entomb them there...
This is a book about a friendship under siege, and how jealousy and betrayal cast very long shadows &#8211; which can stalk you to the grave.', 'https://images.gr-assets.com/books/1395017679m/3824832.jpg', '3824832', '3.84', '116', '7', 'https://www.goodreads.com/book/show/3824832-el-dorado');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Poems of Emily Dickinson', '', 'The Collected Poems of Emily Dickinson, by Emily Dickinson, is part of the Barnes & Noble Classicsseries, which offers quality editions at affordable prices to the student and the general reader, including new scholarship, thoughtful design, and pages of carefully crafted extras. Here are some of the remarkable features of Barnes & Noble Classics:
All editions are beautifully designed and are printed to superior specifications; some include illustrations of historical interest. Barnes & Noble Classics pulls together a constellation of influences--biographical, historical, and literary--to enrich each reader''s understanding of these enduring works.
Born in Amherst, Massachusetts in 1830, Dickinsonbegan life as an energetic, outgoing young woman who excelled as a student. However, in her mid-twenties she began to grow reclusive, and eventually she rarely descended from her room in her father''s house. She spent most of her time working on her poetry, largely without encouragement or real interest from her family and peers, and died at age fifty-five. Only a handful of her 1,775 poems had been published during her lifetime. When her poems finally appeared after her death, readers immediately recognized an artist whose immense depth and stylistic complexities would one day make her the most widely recognized female poet to write in the English language. Dickinson''s poetry is remarkable for its tightly controlled emotional and intellectual energy. The longest poem covers less than two pages. Yet in theme and tone her writing reaches for the sublime as it charts the landscape of the human soul. A true innovator, Dickinson experimented freely with conventional rhythm and meter, and often used dashes, off rhymes, and unusual metaphors--techniques that strongly influenced modern poetry. Dickinson''s idiosyncratic style, along with her deep resonance of thought and her observations about life and death, love and nature, and solitude and society, have firmly established her as o', 'https://images.gr-assets.com/books/1333576766m/13578497.jpg', '13578497', '4.21', '115', '8', 'https://www.goodreads.com/book/show/13578497-collected-poems-of-emily-dickinson');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Trout Fishing in America / The Pill versus the Springhill Mine Disaster / In Watermelon Sugar', '', 'An omnibus edition of three counterculture classics by Richard Brautigan that embody the spirit of the 1960s.
Trout Fishing in Americais by turns a hilarious, playful, and melancholy novel that wanders from San Francisco through America''s rural waterways; In Watermelon Sugarexpresses the mood of a new generation, revealing death as a place where people travel the length of their dreams, rejecting violence and hate; and The Pill Versus the Springhill Mine Disasteris a collection of nearly 100 poems, first published in 1968.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '9207144', '4.15', '115', '5', 'https://www.goodreads.com/book/show/9207144-trout-fishing-in-america-the-pill-versus-the-springhill-mine-disaster');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Cocktail Party', '', 'A modern verse play about the search for meaning, in which a psychiatrist is the catalyst for the action. "An authentic modern masterpiece" (New York Post). "Eliot really does portray real-seeming characters. He cuts down his poetic effects to the minimum, and then finally rewards us with most beautiful poetry" (Stephen Spender).', 'https://images.gr-assets.com/books/1382939971m/926667.jpg', '926667', '3.71', '115', '12', 'https://www.goodreads.com/book/show/926667.The_Cocktail_Party');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Untuk Matamu', '', '', 'https://images.gr-assets.com/books/1459087821m/29629652.jpg', '29629652', '3.92', '114', '6', 'https://www.goodreads.com/book/show/29629652-untuk-matamu');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Libertine', '', 'A sexually charged comedy by the award-winning playwright, about the life of debauched Restoration poet the Earl of Rochester, and his relationship with actress Elizabeth Barry.
The Libertine tells the story of the Earl of Rochester, friend and confidant of Charles II and the most notorious rake of his age. He was an anti-monarchist Royalist, an atheist who converted to Christianity and a lyric poet who revelled in pornography. The play centres on the moment his cynicism is confounded when he falls in love in earnest.
Thoroughly modern in its attitude to Rochester''s sexual indulgence, the play is also a thrillingly convincing portrait of the period and an accomplished comedy of manners.
Commissioned and directed by Max Stafford-Clark for Out of Joint, The Libertine was first performed on tour and at the Royal Court Theatre alongside the Restoration comedy, The Man of Mode, which offers another, contemporary view of Rochester.
Stephen Jeffreys is the author of A Going Concern, The Clink and Valued Friends, which won him the Evening Standard Most Promising Playwright Award. He also adapted A Jovial Crew for the RSC.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '732112', '3.81', '114', '10', 'https://www.goodreads.com/book/show/732112.The_Libertine');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Nature of Things', '', 'Poetry. Translated from the French by Lee Fahnestock. First published in 1942 and considered the keystone of Francis Ponge''s work, Le parti pris de chosesappears here in its entirety. It reveals his preoccupation with nature and its metaphoric transformation through the creative ambiguity of language. "My immediate reaction to Lee Fahnenstock''s translation was: this must certainly be ''Ponge''s voice in English''...[She] gives us his tones, rhythms, humor...[and] maneuvers his word play with respect and unostentatious discretion"--Barbara Wright, translator of Queneau, Pinget, Sarraute.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '418054', '3.96', '114', '8', 'https://www.goodreads.com/book/show/418054.The_Nature_of_Things');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Aeneid', '', 'This extraordinary new translation of Virgil''s Aeneidstands alone among modern translations for its accuracy and poetic appeal. Sarah Ruden, a lyric poet in her own right, renders the classic poem in the same number of lines as the original work--a very rare feat that maintains technical fidelity to the original without diminishing its emotional power.
Ruden''s translation follows Virgil''s content faithfully, and the economy and fast pace she achieves are true to his own unflagging narrative force. With its central theme of national destiny versus. the destiny of individuals, the poem has great resonance in our own times, and Ruden adheres closely to the poet''s message. Her rendering of Virgil''s words gives immediacy to his struggling faith that history has beauty and purpose in spite of its pain. With this distinguished translation, modern readers can experience for themselves the timeless power of Virgil''s masterpiece.', 'https://images.gr-assets.com/books/1328826902m/6342596.jpg', '6342596', '3.81', '113', '21', 'https://www.goodreads.com/book/show/6342596-the-aeneid');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Gilgamesh: The New Translation', '', 'The EPIC OF GILGAMESH is the oldest story that has come down to us through the ages of history. It predates the BIBLE, the ILIAD and the ODYSSEY. The EPIC OF GILGAMESH relates the tale of the fifth king of the first dynasty of Uruk (in what is modern day Iraq) who reigned for one hundred and twenty-six years, according to the ancient Sumerian King List. GILGAMESH was first inscribed in cuneiform writing on clay tablets by an unknown author during the Sumerian era and has been described as one of the greatest works of literature in the recounting of mankind''s unending quest for immortality.', 'https://images.gr-assets.com/books/1408556135m/22803099.jpg', '22803099', '3.8', '113', '20', 'https://www.goodreads.com/book/show/22803099-gilgamesh');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Fold Me a Poem', '', 'Join a young boy as he creates a world filled with origami creatures of all shapes and sizes out of an array of brightly colored paper. From roosters waking up and buffalo pawing the tablecloth to cheetahs racing lions and moths that yearn for butterfly colors, here is a glimpse into the vibrant imagination of a child.
Award-winning author Kristine O''Connell George''s thirty-two spirited poems combine seamlessly with celebrated artist Lauren Stringer''s luminous illustrations to create a poetry collection that is truly like no other.
Features an illustrator''s note and an extensive listing of origami-related books and websites.', 'https://images.gr-assets.com/books/1328876949m/620722.jpg', '620722', '3.83', '111', '42', 'https://www.goodreads.com/book/show/620722.Fold_Me_a_Poem');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Koerikoeloem', '', 'De eerste gedichtenbundel van Tjitske Jansen Het moest maar eens gaan sneeuwen(2003) is met ruim tienduizend exemplaren het best verkochte poeziedebuut van Nederland sinds Neeltje Maria Mins Voor wie ik liefheb wil ik heten(1966). Jansen las voor van Terschelling tot Kaapstad, en staat bekend om haar adembenemende optredens.
Vorig jaar liet ze op de Vlaamse radio nieuw werk horen. ''Ze trekt je mee, prikkelt je verbeelding, eist je aandacht, laat je achter met het gevoel: nee, dit kan nog niet gedaan zijn, zeg me dat het niet waar is, is dit nu al gedaan, ik eis meer!'' schreef een bewonderaar op zijn weblog nadat hij de opnames had bijgewoond. Omdat de dichteres zelf ook vond dat dit uit fragmenten opgebouwde gedicht om meer vroeg, werkte ze eraan verder. In liefdevolle observaties laat ze het verleden botsen op het heden, schakelt ze moeiteloos tussen anti-aanbakpan en God, en mixt ze documentairestijl met sprookjesfiguren. Ze toont de condition humaine aan de hand van haar persoonlijke geschiedenis.
Koerikoeloemis een zinderende compositie. Het is een mozaiek vol herinneringen. Een mozaiek van verbeelding. Eigenzinnig nieuw werk van een van de meest populaire dichteressen van dit moment.', 'https://images.gr-assets.com/books/1430490946m/2817558.jpg', '2817558', '4.17', '110', '15', 'https://www.goodreads.com/book/show/2817558-koerikoeloem');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems and Shorter Writings', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '120367', '3.82', '110', '6', 'https://www.goodreads.com/book/show/120367.Poems_and_Shorter_Writings');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Words for the Wind: The Collected Verse', '', '...
Salyangozlarla, kurbaga sicrayislariyla, geldim buraya, ruh. Soyle bana, deriden yoksun beden, bir balik terler mi? Bu damarlarin icinden surunerek gecip gidemem geri, Kivraniyorum bir baska secenek icin. Ucurumlar ! Ucurumlar firlatiyor beni gerisingeri ."
Bu kitapta yer alan siirler 1930-1963 yillari arasinda Theodore Roethke tarafindan yazildi. Roethke, deneyiciligin moda oldugu bir donemde lirik ve metafizik siirler yazdi. Insana oldugu kadar yerin yuzune de yapilmis "dikine" bir yolculuktu bu siirler ve Aysenur Guvenir ayni yolculugu 1996''da Turkce''de tekrarladi. Roethke gibi, onun da yaninda ruzgara acik bir sogut, atiyla uyuyan bir cadi, yagmurdan sirilsiklam bir orumcek vardir.', 'https://images.gr-assets.com/books/1207182295m/1089337.jpg', '1089337', '4.43', '109', '7', 'https://www.goodreads.com/book/show/1089337.Words_for_the_Wind');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('أوراق العشب', '', 'Whitman is today regarded as America''s Homer or Dante, and his work the touchstone for literary originality in the New World. In Leaves of Grass, he abandoned the rules of traditional poetry - breaking the standard metred line, discarding the obligatory rhyming scheme, and using the vernacular. Emily Dickinson condemned his sexual and physiological allusions as `disgraceful'', but Emerson saw the book as the `most extraordinary piece of wit and wisdom that America has yet contributed''. A century later it is his judgement of this autobiographical vision of the vigour of the American nation that has proved the more enduring. This is the most up-to-date edition for student use, with full critical apparatus.', 'https://images.gr-assets.com/books/1330225134m/13500593.jpg', '13500593', '4.13', '108', '31', 'https://www.goodreads.com/book/show/13500593');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Infinitesimals', '', '"Kasischke''s poems are powered by a skillful use of imagery and the subtle, ingenious way she turns a phrase."--Austin American-Statesman
The Infinitesimalsstares directly at illness and death, employing the same highly evocative and symbolic style that earned Laura Kasischke the 2012 National Book Critics Circle Award for poetry. Drawing upon her own experiences with cancer, and the lives and deaths of loved ones, Kasischke''s new work commands a lyrical and dark intensity.
Laura Kasischkeis the author of eight collections of poetry and seven novels. She teaches at the University of Michigan and lives in Ann Arbor, Michigan.', 'https://images.gr-assets.com/books/1380493168m/18528280.jpg', '18528280', '4.32', '108', '14', 'https://www.goodreads.com/book/show/18528280-the-infinitesimals');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Letters To A Young Poet', '', 'Rilke''s timeless letters about poetry, sensitive observation, and the complicated workings of the human heart.
Born in 1875, the great German lyric poet Rainer Maria Rilke published his first collection of poems in 1898 and went on to become renowned for his delicate depiction of the workings of the human heart. Drawn by some sympathetic note in his poems, young people often wrote to Rilke with their problems and hopes. From 1903 to 1908 Rilke wrote a series of remarkable responses to a young, would-be poet on poetry and on surviving as a sensitive observer in a harsh world. Those letters, still a fresh source of inspiration and insight, are accompanied here by a chronicle of Rilke''s life that shows what he was experiencing in his own relationship to life and work when he wrote them.', 'https://images.gr-assets.com/books/1395944320m/21792868.jpg', '21792868', '4.34', '108', '8', 'https://www.goodreads.com/book/show/21792868-letters-to-a-young-poet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Understanding Poetry', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '668953', '3.95', '107', '12', 'https://www.goodreads.com/book/show/668953.Understanding_Poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Teatro', '', 'Stefano Benni e il teatro: una felice consuetudine che dura da piu di dieci anni, una formidabile miscela di fantasia, comicita corosiva e invenzioni, tutte per la scena e molto spesso dedicate agli amici attori (soprattuto attrici) e registi che ne sono stati gli interpreti e realizzatori.', 'https://images.gr-assets.com/books/1331581084m/177299.jpg', '177299', '3.49', '105', '3', 'https://www.goodreads.com/book/show/177299.Teatro');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Aeneid', '', 'Translated by Michael J. Oakley
The Aeneid is Virgil''s Masterpiece. His epic poem recounts the story of Rome''s legendary origins from the ashes of Troy and proclaims her destiny of world dominion. This optimistic vision is accompanied by an undertow of sadness at the price that must be paid in human suffering to secure Rome''s future greatness. The tension between the public voice of celebration and the tragic private voice is given full expression both in the doomed love of Dido and Aeneas, and in the fateful clash between the Trojan leader and the Italian hero, Turnus. Hailed by T.S. Eliot as ''the classic of all Europe'', Virgil''s Aeneid has enjoyed a unique and enduring influence on European literature, art and politics for the past two thousand years.', 'https://images.gr-assets.com/books/1397760430m/831071.jpg', '831071', '3.81', '105', '11', 'https://www.goodreads.com/book/show/831071.The_Aeneid');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Domestic Violence: Poems', '', 'These are poems about the charged spaces in which people live, about the interiors where seductions, quarrels, memories, and griefs occur. A marriage is a window for outward violence; a painted cup becomes a theater for a long love; in an ordinary room a mythic violation takes place.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '256029', '4.08', '105', '12', 'https://www.goodreads.com/book/show/256029.Domestic_Violence');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hallelujah Anyway', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1650189', '4.54', '104', '4', 'https://www.goodreads.com/book/show/1650189.Hallelujah_Anyway');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Resurrection Update: Collected Poems, 1975-1997', '', 'The complete works of an extraordinary poet who consistently refines the notion of what constitutes an Americansound.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '218985', '4.31', '104', '10', 'https://www.goodreads.com/book/show/218985.Resurrection_Update');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Evening Train: Poetry', '', 'At her most moving and meditative, impressive and musical, Denise Levertov addresses in her poetry collection, Evening Train, the nature of faith and love, the imperiled beauty of the natural world, and the horrors of the Gulf War.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '396581', '4.22', '103', '5', 'https://www.goodreads.com/book/show/396581.Evening_Train');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Madonna Anno Domini: Poems', '', 'In his first collection, Joshua Clover presents a harrowing poetic manifesto for the coming century. Clover fuses formal control, a solid grounding in poetic tradition (his allusions range from Shakespeare to Dickinson to John Cale), and sheer visionary exhilaration into a technical, moral, aesthetic, and imaginative lexicon that irradiates each page.The eerie cyberglow of Clover''s lines illuminates a pageant of blurred and fragmented desolation: the Bomb, death camps, the Persian Gulf War, the beating of Rodney King, the whole numbing litany of modern horrors. Clover is a master of poetic shorthand, of the stark, unnerving image as immediate as yellow tape at a crime scene.
Madonna anno domini is a sacrament for the twilight of the atomic age, a hellish Interzone with "God in abeyance" where dazed speakers search through the vertigo of negation for love and belief. And here. in this utterly convincing vision of a world whose center has long since lost its hold, we see the life on whose brink we, at the end of the millennium, find ourselves poised.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1415440', '3.97', '103', '8', 'https://www.goodreads.com/book/show/1415440.Madonna_Anno_Domini');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poets'' Grimm: 20th Century Poems from Grimm Fairy Tales', '', 'Writers and readers have long been inspired by the haunting wisdom and sheer imaginative power to be found in the fairy tales of the immortal Brothers Grimm. The editors have collected more than a hundred poems inspired by Grimm tales and written by our finest living poets. A brilliant and informative anthology, a teachable text. Jeanne Marie Beaumont first book of poetry, "Placebo Effects," was selected by William Matthews for the National Poetry Series in 1997. She teaches at Rutgers University. Claudia Carlson works at Oxford University Press in New York. Her poems have appeared in "Heliotrope, Coracle, Space and Time, Fantastic Stories" and "NYCBigCityLit.comm"', 'https://images.gr-assets.com/books/1377169834m/410289.jpg', '410289', '4.02', '103', '17', 'https://www.goodreads.com/book/show/410289.The_Poets_Grimm');
