INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Arcanum 17', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '168311', '3.56', '102', '7', 'https://www.goodreads.com/book/show/168311.Arcanum_17');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('What Are You Glad About? What Are You Mad About?: Poems for When a Person Needs a Poem', '', 'From the beloved and internationally bestselling author of Alexander and the Terrible, Horrible, No Good, Very Bad Day, Judith Viorst comes a brand-new collection of clever, hilarious, and poignant poems that touch on every aspect of the roller-coaster ride that is childhood.
Did you wake up this morning all smiley inside?
Does life taste like ice cream and cake?
Or does it seem more like your goldfish just died
And your insides are one great big ache?
From school to family to friends, from Grrrr to Hooray!, Judith Viorst takes us on a tour of feelings of all kinds in this thoughtful, funny, and charming collection of poetry that&#8217;s perfect for young readers just learning to sort out their own emotions.', 'https://images.gr-assets.com/books/1439913848m/25785774.jpg', '25785774', '3.85', '102', '31', 'https://www.goodreads.com/book/show/25785774-what-are-you-glad-about-what-are-you-mad-about');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Theogony. Works and Days. Testimonia.', '', 'Hesiod describes himself as a Boeotian shepherd who heard the Muses call upon him to sing about the gods. His exact dates are unknown, but he has often been considered a younger contemporary of Homer. This volume of the new Loeb Classical Library edition offers a general introduction, a fluid translation facing an improved Greek text of Hesiod''s two extant poems, and a generous selection of testimonia from a wide variety of ancient sources regarding Hesiod''s life, works, and reception.
In "Theogony" Hesiod charts the history of the divine world, narrating the origin of the universe and the rise of the gods, from first beginnings to the triumph of Zeus, and reporting on the progeny of Zeus and of goddesses in union with mortal men. In "Works and Days" Hesiod shifts his attention to the world of men, delivering moral precepts and practical advice regarding agriculture, navigation, and many other matters; along the way he gives us the myths of Pandora and of the Golden, Silver, and other Races of Men.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '694475', '4.25', '101', '7', 'https://www.goodreads.com/book/show/694475.Theogony_Works_and_Days_Testimonia_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Fanny Says', '', 'An "unleashed love song" to her late grandmother, Nickole Brown''s collection brings her brassy, bawdy, tough-as-new-rope grandmother to life. With hair teased to Jesus, mile-long false eyelashes, and a white Cadillac Eldorado with atomic-red leather seats, Fanny is not your typical granny rocking in a chair. Instead, think of a character that looks a lot like Eva Gabor in Green Acres, but darkened with a shadow of Flannery O''Connor. A cross-genre collection that reads like a novel, this book is both a collection of oral history and a lyrical and moving biography that wrestles with the complexities of the South, including poverty, racism, and domestic violence.', 'https://images.gr-assets.com/books/1414003093m/23129933.jpg', '23129933', '4.49', '101', '14', 'https://www.goodreads.com/book/show/23129933-fanny-says');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'This new addition to the elegant Library of Classic Poets series features selections from one of the best-loved poets of the early twentieth century. Elegantly packaged in a handsome edition with a satin ribbon marker, this volume is the perfect addition to any poetry library. From the prolific T.S. Eliot, a pioneer of modernism, here are his most groundbreaking works, including:
* "The Wasteland"
* "The Love Song of J. Alfred Prufrock"
* "Mr. Eliot''s Sunday Morning Service"', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '65338', '4.24', '101', '8', 'https://www.goodreads.com/book/show/65338.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', '', 'https://images.gr-assets.com/books/1309199052m/375181.jpg', '375181', '4.12', '101', '12', 'https://www.goodreads.com/book/show/375181.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hyperion a Fragment', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2715832', '4.1', '101', '6', 'https://www.goodreads.com/book/show/2715832-hyperion-a-fragment');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Tristimania', '', 'Tristimania is Mary Ruefle''s eighth book of poems.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '508152', '4.25', '100', '9', 'https://www.goodreads.com/book/show/508152.Tristimania');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Yes! We Are Latinos: Poems and Prose About the Latino Experience', '', 'Juanita lives in New York and is Mexican. Felipe lives in Chicago and is Panamanian, Venezuelan, and black. Michiko lives in Los Angeles and is Peruvian and Japanese. Each of them is also Latino.
Thirteen young Latinos and Latinas living in America are introduced in this book celebrating the rich diversity of the Latino and Latina experience in the United States. Free-verse fictional narratives from the perspective of each youth provide specific stories and circumstances for the reader to better understand the Latino people''s quest for identity. Each profile is followed by nonfiction prose that further clarifies the character''s background and history, touching upon important events in the history of the Latino American people, such as the Spanish Civil War, immigration to the US, and the internment of Latinos with Japanese ancestry during World War II.
Alma Flor Ada and F. Isabel Campoy''s informational yet heartwarming text provides a resource for young Latino readers to see themselves, while also encouraging non-Latino children to understand the breadth and depth of the contributions made by Latinos in the US. Caldecott Medalist David Diaz''s hand-cut illustrations are bold and striking, perfectly complementing the vibrant stories in the book.
YES! WE ARE LATINOS stands alone in its presentation of the broad spectrum of Latino culture and will appeal to readers of fiction and nonfiction.', 'https://images.gr-assets.com/books/1389592118m/16670129.jpg', '16670129', '4.09', '100', '34', 'https://www.goodreads.com/book/show/16670129-yes-we-are-latinos');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Tako zamišljam nebo', '', '', 'https://images.gr-assets.com/books/1402993851m/12143095.jpg', '12143095', '4.81', '100', '5', 'https://www.goodreads.com/book/show/12143095-tako-zami-ljam-nebo');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('William Shakespeare: The Complete Works', '', '"But thy eternal summer shall not fade"
"Nor lose possession of that fair thou ow''st; "
"Nor shall Death brag thou wander''st in his shade, "
"When in eternal lines to time thou grow''st: "
"So long as men can breathe, or eyes can see, "
"So long lives this, and this gives life to th"ee.
-- from Sonnet 18
No home should be without this: every play, from the early histories to the sad, wise" Winter''s Tale "and "The Tempest"; every exquisitely crafted sonnet; every long poem (such as "Venus and Adonis" and "The Rape of Lucrece") written by the greatest writer in the English language. This edition of the Bard of Avon''s complete works is a facsimile of the definitive Shakespeare Head edition published originally in Oxford, England. All the plays are arranged in chronological order of their composition, rather than by genre, so that the evolution of Shakespeare''s monumental genius can be more easily followed and appreciated.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1344192', '4.47', '99', '10', 'https://www.goodreads.com/book/show/1344192.William_Shakespeare');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Transfer', '', '"In the current literary scene, one of the most heartening influences is the work of Naomi Shihab Nye. Her poems combine transcendent liveliness and sparkle along with warmth and human insight. She is a champion of the literature of encouragement and heart. Reading her work enhances life."-- William Stafford
Dusk
where is the name no one answered to
gone off to live by itself
beneath the pine trees separating the houses
without a friend or a bed
without a father to tell it stories
how hard was the path it walked on
all those years belonging to none
of our struggles drifting under
the calendar page elusive as
residue when someone said
how have you been it was
strangely that name that tried
to answer
Naomi Shihab Nye has spent thirty-five years traveling the world to lead writing workshops and inspire students of all ages. In her newest collection Transfershe draws on her Palestinian American heritage, the cultural diversity of her home in Texas, and her extensive travel experiences to create a poetry collection that attests to our shared humanity.
Among her awards, Naomi Shihab Nyehas been a Lannan Fellow, a Guggenheim Fellow, and a Witter Bynner Fellow. She has received a Lavan Award from the Academy of American Poets, the Isabella Gardner Poetry Award, the Paterson Poetry Prize, and four Pushcart prizes. In January 2010, she was elected to the board of chancellors of the Academy of American Poets.', 'https://images.gr-assets.com/books/1344711913m/11715347.jpg', '11715347', '4.31', '99', '23', 'https://www.goodreads.com/book/show/11715347-transfer');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Natural History', '', 'Dan Chiasson, hailed as "one of the most gifted poets of his generation" upon the appearance of his first book, takes inspiration for his stunning new collection from the Historia Naturalisof Pliny the Elder.
"What happens next, you won''t believe," Chiasson writes in "From the Life of Gorky," and it is fair warning. This collection suggests that a person is like a world, full of mysteries and wonders-and equally in need of an encyclopedia, a compendium of everything known. The long title sequence offers entries such as "The Sun" ("There is one mind in all of us, one soul, / who parches the soil in some nations / but in others hides perpetually behind a veil"), "The Elephant" ("How to explain my heroic courtesy?"), "The Pigeon" ("Once startled, you shall feel hours of weird sadness / afterwards"), and "Randall Jarrell" ("If language hurts you, make the damage real"). The mysteriously emotional individual poems coalesce as a group to suggest that our natural world is populated not just by fascinating creatures-who, in any case, are metaphors for the human as Chiasson considers them- but also by literature, by the ghosts of past poetries, by our personal ghosts. Toward the end of the sequence, one poem asks simply, "Which Species on Earth Is Saddest?" a question this book seems poised to answer. But Chiasson is not finally defeated by the sorrows and disappointments that maturity brings. Combining a classic, often heartbreaking musical line with a playful, fresh attack on the standard materials of poetry, he makes even our sadness beguiling and beautiful.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '821682', '3.86', '98', '16', 'https://www.goodreads.com/book/show/821682.Natural_History');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Kitchen Sink: New and Selected Poems, 1972-2007', '', '"Albert Goldbarth is . . . a contemporary genius with the language itself . . . There is simply no contemporary poet like him." --David Baker, The Kenyon Review
Albert Goldbarth has created an unmistakable signature style--learned, copious, hilarious, and heartbreaking--which has so far spanned an award-winning career of thirty-five years. The Kitchen Sinkbrings together forty new poems with a rich selection of earlier poetry, ranging from the brief, flickering lyric to the long, narrative sequence. In both forms, Goldbarth exerts a wild showmanship and an ever-widening scope to illustrate the complex character and interconnectedness of humanity, history, and art. The Kitchen Sinkis the definitive book by one of America''s most original and entertaining poets.', 'https://images.gr-assets.com/books/1316729528m/216122.jpg', '216122', '4.16', '98', '15', 'https://www.goodreads.com/book/show/216122.The_Kitchen_Sink');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems of Pablo Neruda', '', 'The perfect gift for Valentine''s Day
Selected Poems contains Neruda''s resonant, exploratory, intensely individualistic verse, rooted in the physical landscape and people of Chile. Here we find sensuous songs of love, tender odes to the sea, melancholy lyrics of heartache, fiery political statements and a frank celebration of sex. This is an enticing, distinctive and celebrated collection of poetry from the greatest twentieth century Latin American poet.', 'https://images.gr-assets.com/books/1333576324m/13142341.jpg', '13142341', '4.39', '98', '14', 'https://www.goodreads.com/book/show/13142341-selected-poems-of-pablo-neruda');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('My America: A Poetry Atlas of the United States', '', 'In My America,Lee Bennett Hopkins weaves together fifty poems -- grouped by geographic region -- to create a remarkable portrait of the United States. Here is America in all its stunning variety, from the dramatic seacoast of the Northeast and the rippling cornfields of the Plains States to the shimmering deserts of the Southwest and the majestic redwood forests of the Pacific Coast. But here, too, are the ties that bind this nation together -- the hopes and dreams of those who live in our cities and towns and on farms.
The voices of beloved poets like Langston Hughes, Carl Sandburg, Nikki Giovanni, and Lilian Moore blend with new voices to sing not just of landmarks like the Mississippi River, the Grand Canyon, and the Everglades, but of daily life across the land. Complementing these personal, moving visions of America are maps of the regions and fascinating facts for each state.
Stephen Alcorn''s brilliant, textured artwork makes this book a feast for the eyes as well as for the imagination. Impressive for its breadth, depth, and beauty, My Americais a volume readers will savor as they read it time and time again. It is fitting homage to our wideranging, ever-changing land.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '467119', '3.82', '98', '29', 'https://www.goodreads.com/book/show/467119.My_America');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Samlade dikter: 1954–1996', '', 'Alla Tomas Transtromers hittills utgivna diktsamlingar - i en volym fran debutboken "17 dikter" till och med "Sorgegondolen" som utkom 1996.', 'https://images.gr-assets.com/books/1344254611m/865204.jpg', '865204', '4.23', '98', '6', 'https://www.goodreads.com/book/show/865204.Samlade_dikter');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Borderlands/La Frontera', '', 'First published in 1987, "Borderlands" has become a classic in Chicano border studies, feminist theory, gay and lesbian studies, and cultural studies. Anzaldua, a Chicana native of Texas, explores in prose and poetry the murky, precarious existence of those living on the frontier between cultures and languages. Writing in a lyrical mixture of Spanish and English that is her unique heritage, she meditates on the condition of Chicanos in Anglo culture, women in Hispanic culture, and lesbians in the straight world. Her essays and poems range over broad territory, moving from the plight of undocumented migrant workers to memories of her grandmother, from Aztec religion to the agony of writing. Anzaldua is a rebellious and willful talent who recognizes that life on the border,"life in the shadows,"is vital territory for both literature and civilization. Venting her anger on all oppressors of people who are culturally or sexually different, the author has produced a powerful document that belongs in all collections with emphasis on Hispanic American or feminist issues.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '598195', '4.25', '98', '8', 'https://www.goodreads.com/book/show/598195.Borderlands_La_Frontera');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('One Hundred More Poems from the Chinese: Love and the Turning Year', '', 'Love and the Turning Yearincludes a selection from the Yueh Fu--folk songs from the Six Dynasties Period (fourth-fifth centuries A.D.). Most of the songs are simple, erotic lyrics. Some are attributed to legendary courtesans, while others may have been sung at harvest festivals or marriage celebrations. In addition to the folk songs, Rexroth offers a wide sampling of Chinese verse: works by 60 different poets, from the third century to our own time. Rexroth always translated Chinese poetry--as he said--"solely to please myself." And he created, with remarkable success, English versions which stand as poems in their own right.', 'https://images.gr-assets.com/books/1486602119m/236184.jpg', '236184', '4.31', '98', '11', 'https://www.goodreads.com/book/show/236184.One_Hundred_More_Poems_from_the_Chinese');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Literary Christmas: An Anthology', '', 'For as long as Christmas has been celebrated, poets and writers have sought to explore every aspect of it, from the story of the nativity to the festive traditions families worldwide have established over the centuries. And such works have forever changed the way we think about the holiday. Where would Christmas be today without Ebenezer Scrooge or "''Twas the Night Before Christmas"?
A Literary Christmasis a seasonal compendium that collects poems, short stories, and prose by some of the greatest poets and writers in the English language. Like Charles Dickens''s Ghosts of Christmas Past and Present, the selections featured here are representative of times old and new. Readers will enjoy a convivial Christmas Day with Samuel Pepys, Anthony Trollope, George Eliot, and Nancy Mitford; venture out into the snow in the company of Jane Austen, Henry James, and Charles Dickens''s ever-popular Mr. Pickwick; and warm up by the fire with the seasonal tales of Dylan Thomas, Kenneth Grahame, and Oscar Wilde. As a companion to the book, A Literary Christmasis also being released as a two-CD set, featuring readings of many of the same poems and prose extracts from the book. An entertaining and instructive way to survey great literature, A Literary Christmasis the perfect gift for anyone seeking to start their own literary Christmas traditions.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '17674218', '3.95', '98', '21', 'https://www.goodreads.com/book/show/17674218-a-literary-christmas');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Leaves of Grass', '', 'Whitman is today regarded as America''s Homer or Dante, and his work the touchstone for literary originality in the New World. In Leaves of Grass, he abandoned the rules of traditional poetry - breaking the standard metred line, discarding the obligatory rhyming scheme, and using the vernacular. Emily Dickinson condemned his sexual and physiological allusions as `disgraceful'', but Emerson saw the book as the `most extraordinary piece of wit and wisdom that America has yet contributed''. A century later it is his judgement of this autobiographical vision of the vigour of the American nation that has proved the more enduring. This is the most up-to-date edition for student use, with full critical apparatus.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '28962764', '4.13', '98', '3', 'https://www.goodreads.com/book/show/28962764-leaves-of-grass');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Holding Company: Poems', '', 'In Holding Company, Major Jackson explores art, literature, and music as a kingdom, or an empire, a dark, seductive force in our lives. In an effort to understand desire, beauty, and love as transient anodynes to metaphysical loneliness, he invokes Constantine Cavafy, Pablo Neruda, Anna Akhmatova, and Dante Rossetti.
from "Jewel-Tongued"
The stillness of a lover''s mouth
assaulted me. I never wearied of anecdotes
on the Commons, gesturing until I scattered
myself into a luminance, shining over a city
of women. Was I less human or more? I hear still
my breathing echoing off their pillows. So many
eyes like crushed flowers. Our fingers splayed
over a bed''s edge. We were blown away.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '7786942', '3.59', '97', '12', 'https://www.goodreads.com/book/show/7786942-holding-company');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Tell Me Where It Hurts', '', 'Bestselling author J.R. Rogue returns with her second volume of poetry, Tell Me Where It Hurts, a raw, heartbreaking, and honest glimpse into the demons she has faced in her 33 years.', 'https://images.gr-assets.com/books/1463339739m/30193342.jpg', '30193342', '4.34', '97', '27', 'https://www.goodreads.com/book/show/30193342-tell-me-where-it-hurts');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Execution Poems: The Black Acadian Tragedy of "George and Rue"', '', 'Gaspereau Press'' best-selling title, Execution Poems, is George Elliott Clarke''s complex lament for his late cousins, George and Rue - two Black men who were hanged for the murder of a taxi driver. After the overwhelming interest generated by the original limited letterpress edition of Execution Poems, Gaspereau Press released this trade edition which went on to win Canada''s highest literary honour in 2001. The jurors of the Governor General''s Literary Award called this book "raging, gristly, public -- and unflinchingly beautiful," and remarked on Clarke''s "explosive, original language."
In 1949, George and Rufus Hamilton were hanged for the murder of a taxi driver in Fredericton, New Brunswick. Fifty years later, Clarke has written, in his abundant style, a series of poems that embody both damnation and redemption, offering convoluted triumphs alongside tragedy and blurring the line between perpetrator and victim. What Clarke presents in Execution Poemsis uncomfortable. He reminds us of racism and poverty; of their brutal, tragic results. He reminds us of society''s vengefulness. He blurs the line between the perpetrator and the victim -- a line we''d prefer remain simple and clear. At the heart of it, Clarke is frustrating the notion that society deals any better with these issues today than it did in the 1940s.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '325698', '3.99', '97', '4', 'https://www.goodreads.com/book/show/325698.Execution_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Adam Robison and Other Poems', '', 'Poetry. "Not only my favorite title of the year, but this is also a book I have been waiting to hold in my hands with great anticipation for quite some time--as a friend, yes, but more so in language glee. Adam can truly speak it in a way I have never heard anyone else speak. This is going to be one to drink milk in bed with"--Blake Butler. "From trompe l''oeil title to anomalous index, this is a book of pristine openings and closings, preoccupied with structure, literary convention, popular and intellectual culture, biography, genre and identity. Somewhat skeptically, it marks out a testing ground for poetry. And poetry, confident in those sparkling titles and last lines, jumps into the ring"--Mairead Byrne.', 'https://images.gr-assets.com/books/1266422518m/7745585.jpg', '7745585', '4.49', '96', '19', 'https://www.goodreads.com/book/show/7745585-adam-robison-and-other-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Stranger Manual', '', 'Catie Rosemurgy''s second collection, The Stranger Manual, is a wild rush across the American grain. The poems follow an unlikely character named Miss Peach, an unpredictable, cartoonish shapeshifter, who emerges onto the page dragging the myth of the individual, various gender scripts, and the grand tradition of the poetic persona along with her. She becomes an outsider, a hero, an intruder, a rock star. The town around her, Gold River, is also always in flux--part center and part mirage. The Stranger Manualcelebrates the fractious nature of self and society in poems that are fabulist, speculative, and alluring.', 'https://images.gr-assets.com/books/1312035784m/7049415.jpg', '7049415', '4.18', '96', '13', 'https://www.goodreads.com/book/show/7049415-the-stranger-manual');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('What is Goodbye?', '', 'Jerilyn and Jesse have lost their beloved older brother. But each of them deals with Jaron''s death differently. Jerilyn tries to keep it in and hold it together; Jesse acts out. But after a year of anger, pain, and guilt, they come to understand that it''s time to move on. It''s time for a new family picture-with one piece missing, yet whole again. Through the alternating voices of a brother and sister, Nikki Grimes eloquently portrays the grieving process in this gem of a book that is honest, powerful, and ultimately hopeful. Nikki Grimes is the distinguished author of more than two-dozen children''s books. She received the 2003 Coretta Scott King Award for her novel Bronx Masquerade and a 2003 Coretta Scott King Honor citation for Talkin'' About Bessie. Many of her books have been cited as Notable Books by the American Library Association, including Come Sunday, a picture book in verse; Something on My Mind; and Meet Danitra Brown, which also won a Coretta Scott King Honor. She lives in southern California.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '972086', '3.88', '96', '31', 'https://www.goodreads.com/book/show/972086.What_is_Goodbye_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Odyssey: Translated by Robert Fitzgerald', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '18165617', '4.13', '95', '14', 'https://www.goodreads.com/book/show/18165617-the-odyssey');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hiawatha', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '913271', '4.14', '95', '12', 'https://www.goodreads.com/book/show/913271.Hiawatha');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Midnight Monologues', '', 'Midnight Monologues is Charissa Ong Ty''s first published English Poetry and Short Stories book. The book is categorized into four parts, LOST, FOUND, HOPE and Short Stories. In an age of lesser readers and short attention spans, she hopes this book could stir ideas in the most efficient way possible; through really short, melodious writing.
She is currently working on her second book, titled Daylight Dialogues and plans to release it next year.
Awards
- Award-Winning Finalist in the "Poetry" category of the 2017 International Book Awards
- Award-Winning Finalist in the "Best Cover Design: Fiction" category of the 2017 International Book Awards
- MPH Best Paperback Fiction Nominee 2016
Get it on Amazon Kindle:
http://amzn.to/2AHkNzT', 'https://images.gr-assets.com/books/1464079955m/30278847.jpg', '30278847', '4.18', '94', '28', 'https://www.goodreads.com/book/show/30278847-midnight-monologues');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('On the Rocks', '', 'Read a brand new Ellen Hopkins story EXCLUSIVELY on Wattpad
A young widow and a complicated doctor spend an explosive night together with unintended consequences in this prequel to Ellen Hopkins'' LOVE LIES BENEATH.', 'https://images.gr-assets.com/books/1433214749m/25647256.jpg', '25647256', '3.65', '94', '13', 'https://www.goodreads.com/book/show/25647256-on-the-rocks');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Understanding Poetry (The Modern Scholar: Way with Words, Vol. 4)', '', 'Wheaton College English professor Michael D.C. Drout submerses listeners in poetry''s past, present, and future, addressing such poets as Milton, Wordsworth, Shelley, and Keats, and explaining in simple terms what poetry is while following its development through the centuries.', 'https://images.gr-assets.com/books/1279653353m/6435705.jpg', '6435705', '4.16', '93', '5', 'https://www.goodreads.com/book/show/6435705-understanding-poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poetry Speaks Expanded', '', 'By the time you''re done, your biggest problem may be that you wish there was more."
WALL STREET JOURNAL
"The definitive anthology of poets reading their own work."
-- PUBLISHERS WEEKLY
"This grand immersion in poetry follows the best-selling Poetry Speaks (2001) and includes a never-before-published and truly thrilling recording of James Joyce reading "Anna Livia Plurabelle" from Finnegans Wake. Book and CDs work beautifully together, kindling deeper appreciation for the transmuting power of poetry, a practice of discipline, skill, and magic."
- BOOKLIST
..".The prose comes to life when read aloud, especially when you hear James Joyce read it himself."
NPR''s ALL THINGS CONSIDERED host Jacki Lyden
"This tome is a reminder how the human spirit is capable of finding an outlet in oppressive times, how poetry can help explain why we do what we do as a thinking people...Certainly, in our struggle to make sense out of what we do not understand, Poetry Speaks Expanded helps on so many levels." Carol Hoenig, THE HUFFINGTON POST
..".[A] bountiful experience: there is the thrill of discovery and re-discovery as with any good anthology, with an added emphasis on the poets'' personalities and growth" John Hammond, SAN ANTONIO EXPRESS-NEWS
"[An] accessible, beautifully executed collection guaranteed to offer poetry fans a memorable reading and listening experience" WORDCANDY.NET
..".[A]s I savored these beautiful poems, it reminded me of French poet Charles Baudelaire who wrote, ''Any man can go without food for two days - but not without poetry.''" - Norm Goldman, BOOKPLEASURES.COM
"Light[s] up a reader''s eyes." - Frank Wilson, PHILADELPHIA INQUIRER
Hear And Read All Of These Poets (And More)
244 Poems Included In The Book
107 Poems Read By The Poets Themselves On 3 Audio CDs
Robert Graves, E. E. Cummings, Walt Whitman, Ezra Pound, William Butler Yeats, Gertrude Stein, Carl Sandburg, James Joyce, William Carlos Williams, Ted Hughes, Robinson Jeffers, Philip Larkin, Wallace Stevens,', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1206077', '4.52', '93', '15', 'https://www.goodreads.com/book/show/1206077.Poetry_Speaks_Expanded');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Lady Of Shalott', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '13647986', '4.17', '93', '7', 'https://www.goodreads.com/book/show/13647986-the-lady-of-shalott');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('فاوست', '', 'Faust, tragedie de M. de Goethe, traduite en francais par M. Albert Stapfer. Ornee d''un portrait de l''auteur, et de 17 dessins composes d''apres les principales scenes de l''ouvrage et executes sur pierre par M. Eugene DelacroixDate de l''edition originale: 1828Sujet de l''ouvrage: Goethe, Johann Wolfgang von (1749-1832) -- PortraitsCe livre est la reproduction fidele d''une oeuvre publiee avant 1920 et faitPartie d''une collection de livres reimprimes a la demande editee par Hachette Livre, dans le cadre d''un partenariat avec la Bibliotheque nationale de France, offrant l''opportunite d''acceder a des ouvrages anciens et souvent rares issus des fonds patrimoniaux de la BnF.Les oeuvres faisantPartie de cette collection ont ete numerisees par la BnF et sont presentes sur Gallica, sa bibliotheque numerique.En entreprenant de redonner vie a ces ouvrages au travers d''une collection de livres reimprimes a la demande, nous leur donnons la possibilite de rencontrer un public elargi et participons a la transmission de connaissances et de savoirs parfois difficilement accessibles.Nous avons cherche a concilier la reproduction fidele d''un livre ancien a partir de sa version numerisee avec le souci d''un confort de lecture optimal. Nous esperons que les ouvrages de cette nouvelle collection vous apporteront entiere satisfaction.Pour plus d''informations, rendez-vous sur www.hachettebnf.frhttp://gallica.bnf.fr/ark:/12148/bpt6k134831w', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '3652189', '3.97', '93', '10', 'https://www.goodreads.com/book/show/3652189');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Goblin Market', '', 'This lovely gift edition of Christina Rossetti''s most famous poem will enchant readers of all ages. For children, the story offers a captivating adventure into a land of fantasy. For adults, it''s a lyric and sensual allegory of temptation, sacrifice, and salvation. Arthur Rackham, a peerless illustrator of fairy tales and supernatural creatures, portrays the poem''s otherworldly attractions in four color and 20 black-and-white images plus a reproduction of a rare watercolor.', 'https://images.gr-assets.com/books/1347045137m/8471063.jpg', '8471063', '4.08', '93', '9', 'https://www.goodreads.com/book/show/8471063-goblin-market');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Practical Water', '', 'Winner of the Los Angeles Times Book Award for Poetry (2009)
Finalist for the Northern California Book Award for Poetry (2009)
Practical Water is, like Brenda Hillman''s previous two books, Cascadia and Pieces of Air in the Epic, both an elemental meditation and an ecopoetics; this time her subject is water: Taoist water, baptismal water, water from the muses'' fountains, the practical waters of hydrology from which we draw our being--and the stilled water in a glass in a Senate chamber. Not since Allen Ginsberg tried to levitate the Pentagon has American poetry seen the likes of the hallucinatory wit and moral clarity that Hillman brings to Washington in her poems about Congressional Hearings on the Iraq War. Here also--because it is about many kinds of power--is a sequence of twinned lyrics for the moon, governess of tides and night vision, for visible and invisible faces. Violence and the common world, fact and dream, science and magic, intuition and perception are reconfigured as the poet explores matters of spirit in political life and earthly fate. If it is time to weep by the waters of Babylon, it is also time to touch water''s living currents. No one is reimagining the possibilities of lyric poetry with more inventiveness; this is masterful work by one of our finest poets.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6421376', '4.0', '92', '11', 'https://www.goodreads.com/book/show/6421376-practical-water');
