INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poesias Completas', '', 'A meio do seculo passado ja me apercebera, confusamente, que tanto ou mais do que eu estavam doentes as palavras...
"A meio do seculo passado ja me apercebera, confusamente, que tanto ou mais do que eu estavam doentes as palavras. Uma terapeutica, a do alambique, levaria a meditacao do branco sobre o branco, e no melhor dos casos ao silencio. A da ignicao, se permitia revelacoes -- nos teus bonitos, banais, olhos castanhos, o favor do seu "verde secreto" -- carregava ainda as execraveis maiusculas "Amor, Aventura, Poesia", e com elas a fantasmagoria do sagrado, a "vida mentirosa, mental". Outra comecava em No Reino da Dinamarca, dura e feroz como a abrir nos fora dito: "diamante cruel". Supunha um diagnostico: o destino como "solidao e magoa", o "quotidiano nao", a vida que "nao vivemos", a vizinhanca do grotesco normal, do vil decente, e ainda, contudo, o beijo do "jovem amor que recebeu / mandado de captura ou de despejo". Sobretudo, para quem lia ou, pior, escrevia versos, mandava romper com a "poetica poesia", afastar os "cabeleireiros de palavras, / pirotecnicos do estupor", lutar contra o "bonito" para fazer "bom". Noutra aparentemente diversa circunstancia, quanta merecida e salutar bofetada nos da O''Neill. Ir, ao contrario, buscar saude a linguagem doente, no sarcasmo e no jogo, no sem cerimonia e no impuro; e a meio, dizer serenamente algumas verdades decisivas, algumas emblematicas: que o medo "tudo vai ter" ou o "remorso de todos nos". Mallarme, -- "a tristeza e que nao ha por lustro um", decerto sob o lustre - nao se limitava, nao se limita para nos, a reduzir o pobre mundo nosso as sobras do poema; diz-nos antes que a poesia pode e deve atravessar a realidade toda, ate ao singular e insigificante, e ao impossivel que lhe resiste, tipo mosca Albertina. Tornar-se livro o mundo, e tornar-se mundo o livro, e ainda, nao coincidirem nunca."
Antonio Franco Alexandre in A Phala
Reedicao da "Assirio & Alvim" da obra de Novembro de 2000.', 'https://images.gr-assets.com/books/1450535745m/4570613.jpg', '4570613', '4.17', '92', '5', 'https://www.goodreads.com/book/show/4570613-poesias-completas');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Against Expression: An Anthology of Conceptual Writing', '', '', 'https://images.gr-assets.com/books/1300754203m/9333970.jpg', '9333970', '3.95', '91', '11', 'https://www.goodreads.com/book/show/9333970-against-expression');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poetry is Not a Project', '', 'In a style much like her poetry--expansive, vulnerable, and never without fire--Dorothea Lasky delivers a theory of writing based as much in the Humanist tradition as Hermeticism. Calling poets away from civilization, back towards the wilderness, Lasky brazenly urges artists away from conceptual programs, resurrecting imagination and faith-in-the-uncertain as saviors from mediocrity.', 'https://images.gr-assets.com/books/1273938517m/8077005.jpg', '8077005', '4.46', '91', '17', 'https://www.goodreads.com/book/show/8077005-poetry-is-not-a-project');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Wait', '', 'Wait finds C. K. Williams by turns ruminative, stalked by "the conscience-beast, who harries me," and "riven by idiot vigor, voracious as the youth I was for whom everything was going too slowly, too slowly." Poems about animals and rural life are set hard by poems about shrapnel in Iraq and sudden desire on the Paris Metro; grateful invocations of Herbert and Hopkins give way to fierce negotiations with the shades of Coleridge, Dostoevsky, and Celan. What the poems share is their setting in the cool, spacious, spotlit, book-lined place that is Williams''s consciousness, a place whose workings he has rendered for fifty years with inimitable candor and style.', 'https://images.gr-assets.com/books/1312000101m/7713912.jpg', '7713912', '3.72', '91', '22', 'https://www.goodreads.com/book/show/7713912-wait');
