INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Earlier Poems', '', 'The haunting collection of poems that gathers the first four books of Pulitzer winner Franz Wright under one cover, where "fans old and new will find a feast amid famine" (Publishers Weekly), and discover how large this poet''s gift was from the start.
From the Trade Paperback edition.', 'https://images.gr-assets.com/books/1320460831m/148160.jpg', '148160', '4.19', '90', '8', 'https://www.goodreads.com/book/show/148160.Earlier_Poems');
