INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('When the Only Light Is Fire', '', 'In his debut chapbook of poetry, Saeed Jones walks on the periphery of the South, those places on the outskirts of town, in bars after midnight, and on dangerous backroads where most people keep their heads down or look the other way. Through Texas and Tennessee, Alabama and the riverbeds of the Mississippi, these poems wrap themselves in cloaks of masks and comfort; garments we learn are flammable if we stand too close to flames.', 'https://images.gr-assets.com/books/1321207110m/12086014.jpg', '12086014', '4.51', '90', '13', 'https://www.goodreads.com/book/show/12086014-when-the-only-light-is-fire');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Writing Kind of Day, A', '', 'Boyds Mills Press publishes a wide range of high-quality fiction and nonfiction picture books, chapter books, novels, and nonfiction', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '53352', '4.31', '90', '20', 'https://www.goodreads.com/book/show/53352.Writing_Kind_of_Day_A');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Songs of a Sourdough', '', 'The vigour, humour and rugged rhythms of Robert Service''s ballads of Yukon have given them great appeal. This is a collection of 33 poems that relate to his years in North America, and include Shooting Dan McGrew and Cremation of Sam McGree.', 'https://images.gr-assets.com/books/1328831720m/1184698.jpg', '1184698', '4.25', '90', '8', 'https://www.goodreads.com/book/show/1184698.Songs_of_a_Sourdough');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Budget Travel through Space and Time: Poems', '', 'A new kaleidoscopic itinerary of poems by Albert Goldbarth, twice winner of the National Book Critics Circle Award
The glass eye = a prosthetic eye.
And a telescope lens?--the dream life
of the glass eye when it''s closed.
--from "About the Dead"
Albert Goldbarth''s trusty travel guide, Budget Travel through Space and Time, is a steal. For only $14.00, you can:
* Observe the nation of Tuvalu sinking into the Pacific!
* Discover Goldbarth''s Law of Physics ("At the moment when the past becomes two futures, / it becomes two pasts")!
* Earn 27,000 frequent-flyer miles* by accompanying the Arctic tern on its annual migration!
* Witness William Herschel construct his famed telescope from horse manure in the late 1770s!
* Journey into the Paleolithic and waaaybeyond to observe "The Most Ancient Light in Existence"!
* Witness why Goldbarth is "a dazzling virtuoso who can break your heart" (Joyce Carol Oates), and ponder how "Goldbarth finds startling and intricate connections where no one else has thought to look" (National Book Critics Circle citation, 2002)!
*Budget restrictions apply', 'https://images.gr-assets.com/books/1316635612m/216123.jpg', '216123', '4.2', '89', '5', 'https://www.goodreads.com/book/show/216123.Budget_Travel_through_Space_and_Time');
