INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Pillow Thoughts', '', 'Make a cup of tea and let yourself feel.
Pillow Thoughtsis a collection of poetry and prose about heartbreak, love, and raw emotions. It is divided into sections to read when you feel you need them most.', 'https://images.gr-assets.com/books/1498032940m/35489042.jpg', '35489042', '3.9', '88', '37', 'https://www.goodreads.com/book/show/35489042-pillow-thoughts');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('some planet', '', '"These poems break, bend, and resist natural law, only to make from this brokenness a new pattern, a transcendental taxonomy."
-Chelsea Werner-Jatzke for Poetry Northwest
SOME PLANET is john mortara''s debut full-length poetry collection. Featuring interactive elements like flow chart poems, fill-in-the-blank poems, and even poems you can cut out and fold yourself, SOME PLANET is a widely surprising, firery-hearted, original-as-heck attempt at knowing the universe inside of each of us.', 'https://images.gr-assets.com/books/1431175747m/25378291.jpg', '25378291', '4.36', '88', '13', 'https://www.goodreads.com/book/show/25378291-some-planet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Balada Pyanhabib', '', 'Pyanhabib yang kadang menyelit, kadang menyerangguh, kadang menyelinap, kadang menyelusup di antara kita.', 'https://images.gr-assets.com/books/1335839025m/13629111.jpg', '13629111', '4.1', '88', '19', 'https://www.goodreads.com/book/show/13629111-balada-pyanhabib');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Anthology of Modern American Poetry', '', 'Anthology of Modern American Poetry contains more than 750 poems by 161 American poets, including many who have not been anthologized before. Spanning a period from Walt Whitman to Sherman Alexie, this collection is the first to review the twentieth century comprehensively. It presents not only the canonical poetry of the last hundred years but also numerous poems by women, minority, and progressive writers only rediscovered in the past two decades.
Uniquely comprehensive, Anthology of Modern American Poetry represents Robert Frost with 23 poems, Wallace Stevens with 22, and Marianne Moore with 14, including her most ambitious long poems. William Carlos Williams is represented not only by his exquisite short lyrics, but also with an experimental combination of poetry and prose. With 29 poems, Langston Hughes is given full treatment for the first time in any comprehensive anthology. Substantial selections by contemporary poets like John Ashbery, Sylvia Plath, Frank O''Hara, Philip Levine, Lucille Clifton, Judy Grahn, Adrian Louis, Yusef Komunyakaa, Martin Espada, and Sherman Alexie are also included.
Anthology of Modern American Poetry is the first anthology to give full treatment to American long poems and poem sequences. T.S. Eliot''s The Waste Land, Gertrude Stein''s "Patriarchal Poetry," William Carlos Williams''s The Descent of Winter, Edna St. Vincent Millay''s "Sonnets from an Ungrafted Tree," Muriel Rukeyser''s "The Book of the Dead," Melvin Tolson''s Libretto for the Republic of Liberia, Theodore Roethke''s "North American Sequence," Gwendolyn Brooks''s "Gay Chaps at the Bar," Kenneth Rexroth''s "The Love Poems of Marichiko," both Allen Ginsberg''s "Howl" and his "Wichita Vortex Sutra," and both Adrienne Rich''s "Shooting Script" and her "Twenty-One Love Poems" are all included in their entirety.
Anthology of Modern American Poetry offers the most detailed annotations available in an anthology of this type. Many works benefit from specially commissioned research that pr', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '172852', '4.06', '88', '6', 'https://www.goodreads.com/book/show/172852.Anthology_of_Modern_American_Poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Seven Notebooks: Poems', '', 'An ant to the stars
or stars to the ant--which is
more irrelevant?
Weekend Jet Skiers--
rude to call them idiots,
yes, but facts are facts.
Clamor of seabirds
as the sun falls--I look up
and ten years have passed."
--from "Dawn Notebook"
Such is the expansive terrain of Seven Notebooks: the world as it is seen, known, imagined, and dreamed; our lives as they are felt, thought, desired, and lived. Written in forms that range from haiku to prose, and in a voice that veers from incantatory to deadpan, these seven poetic sequences offer diverse reflections on language and poetry, time and consciousness, civilization and art--to say nothing of bureaucrats, surfboards, and blue margaritas. Taken collectively, Seven Notebookscomposes a season-by-season account of a year in the life of its narrator, from spring in Chicago to summer at the Jersey Shore to winter in Miami Beach. Not a novel in verse, not a poetic journal, but a lyric chronicle, this utterly unique book reclaims territory long abandoned by American poetry, a characteristic ambition of Campbell McGrath, one of the most honored, accessible, and humanistically engaged writers of our time.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1239200', '3.99', '88', '15', 'https://www.goodreads.com/book/show/1239200.Seven_Notebooks');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Broken Tower: The Life of Hart Crane', '', 'Few poets have lived as extraordinary and fascinating a life as Hart Crane, the American poet who made his meteoric rise in the late 1920s and then as suddenly flamed out, killing himself at the age of thirty-two and thus turning his life and poetry into the stuff of myth.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '75496', '4.01', '87', '9', 'https://www.goodreads.com/book/show/75496.The_Broken_Tower');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('English Romantic Writers', '', 'When preparing English Romantic Writers, one of the principal considerations was the relevance of the English Romantic writers to our own generation. This book offers a very generous selection from authors who have traditionally held a large place in our consciousness of English Romanticism, but it also includes other figures, especially women, who have been less emphasized in the past. The intellectual discourses of the age concerning governance, politics, and the impact of the French Revolution, gender and the status of women, the nature of nature and of human psychology, and the theory of literature and art are represented in the prose and poetry of writers like Wordsworth, Coleridge, the Shelleys, and Keats. There is also an usually large selection of ancillary materials -- letters, journals, reviews, and reminiscences of the writers.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1008485', '4.28', '87', '3', 'https://www.goodreads.com/book/show/1008485.English_Romantic_Writers');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Desiderata of Happiness: A Collection of Philosophical Poems', '', 'In a uniform format with Desiderataand The Desiderata of Love(with all-new illustrations and a fresh new jacket), this is a collection of life-affirming poems by a writer who has inspired and comforted countless readers. Line drawings.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '653046', '4.5', '87', '10', 'https://www.goodreads.com/book/show/653046.The_Desiderata_of_Happiness');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Dream of a Common Language: Poems, 1974-1977', '', '', 'https://images.gr-assets.com/books/1376585739m/1134602.jpg', '1134602', '4.32', '87', '14', 'https://www.goodreads.com/book/show/1134602.The_Dream_of_a_Common_Language');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poetry in the Making: An Anthology', '', 'Drawn from Ted Hughes''s celebrated programs for the BBC''s "Listening and Writing" series, Poetry in the Makingis a fresh, student-friendly discussion of what Hughes calls "imaginative writing." Offering generous citations from the work of several English-speaking, mostly modern or contemporary poets--including Hopkins, Dickinson, Eliot, Larkin, Plath, and himself--Hughes provides a useful and readable primer on "the kind of [poetry] writing children can do without becoming false to themselves." Like Kenneth Koch''s classic Wishes, Lies, and Dreams, Poetry in the Makingpresents new ideas on how children and other beginners might best compose their own poems while also presenting candid, and more general, insights that all students and scholars of the art or craft of verse will find inspiring.
And although these pieces were primarily intended to help students improve their creative writingn abilities, they are also an effective introduction to Hughes''s own work and the influences other writers have had on him. Hughes, who was Poet Laureate to Queen Elizabeth II at the time of his death 1998, casually and colorfully discusses how he came to write, what inspires him (and why), and the difficulties that he (and other writers) confront when writing.', 'https://images.gr-assets.com/books/1312003735m/743913.jpg', '743913', '4.02', '87', '12', 'https://www.goodreads.com/book/show/743913.Poetry_in_the_Making');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Poems 1909-1962', '', 'Poet, dramatist, critic and editor, T. S. Eliotwas one of the defining figures of twentieth-century poetry. This edition of Collected Poems 1909-1962includes his verse from Prufrock and Other Observations (1917) to Four Quartets (1943), and includes such literary landmarks as The Waste Land and Old Possum''s Book of Practical Cats.', 'https://images.gr-assets.com/books/1334059107m/13595971.jpg', '13595971', '4.29', '87', '14', 'https://www.goodreads.com/book/show/13595971-collected-poems-1909-1962');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Muriel Rukeyser Reader', '', 'Bringing together works only sparsely anthologized or long out of print, this book is a resource for understanding the range, depth, and originality of this pioneering writer whom the poet Anne Sexton named "Muriel, mother of everyone."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '202159', '4.38', '87', '4', 'https://www.goodreads.com/book/show/202159.A_Muriel_Rukeyser_Reader');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Close Calls With Nonsense: Reading New Poetry', '', 'Essays and critical writings on contemporary poetry by Stephen Burt, "the finest critic of his generation" (Lucie Brock-Broido)
Stephen Burt''s Close Calls with Nonsense provokes readers into the elliptical worlds of Rae Armantrout, Paul Muldoon, C. D. Wright, and other contemporary poets whose complexities make them challenging, original, and, finally, readable. Burt''s intelligence and enthusiasm introduce both tentative and longtime poetry readers to the rewards of reading new poetry. As Burt writes in the title essay: "The poets I know don''t want to be famous people half so much as they want their best poems read; I want to help you find and read them. I write here for people who want to read more new poetry but somehow never get around to it; for people who enjoy Seamus Heaney or Elizabeth Bishop and want to know what next; for people who enjoy John Ashbery or Anne Carson but aren''t sure why; and, especially, for people who read the half-column poems in glossy magazines and ask, ''Is that all there is?''"', 'https://images.gr-assets.com/books/1312053207m/3998688.jpg', '3998688', '4.1', '87', '12', 'https://www.goodreads.com/book/show/3998688-close-calls-with-nonsense');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poems of Charles Reznikoff 1918-1975', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '557469', '4.51', '86', '9', 'https://www.goodreads.com/book/show/557469.The_Poems_of_Charles_Reznikoff_1918_1975');
