INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('20 Poemas De Amor y Una Cancion Desesperada / 100 Sonetos De Amor', '', 'Su ultima aparicion en publico fue el 5 de diciembre de 1972, donde el pueblo chileno realizo un homenaje al poeta en el Estadio Nacional.
En febrero de 1973, por razones de salud, renuncia a su cargo de embajador en Francia.
Despues del golpe militar del 11 de septiembre su salud se agrava y el 19 es trasladado de urgencia desde su casa de Isla Negra a Santiago, donde muere debido a un cancer de prostata el 23 a las 22.30 en la Clinica Santa Maria. En 2011 un articulo16 recogio declaraciones de Manuel Araya Osorio, asistente del poeta desde noviembre de 1972 hasta su muerte, quien aseguraba que Neruda habria sido asesinado en la clinica tras aplicarsele una inyeccion letal. Aunque la informacion fue desmentida por la Fundacion Pablo Neruda,17 el Partido Comunista solicito, el 6 de diciembre, la exhumacion de los restos del Nobel de Literatura, para verificar si fue envenenado.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '24238476', '4.32', '85', '3', 'https://www.goodreads.com/book/show/24238476-20-poemas-de-amor-y-una-cancion-desesperada-100-sonetos-de-amor');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Intimate Kisses: The Poetry of Sexual Pleasure', '', 'In 1997, sex therapist and marriage counselor Wendy Maltz, author of the Sexual Healing Journey and coauthor of Private Thoughts, compiled Passionate Hearts, an anthology of "poems that inspire and celebrate healthy sexual intimacy; poems in which heart connection was at the core of the sexual experience." In Intimate Kisses, Maltz follows on the success of Passionate Hearts with a new anthology of poetry that continues her celebration of healthy sexuality and, in the process, turns up the heat.
Intimate Kisses revels in what may be life''s greatest mystery, through some of richest, most celebrated poetry ever written. Included in this anthology are 121 poems by such poets as Marge Piercy, Emily Dickenson, Jelaluddin Rumi, Nikki Giovanni, Anne Sexton, Sharon Olds, Octavio Paz, Molly Peacock, Dorianne Laux, Jane Hirshfield, Elizabeth Barrett Browning, Galway Kinnell, and W.S. Merwin, as well as dozens of lesser-known and unpublished poets.', 'https://images.gr-assets.com/books/1299403765m/857449.jpg', '857449', '4.17', '85', '11', 'https://www.goodreads.com/book/show/857449.Intimate_Kisses');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Elder Edda: A Book of Viking Lore', '', 'Compiled by an unknown author in Iceland around 1270, and based on sources dating back centuries earlier, the single main manuscript of The Elder Edda is one of the literary wonders of the medieval world and the greatest source of knowledge of Viking lore in existence. These mythological and heroic poems tell of gods and mortals from an ancient era: the giant-slaying Thor, the doomed Volsung family, the hell-ride of Brynhild and the cruelty of Alti the Hun. Eclectic, incomplete and fragmented, these verses nevertheless retain their stark beauty and their power to enthral, opening a window on to the thoughts, beliefs and hopes of the Vikings and their world. Andy Orchard''s new translation faithfully conveys the spare, unadorned style of the original metre and language. The glossed text is accompanied by four additional poems, a chronology, further reading, an index of names, a note on pronunciation, and an introduction discussing the poems in detail, the history of The Elder Edda and its influence on writers from Tennyson to Tolkien."', 'https://images.gr-assets.com/books/1311644145m/1388192.jpg', '1388192', '4.25', '85', '12', 'https://www.goodreads.com/book/show/1388192.The_Elder_Edda');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Tree House', '', 'An essential new collection from one of Picador''s leading poets our conduct within family and society. In The Tree House Jamie argues - as Burns did before her - for an engagement of the whole being through a kind of practical earthly spirituality. These often startling encounters with animals, birds, and other humans propose a way of living which recognises the earth as home to many different consciousnesses -- and a means of authentic engagement with ''this, the only world''. Together they form one of the most powerful poetic statements of recent years.', 'https://images.gr-assets.com/books/1356134901m/1840718.jpg', '1840718', '3.89', '83', '10', 'https://www.goodreads.com/book/show/1840718.The_Tree_House');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Road to Emmaus: Poems', '', 'A moving, subtle sequence of narrative poems, from a sharp new poetic voice
Two strangers walk toward Emmaus. Christ has just been crucified, and they are heartbroken--until a third man joins them on the road and comforts them. Once they reach Emmaus and break bread, the pair realizes they have been walking with Christ himself. But in the moment they recognize him, he disappears. Spencer Reece draws on this tender story in his mesmerizing collection--one that fearlessly confronts love and its loss, despair and its consolation, and faith in all of its various guises.
Reece''s central figure in The Road to Emmausis a middle-aged man who becomes a priest in the Episcopal Church; these poems follow him to New York City, to Honduras, to a hospital where he works as a chaplain, to a prison, to an Alcoholics Anonymous meeting. With language of simple, lyrical beauty that gradually accrues weight and momentum, Reece spins compelling dramas out of small moments: the speaker, living among a group of orphans, wondering "Was it true, what they said, that a priest is a house lit up?"; two men finding each other at a Coming Out Group; a man trying to become visible after a life that had depended on not being seen.
A yearning for connection, an ache of loneliness, and the instant of love disappearing before our eyes haunt this long-awaited second collection from Spencer Reece.', 'https://images.gr-assets.com/books/1377580060m/17934375.jpg', '17934375', '4.12', '83', '15', 'https://www.goodreads.com/book/show/17934375-the-road-to-emmaus');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Persuasión de los días', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '579444', '4.19', '82', '3', 'https://www.goodreads.com/book/show/579444.Persuasi_n_de_los_d_as');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Moose Boosh: A Few Choice Words About Food', '', 'What to talk about at the dinner table? Why how to eat Slippery Noodles, of course!
Twirl them, whirl them, slop them, slip them,
twist them, curl them, whip them, flip them,
sip them, slurp them, chew them, beat them.
But you must use your fork, when you eat them.
But what happens when you eat too much, like Ruby-Loo?
She ate and ate and ate and ate,
until her tummy started to roar,
"Run," it said, "run."
So she ran to the toilette and slammed the door.
Eating at the dinner table is so much more fun when you can share these silly poems out loud. Parents will see how children experiences food (for real!) and kids may just try a few more bites, or at least ask where our food comes from.
Award wining artist Eric-Shabazz Larkin, in a high-spirited debut as author and illustrator, captures the joy of eating together and will bring the whole family together to the dinner table.', 'https://images.gr-assets.com/books/1413517663m/20578750.jpg', '20578750', '3.57', '82', '41', 'https://www.goodreads.com/book/show/20578750-a-moose-boosh');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Odyssey', '', '''Muse, tell me of a man: a man of much resource, who was made to wander far and long, after he had sacked the sacred city of Troy. Many were the men whose lands he saw and came to know their thinking: many too the miseries at sea, which he suffered in his heart, as he sought to win his own life and the safety of his companions.'' Recounting the epic journey home of Odysseus from the Trojan War, The Odyssey- alongside its sister poem The Iliad- stands as the well-spring of Western Civilisation and culture, an inspiration to poets, writers and thinkers for thousands of years since. This authoritative prose translation by Martin Hammond brings Homer''s great poem of homecoming to life as Odysseus battles through such familiar dangers as the cave of the Cyclops, the call of the Sirens and his hostile reception back in his native land of Ithaca.', 'https://images.gr-assets.com/books/1403502544m/128110.jpg', '128110', '3.73', '82', '13', 'https://www.goodreads.com/book/show/128110.The_Odyssey');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Prophet', '', 'Kahlil Gibran''s masterpiece, The Prophet, is one of the most beloved classics of our time. Published in 1923, it has been translated into more than twenty languages, and the American editions alone have sold more than nine million copies.
The Prophet is a collection of poetic essays that are philosophical, spiritual, and, above all, inspirational. Gibran''s musings are divided into twenty-eight chapters covering such sprawling topics as love, marriage, children, giving, eating and drinking, work, joy and sorrow, housing, clothes, buying and selling, crime and punishment, laws, freedom, reason and passion, pain, self-knowledge, teaching, friendship, talking, time, good and evil, prayer, pleasure, beauty, religion, and death.
Each essay reveals deep insights into the impulses of the human heart and mind. The Chicago Post said of The Prophet: "Cadenced and vibrant with feeling, the words of Kahlil Gibran bring to one''s ears the majestic rhythm of Ecclesiastes . . . If there is a man or woman who can read this book without a quiet acceptance of a great man''s philosophy and a singing in the heart as of music born within, that man or woman is indeed dead to life and truth."
With twelve full-page drawings by Gibran, this beautiful work makes an incredible gift for anyone seeking enlightenment and inspiration', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '943887', '4.23', '82', '10', 'https://www.goodreads.com/book/show/943887.The_Prophet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hamlet (No Fear Shakespeare)', '', 'No Fear Shakespeare Graphic Novelsis a series based on the translated texts of the plays found in No Fear Shakespeare. The original No Fearseries made Shakespeare''s plays much easier to read, but these dynamic visual adaptations are impossible to put down. Each of the titles is illustrated in its own unique style, but all are distinctively offbeat, slightly funky, and appealing to teen readers. Each book will feature:', 'https://images.gr-assets.com/books/1363160162m/17609461.jpg', '17609461', '4.01', '82', '14', 'https://www.goodreads.com/book/show/17609461-hamlet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Songs of Maldoror', '', 'Le Comte de Lautreamont was the nom de plume of Isidore Ducasse, a Uruguayan-born French writer and poet whose only surviving major work of fiction, Les Chants de Maldoror, was discovered by the Surrealists, who hailed the work as a dark progenitor of their movement. It was in Les Chants de Maldororthat Andre Breton discovered the phrase that would come to represent the Surrealist doctrine of objective chance: "as beautiful as the random encounter between an umbrella and a sewing-machine upon a dissecting-table. Artists inspired by Lautreamont include Man Ray, Rene Magritte, Max Ernst, Andre Masson, Yves Tanguy and, in particular, Salvador Dali, who in 1933 produced an entire series of illustrations for Les Chants de Maldoror. Twenty of those illustrations are included, for the first time, in this new, definitive edition of Lautreamont''s influential masterpiece. Vividly translated by R. J. Dent the first new translation for over thirty years--this edition also includes a foreword by French Surrealist poet Paul Eluard and a concise biography of the author by poet Jeremy Reed. In addition, an introduction by series editor Candice Black details the links between Maldoror and the Surrealist movement.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '9719801', '4.19', '82', '7', 'https://www.goodreads.com/book/show/9719801-the-songs-of-maldoror');
