INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Bartholomew Biddle and the Very Big Wind', '', 'A soaring bedsheet carries a young boy on three incredible adventures in this compelling debut by acclaimed film director Gary Ross.
Bartholomew Biddle''s life has always been pretty ordinary, but when a huge wind blows past his window one night, he feels the call of adventure -- and he can''t resist the urge to grab his bedsheet and catch a ride. Soon he''s soaring far above his little town, heading wherever the wind takes him! After spending time on an island full of pleasure-seeking pirates and at a prep school that boasts a hundred shades of gray, Bart finds himself in a mysterious cove where the wind doesn''t blow. Stuck, Bart is forced to face the fact that his flying days might be over. Will he ever get home again?', 'https://images.gr-assets.com/books/1333579070m/13572905.jpg', '13572905', '3.98', '82', '25', 'https://www.goodreads.com/book/show/13572905-bartholomew-biddle-and-the-very-big-wind');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Foglie d''erba', '', '"Foglie d''erba" di Walt Whitman e la raccolta poetica di una vita. Costantemente modificata dall''autore fino ai suoi ultimi giorni, e un''opera che si muove rapida tra la celebrazione appassionata del corpo sensuale e l''invocazione alla presa di coscienza universale. Stampato per la prima volta in forma anonima, "diverso" gia nella sua struttura slegata e fluviale, "Foglie d''erba" inneggia alla memoria storica del Paese e grida la gioia dei sentimenti, l''urgenza naturalistica, ma anche il dolore della guerra. Il riconoscimento delle diversita e l''onesta delle emozioni sono la pietra angolare della poetica di Whitman. Con lui nasce il Sogno Americano.', 'https://images.gr-assets.com/books/1352491499m/9661702.jpg', '9661702', '4.13', '81', '3', 'https://www.goodreads.com/book/show/9661702-foglie-d-erba');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('En hårnål klemt inde bag panelet', '', 'Soren Ulrik Thomsen nye bog, EN HARNAL KLEMT INDE BAG PANELET, bestar af korte tekster om tiden, der bade forsvinder bagud og flygter fremover. Tekster fulde af sansninger, stemninger og iagttagelser. Fra det essayistisk reflekterende til erindringshistorier og prosadigte. Fra det ra til det rorende. Godt hundrede noter fra eftertiden om ikke at lade fortiden stivne til klicheer og om at forholde sig kritisk til nutiden og samtidig insistere pa sin principielle optimisme. Om at mistro alle, der laenges efter den gamle verden, og frygte dem, der vil bygge en ny. Og om at Jeg. Er. Her. Nu, men jo ogsa altid et andet sted.', 'https://images.gr-assets.com/books/1455817152m/29219191.jpg', '29219191', '4.34', '81', '11', 'https://www.goodreads.com/book/show/29219191-en-h-rn-l-klemt-inde-bag-panelet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Short Haul Engine', '', 'Karen Solie takes risks with perception and language, risks that pay off in such startling ways that it''s hard to believe this is a first book. Short Haul Engine is one great twist of fate and fury after another. The writing is clear, striking and open to all sorts of possibilities. Even at their most playful, these poems dive much deeper than initially expected. There''s a remarkably dark sense of humour at work here, but tempered with a haunting vulnerability that makes even the sharpest lines tremble.
from "Signs Taken for Wonders" ... Too delicate for these dog-days, small, clover-blonde, my sister sews indoors. I ask her to fashion me into something nice, ivory silk. I am a big girl, sunburnt skin like raw meat, sweating two pews in front of the Blessed Virgin....', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2115719', '4.25', '81', '8', 'https://www.goodreads.com/book/show/2115719.Short_Haul_Engine');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Runny Babbit', '', '"Runny Babbit lent to wunch
And heard the saitress way,
"We have some lovely stabbit rew --
Our Special for today.""
From the legendary creator of "Where the Sidewalk Ends, A Light in the Attic, Falling Up, " and "The Giving Tree" comes an unforgettable new character in children''s literature.
Welcome to the world of Runny Babbit and his friends Toe Jurtle, Skertie Gunk, Rirty Dat, Dungry Hog, Snerry Jake, and many others who speak a topsy-turvy language all their own.
"So if you say, "Let''s bead a rook
That''s billy as can se,"
You''re talkin'' Runny Babbit talk,
Just like mim and he."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '838060', '4.12', '80', '6', 'https://www.goodreads.com/book/show/838060.Runny_Babbit');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Yabo', '', 'Fiction. African American Studies. LGBT Studies. Women''s Studies. "See YABO... like a Mingus composition: Pentecostal, blues-inflected, full of wit and that deep literacy of the black diaspora. The present, the past, the uncertain future collapse upon themselves in this narrative of place/s. Our dead move with us: behind us, above us, confronting us--in Manhattan; Asheville (N.C.); Buffalo, NY; Jamaica; the hold of a funky slave ship; crossing and bending lines between genders, sexualities, longing and geographies. Time is a river endlessly coursing, shallow in many places, deep for long miles, and, finally, deadly as the hurricane that engulfs and destroys the slave vessel, ''Henrietta Marie.'' YABO calls our ghosts back and holds us accountable for memory."--Cheryl Clarke', 'https://images.gr-assets.com/books/1396403747m/21442388.jpg', '21442388', '4.46', '80', '15', 'https://www.goodreads.com/book/show/21442388-yabo');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Core Samples from the World', '', 'Forrest Gander''s Core Samples from the Worldis a magnificent compendium of poetry, photography, and essay (a form of Japanese haibun). Collaborating with three acclaimed photographers, Gander explores tensions between the familiar and foreign. His eloquent new work voices an ethical concern for others, exploring empathic relations in which the world itself is fundamental. Taking us around the globe to China, Mexico, Bosnia-Herzegovina, and Chile, Core Samples shows how Gander''s "sharp sense of place has made him the most earthly of our avant-garde, the best geographer of fleshly sites since Olson" (Donald Revell,
The Colorado Review).', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '10041732', '4.05', '80', '11', 'https://www.goodreads.com/book/show/10041732-core-samples-from-the-world');
