INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('مدامع العشاق', '', '''kthr sh`r l`rb mn lHdyth `n lHb, w`n lHsn wtnw`t mdhhbhm fy wSf m yshq~ bh lmHb, wm yn`m bh lHbyb, wymkn rj` klmhm fy lnsyb l~ ''Slyn thnyn: l''wl: wSf m ylqy lmHbwb mn `nt lHb. wydkhl fy dhlk kl m yhyj lwjd, wythyr ldm`, kHdyth lfrq, wl`tb, wldhkr~, wlHnyn. lthny: wSf m yr~ lsh`r fy ''Hbbhm mn rw`@ lHsn wydkhl fy dhlk kl m ttmt` bh lnfs, wl`yn, mn jml l''bdn wl''rwH, kwSf l`ywn, wlkhdwd, wlthGr, wlSdwr... wklHdyth `n l`Tf, wlrfq, wlwf wl`ft. wqd r''~ l''dyb zky mbrk tfSyl mdhhb lnsyb fy wSf m yshq~ bh lmHbwn fy ktbh ldhy nqlb SfHth "mdm` l`shq".', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '9560630', '3.85', '79', '12', 'https://www.goodreads.com/book/show/9560630');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Rimas - Gustavo Adolfo Becquer', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1849948', '4.22', '79', '2', 'https://www.goodreads.com/book/show/1849948.Rimas_Gustavo_Adolfo_Becquer');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Norton Anthology of American Literature', '', 'The Norton Anthology of American Literatureis the classic survey of American literature from its sixteenth-century origins to its flourishing present. This volumeVolume Dcovers American literature from 1914 to 1945.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '767928', '4.14', '78', '3', 'https://www.goodreads.com/book/show/767928.The_Norton_Anthology_of_American_Literature');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Complex Sleep', '', 'Complex Sleep, Tony Tost''s ambitious second book of poems, leaps upward with an astounding multiplicity of voices, utterances, and bursts. Each leap marks a sure and precise entry into a world of images, ideas, and sensations that is brand new - the true accomplishment of any poetic work. audacious in scope, swiping at meaning via language as fragmented music. Tost takes on the problem of physical shape, reorchestrates phrases according to the alphabet, and writes himself into the hypnagogic state between waking and dreaming. Informed by their own procedural constraints, these poems invent forms that tap the unconscious poetic, the very complexity embodied in sleep. All the while, Tost reforms utterance beyond the mere epistemology of much contemporary poetry. discovering the what, Complex Sleep is about discovering how to say what needs to be said. Skip the opera, this book performs.', 'https://images.gr-assets.com/books/1328757838m/375893.jpg', '375893', '4.12', '78', '9', 'https://www.goodreads.com/book/show/375893.Complex_Sleep');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Tijuana Book of the Dead', '', 'From the author of Pulitzer-nominated The Devil''s Highwayand national bestseller The Hummingbird''s Daughtercomes an exquisitely composed collection of poetry on life at the border. Weaving English and Spanish languages as fluidly as he blends cultures of the southwest, Luis Urrea offers a tour of Tijuana, spanning from Skid Row, to the suburbs of East Los Angeles, to the stunning yet deadly Mojave Desert, to Mexico and the border fence itself. Mixing lyricism and colloquial voices, mysticism and the daily grind, Urrea explores duality and the concept of blurring borders in a melting pot society.', 'https://images.gr-assets.com/books/1403405837m/22557362.jpg', '22557362', '4.17', '78', '16', 'https://www.goodreads.com/book/show/22557362-tijuana-book-of-the-dead');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('W. B. Yeats: Selected Poems', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '82319', '4.18', '78', '6', 'https://www.goodreads.com/book/show/82319.W_B_Yeats');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Bukowski, 20 poemas', '', 'Ajeno, distante, crudo adjetivador de su vida y de la vida de los demas, en sus 20 libros de poemas, publicados hasta su muerte en 1994, exploro temas alrededor de los cuales desarrollo una filosofia sobre el alcohol, las mujeres, el sexo, el desempleo y las carreras de caballos.
Reiterativo y circular, irreverente consigo mismo y declarado enemigo de la esperanza, nunca aburrio a los miles de lectores norteamericanos que buscaban avidos sus libros y viajaban a escucharlo en los auditorios aunque solo alcanzara a balbucear algunos versos por culpa del whisky que el nunca abandono y que a el nunca lo abandono.
Bukowsky tuvo una ventaja sobre los seres presuntamente normales: conocio el infierno, se paseo por el, volvio y lo mostro en sus poemas:
"Esta bien ser un escritor/ hambriento/ pero no/un escritor/ hambriento que bebe./ Los borrachos/ nunca son perdonados".', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '7113815', '3.67', '78', '7', 'https://www.goodreads.com/book/show/7113815-bukowski-20-poemas');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('هاملت', '', 'One of the greatest plays of all time, the compelling tragedy of the tormented young prince of Denmark continues to capture the imaginations of modern audiences worldwide. Confronted with evidence that his uncle murdered his father, and with his mother''s infidelity, Hamlet must find a means of reconciling his longing for oblivion with his duty as avenger. The ghost, Hamlet''s feigned madness, Ophelia''s death and burial, the play within a play, the "closet scene" in which Hamlet accuses his mother of complicity in murder, and breathtaking swordplay are just some of the elements that make Hamlet an enduring masterpiece of the theater.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '22079475', '4.01', '77', '7', 'https://www.goodreads.com/book/show/22079475');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Magic with Skin On', '', 'In her much-anticipated debut poetry collection, Morgan Nikola-Wren has woven her signature romantic grit through a stunning, modern-day fairy tale. Chronicling the relationship between a lonely artist and her absent--albeit abusive--muse, Magic with Skin On will gently break you, then put you back together again.', 'https://images.gr-assets.com/books/1487806008m/34376890.jpg', '34376890', '4.52', '77', '28', 'https://www.goodreads.com/book/show/34376890-magic-with-skin-on');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('يسوع ابنْ الإنسان', '', 'In Jesus Son of Man Jesus is portrayed through the words of 77 contemporaries who knew him. Gibran allows the reader to see Jesus through the eyes of a group of people, enemies and friends alike. Each has an opinion about Jesus based on their own experience. Khalil Gibran was a Lebanese-American artist, poet, and writer. As a young man he emigrated with his family to the United States where he studied art and began his literary career. His Romantic style was at the heart of a renaissance in modern Arabic literature he is still celebrated as a literary hero.', 'https://images.gr-assets.com/books/1365341146m/17737170.jpg', '17737170', '3.99', '76', '6', 'https://www.goodreads.com/book/show/17737170');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Хълбоци и пеперуди', '', 'Zhivot''t i poeziiata se obichat, no sa razdeleni. Zatova stikhosbirkata na Rene Karabash e v''zhe za dvoino samoubiistvo. Zhilavo i neumolimo, i istinski obichlivo v''zhe.
Marin Bodakov
Ob''rnakh tazi kniga ,,s khastara nav''n". Dokato opipvakh podutinite, stikhovete i padakha kato ,,gilotini" v''rkhu pred-razs''d''tsite mi, i te, ,,postmortem", se prevr''shchakha v bezsramni razs''d''tsi za palachite si. Po vsichko lichi, che oshche v detstvoto si Rene e zav''rshila universitetite na Gorki s ,,otlichen".
Aziz Sha(k)ir - Tash
Peperudi v kh''lboka na dumite, oko, koeto gleda nav''tre, kozha, koiato zasmukva praznoto, drugoto.
V Kh''lbotsi i peperudi Rene Karabash osezava dumite kato kozha; iska ot tiakh da dokosvat, da b''dat pogl''shchani ili da khapiat samite te. Samoizpitanie na opita v ezika: opit da se ulovi erosa na neulovimoto - nastoichivo, natrapchivo, nepreodolimo - useshchane, kogato si veche, i neobratimo, v negov plen. Kartografiia na telata dumi, koiato trogva i raztrogva.
Boian Manchev', 'https://images.gr-assets.com/books/1434388038m/25731868.jpg', '25731868', '3.86', '76', '8', 'https://www.goodreads.com/book/show/25731868');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Veils', '', 'Something of a historical event, this book combines loosely "autobiographical" texts by two of the most influential French intellectuals of our time. "Savoir," by Helene Cixous, is a brief but densely layered account of her experience of recovered sight after a lifetime of severe myopia, an experience that ends with the unexpected turn of grieving for what is lost. Her literary inventiveness mines the coincidence in French between the two verbs savoir(to know) and voir(to see). Jacques Derrida''s "A Silkworm of One''s Own" complexly muses on a host of autobiographical, philosophical, and religious motifs--including his varied responses to "Savoir." The two texts are accompanied by six beautiful and evocative drawings that play on the theme of drapery over portions of the body.
Veilssuspends sexual difference between two homonyms: la voile(sail) and le voile(veil). A whole history of sexual difference is enveloped, sometimes dissimulated here--in the folds of sails and veils and in the turns, journeys, and returns of their metaphors and metonymies.
However foreign to each other they may appear, however autonomous they may be, the two texts participate in a common genre: autobiography, confession, memoirs. The future also enters in: by opening to each other, the two discourses confide what is about to happen, the imminenceof an event lacking any common measure with them or with anything else, an operation that restores sight and plunges into mourning the knowledge of the previous night, a "verdict" whose threatening secret remains out of reach by our knowledge.', 'https://images.gr-assets.com/books/1407813066m/153356.jpg', '153356', '4.15', '76', '4', 'https://www.goodreads.com/book/show/153356.Veils');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('You Never Know', '', '', 'https://images.gr-assets.com/books/1354209377m/104121.jpg', '104121', '4.17', '76', '7', 'https://www.goodreads.com/book/show/104121.You_Never_Know');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Unscrambled Eggs', '', 'Profound and riveting, this is a 60 poem book collection with poetry that enlightens, speaks the way of life and the world. The poems from Unscrambled Eggs has a universal appeal, and is true to life in form. Unscrambled Eggs was written over a five year period and is an honest and thought-provoking book that deals with everyday life issues. It is a stirring compilation of poems about living your dream and finding one''s purpose. http://www.nadiajanicebrown.com', 'https://images.gr-assets.com/books/1461299320m/3184065.jpg', '3184065', '3.71', '76', '27', 'https://www.goodreads.com/book/show/3184065-unscrambled-eggs');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Not about Heroes', '', 'Drama Characters: 2 males
Set Requirements: Unit set
"Dulce et decorum est/Pro patria mori," facetiously penned British poet Wilfred Owen, who was soon to die in the Great War. It is sweet and fitting to die for one''s country. This moving play is about the poetic life and the inter relationship between two of the finest Great War poets: Owen who died and Siegfried Sasson who didn''t. Told by means of letters and poetry, Not About Heroes paints a vivid picture of the war. It was staged to great acclaim at the Williamstown Theatre Festival and had an Off Broadway run.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '820475', '3.92', '76', '8', 'https://www.goodreads.com/book/show/820475.Not_about_Heroes');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Book for My Brother', '', 'This newest collection of poems from Tomaz Salamun is exuberant, ambitious, and full of surprises. Here the devil is encountered and understood-
I see the devil''s head, people, I see his whole body . . . 
he longs for innocence, as we do. 
Here the poet juggles many tones, languages, and countries. Desire is evoked as both frustrating and exhilarating-
I''m watered by longing, knocking my
head into the wall, on the ground, or I burn, burn,
folded up on the couch.
And memory comes back to remind us of the laws and experiences of childhood-
Once again you are let loose in the sea
only after five o''clock in the afternoon to take
a dose of sunlight like the ticking of the clock.
At once daring and clear-voiced, The Book for My Brother is an extraordinary achievement.', 'https://images.gr-assets.com/books/1328874975m/669757.jpg', '669757', '3.99', '76', '14', 'https://www.goodreads.com/book/show/669757.The_Book_for_My_Brother');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Kaptan Yemeğe Çıktı ve Tayfalar Gemiyi Ele Geçirdi', '', 'Kimseyle yarismiyorum ve olumsuzluge dair dusuncelerim yok. Umurumda bile degil. Hayatta iken devinmek onemli olan. Gun isiginda kapilar acilir ve atlar isigin icine firlar ve cokeyler; parlak ipek giysilerinin icinde kucuk seytanlar, zorlayarak, sapina kadar. Ihtisam devinimde ve hodri meydan diyebilmektedir. Olumun cani cehenneme. Her sey bugun, bugun bugun. Evet.', 'https://images.gr-assets.com/books/1504552186m/15788435.jpg', '15788435', '3.89', '76', '5', 'https://www.goodreads.com/book/show/15788435-kaptan-yeme-e-kt-ve-tayfalar-gemiyi-ele-ge-irdi');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'For his Selected Poems, C. K. Williams has chosen from three decades of his work to represent every aspect of his marvelous career.', 'https://images.gr-assets.com/books/1312058866m/518246.jpg', '518246', '4.29', '75', '4', 'https://www.goodreads.com/book/show/518246.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Importance of Being Ernest', '', 'This is not the play by Oscar Wilde.
Ernest (Ernie) Cline has been Ernest his whole life and in this first slim (48 pages) volume, he begins to explain to us what that has meant in these poems intended for performance. This companion book to his CD, The Geek Wants Out, contains many of the same poems, notably: The Geek Wants Out, Dance Monkeys Dance, and Nerd Porn Auteur among others. It also contains three bonus poems not found on the CD. Cline''s work is simultaneously clever, witty, intelligent and 100% Airwolf! Some strong language and subject matter in some poems.', 'https://images.gr-assets.com/books/1369154043m/17660095.jpg', '17660095', '3.94', '75', '17', 'https://www.goodreads.com/book/show/17660095-the-importance-of-being-ernest');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Weeds and Wild Flowers', '', '"Weeds and Wild Flowers" is a magical meeting of the poems of Alice Oswald and the etchings of Jessica Greenman. Within its pages, everyday flora take on an extraordinary life, jostling tragically at times, at times comically, for a foothold in a busying world. Stunningly visualised and skilfully animated, this imaginative collaboration beckons us toward a landscape of botanical characters, and invites us to see ourselves among them.', 'https://images.gr-assets.com/books/1373032425m/6218380.jpg', '6218380', '4.23', '74', '7', 'https://www.goodreads.com/book/show/6218380-weeds-and-wild-flowers');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '236183', '4.15', '74', '9', 'https://www.goodreads.com/book/show/236183.Selected_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Four Revenge Tragedies: The Spanish Tragedy; The Revenger''s Tragedy; The Revenge of Bussy D''Ambois; And the Atheist''s Tragedy', '', 'The Revenge Tragedy flourished in Britain during the late sixteenth and early seventeenth centuries. The classic ingredients of the genre are a quest for vengeance, mad scenes, a play within a play, and carnage. Each of the four plays here subverts the genre, and deals with fundamental moral questions about justice and the individual, while registering the strains of life in an increasingly fragile social hierarchy. This edition includes Thomas Kyd''s The Spanish Tragedy, the anonymous The Revenger''s Tragedy (variously ascribed to Cyril Tourneur and Thomas Middleton), The Revenge of Bussy D''Ambois by George Chapman, and Tourneur''s The Atheist''s Tragedy.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '295769', '3.78', '74', '4', 'https://www.goodreads.com/book/show/295769.Four_Revenge_Tragedies');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Haiku: Il fiore della poesia giapponese da Basho all''Ottocento', '', '"Ogni cosa piccola e bella" scrive Sei Shonagon nelle sue Note del guanciale. Lo haiku, la piu piccola forma di poesia esistente, scandito in tre versi di 5-7-5 sillabe, affonda le sue radici nel passato lontano della cultura nipponica: originariamente prima strofa, detta hokku, di un componimento piu lungo, acquista un''importanza sempre crescente fino ad essere riconosciuto come un genere pienamente indipendente, e viene ribattezzato "haiku" nell''Ottocento da Masaoka Shiki.
Il grande mastro Basho (1644-1694) e quanti verranno dopo di lui riescono con gli haiku a cogliere il respiro del mondo e a proiettarlo in una dimensione senza soggetto e senza tempo: contro uno sfondo naturale grande, mai descritto ma solo suggerito da un termine che metonimicamente indica la stagione, un movimento infinitesimale ci scuote, ci fa conoscere il fueki ryuko, "l''impermanenza e l''eternita" che costituiscono il gioco eterno della vita.
Questa antologia segue la storia dello haiku dalla sua prima grande fioritura nel Seicento, epoca di profondo rinnovamento sociale in Giappone, fino alle soglie del periodo contemporaneo, attraverso nuove traduzioni che mirano a restituire al pubblico italiano l''icasticita e la purezza di questa forma poetica che fin dal suo primo apparire ha affascinato l''Occidente.', 'https://images.gr-assets.com/books/1347801496m/9693693.jpg', '9693693', '4.0', '74', '8', 'https://www.goodreads.com/book/show/9693693-haiku');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Own Face', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '367563', '4.59', '74', '4', 'https://www.goodreads.com/book/show/367563.Own_Face');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Blue Wizard Is about to Die!: Prose, Poems, and Emoto-Versatronic Expressionist Pieces about Video Games, 1980-2003', '', 'The first collection of poetry about video games ever published, BWIATD takes its readers on a psychotic and hilarious tour through the arcade and console games of the Eighties (and beyond). Funny, approachable, and beautifully illustrated by Warren Wucinich, BWIATD is sure to delight and thrill anyone who enjoys (or has enjoyed) playing video games.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '722818', '3.27', '74', '10', 'https://www.goodreads.com/book/show/722818.Blue_Wizard_Is_about_to_Die_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Horal / La Señal', '', 'La Biblioteca Jaime Sabines pone al alcance de los lectores la obra completa, en cuatro volumenes, de uno de los mas admirados poetas contemporaneos de Mexico.
En esta edicion, revisada y contrastada con los documentos originales del poeta, se reunen Horal (1950) y La senal (1951), los dos primeros libros de Jaime Sabines, que revitalizaron la poesia mexicana de manera determinante e irreversible.', 'https://images.gr-assets.com/books/1485566347m/18295691.jpg', '18295691', '4.11', '74', '3', 'https://www.goodreads.com/book/show/18295691-horal-la-se-al');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Sand and Foam', '', 'Halil Cibran''in zamaninda kucuk kagit parcalarina ve defterlerine karaladigi aforizma ve mesellerden olusan bu kucuk kitap, sanatcinin parcali bir "otoportresi"ni ortaya koyuyor. Ruhunun derinliklerinden gelen carpici ve cagrisimli imgelerle ask, guzellik, doga ve insanlik durumuna iliskin bir turlu ifadesini bulamayip "suskunluga gomulmus" olani ifsa ediyor.
Cibran''in yetmis yili askin bir sure once yayimlanmis yapitlari, bugun dunyanin dort bir yanindaki okurlara ulasmayi surduruyor. Sozcuklerinin butun cografyalara uzanmasinda, bu yapitlarin bircok dile cevrilmesinin yani sira onun irk, din, dil ayrimi gozetmeksizin insanligi bir butun olarak ele alan felsefesinin de rolu var kuskusuz. Bir de insana dair verdigi mesajlarin her donemde gecerli, "ezeli-ebedi" olmasinin.
Ermis''in ardindan, 1926''da yayimlanan Kum ve Kopuk 1960''larda dusunen ve ureten insanlarin yuregine dokunmustu. Beatles uyesi John Lennon, bir trafik kazasinda yitirdigi annesi icin yazdigi "Julia" adli sarkida bu yapittan satirlara yer vermisti.
(Tanitim Bulteninden)', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '842813', '4.09', '74', '9', 'https://www.goodreads.com/book/show/842813.Sand_and_Foam');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'Thom Gunn was an Elizabethan poet in modern guise, though there''s nothing archaic, quaint, or sepia-toned about his poetry. His method was dispassionate and rigorous, uniquely well suited for making a poetic record of the tumultuous time in which he lived. Gunn''s dozens of brilliantly realized poems about nature, friendship, literature, sexual love, and death are set against the ever-changing backdrop of San Francisco -- the druggy, politically charged sixties and the plague years of AIDS in the eighties. Perhaps no contemporary poet was better equipped -- by temperament, circumstance, or poetic gift -- to engage the subjects of eros and thanatos than Thom Gunn. This new Selected Poems, edited and with an introduction by the poet August Kleinzahler, supplants the 1979 Selected, presenting more of the later work and providing a fuller retrospective account of the breadth and magnitude of Gunn''s extraordinary achievement.', 'https://images.gr-assets.com/books/1316638334m/5760565.jpg', '5760565', '3.87', '74', '13', 'https://www.goodreads.com/book/show/5760565-selected-poems');
