INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Das Nibelungenlied', '', 'Mittelhochdeutsch / Neuhochdeutsch
Das um 1200 entstandene Nibelungenlied ist eines der grossartigsten und schwierigsten Werke der deutschen Literatur des Mittelalters. Es wird hier im Originaltext und einer prazisen Prosaubersetzung, begleitet von einem umfangreichen Kommentar, vorgelegt.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '18263', '3.87', '73', '8', 'https://www.goodreads.com/book/show/18263.Das_Nibelungenlied');
