INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('I Promised You I Wouldn''t Write This', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '24753588', '4.08', '73', '12', 'https://www.goodreads.com/book/show/24753588-i-promised-you-i-wouldn-t-write-this');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('S O S: Poems, 1961-2013', '', 'A New York TimesEditors'' Choice
Fusing the personal and the political in high-voltage verse, Amiri Baraka--"whose long illumination of the black experience in America was called incandescent in some quarters and incendiary in others" (New York Times)--was one of the preeminent literary innovators of the past century. Selected by Paul Vangelisti, this volume comprises the fullest spectrum of Baraka''s rousing, revolutionary poems, from his first collection to previously unpublished pieces composed during his final years.
Throughout Baraka''s career as a prolific writer (also published as LeRoi Jones), he was vehemently outspoken against oppression of African American citizens, and he radically altered the discourse surrounding racial inequality. The environments and social values that inspired his poetics changed during the course of his life, a trajectory that can be traced in this retrospective spanning more than five decades of profoundly evolving subjects and techniques. Praised for its lyricism and introspection, his early poetry emerged from the Beat generation, while his later writing is marked by intensely rebellious fervor and subversive ideology. All along, his primary focus was on how to live and love in the present moment despite the enduring difficulties of human history.', 'https://images.gr-assets.com/books/1418105604m/22557366.jpg', '22557366', '4.29', '72', '9', 'https://www.goodreads.com/book/show/22557366-s-o-s');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Seeds From a Birch Tree: Writing Haiku and The Spiritual Journey', '', 'A Zen Buddhist monk explains the value of haiku, a three-line, seventeen-syllable poem, as a writing meditation and spiritual guide and provides exercises to help readers compose their own haiku.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '873462', '4.16', '72', '7', 'https://www.goodreads.com/book/show/873462.Seeds_From_a_Birch_Tree');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Movement in Black', '', 'Pat Parker -- that revolutionary, raw and as they used to say, "right-on sister" -- would be celebrating her fifty-fifth birthday in 1999 had she not died of breast cancer ten years ago. To honor her work and call attention to the significance of her contributions, Firebrand Books is publishing a new, expanded edition of her classic, Movement In Black.With an incisive introduction by Cheryl Clarke, celebrations/ remembrances/tributes from ten outstanding African American women writers, and a dozen previously unpublished pieces, Movement In Black is a must read/ must have on your book shelf.
Whether she was presenting her poetry on street corners, performing with other women -- writers, musicians, activists -- in bars and auditoriums, rallying the crowd at political events, preaching to the converted, or converting the ill-informed, Pat Parker was a presence.
She wrote about gut issues: the lives of ordinary Black people, violence, loving women, the legacy of her African American heritage, being queer. She was a woman who engaged life fully, both personally and as a political activist, linking the struggles for racial, gender, sexual, and class equality long before it was "PC" to do so. She died as she lived -- fighting forces larger than herself.
The publication of Movement In Black is an opportunity, both for those who were around the first time and those who are new to her work, to experience and enjoy Pat Parker''s power.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1222469', '4.4', '72', '3', 'https://www.goodreads.com/book/show/1222469.Movement_in_Black');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ideas of Order', '', 'Wallace Stevens did not publish his first book of poetry until the age of 44 and did not issue his second book, Ideas of Order, for over a decade. This rare signed limited edition of that crucial work features his illuminating meditation on art--"The Idea of Order at Key West"--along with 32 additional poems, each the sublime expression of a body of work praised by critics as "drenched with the life of his senses. This vibrant fact forms the core of his exploration of the interplay between the mind and reality... What gives his best work its astonishing power and vitality is the way in which a fixed point of view, maturing naturally, eventually takes in more than a constantly shifting point of view could get at" (New York Times). Awarded the 1955 Pulitzer Prize for Poetry, "no poet gives us more to think about or greater reward for thinking" (Chiasson, New York Review of Books).', 'https://images.gr-assets.com/books/1345884861m/6580847.jpg', '6580847', '4.31', '72', '3', 'https://www.goodreads.com/book/show/6580847-ideas-of-order');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Portable Walt Whitman', '', 'When Walt Whitman self-published Leaves of Grassin 1855 it was a slim volume of twelve poems and he was a journalist and poet from Long Island, little-known but full of ambition and poetic fire. To give a new voice to the new nation shaken by civil war, he spent his entire life revising and adding to the work, but his initial act of bravado in answering Ralph Waldo Emerson''s call for a national poet has made Whitman the quintessential American writer. This rich cross-section of his work includes poems from throughout Whitman''s lifetime as published on his deathbed edition of 1891, short stories, his prefaces to the many editions of Leaves of Grass, and a variety of prose selections, including Democratic Vistas, Specimen Days, and Slang in America.
For more than seventy years, Penguin has been the leading publisher of classic literature in the English-speaking world. With more than 1,700 titles, Penguin Classics represents a global bookshelf of the best works throughout history and across genres and disciplines. Readers trust the series to provide authoritative texts enhanced by introductions and notes by distinguished scholars and contemporary authors, as well as up-to-date translations by award-winning translators.', 'https://images.gr-assets.com/books/1403540175m/45288.jpg', '45288', '4.34', '72', '6', 'https://www.goodreads.com/book/show/45288.The_Portable_Walt_Whitman');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Bodaj bi!', '', '"Tomas Ulej obohacuje nas tradicny utociaci humor vtipom a noblesou a nazorom," napisal o tvorbe Tomasa Uleja basnik a aforista Tomas Janovic. Po uspesnej knihe aforizmov a epigramov Ale, ktora ziskala Cenu Ivana Kraska za debut v literature, prichadza teraz Tomas Ulej s druhou.
Nech knihu otvorite kdekolvek, vyvali sa na vas instantna mudrost a vtip. Bodaj bi! je oslavou slov(enciny) a skrytych vyznamov, ktore sa ukryvaju v nasom jazyku. Idealny darcek pre vsetkych, ktori, slovami Tomasa Uleja, aj ,,vedia kolko je dva plus dva", ale nie je im to ,,jedno".', 'https://images.gr-assets.com/books/1413289711m/21415507.jpg', '21415507', '4.42', '72', '13', 'https://www.goodreads.com/book/show/21415507-bodaj-bi');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Owl and the Pussycat', '', 'In this beautifully illustrated edition of Lear''s beloved nonsense poem, Mortimer takes the reader on the delightful voyage of the Owl and the Pussycat, across the sea and into lush jungles, all by the light of the moon. Full color.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '389058', '4.2', '72', '14', 'https://www.goodreads.com/book/show/389058.The_Owl_and_the_Pussycat');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Scars Upon My Heart: Women''s Poetry And Verse Of The First World War', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1797237', '3.97', '71', '11', 'https://www.goodreads.com/book/show/1797237.Scars_Upon_My_Heart');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Norton Anthology of American Literature', '', 'The Eighth Edition features a diverse and balanced variety of works and thorough but judicious editorial apparatus throughout. The new edition also includes more complete works, much-requested new authors, 170 in-text images, new and re-thought contextual clusters, and other tools that help instructors teach the course they want to teach.
The Norton Anthology of American Literature is now available as an interactive ebook, at just a fraction of the print price.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '13298184', '4.14', '71', '2', 'https://www.goodreads.com/book/show/13298184-the-norton-anthology-of-american-literature');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Полтава', '', '', 'https://images.gr-assets.com/books/1350557300m/1886290.jpg', '1886290', '3.99', '71', '4', 'https://www.goodreads.com/book/show/1886290._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Missing Children', '', 'A daring and innovative collection of new poems by the controversial author of Paul''s Caseand VillainElle.
Missing Childrenis a daring and innovative collection of new poems by the controversial author of Paul''s Caseand VillainElle. Here, Lynn Crosbie creates a bold fusion of genres by taking traditional elements of the novel - dialogue, plot, and description - and weaving them through a series of narratively linked poems. Centering on a man and a woman obsessively drawn to each other, Missing Childrenunfolds around a forbidden relationship and a series of letters, written by the protagonist, to the parents of missing children. Infused with psychological insight, rich in cultural iconography, and written in spare, clear language, Missing Childrentakes us to the moral fringes of society and challenges us to judge what we find. Crosbie breaks new stylistic and dramatic ground in this compelling, original collection.', 'https://images.gr-assets.com/books/1320491902m/3028840.jpg', '3028840', '3.63', '71', '3', 'https://www.goodreads.com/book/show/3028840-missing-children');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poesía no eres tú', '', 'Entre los poetas de Mexico, Rosario Castellanos se singulariza por la propension a descender al interior de su conciencia en busca de emociones que, convertidas en canto o en elegia, suelen aflorar en descarnados versos. En este volumen puede encontrarse, entre otras obras, "La lamentacion de Dido," que sobresale entre lo mas fino y depurado de su voz poetica.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1187364', '4.42', '71', '6', 'https://www.goodreads.com/book/show/1187364.Poes_a_no_eres_t_');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ants on the Melon: a Collection of Poems', '', 'Already singled out by The New York Times and the subject of a feature in The New Yorker, Virginia Adair has, after decades of shunning book publication, decided to collect eighty of her best poems in a volume that will surely be hailed as among the most accomplished works of our time.
Ants on the Melon includes poems that concern the author''s childhood, that explore sensuality in candid terms, that starkly treat her husband''s suicide and her own blindness, and that explore both her own emotional landscape and the universal mysteries of the human condition. Technically brilliant, using strict, classical prosody, yet entirely modern in sensibility, Virginia Adair''s poetry will play a central role in the ongoing American poetry renaissance.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1286592', '4.02', '71', '10', 'https://www.goodreads.com/book/show/1286592.Ants_on_the_Melon');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('یک زن تنها: فروغ فرخزاد و شعرهایش', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1300420', '4.08', '70', '4', 'https://www.goodreads.com/book/show/1300420._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Táin', '', '"[A] brilliant and altogether engaging new translation" (Los Angeles Times) of the greatest epic in Irish literature
Dating from the eighth century, The Tin is the oldest Irish epic, a mythic tale on par with Beowulf and The Aeneid. Following legendary warrior C Chulainn into his battle against the invading army of Connacht, The Tin is the story of the emergence of a hero, a paean to the Irish landscape, and a bawdy and contentious marital farce. In its first translation in forty years, Ciaran Carson brings this seminal work of Irish literature fully to life, capturing all of its visceral power in what acclaimed poets Seamus Heaney and Paul Muldoon individually called one of the best books of the year.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2260201', '3.97', '70', '19', 'https://www.goodreads.com/book/show/2260201.The_T_in');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Funny', '', 'A tour de force, Funny is a stunning masterpiece of poetic, as well as philosophic and comic, invention. It creates a musing world, where the issues are philosophical but the focus is always on people, on our most private ways of balancing our accounts. The poems are psychological; tender and humane, and somehow ruthless. This is poetry that swarms with ideas, that revels in rhythmic intricacy and literary references, but is also clear as a bell, and tells marvelous stories.', 'https://images.gr-assets.com/books/1328870747m/779540.jpg', '779540', '4.26', '70', '13', 'https://www.goodreads.com/book/show/779540.Funny');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Wideawake Field: Poems', '', '', 'https://images.gr-assets.com/books/1311971764m/1074184.jpg', '1074184', '3.66', '70', '10', 'https://www.goodreads.com/book/show/1074184.Wideawake_Field');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Sonnets', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '472703', '4.51', '69', '3', 'https://www.goodreads.com/book/show/472703.Sonnets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Aim For The Head: The Zombie Hunters Guide To Poetry', '', 'Film buffs have George Romero. TV nerds have "The Walking Dead." Fiction fans have World War Z. Now, a cross-section of some of the best contemporary poets from the stage and the page rise up and shamble their way through an anthology of post-apocalyptic zombie poetry edited by Write Bloody author and GeekWeek.com personality Rob "Ratpack Slim" Sturma. Funny, creepy, shocking, and even poignant, this collection challenges award winning authors like Scott Woods, Laura Yes Yes, and Khary Jackson to shake the dust off of old conventions, pull the triggers on their imaginations, and...Aim For The Head.', 'https://images.gr-assets.com/books/1310811894m/12027057.jpg', '12027057', '3.78', '69', '13', 'https://www.goodreads.com/book/show/12027057-aim-for-the-head');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Mystery of the Hidden Driveway', '', 'In The Mystery of the Hidden Driveway, Jennifer L. Knox expands on her inimitable cast of characters, in hilariously poignant poems. In poems like "Marriage" and "One Ton of Dirt," Knox ventures further into autobiographical territory than she''s ever gone before, in ways that will startle those familiar with her previous books, exploring relationships with her exes, her parents, and her younger self. Like the best comedians (to whom she''s often compared), Knox is never merely funny. Each of her speakers, even the bedraggled coyote that walks into a Quizno''s, has something important to say. Bob Hicock describes the effect of her trademark dark humor perfectly when he says, "The oddities of her work create a space in which it''s possible to be oddly sincere. Knox is asking what really matters, in poems that move powerfully toward an answer." www.jenniferlknox.com.', 'https://images.gr-assets.com/books/1291275163m/9368172.jpg', '9368172', '4.2', '69', '12', 'https://www.goodreads.com/book/show/9368172-the-mystery-of-the-hidden-driveway');
