INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Our Farm: By the Animals of Farm Sanctuary', '', 'Maya the cow, J.D. the piglet, Hilda the sheep, and a dozen more animals all speak directly to the reader, showing off their unique personalities in this wonderful collection of poems. Master watercolorist Robert Rahway Zakanitch provides a portrait that perfectly captures the essence of each creature. Together the poems and paintings add up to a picture of life on the friendliest farm around.
Maya Gottfried based her poems on real animals from Farm Sanctuary, a safe haven for injured or abused farm animals with locations in New York and California.', 'https://images.gr-assets.com/books/1320499058m/6819632.jpg', '6819632', '4.17', '68', '15', 'https://www.goodreads.com/book/show/6819632-our-farm');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Averno: Poems', '', 'Averno is a small crater lake in southern , regarded by the ancient Romans as the entrance to the underworld. That place gives its name to Louise Gluck''s eleventh collection: in a landscape turned irretrievably to winter, it is the only source of heat and light, a gate or passageway that invites traffic between worlds while at the same time opposing their reconciliation. Avernois an extended lamentation, its long, restless poems no less spellbinding for being without plot or hope, no less ravishing for being savage, grief-stricken. What Averno provides is not a map to a point of arrival or departure, but a diagram of where we are, the harrowing, enduring presence.
Avernois a 2006 National Book Award Finalist for Poetry.', 'https://images.gr-assets.com/books/1312067377m/807673.jpg', '807673', '4.17', '68', '8', 'https://www.goodreads.com/book/show/807673.Averno');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Cradle Of The Real Life', '', 'In Jean Valentine''s first book, her poems transformed dreams into living experience by means of luminous language that echoed the unconscious mind''s revelations. In her later books, she almost reverses this process to show life as veiled and inconclusive, suggestive rather than definitive. The elliptical yet lucid craft of her poems presents experience as only imperfectly graspable. The poems ride lightly on the waves of thought, more textures than statements. Some readers have characterized Valentine as a "deep image" writer, but syntactically her work is more akin to the work of Mandelstam and Paul Celan than to that of Lorca and Neruda.
The Cradle of the Real Life is divided into two sections, the shorter first section dealing with loss and death and the longer second section, entitled "Her Lost Book," which weaves memories with various metaphors for writing, and deals specifically with the "problem" of women''s writing. These finely wrought pieces take stark subject matter and make it shimmer; the poems take their shape as much from the absences as from the words, just as life is given meaning by the losses we survive.', 'https://images.gr-assets.com/books/1356476704m/852662.jpg', '852662', '4.23', '67', '3', 'https://www.goodreads.com/book/show/852662.The_Cradle_Of_The_Real_Life');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems of Akhmatova', '', 'In her finely crafted translations Coffin has been uniquely successful in reproducing the directness and striking effects characteristic of Akhmatova''s poetry, and she is the first to remain true to Akhmatova''s rhyme and cadence. The poems are prefaced by a thoughful introduction by the poet Joseph Brodsky, a friend of Akhmatova in her later years.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '626675', '4.31', '67', '7', 'https://www.goodreads.com/book/show/626675.Poems_of_Akhmatova');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Nilling: Prose', '', 'Nilling: Prose is a sequence of 6 loosely linked prose essays about noise, pornography, the codex, melancholy, Lucretius, folds, cities and related aporias: in short, these are essays on reading.
I have tried to make a sketch or a model in several dimensions of the potency of Arendt''s idea of invisibility, the necessary inconspicuousness of thinking and reading, and the ambivalently joyous and knotted agency to be found there. Just beneath the surface of the phonemes, a gendered name rhythmically explodes into a founding variousness. And then the strictures of the text assert again themselves. I want to claim for this inconspicuousness a transformational agency that runs counter to the teleology of readerly intention. Syllables might call to gods who do and don''t exist. That is, they appear in the text''s absences and densities as a motile graphic and phonemic force that abnegates its own necessity. Overwhelmingly in my submission to reading''s supple snare, I feel love.', 'https://images.gr-assets.com/books/1334205095m/13598539.jpg', '13598539', '4.26', '66', '8', 'https://www.goodreads.com/book/show/13598539-nilling');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('بهشت گمشده، سه کتاب اول', '', 'John Milton''s Paradise Lost is one of the greatest epic poems in the English language. It tells the story of the Fall of Man, a tale of immense drama and excitement, of rebellion and treachery, of innocence pitted against corruption, in which God and Satan fight a bitter battle for control of mankind''s destiny. The struggle rages across three worlds - heaven, hell, and earth - as Satan and his band of rebel angels plot their revenge against God. At the center of the conflict are Adam and Eve, who are motivated by all too human temptations but whose ultimate downfall is unyielding love.
Marked by Milton''s characteristic erudition, Paradise Lost is a work epic both in scale and, notoriously, in ambition. For nearly 350 years, it has held generation upon generation of audiences in rapt attention, and its profound influence can be seen in almost every corner of Western culture.
(P)2009 Tantor', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2265305', '3.8', '66', '9', 'https://www.goodreads.com/book/show/2265305._');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Amazing Peace', '', 'Celebrate Christmas with the joyous poetry of the incomparable Maya Angelou. "Angels and Mortals, Believers and Nonbelievers, look heavenward," she writes, "and speak the word aloud. Peace." Angelou''s moving poem is a radiant affirmation of the goodness of humanity. First read at the 2005 White House tree-lighting ceremony, it comes alive again as a fully illustrated children''s book, celebrating the promise of peace in the holiday season. In this simple story, a family joins with their community--rich and poor, black and white, Muslim and Jew--to celebrate the holidays. This special package includes an audio CD of the author reading the poem aloud.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '3295509', '4.14', '66', '22', 'https://www.goodreads.com/book/show/3295509-amazing-peace');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Arte poética: Seis conferencias en Harvard', '', 'El lector tiene en sus manos un libro inedito de Jorge Luis Borges, integrado por seis conferencias sobre poesias pronunciadas en ingles en la Universidad de Harvard durante el curso 1967-1968. A lo largo de unas paginas tan brillantes y precisas que cuesta creer que fuesen dichas -y no leidas- un Borges en la plenitud de s u talento reflexiona sobre los misterios y tesoros de la palabra poetica. En la linea del ensayo imaginativo y suavemente ironico de sus mejores inquisiciones, estas conferencias deslumbrantes nos recuerdan, entre otras cosas, el especial atractivo de ciertas metaforas, la fuerza y la dignidad de la epica (a juicio de Borges, genero narrativo preferible a la novela), la belleza que se esconde en las traducciones mas felices, la corta distancia que media entre el buen poema y el malo, o la impronta que la tradicion deja sobre cada imagen, cada palabra y cada lector. A traves de un torrente de autores, libros y citas, evocados puntualmente por la prodigiosa memoria del escritor argentino, este Arte poetica nos revela el credo literario de uno de los grandes fabuladores del siglo XX.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '554651', '4.29', '66', '3', 'https://www.goodreads.com/book/show/554651.Arte_po_tica');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Love Poems', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '8358434', '4.29', '65', '2', 'https://www.goodreads.com/book/show/8358434-love-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Elegies', '', 'Winner of the Whitbread Book of the Year in 1985, these poems were written after the death of Douglas Dunn''s first wife in March 1981.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1853394', '4.35', '65', '9', 'https://www.goodreads.com/book/show/1853394.Elegies');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Selected Letters of Allen Ginsberg and Gary Snyder', '', 'One of the central relationships in the Beat scene was the long-lasting friendship of Allen Ginsberg and Gary Snyder. Ginsberg introduced Snyder to the East Coast Beat writers, including Jack Kerouac, while Snyder himself became the model for the serious poet that Ginsberg so wanted to become. Snyder encouraged Ginsberg to explore the beauty of the West Coast and, even more lastingly, introduced Ginsberg to Buddhism, the subject of so many long letter exchanges between them. Beginning in 1956 and continuing through 1991, the two men exchanged more than 850 letters. Bill Morgan, Ginsberg''s biographer and an important editor of his papers, has selected the most significant correspondence from this long friendship. The letters themselves paint the biographical and poetic portraits of two of America''s most important--and most fascinating--poets. Robert Hass'' insightful introduction discusses the lives of these two major poets and their enriching and moving relationship.', 'https://images.gr-assets.com/books/1328744781m/3385038.jpg', '3385038', '4.05', '64', '9', 'https://www.goodreads.com/book/show/3385038-the-selected-letters-of-allen-ginsberg-and-gary-snyder');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('ديوان فايق عبد الجليل', '', '', 'https://images.gr-assets.com/books/1325767621m/10154769.jpg', '10154769', '4.19', '64', '13', 'https://www.goodreads.com/book/show/10154769');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('From Room to Room', '', 'The poems in Jane Kenyon''s first book are full of respect for a life deeply felt. Her vision apprehends the mystery beneath everyday circumstances and objects, from the thimble to the edges of the map. The final section is translations of six poems by Anna Akhmatova.', 'https://images.gr-assets.com/books/1370983621m/435060.jpg', '435060', '4.16', '64', '6', 'https://www.goodreads.com/book/show/435060.From_Room_to_Room');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hamlet', '', 'One of the greatest plays of all time, the compelling tragedy of the tormented young prince of Denmark continues to capture the imaginations of modern audiences worldwide. Confronted with evidence that his uncle murdered his father, and with his mother''s infidelity, Hamlet must find a means of reconciling his longing for oblivion with his duty as avenger. The ghost, Hamlet''s feigned madness, Ophelia''s death and burial, the play within a play, the "closet scene" in which Hamlet accuses his mother of complicity in murder, and breathtaking swordplay are just some of the elements that make Hamlet an enduring masterpiece of the theater.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1916751', '4.01', '64', '9', 'https://www.goodreads.com/book/show/1916751.Hamlet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Silence: A Thirteenth-Century French Romance', '', 'A facing-page translation.
This bilingual edition, a parallel text in Old French and English, is based on a reexamination of the Old French manuscript, and makes Silence available to specialists and students in various fields of literature and women''s studies.
The Roman de Silence, an Arthurian romance of the thirteenth century, tells of a girl raised as a boy, equally accomplished as a minstrel and knight, whose final task, the capture of Merlin, leads to her unmasking.
Glossary, Bibliography, Proper Name list, Notes. B/W Frontispiece illustration.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '654484', '4.01', '64', '6', 'https://www.goodreads.com/book/show/654484.Silence');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Where the Sidewalk Ends: Poems and Drawings', '', 'Shel Silverstein, the New York Timesbestselling author of The Giving Tree, A Light in the Attic, Falling Up, and Every Thing On It, has created a poetry collection that is outrageously funny and deeply profound. Come in...for where the sidewalk ends, Shel Silverstein''s world begins.
You''ll meet a boy who turns into a TV set, and a girl who eats a whale. The Unicorn and the Bloath live there, and so does Sarah Cynthia Sylvia Stout who will not take the garbage out. It is a place where you wash your shadow and plant diamond gardens, a place where shoes fly, sisters are auctioned off, and crocodiles go to the dentist.
Shel Silverstein''s masterful collection of poems and drawings stretches the bounds of imagination and will be cherished by readers of all ages. This is a collection that belongs on everyone''s bookshelf. Makes a great gift for special occasions such as holidays, birthdays, and graduation.
And don''t miss Runny Babbit Returns, the new book by Shel Silverstein!', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '838069', '4.29', '64', '7', 'https://www.goodreads.com/book/show/838069.Where_the_Sidewalk_Ends');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Tulip-Flame', '', 'Winner of the 2013 Cleveland State University Poetry Center First Book Prize, selected and with a foreword by Tracy K. Smith', 'https://images.gr-assets.com/books/1393126798m/20888432.jpg', '20888432', '4.28', '64', '7', 'https://www.goodreads.com/book/show/20888432-the-tulip-flame');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('City Eclogue', '', 'Poetry. African American Studies. Ed Roberson might no longer live in Pittsburgh, but the city in which he was born and raised still leaves its fragmented structures etched throughout his poetry. A city of hard work and hard times, the now-impoverished neighborhoods that had at one time stood as centers of jazz and art; the hills, the rivers, the skyscraping iron and steel, and the pain. Though most of the poems in this collection do not necessarily take place in Pittsburgh, there is a rhythmic fragmentation here painting portraits of urban life in general. Beauty, music, poverty, blood, and concrete seem to live within the line breaks, while breath-stopping pauses halt you just long enough so that--like at a smoky backroom jazz club--you can''t wait to see what he does next.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1403', '4.19', '64', '7', 'https://www.goodreads.com/book/show/1403.City_Eclogue');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('A Test of Poetry', '', 'By juxtaposing several translations of the same passage from Homer; an elegy from Ovid and lines from Herrick that read like an adaptation of Ovid; or a 15th-century poem about a rooster and a contemporary poem about white chickens, Louis Zukofsky has established a means for judging the values of poetic writing.
A wonderful education for the fledgling poet, this handbook, first published in 1948, is the best elucidation of Zukofsky''s "objectivist" premises for recognizing value in specific instances of poetry.', 'https://images.gr-assets.com/books/1359618537m/375188.jpg', '375188', '4.37', '64', '4', 'https://www.goodreads.com/book/show/375188.A_Test_of_Poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('This Longing: Poetry, Teaching Stories, and Letters', '', 'This Rumi collection features selections from one of the world''s great spiritual masterpieces, the Mathnawi. The Mathnawiconsists of six volumes of poetry in rhyme--over fifty-one thousand verses--inspired by folklore, the Qur''an, stories of saints and teachers, and sayings of Muhammed. Rendered by Rumi''s premier English translators, these excerpts from the Mathnawiare presented in American free-verse style.', 'https://images.gr-assets.com/books/1320556162m/231506.jpg', '231506', '4.14', '64', '6', 'https://www.goodreads.com/book/show/231506.This_Longing');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Smith Blue', '', 'In Smith Blue, Camille T. Dungy offers a survival guide for the modern heart as she takes on twenty-first-century questions of love, loss, and nature. From a myriad of lenses, these poems examine the human capability for perseverance in the wake of heartbreak; the loss of beloved heroes and landscapes; and our determination in the face of everyday struggles. Dungy explores the dual nature of our presence on the planet, juxtaposing the devastation caused by human habitation with our own vulnerability to the capricious whims of our environment. In doing so, she reveals with fury and tenderness the countless ways in which we both create and are victims of catastrophe.
This searing collection delves into the most intimate transformations wrought by our ever-shifting personal, cultural, and physical terrains, each fraught with both disillusionment and hope. In the end, Dungy demonstrates how we are all intertwined, regardless of race or species, living and loving as best we are able in the shadows of both man-made and natural follies.
FlightIt is the day after the leaves, when buckeyes, like a thousand thousand pendulums, clock trees, and squirrels, fat in their winter fur, chuckle hours, chortle days. It is the time for the parting of our ways. You slid into the summer of my sleeping, crept into my lonely hours, ate the music of my dreams. You filled yourself with the treated sweet I offered, then shut your rolling eyes and stole my sleep. Came morning and me awake. Came morning. Awake, I walked twelve miles to the six-gun shop. On the way there I saw a bird-of-prayer all furled up by the river. I called to it. It would not unfold. On the way home I killed it. It is the time of the waking cold, when buckeyes, like a thousand thousand metronomes, tock time, and you, fat on my summer sleep, titter toward me, walk away. It is the time for the parting of our days.', 'https://images.gr-assets.com/books/1349386458m/10724131.jpg', '10724131', '4.3', '64', '10', 'https://www.goodreads.com/book/show/10724131-smith-blue');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poets in a Landscape', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1504664', '4.19', '63', '11', 'https://www.goodreads.com/book/show/1504664.Poets_in_a_Landscape');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Stuffed Owl: An Anthology of Bad Verse', '', 'The editors of this legendary and hilarious anthology write: "It would seem at a hasty glance that to make an anthology of Bad Verse is on the whole a simple matter . . . On the contrary . . . Bad Verse has its canons, like Good Verse. There is bad Bad Verse and good Bad Verse. It has been the constant preoccupation of the compilers to include in this book chiefly good Bad Verse." Here indeed one finds the best of the worst of the greatest poets of the English language, masterpieces of the maladroit by Dryden, Wordsworth, and Keats, among many others, together with an index ("Maiden, feathered, uncontrolled appetites of, 59;. . . Manure, adjudged a fit subject for the Muse, 91") that is itself an inspired work of folly.', 'https://images.gr-assets.com/books/1320561382m/24517.jpg', '24517', '3.77', '63', '8', 'https://www.goodreads.com/book/show/24517.The_Stuffed_Owl');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Kepulangan Kelima', '', 'Kepulangan Kelima adalah sebuah buku puisi kolaborasi Irwan Bajang bersama Ari KPIN, sebuah kelompok musikalisasi puisi dan Octora Guna Nugraha, seorang ilustrator.
Puisi ini disusun dari puisi-puisi pilihan Irwan Bajang selama rentang 5 tahun, sejak 2008-2013.
Dalam buku ini kita akan menemukan dua seni yang berbeda; yakni seni rupa dan seni musik. Octora menerjemahkan ulang puisi dalam buku ini ke dalam ilustrasinya, lalu Ari KPIN bersama sanggar musiknya membuat lagu berdasarkan lirik puisi dalam buku ini. Dalam lagu, Irwan juga menjadi narator di beberapa selingan musik puisi yang diciptakan.
Buku ini lebih tepat disebut sebagai Album Puisi, Musik dan Ilustrasi. Tampilan buku ini dibuat sebagai perkawinan antara puisi dan ilustrasi. Beberapa ilustrasi baik hitam-putih maupun warna menghiasi badan puisi dalam buku Kepulangan Kelima ini. Di dalam buku juga diselipkan CD musikalisasi.
Ini adalah kumpulan puisi puisi yang diapresiasi dengan dua seni lain yang berbeda.', 'https://images.gr-assets.com/books/1368301582m/17909016.jpg', '17909016', '3.97', '63', '10', 'https://www.goodreads.com/book/show/17909016-kepulangan-kelima');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Un coup de dés jamais n''abolira le hasard', '', '', 'https://images.gr-assets.com/books/1459752592m/2180403.jpg', '2180403', '4.06', '63', '4', 'https://www.goodreads.com/book/show/2180403.Un_coup_de_d_s_jamais_n_abolira_le_hasard');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Realizing the Impossible: Art Against Authority', '', 'Protestors, rows of riot cops, tear gas lobbed into crowds--these are the images that easily flood into the mind when one thinks about a gathering to protest the IMF, the WTO, a meeting of the G8, or the war on Iraq. The movement against corporate globalization has brought anti-authoritarian politics into the forefront of world consciousness, but what do we know--and what have we seen, really--of the cultural and aesthetic sides of these and other rebellions against the status quo? To date, precious little has been written by anarchists and anti-authoritarians about the role of art and culture in society, and in revolutionary movements like these.
Realizing the Impossibleis an inclusive and sprawling collection of art and writings that addresses this gap in our understanding of revolutionary movements. Do-it--yourself printmaking, Zapatista video, street art in Argentina''s popular uprisings, radical puppetry, the monuments to Haymarket martyrs, turn-of-the-century Australian Industrial Workers of the World printmakers, illustrator Clifford Harper, and wobbly poet Carlos Cortez are just a few themes in this collection that bridges time and geographical and cultural boundaries.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '381853', '4.13', '63', '9', 'https://www.goodreads.com/book/show/381853.Realizing_the_Impossible');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Crave Radiance: New and Selected Poems 1990-2010', '', 'The first career retrospective by the award-winning poet Elizabeth Alexander, including her poem delivered at Barack Obama''s presidential inauguration
We crave radiance in this austere world, 
light in the spiritual darkness. 
Learning is the one perfect religion, 
its path correct, narrow, certain, straight. 
--from "Allegiance" 
Over twenty years, Elizabeth Alexander has become one of America''s most exciting and important poets, and her selection as the inaugural poet by President Obama confirmed her place as one of the indispensable voices of our time. Crave Radiance: New and Selected Poems 1990-2010 gathers twenty pages of new poetry, along with generous selections from her previous work. The result is the definitive volume to date by this American master.', 'https://images.gr-assets.com/books/1316729297m/7920491.jpg', '7920491', '4.01', '63', '10', 'https://www.goodreads.com/book/show/7920491-crave-radiance');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('All the Words Are Yours', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '25983909', '4.16', '63', '11', 'https://www.goodreads.com/book/show/25983909-all-the-words-are-yours');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Tutaj', '', 'A new book of poems by Wislawa Szymborska is a rare and exciting event. When Herewas published in Poland, reviewers marveled, How is it that she keeps getting better?" These twenty-seven poems, as rendered by prize-winning translators Clare Cavanagh and Stanislaw Baranczak, are among her greatest ever. Whether writing about her teenage self, microscopic creatures, or the upsides to living on Earth, she remains a virtuoso of form, line, and thought.
From the title poem:
I can''t speak for elsewhere,
but here on Earth we''ve got a fair supply of everything.
Here we manufacture chairs and sorrows,
scissors, tenderness, transistors, violins, teacups, dams, and quips . . . 
Like nowhere else, or almost nowhere,
you''re given your own torso here,
equipped with the accessories required
for adding your own children to the rest.
Not to mention arms, legs, and astonished head.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6164314', '4.24', '63', '5', 'https://www.goodreads.com/book/show/6164314-tutaj');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Sorgen bär fjäderdräkt', '', 'I en lagenhet i London sorjer tva soner och deras far den plotsliga bortgangen av en alskad mor och maka. Nar deras fortvivlan ar som storst ringer det pa dorren och utanfor star den fjaderkladda sorgen. Krakan fastslar att han kommer att stanna hos den forkrossade familjen tills han inte langre behovs. Han blir deras terapeut, beskyddare och hjalpreda. Ibland obehaglig och konfronterande men ocksa varm och trostande. Med krakans hjalp borjar familjen langsamt att laka.
Sorgen bar fjaderdraktar en parafras pa Ted Hughes beromda diktsamling om krakan och en utsokt och poetisk blandning mellan novell, fabel och essa om sorg och karlek.', 'https://images.gr-assets.com/books/1471430372m/31537692.jpg', '31537692', '3.9', '62', '3', 'https://www.goodreads.com/book/show/31537692-sorgen-b-r-fj-derdr-kt');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Book of Forms: A Handbook of Poetics', '', 'Since 1968 Lewis Turco''s Book of Forms has been a staple in the libraries of writers, teachers, poets, and others who care about the craft of poetry. The 160-page first edition was followed in 1986 by the 292-page New Book of Forms, reprinted six times and one of UPNE''s Top Ten Best Sellers. Now Turco has expanded and updated his classic once again, adding many new forms, including the ghazal, rubliw, double dactyl, various Japanese forms other than the haiku and tanka, Clerihew, amphigory, backwoods boast, and quaternion. Twenty percent larger than before, it now includes six in-depth prosodic essays and an entirely new discussion of the rules of scansion, never before formulated in such a simple system and not available in any other handbook.
The Elements of Poetry section has been reorganized in three genres: Dramatic Poetry, Lyric Poetry, and Narrative Poetry. Many new poems from all of English and American literature have been added or substituted in order to provide clear examples of all terms and forms to be found in the book. In short, no handbook ever published in the English language is as complete and helpful as the third edition of The Book of Forms.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '801560', '4.22', '62', '8', 'https://www.goodreads.com/book/show/801560.The_Book_of_Forms');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Wing Nuts: Screwy Haiku', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '704877', '3.55', '62', '20', 'https://www.goodreads.com/book/show/704877.Wing_Nuts');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Some Desperate Glory: The First World War the Poets Knew', '', 'The story of World War I, through the lives and words of its poets
The hundredth anniversary of the outbreak of what many believed would be the war to end all wars is in 2014. And while World War I devastated Europe, it inspired profound poetry--words in which the atmosphere and landscape of battle are evoked perhaps more vividly than anywhere else.
The poets--many of whom were killed--show not only the war''s tragedy but also the hopes and disappointments of a generation of men. In Some Desperate Glory, the historian and biographer Max Egremont gives us a transfiguring look at the life and work of this assemblage of poets. Wilfred Owen with his flaring genius; the intense, compassionate Siegfried Sassoon; the composer Ivor Gurney; Robert Graves, who would later spurn his war poems; the nature-loving Edward Thomas; the glamorous Fabian Socialist Rupert Brooke; and the shell-shocked Robert Nichols--all fought in the war, and their poetry is a bold act of creativity in the face of unprecedented destruction.
Some Desperate Glory includes a chronological anthology of the poets'' works, telling the story of the war not only through the lives of these writers but also through their art. This unique volume unites the poetry and the history of the war--so often treated separately--granting readers the pride, strife, and sorrow of the individual soldier''s experience coupled with a panoramic view of the war''s toll on an entire nation.', 'https://images.gr-assets.com/books/1396825583m/18490555.jpg', '18490555', '3.8', '62', '16', 'https://www.goodreads.com/book/show/18490555-some-desperate-glory');
