INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('لطفاً این کتاب را بکارید', '', '', 'https://images.gr-assets.com/books/1296158684m/9219760.jpg', '9219760', '3.58', '61', '4', 'https://www.goodreads.com/book/show/9219760');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('My Way: Speeches and Poems', '', '"Verse is born free but everywhere in chains. It has been my project to rattle the chains."(from "The Revenge of the Poet-Critic")
In My Way,(in)famous language poet and critic Charles Bernstein deploys a wide variety of interlinked forms--speeches and poems, interviews and essays--to explore the place of poetry in American culture and in the university. Sometimes comic, sometimes dark, Bernstein''s writing is irreverent but always relevant, "not structurally challenged, but structurally challenging."
Addressing many interrelated issues, Bernstein moves from the role of the public intellectual to the poetics of scholarly prose, from vernacular modernism to idiosyncratic postmodernism, from identity politics to the resurgence of the aesthetic, from cultural studies to poetry as a performance art, from the small press movement to the Web. Along the way he provides "close listening" to such poets as Charles Reznikoff, Laura Riding, Susan Howe, Ezra Pound, Allen Ginsberg, and Gertrude Stein, as well as a fresh perspective on L=A=N=G=U=A=G=E,the magazine he coedited that became a fulcrum for a new wave of North American writing.
In his passionate defense of an activist, innovative poetry, Bernstein never departs from the culturally engaged, linguistically complex, yet often very funny writing that has characterized his unique approach to poetry for over twenty years. Offering some of his most daring work yet--essays in poetic lines, prose with poetic motifs, interviews miming speech, speeches veering into song--Charles Bernstein''s My Wayilluminates the newest developments in contemporary poetry with its own contributions to them.
"The result of [Bernstein''s] provocative groping is more stimulating than many books of either poetry or criticism have been in recent years."--Molly McQuade, Washington Post Book World
"This book, for all of its centrifugal activity, is a singular yet globally relevant perspective on the literary arts and their institutions, offered in good fait', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '233511', '4.05', '61', '4', 'https://www.goodreads.com/book/show/233511.My_Way');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Oneiromance', '', 'Poetry. Winner of the 2007 Gatewood Prize, Kathleen Rooney''s ONEIROMANCE (AN EPITHALAMION) explores the absurdity and divinity of the marriage ceremony through a dizzying dream sequence with playful verse that skillfully blends call and response with Shakespearean odes, romance and cynicism, story-telling and wordplay. Patty Seyburn proclaims: "These poems contain deep doubt and true sentiment, providing that pleasure-giving union of provocation and renewal." Rooney is a founding editor of Rose Metal Press and the author of Reading with Oprah: The Book Club That Changed America (University of Arkansas, 2005).', 'https://images.gr-assets.com/books/1335636457m/3434158.jpg', '3434158', '4.54', '61', '8', 'https://www.goodreads.com/book/show/3434158-oneiromance');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Essence of Rumi', '', 'A Compact yet thoroughly informative series on philosophical and religious topics, written with the general reader in mind.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '265643', '3.96', '61', '6', 'https://www.goodreads.com/book/show/265643.The_Essence_of_Rumi');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ou o Poema Contínuo', '', '', 'https://images.gr-assets.com/books/1352488849m/5997878.jpg', '5997878', '4.32', '61', '3', 'https://www.goodreads.com/book/show/5997878-ou-o-poema-cont-nuo');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Real West Marginal Way: A Poet''s Autobiography', '', 'Hugo was also an editor of the Yale Younger Poets series and a distinguished teacher and master of the personal essay. Now many of his essays have been assembled and arranged by Ripley Hugo, the poet''s widow and a writer and teacher, and Lois and James Welch, writers and close friends of the poet. Together the essays constitute a compelling autobiographical narrative that takes Hugo from his lonely childhood through the war years and his working and creative life to an interview just before his death in 1982. William Matthews, also a friend of Hugo''s, has written an introduction.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '344344', '4.41', '61', '8', 'https://www.goodreads.com/book/show/344344.The_Real_West_Marginal_Way');
