INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('For Love of Common Words: Poems', '', 'The scariest sentence in the English language is brief, threatening, and hopeful. It is deceptive, simple, and as common as water: anything is possible. This second collection by Steve Scafidi is haunted by the possible and "the bells of the verb to be" that "ring-a-ding-ding calling us / to the holy dark of this first / warm night of Spring." When anything is possible, Scafidi finds, horror is as likely as delight. In poems both meditative and defiant he mourns the eventual loss of all that we love and finds consolation, wherever possible, in the rhythm of common words and "the sacred guesswork" of the imagination. Here is the dangerous world we all have in common. Here is a brief and hopeful book.Steve Scafidi is the author of the poetry collection Sparks from a Nine-Pound Hammer, winner of the Larry Levis Reading Prize. His poem "The Egg Suckers" received the 2005 James Boatwright Prize from Shenandoah literary magazine. He is a cabinetmaker and lives with his family in Summit Point, West Virginia.
"Steve Scafidi''s poem ''The Egg Suckers'' made me laugh, fidget, and ponder my own path through this omnivorous world. It reminds us that things are constantly happening beneath our very feet, that a secret history is being forged that we''ll never read about in the newspapers. Like Theodore Roethke, Scafidi describes a nature that is at least as nasty as it is nice and then lets us know that-oops!-we''re on the menu, too. Re-reading ''The Egg Suckers, '' I laughed again. And then I made breakfast."-David Kirby', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '640076', '4.28', '61', '6', 'https://www.goodreads.com/book/show/640076.For_Love_of_Common_Words');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Byron''s Poetry and Prose', '', 'Byron''s Poetry and Prosepresents an extensive selection of Byron''s poetry, letters, and journal entries in chronological clusters, allowing readers to see the changes that took place in his writing in the context of the places he lived and his fame, exile, and travels."Criticism" is chronologically keyed to Byron''s poetry and reprints both classic and recent examinations of Byron''s writing and life, including assessments by Anne Barton, Donald H. Reiman, Jane Stabler, Jerome J. McGann, Susan J. Wolfson, and James Chandler. 
A Biographical Register, Chronology, Selected Bibliography, and Index of Poem Titles and First Lines are also included.
.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1323028', '4.2', '61', '8', 'https://www.goodreads.com/book/show/1323028.Byron_s_Poetry_and_Prose');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The White Goddess', '', 'This labyrinthine and extraordinary book, first published more than fifty years ago, was the outcome of Graves''s vast reading and curious research into strange territories of folklore, mythology, religion and magic. Erudite and impassioned, it is a scholar-poet''s quest for the meaning of European myths, a polemic about the relations between man and woman, and also an intensely personal document in which Graves explored the sources of his own inspiration and, as he believed, all true poetry.
This new edition has been prepared by Grevel Lindop, who has written an illuminating introduction. The text of the book incorporates all Graves''s final revisions, as well as his replies to two of the original reviewers, and a long essay in which he describes the months of inspiration in which The White Goddesswas written.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '55427', '4.02', '60', '6', 'https://www.goodreads.com/book/show/55427.The_White_Goddess');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems 1962-2012', '', 'The collected works of the inimitable Pulitzer Prize-winning poet
It is the astonishment of Louise Gluck''s poetry that it resists collection. With each successive book her drive to leave behind what came before has grown more fierce, the force of her gaze fixed on what has yet to be imagined. She invented a form to accommodate this need, the book-length sequence of poems, like a landscape seen from above, a novel with lacunae opening onto the unspeakable. The reiterated yet endlessly transfigured elements in this landscape--Persephone, a copper beech, a mother and father and sister, a garden, a husband and son, a horse, a dog, a field on fire, a mountain--persistently emerge and reappear with the dark energy of the inevitable, shot through with the bright aspect of things new-made.
From the outset ("Come here / Come here, little one"), Gluck''s voice has addressed us with deceptive simplicity, the poems in lines so clear we "do not see the intervening fathoms."
From within the earth''s
bitter disgrace, coldness and barrenness
my friend the moon rises: 
she is beautiful tonight, but when is she not beautiful?
To read these books together is to understand the governing paradox of a life lived in the body and of the work wrested from it, the one fated to die and the other to endure.', 'https://images.gr-assets.com/books/1361640105m/17332350.jpg', '17332350', '4.47', '60', '5', 'https://www.goodreads.com/book/show/17332350-poems-1962-2012');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Crystal Text', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1440458', '4.56', '60', '2', 'https://www.goodreads.com/book/show/1440458.The_Crystal_Text');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Gay Science', '', 'Nietzsche wrote The Gay Science, which he later described as "perhaps my most personal book," when he was at the height of his intellectual powers, and the reader will find it an extensive and sophisticated treatment of the philosophical themes and views most central to Nietzsche''s own thought and most influential on later thinkers. This volume presents the work in a new translation by Josefine Nauckhoff, with an introduction by Bernard Williams that elucidates the work''s main themes and discusses their continuing importance.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '83275', '4.26', '60', '6', 'https://www.goodreads.com/book/show/83275.The_Gay_Science');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Lyric Poetry', '', 'It is most fitting that Northwestern University Press, long a leading publisher of Russian literature in translation, launches the Northwestern World Classics series with a new translation of Russia''s greatest poet. Included are many famous poems well known to, and often memorized by, every educated Russian, as well as lighter, more occasional pieces.
Renowned translator James Falen''s collection of 167 of Pushkin''s lyrics is arranged chronologically, beginning with verse written in the poet''s teenage years--Pushkin published his first poem at fifteen and was widely revered by his later teens--and closing with lines composed shortly before his death. As a whole, these selections reveal Pushkin''s development as a poet, but they also capture the wide range of subjects and styles in Pushkin''s poetry.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6878432', '4.15', '60', '6', 'https://www.goodreads.com/book/show/6878432-selected-lyric-poetry');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('To a Fault', '', 'In this impressive debut, Nick Laird explores the sharp edge of relationships, from the intimacy of lovers to the brutality of political violence. Journeying between his native Ulster and his adopted London, he balances ideas of home and flight, the need for belonging and the need to remain outside. Formally deft, rhetorically fresh, these poems never shy from difficult choices, exploring cruelty and vengeance wherever they may be found: in love, in work and against political backdrops. But these are brave, resolute writings that resist despair at all times, affirming instead the need to rebuild and to right oneself, to dust down and carry on.', 'https://images.gr-assets.com/books/1356447706m/251121.jpg', '251121', '3.63', '60', '5', 'https://www.goodreads.com/book/show/251121.To_a_Fault');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Shaking the Pumpkin: Traditional Poetry of the Indian North Americas', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '405069', '4.42', '60', '5', 'https://www.goodreads.com/book/show/405069.Shaking_the_Pumpkin');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Poems Between Women: Four Centuries of Love, Romantic Friendship, and Desire', '', 'The collection Poems Between Women explores many facets of female-female relationships in poems not only about love or affection between or inspired by women but also about the moments that complicate and call into question the nature of sexuality and intimacy between women. Including women married and single, young and old, lesbian, bisexual, and heterosexual, the anthology covers historical development and changing mores through the seventeenth century, after the Restoration of Charles II, a time of relative freedom for women; the eighteenth century, when the cult of romantic friendship reached its peak; the nineteenth century, when women writers wrote about issues of same-sex desire indirectly and explored complex issues such as death in tones of weariness and resignation; and the twentieth century, when poets began to engage in more overt explorations of women''s bodies, sensuality, and lovemaking. Emma Donoghue''s introduction deftly guides readers into the rich tradition of women''s poetry in English, exploring the relationships between poets and their muses and poets and their cultures. Poems Between Women is testimony not only to the recurring theme of the unique bonds among women but also to the universality of love, friendship, and creativity.', 'https://images.gr-assets.com/books/1400878871m/44540.jpg', '44540', '3.88', '60', '4', 'https://www.goodreads.com/book/show/44540.Poems_Between_Women');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Metamorphoses', '', 'This collection of poetry is one of the foremost sources of tales of Roman mythology.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '835547', '4.03', '60', '11', 'https://www.goodreads.com/book/show/835547.The_Metamorphoses');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('From the New World: Poems 1976-2012', '', 'An indispensable volume of poems, selected from almost four decades of work, that tracks the evolution of one of our most renowned contemporary poets, Pulitzer Prize-winner Jorie Graham.
The Poetry Foundation has named Jorie Graham "one of the most celebrated poets of the American post-war generation." In 1996, her volume of poetry selected from her first five books, Dream of a Unified Field, won the Pulitzer Prize. Now, twenty years later, Graham returns with a new selection, this time from eleven volumes, including previously unpublished work, which, in its breathtaking overview, illuminates of the development of her remarkable poetry thus far.
In From the New World--Poems 1976-2014, we can witness the unfolding of Graham''s signature ethical and eco-political concerns, as well as her deft exploration of mythology, history, love and, increasingly, love of the world in a time of crisis. As the work evolves, the depth of compassion grows--gradually transforming, widening and expanding her extraordinary formal resources and her inimitable style.
These pages present a brilliant portrait one of the major voices of American contemporary poetry. As critic Calvin Bedient says, "If Graham has proved oversized as a poet in the field of contemporary poetry, it is because she continually recalls the great Western tradition of philosophical and religious inquiry . . . tenaciously thinking and feeling her way through layer after layer of perception, like no poet before her."', 'https://images.gr-assets.com/books/1404479937m/18144591.jpg', '18144591', '4.13', '59', '4', 'https://www.goodreads.com/book/show/18144591-from-the-new-world');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Measure for Measure', '', 'Measure for Measureis among the most passionately discussed of Shakespeare''s plays. In it, a duke temporarily removes himself from governing his city-state, deputizing a member of his administration, Angelo, to enforce the laws more rigorously. Angelo chooses as his first victim Claudio, condemning him to death because he impregnated Juliet before their marriage.
Claudio''s sister Isabella, who is entering a convent, pleads for her brother''s life. Angelo attempts to extort sex from her, but Isabella preserves her chastity. The duke, in disguise, eavesdrops as she tells her brother about Angelo''s behavior, then offers to ally himself with her against Angelo.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '8516481', '3.67', '59', '2', 'https://www.goodreads.com/book/show/8516481-measure-for-measure');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Handbook of Heartbreak: 101 Poems of Lost Love and Sorrow', '', 'Collected by U.S. Poet Laureate Robert Pinsky, this unique volume brings together works from poets jilted in the sixteenth century to those struggling with heartache today -- including William Shakespeare, Sylvia Plath, Wallace Stevens, Frank O''Hara, Langston Hughes, Emily Dickinson, and Louise Gluck. The Handbook of Heartbreak is a must for anyone who has ever loved -- and lost.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '765987', '3.88', '59', '9', 'https://www.goodreads.com/book/show/765987.The_Handbook_of_Heartbreak');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Questions for Ada', '', 'The artistry of QUESTIONS FOR ADA defies words, embodying the pain, the passion, and the power of love rising from the depths of our souls. Ijeoma Umebinyuo''s poetry is a flower that will blossom in the spirit of every reader as she shares her heart with raw candor. From lyrical lushness to smoky sensuality to raw truths, this tome of transforming verse is the book every woman wants to write but can''t until the broken mirrors of their lives have healed. In this gifted author''s own words--"I am too full of life to be half-loved." A bold celebration of womanhood.', 'https://images.gr-assets.com/books/1488619221m/26068847.jpg', '26068847', '4.41', '59', '12', 'https://www.goodreads.com/book/show/26068847-questions-for-ada');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Naufragio en la 338', '', 'Todas las tablas a las que me agarre en mi ultimo naufragio.
El huracan que destrozo Roma despues de haber probado todos los caminos que me podian hacer llegar a ella.
Un conjunto de errores, heridas, cicatrices curadas con saliva.
El abrazo dado a tiempo antes de que el viento se llevara mis cenizas despues del incendio.
El deseo de sobrevivir a mil mareas.
Los clavos a los que me agarre ardiendo y las balas que me traspasaron la piel pensando que eran las yemas de sus dedos.
La pistola que me puse en la sien mientras cantaba mi cancion favorita y bailaba cuando queria romper a llorar.
El cuento que te escribi antes de dormir contandote lo mucho que me gustaba romperme si era para reir.
La historia de la vez en la que me enamore de la catastrofe antes que de un corazon.
Son las mil lagrimas que sonrei y las mil sonrisas que llore en una habitacion.
Bienvenidos al naufragio, pasen y cojan aire.
Este libro puede ser un salvavidas o la ultima carta de un suicida, eso lo escogen ustedes.', 'https://images.gr-assets.com/books/1423341298m/24863830.jpg', '24863830', '4.05', '59', '6', 'https://www.goodreads.com/book/show/24863830-naufragio-en-la-338');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Nikah Ilalang', '', 'Puisi-puisi dalam Nikah Ilalang ini, sebagaimana ciri puisi Dorothea yang lain, mencitrakan dunia yang keras, kosong, gelap, berbau kematian, kebusukan yang menghadirkan paradoks-paradoks dalam realitas yang jamak. Citra pernikahan, percintaan, kelahiran, keluarga dihadirkan sebagai sesuatu yang menyakitkan, penuh luka, kemunafikan, dan gelap-hampa. Sebagai penyair perempuan, pilihan ciri sajak seperti ini, tentu menentang konvensi sajak perempuan pada umumnya yang cenderung dengan diksi feminin. Boleh jadi, melalui sajaknya ini, Dorothea sengaja melawan stereotip inferioritas perempuan. Bahwa perempuan juga bisa berkuasa dan "bertenaga", awalnya dengan kata.', 'https://images.gr-assets.com/books/1464283929m/1408372.jpg', '1408372', '3.46', '59', '10', 'https://www.goodreads.com/book/show/1408372.Nikah_Ilalang');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Soul Would Have No Rainbow if the Eyes Had No Tears and Other Native American PR', '', 'A collection of short and inspirational Native American proverbs.
Sayings of time-honored truth and contemporary wisdom from the Native American tribes:
Why will you take by force what you may obtain by love?
We will be known forever by the tracks we leave.
He who serves his fellows is the greatest of all.
If a man is as wise as a serpent, he can be as gentle as a dove.
The life of a man is a circle from childhood to childhood, and so it is in everything where power moves.
A sin against a neighbor is an offense against the Great Spirit.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '475003', '3.86', '59', '14', 'https://www.goodreads.com/book/show/475003.Soul_Would_Have_No_Rainbow_if_the_Eyes_Had_No_Tears_and_Other_Native_American_PR');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Toward the Creative Nothing and other writings', '', 'http://www.anti-politics.net/distro/d...
It is difficult to find anarchist works in English that are at the same time "individualist" and explicitly revolutionary, that emphasize the centrality of the aim of individual self-determination to a revolution that will "communalize material wealth" as it will "individualize spiritual wealth". For this and other reasons I chose to translate Toward the Creative Nothing by Renzo Novatore and publish several of his shorter pieces. Written shortly after World War I, as a revolution was occurring in Russia and uprisings were happening in Germany and Italy, this poetic text responds to the upheaval of its time with a call for a revolution that could truly move the human race beyond the spiritual impoverishment, the equality in baseness that democracy and socialism offered. Bourgeois society seemed to have reached its dusk, and Novatore saw the hope for a new dawn only in such a revolution-one that went beyond the mere economic demands of the socialists and communists--a revolution moved by great ideas and great passions that would break with the low values of bourgeois democratic civilization.', 'https://images.gr-assets.com/books/1277165612m/6422978.jpg', '6422978', '3.86', '59', '3', 'https://www.goodreads.com/book/show/6422978-toward-the-creative-nothing-and-other-writings');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Yellow Silk: Erotic Arts and Letters', '', 'A compendium of superb erotic literature and artwork for men and women, Yellow Silk is an unabashedly joyful celebration of human sexuality in all its delightful diversity.
Yellow Silk: Journal of the Erotic Arts was founded in 1981 on the belief that the erotic should play a more visible role in American arts and letters. Drawn from this award-winning publication, the wide variety of short stories, poems, and artwork in this book manages to be both subtle and explicit, with writing ranging from earthy and humorous to tender and thoughtful. Yellow Silk is guided by the editorial policy of "all persuasions, no brutality." In Yellow Silk the erotic is heralded as a loving form of expression, which treats both men and women with dignity, respect, and affection. The result is a quality collection with work by such writers as William Kotzwinkle, Marge Piercy, Gary Soto, Jane Underwood, Marilyn Hacker, and Robert Silverberg.
Complete with black-and-white artwork throughout, Yellow Silk_will appeal to countless readers seeking an erotic alternative.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '805605', '3.93', '59', '4', 'https://www.goodreads.com/book/show/805605.Yellow_Silk');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poetry of Robert Frost: The Collected Poems', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '20322128', '4.3', '58', '4', 'https://www.goodreads.com/book/show/20322128-the-poetry-of-robert-frost');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Winter Stars', '', 'Since the appearance of his first book in 1972, Larry Levis has been one of the most original and most highly praised of contemporary American poets. In Winter Stars, a book of love poems and elegies, Levis engages in a process of relentless self-interrogation about his life, about losses and acceptances. What emerges is not merely autobiography, but a biography of the reader, a "representative life" of our time.', 'https://images.gr-assets.com/books/1328807845m/773136.jpg', '773136', '4.51', '58', '3', 'https://www.goodreads.com/book/show/773136.Winter_Stars');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Make Me Take It from You: Erotic Poetry and Short Stories', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '31821541', '4.53', '58', '42', 'https://www.goodreads.com/book/show/31821541-make-me-take-it-from-you');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Murmur', '', 'Poetry. Cross-Genre."Wildly absorbing, MURMUR is a gorgeous genre-bender: detective novel, film noir and memoir (and autopsy of all three), tricked out with bloody mirrors, blue murder, mutable coffins, loopy interrogations and a dead bombshell''s shoes. This is one fabulous book!" Rikki Ducornet
"Laura Mullen floods the confines of the ''detective novel'' with all possible events, all murderers and all murdered so that, at any point in the narrative, everything has happened and everyone has done it. MURMUR is a further-fiction of displacement and testimony that calls us to the task of deciding not only whether we would or would not do a thing but also whether we even know the difference between the two. A gripping exploration into the brutality of our time that you will not soon forget." Renee Gladman
"MURMUR collects an astonishing array of sorties into language as a terra incognita occasioning the uncanny and always troubled confluence of the subject, the bodies it inhabits and the linguistic remainder. Mullen animates narrative at the level of its basic semantic pulse. You''ll meet a talking corpse, a severed head, a heart drawn on an open palm and the gradual destruction of a face. Mullen is as much an expert in the comic and grotesque, as in the restless and anonymous. With a majestically controlled impatience she constructs a textual space both unnerving and familiar. These are splendid texts of the nameless ones (a ''messenger, '' the ''caller, '' the ''reader'') who interrupt and witness the murmur of the linked deictic shadows of a recurring ''she'' and ''he.'' Never since Beckett has the unnamed been so chilling precisely because it is unnameable." Steve McCaffery
"Laura Mullen''s MURMUR finds the crime in the moments between actions, in language overheard, doubling back, in a style both unnerving and comforting; always midsentence we feel death never dying, ''real despite or because of the staging, '' and in the background, Duras, Hitchcock the passions of mundane horror', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1040064', '4.41', '58', '9', 'https://www.goodreads.com/book/show/1040064.Murmur');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Desiderata of Happiness', '', '', 'https://images.gr-assets.com/books/1439075359m/15189171.jpg', '15189171', '4.4', '58', '3', 'https://www.goodreads.com/book/show/15189171-desiderata-of-happiness');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Cosmos Trilogy', '', '"You Can''t Like Seidel''s Poems--They''re Deliberately Virulent; You Can Only Gasp At Their Skill And Daring, Their Sickening Warp, Their Mercilessness."*
Frederick Seidel''s highly acclaimedCosmos Trilogy is a triple thunderclap of darkness from the poet whom Richard Poirier has recently called "the true heir of Walt Whitman" and of whose first book Robert Lowell wrote "[I] suspect the possibilities of modern poetry have been changed. Here is power that strikes." Reversing the course of Dante''s Divine Comedy, Seidel''s trilogy begins in the heavens, with The Cosmos Poems, and descends, passing through the Purgatorio of Life on Earthto arrive in Manhattan in Area Code 212.', 'https://images.gr-assets.com/books/1311971298m/808937.jpg', '808937', '4.33', '58', '9', 'https://www.goodreads.com/book/show/808937.The_Cosmos_Trilogy');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Brenda Is in the Room, and Other Poems', '', 'Winner of the 2007 Colorado Prize for Poetry
Published by the Center for Literary Publishing at Colorado State University', 'https://images.gr-assets.com/books/1347986420m/2113235.jpg', '2113235', '3.86', '58', '8', 'https://www.goodreads.com/book/show/2113235.Brenda_Is_in_the_Room_and_Other_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems', '', 'Verlaine ranks alongside Baudelaire, Mallarme, and Rimbaud as one of the most influential poets of late nineteenth-century France. Remarkable not only for his exquisitely crafted verse, Verlaine is also the poet of strong emotions and appetites, with an unrivalled gift for the sheer music of poetry, and an inventive approach to its technique. This bilingual edition provides the most comprehensive selection of his poetry yet, offering some 170 poems in lively and fresh translations. It also offers a lucid introduction which illuminates Verlaine''s poetic form within the context of French Impressionism and the poetry of sensation.
About the Series: For over 100 years Oxford World''s Classics has made available the broadest spectrum of literature from around the globe. Each affordable volume reflects Oxford''s commitment to scholarship, providing the most accurate text plus a wealth of other valuable features, including expert introductions by leading authorities, voluminous notes to clarify the text, up-to-date bibliographies for further study, and much more.
"', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6782699', '4.12', '58', '6', 'https://www.goodreads.com/book/show/6782699-selected-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems 1930-1988', '', 'It was as a poet that Samuel Beckett launched himself in the little reviews of 1930s Paris, and as a poet that he ended his career. This new selection, from Whoroscope(1930) to ''what is the word'' (1988), describes a lifetime''s arc of writing. It was as a poet moreover that Beckett made his first breakthrough into writing in French, and the Selected Poemsrepresents work in both languages, including the sequence of brief but highly crafted mirlitonnades, which did so much to usher in the style of his late prose, and come as close as anything he wrote to honouring the ambition to ''bore one hole after another in language, until what lurks behind it - be it something or nothing - begins to seep through.'' Also included are several of Beckett''s translations from contemporaries - Apollinaire, Eluard, Michaux, Montale - in versions which count among his own poetic achievements.
Edited by David Wheatley', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6590725', '3.69', '58', '5', 'https://www.goodreads.com/book/show/6590725-selected-poems-1930-1988');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Drowned Book: Ecstatic and Earthy Reflections of the Father of Rumi', '', 'The Lost Words of the Sufi Master and Father of Rumi
Bahauddin, Rumi''s father, was not only a major force in the development of Islamic spirituality, but also a deeply influential force in his son''s life. In this, the first ever substantial English version of a wonderful but virtually unknown book, Bahauddin proves to be a daring, spiritual genius. His voice comes through the delightful, passionate craft of Coleman Barks, who transforms the Persian translations of John Moyne into fresh spiritual literature.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '125445', '4.31', '58', '8', 'https://www.goodreads.com/book/show/125445.The_Drowned_Book');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('17 dikter', '', '', 'https://images.gr-assets.com/books/1320164451m/7097403.jpg', '7097403', '3.71', '58', '2', 'https://www.goodreads.com/book/show/7097403-17-dikter');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Lipika', '', '', 'https://images.gr-assets.com/books/1486944943m/3773251.jpg', '3773251', '4.2', '58', '3', 'https://www.goodreads.com/book/show/3773251-lipika');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('سونيتات شكسبير الكاملة', '', 'T.S. Eliot once wrote that, "Shakespeare gives the greatest width of human passion," and it is this passion that has traditionally made The Sonnets appealing to literati and laymen alike. Surrounded by mystery, these poems of devotion and jealousy, of a young courtier and a Dark Lady, have been the subject of endless speculation. They are highly mystical and at the same time highly honest; as W. H. Auden wrote, "...what is astonishing about the sonnets, especially when one remembers the age in which they were written, is the impression they make of naked autobiographical confession."
Because they are witty, passionate, personal, and often ever bawdy, The Sonnets stand as one of the greatest poetic tributes ever written to a beloved.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '9316832', '4.24', '58', '13', 'https://www.goodreads.com/book/show/9316832');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The New Human Beings', '', '', 'https://images.gr-assets.com/books/1425539573m/25075649.jpg', '25075649', '4.53', '58', '4', 'https://www.goodreads.com/book/show/25075649-the-new-human-beings');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Ariel', '', 'Ariel(1965) contains many of Sylvia Plath''s best-known poems written in an extraordinary burst of creativity just before her death in 1963, including ''Lady Lazarus'', ''Edge'', ''Daddy'' and ''Paralytic''. The first of four collections to be published by Faber & Faber, Ariel is the volume on which Sylvia Plath''s reputation as one of the most original, daring and gifted poets of the twentieth century rests.
This beautiful hardback reproduces the classic design of the first edition of a volume now recognised to be one of the most shocking and iconic collections of poetry of the twentieth century.
''If the poems are despairing, vengeful and destructive, they are at the same time tender, open to things, and also unusually clever, sardonic, hardminded . . . They are works of great artistic purity and, despite all the nihilism, great generosity . . . the book is a major literary event.'' A. Alvarez in the Observer', 'https://images.gr-assets.com/books/1387314699m/18046427.jpg', '18046427', '4.23', '57', '9', 'https://www.goodreads.com/book/show/18046427-ariel');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Inanna: From the Myths of Ancient Sumer', '', '', 'https://images.gr-assets.com/books/1328770675m/868597.jpg', '868597', '4.05', '57', '9', 'https://www.goodreads.com/book/show/868597.Inanna');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('New Collected Poems', '', 'In Wendell Berry''s upcoming The New Collected Poems, the poet revisits for the first time his immensely popular Collected Poems, which The New York Times Book Reviewdescribed as "a straight-forward search for a life connected to the soil, for marriage as a sacrament and family life" that "affirms a style that is resonant with the authentic," and "[returns] American poetry to a Wordsworthian clarity of purpose."
In The New Collected Poems, Berry reprints the nearly two hundred pieces in Collected Poems, along with the poems from his most recent collections--Entries, Given, and Leavings--to create an expanded collection, showcasing the work of a man heralded by The Baltimore Sunas "a sophisticated, philosophical poet in the line descending from Emerson and Thoreau . . . a major poet of our time."
Wendell Berry is the author of over forty works of poetry, fiction, and non-fiction, and has been awarded numerous literary prizes, including the T.S. Eliot Award, a National Institute of Arts and Letters award for writing, the American Academy of Arts and Letters Jean Stein Award, and a Guggenheim Foundation Fellowship. While he began publishing work in the 1960s, Booklisthas written that "Berry has become ever more prophetic," clearly standing up to the test of time.', 'https://images.gr-assets.com/books/1351663920m/16057624.jpg', '16057624', '4.43', '57', '3', 'https://www.goodreads.com/book/show/16057624-new-collected-poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Güvercin Gerdanlığı', '', 'ktb Twq lHmm@ ''w Twq lHmm@ fy l''lf@ wl''lf hw ktb lbn Hzm l''ndlsy wSf b''nh ''dq m ktb l`rb fy drs@ lHb wmZhrh w''sbbh. trjm lktb l~ l`dyd mn llGt l`lmy@.
wsm lktb kmlan Twq lHmm@ fy l''lf@ wl''ulf. wyHtwy lktb `l~ mjmw`@ mn ''khbr w''sh`r wqSS lmHbyn, wytnwl lktb blbHth wldaWrs `Tf@ lHb lnsny@ `l~ q`d@ t`tmd `l~ shy mn ltHlyl lnfsy mn khll lmlHZ@ wltjrb@. fy`lj bn Hzm fy ''slwb qSSy hdhh l`Tf@ mn mnZwr nsny tHlyly. wlktb yu`d `mlan frydan fy bbh.
Ibn Hazm''s Tawq al-Hamama (''The Ring of the Dove'')
The famous Arabic book on love and lovers, Tawq al-hamama (''the Ring of the Dove''), is a splendid witness to the high age of Islamic culture in Spain. The book was written in or around 1022 CE in Jativa, south of Valencia, by Abu Muhammad `Ali Ibn Hazm al-Andalusi (Cordoba, 994-1064 CE). It is a youth work by this famous Andalusian poet, philosopher, jurist and scholar of comparative religion.
In thirty chapters Ibn Hazm treats thirty moments or personages that are of relevance to love relationships, such as the signs of love, love at first sight, amorous allusions, correpondence between lovers, the messenger between the lovers, being together, fidelity and unfidelity, separation, death. Ibn Hazm alternates from theoritical observations to anecdotes of daily life and he ornates his essays with an abundance of appropriate poetry. The anecdotes are often very peronal and they give the reader a enthralling view on life and love in Islamic Cordoba. All poetry in the Ring of the Dove is Ibn Hazm''s own.
The Ring of the Dove has been preserved in only one manuscript, which is, since 1665, part of the Oriental collections of Leiden University Library (where it is registered as Or. 927). It was copied in 1338 CE, most probably in Egypt or Syria, from an original that is now lost. The manuscript was first acquired in Istanbul in the middle of the 17th century by the learned and bibliophile Dutch ambassador to the Sublime Porte, Levinus Warner (1619-1665). After his death his entire collectio', 'https://images.gr-assets.com/books/1331207646m/13516779.jpg', '13516779', '3.89', '57', '3', 'https://www.goodreads.com/book/show/13516779-g-vercin-gerdanl');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Poet in the World', '', '', 'https://images.gr-assets.com/books/1330129296m/704915.jpg', '704915', '4.52', '57', '7', 'https://www.goodreads.com/book/show/704915.The_Poet_in_the_World');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The 6.5 Practices of Moderately Successful Poets: A Self-Help Memoir', '', 'A private eye turned moderately successful poet leads readers on a satiric, hopeful tour of how to make a life in the arts, while still having a life. Revealing, hilarious, and peppered with sly takes on the ins and outs of contemporary American poetry (chapters include "The Silence of the Iambs," "The Revisionarium, Ask Dr. Frankenpoem," and "The Periodic Table of Poetic Elements"), Jeffrey Skinner offers advice, candor, and wit.
Revision is the process a poem endures to become its best self.
Or, if you are the poet, you are the process a poem endures to become its best self.
Endures because a first draft, like all other objects in the universe, has inertia and would prefer to stay where it is. The poet must not collaborate.
Bestself because the poem is more like a person than a thing, and does not strenuously object to personification.
Yo, poem.
But let''s not get carried away. It''s your poem and you can treat it as you wish; sweet talk it; push it around if that''s what it takes. Alfred Hitchcock notoriously said of the actors in his movies, "They are cattle."
Jeffrey Skinneris the author of five books of poetry, most recently Salt Water Amnesia(Ausable Press, 2005). His poems have appeared in The New Yorker, The Atlantic, The Nation, The American Poetry Review, Poetry, BOMB, and The Paris Review, and his work has earned awards from the National Endowment for the Arts, The Ingram Merrill Foundation, and the Howard Foundation.', 'https://images.gr-assets.com/books/1328693428m/13236917.jpg', '13236917', '3.87', '57', '14', 'https://www.goodreads.com/book/show/13236917-the-6-5-practices-of-moderately-successful-poets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Selected Poems and Prefaces', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '65337', '4.05', '57', '2', 'https://www.goodreads.com/book/show/65337.Selected_Poems_and_Prefaces');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Love Poems', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1806798', '4.05', '57', '6', 'https://www.goodreads.com/book/show/1806798.Love_Poems');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Bronx Masquerade', '', 'Using the structure of a poetry slam, Nikki Grimes'' award-winning novel is a powerful exploration of self, an homage to spoken-word poetry, and an intriguing look into the life of eighteen urban teens. This anniversary edition--celebrating ten years of this wonderfully evocative work--will feature discussion questions, testimonials from teachers, and an all new introduction from the author.', 'https://images.gr-assets.com/books/1309213358m/1251991.jpg', '1251991', '3.95', '57', '16', 'https://www.goodreads.com/book/show/1251991.Bronx_Masquerade');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('When the Moon is Full', '', 'This lunar guide describes the folkloric names of twelve moons according to Native American tradition and showcases their defining characteristics in short verse and beautifully detailed hand-colored woodcuts. A question-and-answer section includes information about the moon''s surface, an explanation of a lunar eclipse, and the true meaning of a blue moon.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '569326', '4.02', '57', '16', 'https://www.goodreads.com/book/show/569326.When_the_Moon_is_Full');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Du Fu: A Life in Poetry', '', 'Du Fu (712-770) is one of the undisputed geniuses of Chinese poetry--still universally admired and read thirteen centuries after his death. Now David Young, author of Black Lab, and well known as a translator of Chinese poets, gives us a sparkling new translation of Du Fu''s verse, arranged to give us a tour of the life, each "chapter" of poems preceded by an introductory paragraph that situates us in place, time, and circumstance. What emerges is a portrait of a modest yet great artist, an ordinary man moving and adjusting as he must in troubled times, while creating a startling, timeless body of work.
Du Fu wrote poems that engaged his contemporaries and widened the path of the lyric poet. As his society--one of the world''s great civilizations--slipped from a golden age into chaos, he wrote of the uncertain course of empire, the misfortunes and pleasures of his own family, the hard lives of ordinary people, the changing seasons, and the lives of creatures who shared his environment. As the poet chases chickens around the yard, observes tear streaks on his wife''s cheek, or receives a gift of some shallots from a neighbor, Young''s rendering brings Du Fu''s voice naturally and elegantly to life.
I sing what comes to me
in ways both old and modern
my only audience right now--
nearby bushes and trees
elegant houses stand
in an elegant row, too many
if my heart turns to ashes
then that''s all right with me . . .
from "Meandering River"', 'https://images.gr-assets.com/books/1320450103m/5501213.jpg', '5501213', '4.26', '57', '12', 'https://www.goodreads.com/book/show/5501213-du-fu');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('While We''ve Still Got Feet', '', 'Familiar to listeners of National Public Radio, David Budbill is beloved by legions for straightforward poems dispatched from his hermitage on Judevine Mountain. Inspired by classical Chinese hermit poets, he follows tradition but cannot escape the complications and struggles of a modern solitary existence. Loneliness, aging and political outrage are addressed in poems that value honesty and simplicity and deplore pretension.
For more than three decades, David Budbillhas lived on a remote mountain in northern Vermont writing poems, reading Chinese classics, tending to his garden and, of course, working on his website. Budbill has been featured more than any other author on Garrison Keillor''s The Writer''s Almanac.', 'https://images.gr-assets.com/books/1324243205m/1385823.jpg', '1385823', '4.02', '56', '11', 'https://www.goodreads.com/book/show/1385823.While_We_ve_Still_Got_Feet');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Romance of the Rose', '', 'This is a new translation of The Romance of the Rose, an allegorical account of the progress of a courtly love affair which became the most popular and influential of all medieval romances. In the hands of Jean de Meun, who continued de Lorris''s work, it assumed vast proportions and embraced almost every aspect of medieval life from predestination and optics, to the Franciscan controversy and the right way to deal with premature hair-loss.', 'https://images.gr-assets.com/books/1345538683m/6483845.jpg', '6483845', '3.66', '56', '6', 'https://www.goodreads.com/book/show/6483845-the-romance-of-the-rose');
