INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hourglass Museum', '', '"Lyrical, intelligent, magical, and honest, the poems are both of this world and out of this world. Her uniquely true and mystical voice is like a glass of pure water: refreshing, healing, and oh, so necessary."--Nin Andrews
"Her poems are an intense vision of the power of art to heal, to help us understand ourselves and our world. Agodon invokes artists as disparate as Kahlo and Cornell, Picasso and Pollock, as a way into the world she creates for us in her deft and musical poems. She brilliantly succeeds."--Wyn Cooper
Kelli Russell Agodonis the author of two previous collections of poetry and lives in Kingston, Washington.', 'https://images.gr-assets.com/books/1380034198m/18406197.jpg', '18406197', '4.55', '52', '12', 'https://www.goodreads.com/book/show/18406197-hourglass-museum');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Handsprings', '', 'Twenty-nine poems about spring are illustrated with Douglas Florian''s distinctive and buoyant watercolours and extol the many virtues of the season-from those muddy puddles and emerging bulbs to rain showers and rainbows and that first day without mittens. Concrete poems, humour, ingenious wordplay, and audience appeal make this a consummate companion to the acclaimed poet''s first three seasonal collections.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '1616959', '3.92', '52', '16', 'https://www.goodreads.com/book/show/1616959.Handsprings');
