INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Judevine: The Complete Poems, 1970-1990', '', 'The stage is "Judevine," an imaginary town in northern Vermont. This is a small stage, sometimes cold and darkened, but filled with characters so finely etched that they stand out as clearly as steeples against the sky. David Budbill plunges into the soul of New England to find characters and stories with lessons for anyone wanting to find the intrinsic nature of the region that has been called "all of America''s backyard." These dark, lyrical, funny narrative poems portray the hopes and joys, pains and despair of people who have been bypassed or bruised by the twentieth century. Budbill has written a song of the down-and-out or overlooked, a song of the unsung. This anthem of the rural renaissance is microcosmic in setting, but universal in scope.', 'https://images.gr-assets.com/books/1390180097m/1133635.jpg', '1133635', '4.06', '51', '4', 'https://www.goodreads.com/book/show/1133635.Judevine');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('L''Amour fou', '', '" Je vous souhaite d''etre follement aimee. " Un des textes fondamentaux du surrealisme. Un des ouvrages de Breton dans lequel s''offre le plus ouvertement la gamme entiere de ses " charmes ". Le hasard et le desir, la vie et le reve, le monde et l''homme entretiennent ici une mysterieuse correspondance de tous les instants.
From backcover', 'https://images.gr-assets.com/books/1441787466m/2408028.jpg', '2408028', '3.89', '51', '3', 'https://www.goodreads.com/book/show/2408028.L_Amour_fou');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Three Way Tavern: Selected Poems', '', 'Ko Un, the preeminent Korean poet of the twentieth century, embraces Buddhism with the versatility of a master Taoist sage. A beloved cultural figure who has helped shape contemporary Korean literature, Ko Un is also a novelist, literary critic, ex-monk, former dissident, and four-time political prisoner. His verse--vivid, unsettling, down-to-earth, and deeply moving--ranges from the short lyric to the vast epic and draws from a poetic reservoir filled with memories and experiences ranging over seventy years of South Korea''s tumultuous history from the Japanese occupation to the Korean war to democracy. This collection, an essential sampling of his poems from the last decade of the twentieth century, offers in deft translation, as lively and demotic as the original, the off-beat humor, mystery, and mythic power of his work for a wide audience of English-speaking readers. It showcases the work of a man whom Allen Ginsberg has called "a magnificent poet, a combination of Buddhist cognoscente, passionate political libertarian, and naturalist historian," who Gary Snyder has said is "a real-world poet!" who "outfoxes the Old Masters and the young poets both," and who Lawrence Ferlinghetti has described as "no doubt the greatest living Korean Zen poet today."', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '404538', '4.21', '51', '9', 'https://www.goodreads.com/book/show/404538.The_Three_Way_Tavern');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Manatee/Humanity', '', 'A fascinating new work from an internationally renowned poet
Anne Waldman''s new investigative hybrid-poem explores the nuances of inter-species communication and compassion. It draws on animal lore, animal encounters (with grey wolf and manatee), dreams, evolutionary biology, neuroscience, and Buddhist ritual to render a text of remarkable sympathy, reciprocity, and power. The poem asks questions as well as urges further engagement with the endangered (including our human selves). Part performance litany, part survival kit, part worried mammalian soundings, Waldman explores, as ever, what it means to inhabit our condition through language and imagination inside a wheel of time. This is the mature work of a philosophical field poet with a shamanic metabolism.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '6011611', '4.2', '50', '6', 'https://www.goodreads.com/book/show/6011611-manatee-humanity');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Trado', '', 'Svetlana Carstean och Athena Farrokhzad traffades pa en oversattarworkshop 2012. Motet utmynnade i att de tolkade varandras diktsamlingar Skruvstadsblomman och Vitsvit till svenska respektive rumanska, utan att beharska spraken ifraga. Trado ar en fortsattning pa deras samarbete. Har ar originalet en konsekvens av oversattningen, i en dikt om arv, forraderi och vanskap, dar tva roster blandar sig och byter plats.', 'https://images.gr-assets.com/books/1462743024m/28531301.jpg', '28531301', '4.16', '50', '2', 'https://www.goodreads.com/book/show/28531301-trado');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Happy Life', '', '"David Budbill is a no-nonsense free-range sage who celebrates tomatoes in September, the whistle of a woodcock and sweet black tea and ancient Chinese poems." --New York Times"Budbill both informs and moves. He is, in short, a delight and a comfort."--Wendell Berry"[Budbill] can be hilarious, as when he gripes, ''What good is my humility / when I am / stuck / in this obscurity?''"--Booklist, starred review"His terse, epigrammatic lyrics are a lilting mirror of classical Chinese poetry."--The Wichita EagleDavid Budbill continues his popular poetic ruminations on life in remote New England--an outward survey of a forested mountain and an introspection of self-reliance, anonymity, and the creative life. Inspired by classical Chinese and Japanese poets, Budbill contemplates the seasons, ambition, his questionable desire for fame and fortune, and simple, focused contentment: "Weed the beans. Pick the peas.""Out in the Woods"The only time I''m really free is when I''m out in the woodscutting firewood, stacking brush, clearing trails.Just the chain saw, the dog and me.Heave and groan, sweat and ache.Work until I can''t stand it anymore.Take a break.Sit on the needle-strewn ground up against a big pine tree,drink some water, stare out through the woods, pet the dog.Stretch out on the ground, take a nap,dog''s head on my lap.Ah, this would be the time and place and wayto die.David Budbill is the author of poems, plays, essays, speeches, and book reviews. He has also served as a commentator on NPR''s All Things Considered. He lives in the mountains of northern Vermont where he tends his garden and website.', 'https://images.gr-assets.com/books/1328758124m/11793659.jpg', '11793659', '4.17', '50', '14', 'https://www.goodreads.com/book/show/11793659-happy-life');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Teogonía', '', 'Hesiodo - La Teogonia es una obra poetica escrita por Hesiodo. Contiene una de las mas antiguas versiones del origen del cosmos y el linaje de los dioses de la mitologia griega. Es una de las obras claves de la epica grecolatina.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '29869936', '3.7', '50', '5', 'https://www.goodreads.com/book/show/29869936-teogon-a');
