INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Le Contre-Ciel', '', 'For this early 20th century French poet-philosopher, life, in its most dynamic sense, can only be experienced after the facade of self-identity has been systematically negated through a kind of metaphysical suicide. In Le Contre-Ciel, Daumal invites us, his readers, to go through this process of regeneration-through-negation with him in order to revive in ourselves a knowledge and understanding of our primordial sources.', 'https://images.gr-assets.com/books/1358746367m/594103.jpg', '594103', '4.3', '50', '3', 'https://www.goodreads.com/book/show/594103.Le_Contre_Ciel');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Dance of No Hard Feelings', '', '', 'https://images.gr-assets.com/books/1354209372m/6533665.jpg', '6533665', '4.04', '50', '5', 'https://www.goodreads.com/book/show/6533665-the-dance-of-no-hard-feelings');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Hemming Flames', '', 'Volume 19 of the May Swenson Poetry Award Series, 2016
Throughout this haunting first collection, Patricia Colleen Murphy shows how familial mental illness, addiction, and grief can render even the most courageous person helpless. With depth of feeling, clarity of voice, and artful conflation of surrealist image and experience, she delivers vivid descriptions of soul-shaking events with objective narration, creating psychological portraits contained in sharp, bright language and image. With Plathian relentlessness, Hemming Flamesexplores the deepest reaches of family dysfunction through highly imaginative language and lines that carry even more emotional weight because they surprise and delight. In landscapes as varied as an Ohio back road, a Russian mental institution, a Korean national landmark, and the summit of Kilimanjaro, each poem sews a new stitch on the dark tapestry of a disturbed suburban family''s world.
The May Swenson Poetry Award is an annual competition named for May Swenson, one of America''s most provocative and vital writers. During her long career, Swenson was loved and praised by writers from virtually every school of American poetry. She left a legacy of fifty years of writing when she died in 1989. She is buried in her hometown of Logan, Utah.', 'https://images.gr-assets.com/books/1465654996m/29993389.jpg', '29993389', '4.87', '50', '23', 'https://www.goodreads.com/book/show/29993389-hemming-flames');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Contemporary American Poets', '', '', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '2340137', '4.04', '50', '6', 'https://www.goodreads.com/book/show/2340137.The_Contemporary_American_Poets');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Owls and Other Fantasies: Poems and Essays', '', 'Within these pages Mary Oliver collects twenty-six of her poems about the birds that have been such an important part of her life-hawks, hummingbirds, and herons; kingfishers, catbirds, and crows; swans, swallows and, of course, the snowy owl, among a dozen others-including ten poems that have never before been collected. She adds two beautifully crafted essays, "Owls," selected for the Best American Essays series, and "Bird," a new essay that will surely take its place among the classics of the genre.
In the words of the poet Stanley Kunitz, "Mary Oliver''s poetry is fine and deep; it reads like a blessing. Her special gift is to connect us with our sources in the natural world, its beauties and terrors and mysteries and consolations."
For anyone who values poetry and essays, for anyone who cares about birds, Owls and Other Fantasieswill be a treasured gift; for those who love both, it will be essential reading.', 'https://images.gr-assets.com/books/1320482202m/2336667.jpg', '2336667', '4.36', '50', '7', 'https://www.goodreads.com/book/show/2336667.Owls_and_Other_Fantasies');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Collected Poems Of Sir Thomas Wyatt', '', '', 'https://images.gr-assets.com/books/1319837480m/2154163.jpg', '2154163', '3.41', '50', '6', 'https://www.goodreads.com/book/show/2154163.Collected_Poems_Of_Sir_Thomas_Wyatt');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Sopa de frijoles / Bean Soup', '', 'A USBBY Outstanding International Books selection
Black beans and black bean soup are staple foods for people who live anywhere from southern Mexico on down through Central America. They are comfort foods. For all people who have left their homeland to live in a new country, comfort food takes on a huge emotional importance.
This delightful poem teaches us all, young and old, how to make a heartwarming bean soup -- from gathering the beans, onions and garlic to letting them swim in the pot, until the house smells wonderful and it''s time for supper.
Jorge Argueta''s poetic voice and Rafael Yockteng''s animated illustrations make this bilingual book about preparing bean soup a fun, almost magical experience.', 'https://images.gr-assets.com/books/1328770820m/6624274.jpg', '6624274', '3.96', '50', '16', 'https://www.goodreads.com/book/show/6624274-sopa-de-frijoles-bean-soup');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Chasers of the Light: Poems from the Typewriter Series', '', 'I would love to say that you make me weak at the knees, but to be quite upfront and completely truthful, you make my body forget it has knees at all. One day, while browsing an antique store in Helena, Montana, photographer Tyler Knott Gregson stumbled upon a vintage Remington typewriter for sale. Standing up and using a page from a broken book he was buying for $2, he typed a poem without thinking, without planning, and without the ability to revise anything. He fell in love. Three years and almost one thousand poems later, Tyler is now known as the creator of the Typewriter Series: a striking collection of poems typed onto found scraps of paper or created via blackout method. Chasers of the Light features some of his most insightful and beautifully worded pieces of work-poems that illuminate grand gestures and small glimpses, poems that celebrate the beauty of a life spent chasing the light.', 'https://images.gr-assets.com/books/1450116582m/28195306.jpg', '28195306', '4.27', '50', '13', 'https://www.goodreads.com/book/show/28195306-chasers-of-the-light');
INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('Drinking with Bukowski: Recollections of the Poet Laureate of Skid Row', '', 'The 20th century''s greatest poet was a guy from L.A. called Hank, who talked straight, drank hard, faced truth, and exposed beauty and vulnerability like no other in his place and time. Drinking with Bukowski is a celebration of that utterly original voice featuring contributions from everyone from the women who loved him to the Hollywood cognoscenti who courted him, from writers who admired him and actors who tried to emulate him to the barflies, strippers, gangsters, poets, crazies, and dreamers who knew him: Raymond Carver, Wanda Coleman, Harold Norse, Michael C. Ford, and Paul Vangelisti pay homage and recount the Dionysian days of L.A. poetry; record producer Harvey Robert Kubernik and journalist Barry Miles remember capturing Buk on vinyl for the first time; novelist Steve Abee remembers the early days of L.A.''s underground newspapers - Open City and the L.A. Free Press - Bukowski''s early stomping grounds.', 'https://s.gr-assets.com/assets/nophoto/book/111x148-bcc042a9c91a29c1d680899eff700a03.png', '50512', '3.58', '50', '3', 'https://www.goodreads.com/book/show/50512.Drinking_with_Bukowski');
