INSERT INTO books (title, author, description, cover_url, goodreads_id, average_rating, ratings_count, review_count, external_url) VALUES ('The Complete Poems', '', '', 'https://images.gr-assets.com/books/1297525414m/6134973.jpg', '6134973', '4.16', '50', '5', 'https://www.goodreads.com/book/show/6134973-the-complete-poems');
